    ;
    move.b  ($18,A4,D2.W),D0
    cmpi.b  #$23,D0
    beq  _L_z04_L_Walker_SetInputDirAndTryShootingBoomerang_CheckTimerToShootBoomerang
    cmpi.b  #$77,D0
    bne  _L_z04_L_Walker_SetInputDirAndTryShootingBoomerang_Exit
