    ;
    lea     ($041F,A4),A0
    move.b  (A0,D2.W),D0
    moveq   #0,D3
    lea     ($0451,A4),A0
    move.b  (A0,D2.W),D3
    jsr     Fireball_MoveOneAxis
    lea     ($0451,A4),A0
    move.b  D0,(A0,D2.W)
    ; Second, load the vertical direction into [0F].
    ;
    lea     ($0437,A4),A0
    move.b  (A0,D2.W),D0
    move.b  D0,($000F,A4)
    ; Load the vertical q-speed and position fraction,
    ; move, then save the position fraction.
    ;
    lea     ($0444,A4),A0
    move.b  (A0,D2.W),D0
    moveq   #0,D3
    lea     ($045E,A4),A0
    move.b  (A0,D2.W),D3
    jsr     Fireball_MoveOneAxis
    lea     ($045E,A4),A0
    move.b  D0,(A0,D2.W)
    even
_L_z04_UpdateFireball_CheckCollisionAndDraw:
    ; Check for collision with Link. If hit, then go destroy the fireball.
    ;
    jsr     CheckShotLinkCollision
    move.b  ($034B,A4),D0
    bne  _L_z04_UpdateFireball_DestroyMonster
    jmp     L_DrawShot

; Params:
; A: q-speed
; Y: position fraction
; [0F]: movement direction
;
; Returns:
; A: position fraction
;
; Load the q-speed and position fraction from the parameters.
;
    even
Fireball_MoveOneAxis:
    lea     ($03BC,A4),A0
    move.b  D0,(A0,D2.W)
    move.b  D3,D0
    lea     ($03A8,A4),A0
    move.b  D0,(A0,D2.W)
    jsr     MoveObject
    ; Return the updated position fraction.
    ;
    lea     ($03A8,A4),A0
    move.b  (A0,D2.W),D0
    rts

    even
InitBubble:
    moveq   #64,D0
    lea     ($03BC,A4),A0
    move.b  D0,(A0,D2.W)
    jmp     InitWalker

    even
InitBlueKeese:
    ; Choose one of eight random directions.
    ;
    move.b  ($18,A4,D2.W),D0
    andi.b #$07,D0
    moveq   #0,D3
    move.b  D0,D3
    lea     (Directions8).l,A0
    move.b  (A0,D3.W),D0
    lea     ($0098,A4),A0
    move.b  D0,(A0,D2.W)
    jsr     ResetFlyerState
    move.b  #$C0,D0
    move.b  D0,($04D1,A4)
    moveq   #31,D0
    lea     ($041F,A4),A0
    move.b  D0,(A0,D2.W)
    rts

    even
InitRedOrBlackKeese:
    jsr     InitBlueKeese
    ; Red and black keeses are like blue ones, but faster.
    ;
    moveq   #127,D0
    lea     ($041F,A4),A0
    move.b  D0,(A0,D2.W)
    rts

    even
UpdateBubble:
    moveq   #64,D0
    jsr     UpdateCommonWanderer
    lea     ($034F,A4),A0
    move.b  (A0,D2.W),D0
    ; If the bubble is not type $2B that temporarily blocks the sword;
    ; then subtract $2B from the type to get 1 or 2, which
    ; represent the blue and red palette rows in sprite attributes.
    ;
    cmpi.b  #$2B,D0
    beq  _L_z04_UpdateBubble_Flash
    ori     #$11,CCR  ; SEC: set C+X
    move.b  #$2B,D1
    eori    #$10,CCR  ; flip X: 6502 SBC polarity
    subx.b  D1,D0   ; SBC #$2B
    eori    #$10,CCR  ; restore X = 6502 C
    jmp     _L_z04_UpdateBubble_Animate

    even
_L_z04_UpdateBubble_Flash:
    ; Else make it flash by cycling all the palette rows.
    ;
    move.b  ($0015,A4),D0
    andi.b #$03,D0
    even
_L_z04_UpdateBubble_Animate:
    jsr     Anim_SetSpriteDescriptorAttributes
    ; Animation counter 1 to switch animation frames every screen frame.
    ;
    moveq   #1,D0
    jsr     AnimateAndDrawCommonObject
    jsr     CheckLinkCollision
    ; If no collision, then return.
    ;
    move.b  ($0006,A4),D0
    beq  _L_z04_UpdateBubble_Exit
    ; If not type $2B (flashing), then go block or unblock the sword
    ; depending on the bubble type.
    ;
    lea     ($034F,A4),A0
    move.b  (A0,D2.W),D0
    cmpi.b  #$2B,D0
    bne  _L_z04_UpdateBubble_BlockOrUnblock
    ; Else the flashing bubble blocks the sword temporarily.
    ; Set a long timer to $10 ($A0 frames) for this purpose.
    ;
    moveq   #16,D0
    move.b  D0,($004C,A4)
    even
_L_z04_UpdateBubble_Exit:
    rts

    even
_L_z04_UpdateBubble_BlockOrUnblock:
    ; Subtract $2C from the type to get the value for blocking: 0 or 1
    ;
    ori     #$11,CCR  ; SEC: set C+X
    move.b  #$2C,D1
    eori    #$10,CCR  ; flip X: 6502 SBC polarity
    subx.b  D1,D0   ; SBC #$2C
    eori    #$10,CCR  ; restore X = 6502 C
    move.b  D0,($052E,A4)
    eori    #$01,CCR  ; normalize C to 6502 polarity before RTS
    rts

; Params:
; A: new value for animation counter
; X: object index
;
    even
AnimateAndDrawCommonObject:
    jsr     Anim_AdvanceAnimCounterAndSetObjPosForSpriteDescriptor
    jsr     Anim_SetObjHFlipForSpriteDescriptor
    moveq   #0,D0
    jmp     DrawObjectNotMirrored

    even
UpdateKeese:
    ; If the magic clock is missing and Link is not lifting an item,
    ; then fly.
    ;
    move.b  ($066C,A4),D0
    move.b  ($0506,A4),D1
    or.b  D1,D0
    bne  _anon_z04_22
    jsr     ControlKeeseFlight
    jsr     MoveFlyer
_anon_z04_22:
    jsr     Anim_FetchObjPosForSpriteDescriptor
    ; Like peahats, keeses animate as fast as they move.
    ; But keese beat their wings at half the rate.
    ;
    lea     ($0437,A4),A0
    move.b  (A0,D2.W),D0
    andi.b #$02,D0
    lsr.b  #1,D0   ; LSR A
    jsr     DrawObjectMirrored
    jsr     CheckMonsterCollisions
    jmp     ResetShoveInfo

    even
ControlKeeseFlight:
    lea     ($0444,A4),A0
    move.b  (A0,D2.W),D0
    jsr     _m68k_tablejump  ; M68K-native table dispatch (replaces JSR TableJump)
    even
ControlKeeseFlight_JumpTable:
    dc.l    Flyer_SpeedUp   ; jump table entry (32-bit for _m68k_tablejump)
    dc.l    Flyer_KeeseDecideState   ; jump table entry (32-bit for _m68k_tablejump)
    dc.l    Flyer_Chase   ; jump table entry (32-bit for _m68k_tablejump)
    dc.l    Flyer_Wander   ; jump table entry (32-bit for _m68k_tablejump)
    dc.l    Flyer_SlowDown   ; jump table entry (32-bit for _m68k_tablejump)
    dc.l    Flyer_Delay   ; jump table entry (32-bit for _m68k_tablejump)

    even
Flyer_KeeseDecideState:
    ; Go to the next state randomly:
    ; Random >= $A0: 2
    ; Random >= $20: 3
    ; Else:          4
    ;
    ; Set up 6 turns.
    ;
    moveq   #2,D3
    move.b  ($19,A4,D2.W),D0
    cmpi.b  #$A0,D0
    bcs.s  __far_z_04_0017
    jmp  Flyer_SetStateAndTurns
__far_z_04_0017:
    addq.b  #1,D3
    cmpi.b  #$20,D0
    bcs.s  __far_z_04_0018
    jmp  Flyer_SetStateAndTurns
__far_z_04_0018:
    addq.b  #1,D3
    even
Flyer_SetStateAndTurns:
    move.b  D3,D0
    lea     ($0444,A4),A0
    move.b  D0,(A0,D2.W)
    moveq   #6,D0
    lea     ($042C,A4),A0
    move.b  D0,(A0,D2.W)
    rts

    even
UpdateZol:
    jsr     UpdateZolState
    jsr     Zol_CheckCollisions
    jsr     Anim_FetchObjPosForSpriteDescriptor
    ; Every 8 screen frames, switch between frame image 0 and 1.
    ;
    moveq   #0,D3
    move.b  ($0015,A4),D0
    andi.b #$08,D0
    bne  _anon_z04_23
    addq.b  #1,D3
_anon_z04_23:
    move.b  D3,D0
    jmp     DrawObjectMirrored

    even
UpdateZolState:
    lea     ($00AC,A4),A0
    move.b  (A0,D2.W),D0
    jsr     _m68k_tablejump  ; M68K-native table dispatch (replaces JSR TableJump)
    even
UpdateZolState_JumpTable:
    dc.l    UpdateZolState0_Wander   ; jump table entry (32-bit for _m68k_tablejump)
    dc.l    UpdateZolState1_Shove   ; jump table entry (32-bit for _m68k_tablejump)
    dc.l    UpdateZolState2_Split   ; jump table entry (32-bit for _m68k_tablejump)

    even
UpdateZolState0_Wander:
    moveq   #24,D0
    jmp     UpdateNormalZolOrGel

    even
UpdateZolState1_Shove:
    ; Move straight and fast until blocked. Then go to state 2.
    ;
    jsr     Gel_MoveSplitting
    bcc  _anon_z04_24
    lea     ($00AC,A4),A0
    addq.b  #1,(A0,D2.W)
_anon_z04_24:
    rts

    even
UpdateZolState2_Split:
    ; We'll create two gels, but destroy the zol. So, increase
    ; the object count by 1 only.
    ;
    addq.b  #1,($034E,A4)
    jsr     DestroyMonster
    jsr     CreateChildGel
    ; If the zol's direction is vertical, then set the first child gel's
    ; direction to left, else up.
    ;
    lea     ($0098,A4),A0
    move.b  (A0,D2.W),D0
    cmpi.b  #$04,D0
    moveq   #2,D0
    bcc  _anon_z04_25
    moveq   #8,D0
_anon_z04_25:
    lea     ($0098,A4),A0
    move.b  D0,(A0,D3.W)
    move.b  D0,-(A5)  ; PHA
    jsr     CreateChildGel
    move.b  (A5)+,D0  ; PLA
    ; Set the second child gel's direction to the opposite of the first one's.
    ;
    lsr.b  #1,D0   ; LSR A
    lea     ($0098,A4),A0
    move.b  D0,(A0,D3.W)
    rts

    even
CreateChildGel:
    moveq   #20,D0
    ; Use the shooting operation to create the gel object.
    ;
    move.b  D0,($0000,A4)
    jsr     ShootLimited
    ; Shots start in state $10. But Child Gel needs to start in state 0.
    ;
    moveq   #0,D0
    lea     ($00AC,A4),A0
    move.b  D0,(A0,D3.W)
    ; Give the child the same grid offset as the parent.
    ;
    lea     ($0394,A4),A0
    move.b  (A0,D2.W),D0
    lea     ($0394,A4),A0
    move.b  D0,(A0,D3.W)
    rts

    even
Zol_CheckCollisions:
    ; If not in state 0, then return.
    ;
    lea     ($00AC,A4),A0
    move.b  (A0,D2.W),D0
    bne  _L_z04_Zol_CheckCollisions_Exit
    ; Check collisions.
    ;
    ; If killed, or got hit but didn't get hurt (invincibility timer = 0),
    ; then return.
    ;
    jsr     Gel_CheckCollisions
    lea     ($0405,A4),A0
    move.b  (A0,D2.W),D0
    bne  _L_z04_Zol_CheckCollisions_Exit
    lea     ($04F0,A4),A0
    move.b  (A0,D2.W),D0
    beq  _L_z04_Zol_CheckCollisions_Exit
    ; If vertically aligned with the square grid, then
    ; use a horizontal direction mask (3).
    ;
    ; Keep in mind that most objects are aligned vertically when
    ; the low nibble of their Y is $D.
    ;
    moveq   #0,D3
    lea     ($0084,A4),A0
    move.b  (A0,D2.W),D0
    andi.b #$0F,D0
    cmpi.b  #$0D,D0
    bne  _anon_z04_26
    moveq   #3,D3
_anon_z04_26:
    move.b  D3,($0000,A4)
    ; If horizontally aligned with the square grid, then
    ; use a vertical direction mask ($C).
    ;
    moveq   #0,D3
    move.b  ($70,A4,D2.W),D0
    andi.b #$0F,D0
    bne  _anon_z04_27
    moveq   #12,D3
_anon_z04_27:
    move.b  D3,D0
    ; Combine the two masks. At most one will be 0.
    ;
    move.b  ($0000,A4),D1
    or.b  D1,D0
    ; The point is to see if the zol is facing in a way that's aligned
    ; with the grid.
    ;
    ; If so, then go to state 1 to do a "big shove".
    ; Else go to state 2, to immediately split in two.
    ;
    ; Examples:
    ; It would be aligned, if moving left along a tile as usual.
    ; It would *not* be aligned, if while moving left, it was hit downward.
    ; - The collision check routines would have made the zol
    ;   face in the direction of the weapon.
    ; - See CheckMonsterWeaponCollision.
    ;
    move.b  ($0098,A4),D1
    and.b  D1,D0
    bne  _anon_z04_28
    lea     ($00AC,A4),A0
    addq.b  #1,(A0,D2.W)
_anon_z04_28:
    lea     ($00AC,A4),A0
    addq.b  #1,(A0,D2.W)
    even
_L_z04_Zol_CheckCollisions_Exit:
    rts

    even
InitGel:
    moveq   #2,D0
    lea     ($00AC,A4),A0
    move.b  D0,(A0,D2.W)
    jmp     InitWalker

    even
UpdateGel:
    jsr     Gel_Move
    jsr     Gel_CheckCollisions
    ; Gels are narrow. So, temporarily shift the X coordinate
    ; 4 pixels to the right.
    ;
    move.b  ($70,A4,D2.W),D0
    move.b  D0,-(A5)  ; PHA
    andi    #$EE,CCR  ; CLC: clear C+X
    move.b  #$04,D1
    addx.b  D1,D0   ; ADC #$04 (X flag = 6502 C)
    move.b  D0,($70,A4,D2.W)
    jsr     Anim_FetchObjPosForSpriteDescriptor
    ; Every two screen frames, switch between frame image 0 and 1.
    ;
    moveq   #0,D3
    move.b  ($0015,A4),D0
    andi.b #$02,D0
    bne  _anon_z04_29
    addq.b  #1,D3
_anon_z04_29:
    ; Set sprite attributes 3: normal sprite, palette row "level".
    ;
    moveq   #3,D0
    jsr     Anim_SetSpriteDescriptorAttributes
    move.b  D3,D0
    jsr     DrawObjectNotMirrored
    move.b  (A5)+,D0  ; PLA
    move.b  D0,($70,A4,D2.W)
    rts

    even
Gel_Move:
    ; Go handle state 0 or 2 as appropriate.
    ;
    moveq   #0,D3
    lea     ($00AC,A4),A0
    move.b  (A0,D2.W),D3
    beq  _L_z04_Gel_Move_State0
    subq.b  #1,D3
    bne  _L_z04_Gel_Move_State2
    ; State 1.
    ;
    ; If the timer has not expired, then move.
    ;
    move.b  ($28,A4,D2.W),D0
    beq  _L_z04_Gel_Move_Move
    jsr     Gel_MoveSplitting
    ; If not blocked while moving, then return.
    ;
    bcc  _L_z04_Gel_Move_Exit
    even
_L_z04_Gel_Move_Move:
    ; Blocked or timer expired.
    ;
    ; Set X coordinate to ((X + 8) AND $F0).
    ;
    move.b  ($70,A4,D2.W),D0
    andi    #$EE,CCR  ; CLC: clear C+X
    move.b  #$08,D1
    addx.b  D1,D0   ; ADC #$08 (X flag = 6502 C)
    andi.b #$F0,D0
    move.b  D0,($70,A4,D2.W)
    ; Set Y coordinate to (((Y + 8) AND $F0) OR $D).
    ;
    lea     ($0084,A4),A0
    move.b  (A0,D2.W),D0
    move.b  #$08,D1
    addx.b  D1,D0   ; ADC #$08 (X flag = 6502 C)
    andi.b #$F0,D0
    ori.b #$0D,D0
    lea     ($0084,A4),A0
    move.b  D0,(A0,D2.W)
    ; Reset the grid offset, and go to state 2.
    ;
    moveq   #0,D0
    lea     ($0394,A4),A0
    move.b  D0,(A0,D2.W)
    lea     ($00AC,A4),A0
    addq.b  #1,(A0,D2.W)
    even
_L_z04_Gel_Move_Exit:
    rts

    even
_L_z04_Gel_Move_State0:
    ; State 0.
    ;
    ; Immediately go to state 1 with QSpeed $20 (half a pixel a frame),
    ; and 5 frame timer.
    ;
    moveq   #32,D0
    lea     ($03BC,A4),A0
    move.b  D0,(A0,D2.W)
    moveq   #5,D0
    move.b  D0,($28,A4,D2.W)
    lea     ($00AC,A4),A0
    addq.b  #1,(A0,D2.W)
    rts

    even
_L_z04_Gel_Move_State2:
    ; State 2.
    ;
    ; Set QSpeed $40 (1 pixel a frame).
    ;
    moveq   #64,D0
; Params:
; A: qspeed
;
    even
UpdateNormalZolOrGel:
    lea     ($03BC,A4),A0
    move.b  D0,(A0,D2.W)
    ; If object timer >= 5, then return.
    ;
    move.b  ($28,A4,D2.W),D0
    cmpi.b  #$05,D0
    bcc  _L_z04_UpdateNormalZolOrGel_Exit
    moveq   #32,D0
    lea     ($041F,A4),A0
    move.b  D0,(A0,D2.W)
    jsr     Wanderer_TargetPlayer
    ; If the monster is between squares, or timer <> 0; then return.
    ;
    lea     ($0394,A4),A0
    move.b  (A0,D2.W),D0
    move.b  ($28,A4,D2.W),D1
    or.b  D1,D0
    bne  _L_z04_UpdateNormalZolOrGel_Exit
    ; Choose a random index (0 to 3) to look up an amount of time.
    ;
    move.b  ($18,A4,D2.W),D0
    andi.b #$03,D0
    moveq   #0,D3
    move.b  D0,D3
    ; If the monster is Zol, then go use this index as is.
    ;
    lea     ($034F,A4),A0
    move.b  (A0,D2.W),D0
    cmpi.b  #$13,D0
    beq  _L_z04_UpdateNormalZolOrGel_SetDelay
    ; Else it's a gel. Add 4 to the index to look in the set of times
    ; for Gel.
    ;
    addq.b  #1,D3
    addq.b  #1,D3
    addq.b  #1,D3
    addq.b  #1,D3
    even
_L_z04_UpdateNormalZolOrGel_SetDelay:
    ; Set a delay at a tile edge for the next time to move.
    ;
    lea     (ZolGelDelays).l,A0
    move.b  (A0,D3.W),D0
    move.b  D0,($28,A4,D2.W)
    even
_L_z04_UpdateNormalZolOrGel_Exit:
    rts

    even
ZolGelDelays:
    dc.b    $18, $28, $38, $48, $08, $18, $28, $38

; Returns:
; C: 1 if blocked
;
; Set the speed to maximum.
;
    even
Gel_MoveSplitting:
    move.b  #$FF,D0
    lea     ($03BC,A4),A0
    move.b  D0,(A0,D2.W)
    ; Set moving direction to facing direction.
    ;
    lea     ($0098,A4),A0
    move.b  (A0,D2.W),D0
    move.b  D0,($000F,A4)
    ; If at a tile boundary, then check for a tile collision.
    ;
    lea     ($0394,A4),A0
    move.b  (A0,D2.W),D0
    bne  _L_z04_Gel_MoveSplitting_CheckRoomBoundary
    jsr     GetCollidingTileMoving
    ; If blocked by a tile, then return C=1.
    ;
    move.b  ($034A,A4),D1
    cmp.b   D1,D0
    bcc  _L_z04_Gel_MoveSplitting_Exit
    even
_L_z04_Gel_MoveSplitting_CheckRoomBoundary:
    ; If blocked by the room boundary, then return C=1.
    ;
    jsr     BoundByRoom
    ori     #$11,CCR  ; SEC: set C+X
    beq  _L_z04_Gel_MoveSplitting_Exit
    ; Move.
    ;
    jsr     MoveObject
    ; Mask the grid offset with $F (to a square length),
    ; and return C=0.
    ;
    lea     ($0394,A4),A0
    move.b  (A0,D2.W),D0
    andi.b #$0F,D0
    andi    #$EE,CCR  ; CLC: clear C+X
    bne  _L_z04_Gel_MoveSplitting_Exit
    lea     ($0394,A4),A0
    move.b  D0,(A0,D2.W)
    even
_L_z04_Gel_MoveSplitting_Exit:
    rts

    even
Gel_CheckCollisions:
    ; TODO:
    ; CheckMonsterCollisions calls GetObjectMiddle which
    ; overwrites [02] and [03]. So, I don't know why these are set here.
    ;
    move.b  ($70,A4,D2.W),D0
    move.b  D0,($0002,A4)
    lea     ($0084,A4),A0
    move.b  (A0,D2.W),D0
    move.b  D0,($0003,A4)
    jmp     CheckMonsterCollisions

    even
StatueRoomLayouts:
    dc.b    $24, $23

    even
StatueFireballCounts:
    dc.b    $03, $01, $01

    even
StatueFireballStartTimes:
    dc.b    $50, $80, $F0, $60

    even
StatuePatternToBasePositionIndex:
    dc.b    $00, $04, $06

; A list of coordinates divided into sets for each pattern.
;
    even
StatueXs:
    dc.b    $24, $C8, $24, $C8, $64, $88, $48, $A8

; A list of coordinates divided into sets for each pattern.
;
    even
StatueYs:
    dc.b    $C0, $BC, $64, $5C, $94, $8C, $82, $86

    even
UpdateStatues:
    ; If person fireballs are enabled (from the two fires), then
    ; go make fireballs with pattern 2.
    ;
    moveq   #2,D3
    move.b  ($04CC,A4),D0
    bne  _L_z04_UpdateStatues_Shoot
    ; Else if the room layout has two or four statues that shoot fireballs,
    ; then go shoot fireballs with the corresponding pattern in Y register:
    ; - layout $23: pattern 1: 2 statues
    ; - layout $24: pattern 0: 4 statues
    ;
    jsr     GetUniqueRoomId
    moveq   #1,D3
_anon_z04_30:
    lea     (StatueRoomLayouts).l,A0
    move.b  (A0,D3.W),D1
    cmp.b   D1,D0
    beq  _L_z04_UpdateStatues_Shoot
    subq.b  #1,D3
    bpl  _anon_z04_30
    rts

    even
_L_z04_UpdateStatues_Shoot:
    ; Look for an empty monster slot.
    ; If none is found, return.
    ;
    ; Later, for each fireball, we'll call a routine to make the fireball
    ; object. This routine takes a shooter object, and instantiates
    ; a fireball object at the shooter's location.
    ;
    ; The object slot we set up here will behave as the shooter.
    ; For each fireball index, this object slot will have its coordinates
    ; changed.
    ;
    ; Note that this means that:
    ; 1. The first fireball made will be its own shooter.
    ;    Practically, there's nothing special about this.
    ; 2. If there is more than one fireball made in a frame,
    ;    then two of them will come from the same statue.
    ;
    ;
    ; Save the fireball pattern.
    move.b  D3,D0
    move.b  D0,-(A5)  ; PHA
    jsr     FindEmptyMonsterSlot
    cmpi.b  #$01,D0
    move.b  (A5)+,D0  ; PLA
    bcc  _L_z04_UpdateStatues_Exit
    ; If we found a slot, but it < 6, return.
    ;
    cmpi.b  #$06,D3
    bcs  _L_z04_UpdateStatues_Exit
    ; Store the object slot in [0A].
    ; Store fireball pattern in [0B].
    ;
    move.b  D3,($000A,A4)
    move.b  D0,($000B,A4)
    ; Look for the number of fireballs to make (minus 1) by pattern number.
    ;
    moveq   #0,D3
    move.b  D0,D3
    moveq   #0,D2
    lea     (StatueFireballCounts).l,A0
    move.b  (A0,D3.W),D2
    even
_L_z04_UpdateStatues_LoopFireball:
    ; For each fireball to make, indexed by X, (1 or 3 down to 0):
    ;
    ; Decrement the fireball timer at this index.
    ;
    moveq   #0,D3
    lea     ($04E8,A4),A0
    move.b  (A0,D2.W),D3
    subq.b  #1,D3
    move.b  D3,D0
    lea     ($04E8,A4),A0
    move.b  D0,(A0,D2.W)
    ; If it was not 0, then this fireball index has to keep waiting
    ; to make a fireball. Go loop again.
    ;
    addq.b  #1,D3
    bne  _L_z04_UpdateStatues_NextLoopFireball
    ; If the random value for this fireball index >= $F0, go loop again.
    ; This fireball index will wait another $100 frames.
    ;
    move.b  ($18,A4,D2.W),D0
    cmpi.b  #$F0,D0
    bcc  _L_z04_UpdateStatues_NextLoopFireball
    ; Else choose one of four start times for the fireball based on
    ; the random value.
    ;
    andi.b #$03,D0
    moveq   #0,D3
    move.b  D0,D3
    lea     (StatueFireballStartTimes).l,A0
    move.b  (A0,D3.W),D0
    lea     ($04E8,A4),A0
    move.b  D0,(A0,D2.W)
    ; The coordinate lists are divided into sets for each pattern.
    ;
    ; Look up the index of the base of the set for the pattern in use.
    ; Add it to the fireball index in X register to get the index of
    ; the coordinate we want within each coordinate list.
    ;
    ;
    ; Pattern
    moveq   #0,D3
    move.b  ($000B,A4),D3
    move.b  D2,D0
    andi    #$EE,CCR  ; CLC: clear C+X
    lea     (StatuePatternToBasePositionIndex).l,A0
    move.b  (A0,D3.W),D1
    addx.b  D1,D0   ; ADC StatuePatternToBasePositionIndex,Y
    moveq   #0,D3
    move.b  D0,D3
    move.b  D2,D0
    move.b  D0,-(A5)  ; PHA
    ; Get Link's coordinates into [00] and [01].
    ;
    moveq   #0,D2
    jsr     Anim_FetchObjPosForSpriteDescriptor
    ; Switch to the new fireball's object slot.
    ;
    moveq   #0,D2
    move.b  ($000A,A4),D2
    ; Look up and set the X coordinate for the fireball object.
    ; Also store it in [02].
    ;
    lea     (StatueXs).l,A0
    move.b  (A0,D3.W),D0
    move.b  D0,($0002,A4)
    move.b  D0,($70,A4,D2.W)
    ; Look up and set the Y coordinate for the fireball object.
    ; Also store it in [03].
    ;
    lea     (StatueYs).l,A0
    move.b  (A0,D3.W),D0
    move.b  D0,($0003,A4)
    lea     ($0084,A4),A0
    move.b  D0,(A0,D2.W)
    ; Set mask value 3 in [04].
    ;
    moveq   #3,D0
    move.b  D0,($0004,A4)
    ; Loop to compare each of Link's coordinates to the fireball's.
    ; Each time the distance < $18, the mask in [04] is shifted right.
    ;
    moveq   #1,D3
    even
_L_z04_UpdateStatues_LoopAxis:
    move.b  ($00,A4,D3.W),D0
    ori     #$11,CCR  ; SEC: set C+X
    move.b  ($02,A4,D3.W),D1
    eori    #$10,CCR  ; flip X: 6502 SBC polarity
    subx.b  D1,D0   ; SBC $0002,Y
    eori    #$10,CCR  ; restore X = 6502 C
    cmpi.b  #$18,D0
    bpl  _anon_z04_31
    cmpi.b  #$E8,D0
    bmi  _anon_z04_31
    move.b  ($0004,A4),D1
    lsr.b  #1,D1   ; LSR $04
    move.b  D1,($0004,A4)
_anon_z04_31:
    subq.b  #1,D3
    bpl  _L_z04_UpdateStatues_LoopAxis
    ; If [04] <> 0, then its value is 1 or 3, meaning that it was shifted
    ; 0 or 1 time, instead of 2.
    ;
    ; This, in turn, means that the distance between Link and the
    ; fireball was >= $18 in at least one axis.
    ;
    ; So, we're OK to finish making the fireball.
    ;
    move.b  ($0004,A4),D0
    beq  _anon_z04_32
    moveq   #85,D0
    jsr     ShootFireball
_anon_z04_32:
    move.b  (A5)+,D0  ; PLA
    moveq   #0,D2
    move.b  D0,D2
    even
_L_z04_UpdateStatues_NextLoopFireball:
    ; Bottom of the loop.
    ; Loop while fireball index >= 0.
    ;
    subq.b  #1,D2
    bpl  _L_z04_UpdateStatues_LoopFireball
    even
_L_z04_UpdateStatues_Exit:
    rts

