CheckZora:
    ; If the zora attribute of this room is off, return.
    ;
    moveq   #0,D3
    move.b  ($00EB,A4),D3
    lea     (NES_SRAM+$087E).l,A0
    move.b  (A0,D3.W),D0
    andi.b #$08,D0
    beq  _L_z04_CheckZora_Exit
    ; If zora is active, return.
    ;
    move.b  ($0514,A4),D0
    bne  _L_z04_CheckZora_Exit
    ; Look for an empty monster slot. If none is found, return.
    ;
    jsr     FindEmptyMonsterSlot
    beq  _L_z04_CheckZora_Exit
    ; Loop $D times looking for a water tile to put a zora on.
    ; Indexed by [0D].
    ;
    moveq   #13,D0
    move.b  D0,($000D,A4)
    ; Switch to the new object slot.
    ;
    moveq   #0,D2
    move.b  ($0059,A4),D2
    even
_L_z04_CheckZora_LoopTileCandidate:
    ; Turn the random value at this index into a $10 pixel aligned X coordinate.
    ; If it = 0 or $F0, go loop again.
    ;
    moveq   #0,D3
    move.b  ($000D,A4),D3
    move.b  ($18,A4,D3.W),D0
    andi.b #$F0,D0
    move.b  D0,($70,A4,D2.W)
    beq  _L_z04_CheckZora_NextLoopTileCandidate
    cmpi.b  #$F0,D0
    beq  _L_z04_CheckZora_NextLoopTileCandidate
    ; Turn the random value into a $10 pixel aligned Y coordinate.
    ; If it < $50 or >= $E0, go loop again.
    ;
    move.b  ($18,A4,D3.W),D0
    lsl.b  #1,D0   ; ASL A
    lsl.b  #1,D0   ; ASL A
    lsl.b  #1,D0   ; ASL A
    lsl.b  #1,D0   ; ASL A
    cmpi.b  #$50,D0
    bcs  _L_z04_CheckZora_NextLoopTileCandidate
    cmpi.b  #$E0,D0
    bcc  _L_z04_CheckZora_NextLoopTileCandidate
    ; Turn it into a normal object Y coordinate by OR'ing it with $D.
    ;
    ori.b #$0D,D0
    lea     ($0084,A4),A0
    move.b  D0,(A0,D2.W)
    ; Get the tile at that location.
    ; If it's not a water tile, then go loop again.
    ;
    jsr     GetCollidableTileStill
    cmpi.b  #$8D,D0
    bcs  _L_z04_CheckZora_NextLoopTileCandidate
    cmpi.b  #$99,D0
    bcc  _L_z04_CheckZora_NextLoopTileCandidate
    ; Flag the zora active, and set up the object.
    ;
    addq.b  #1,($0514,A4)
    moveq   #17,D0
    jmp     SetTypeAndClearObject

    even
_L_z04_CheckZora_NextLoopTileCandidate:
    ; Bottom of the loop. Keep going until loop index [0D] = 0.
    ;
    subq.b  #1,($000D,A4)
    bne  _L_z04_CheckZora_LoopTileCandidate
    even
_L_z04_CheckZora_Exit:
    rts

