    moveq   #32,D0
    move.b  D0,($28,A4,D2.W)
    even
_L_z04_UpdateZora_DestroyWhenDone:
    ; If state = 0, then destroy zora object.
    ; Also flag it inactive, so that the object update loop will try
    ; to make another one.
    ;
    lea     ($00AC,A4),A0
    move.b  (A0,D2.W),D0
    beq.s  __far_z_04_0020
    jmp  L10797_Exit
