; Params:
; A: q-speed of the monster
; Y: shot object type
;
; [01] holds the q-speed of the monster
    even
_TryShooting:
    move.b  D0,($0001,A4)
    ; If the monster is not a blue walking OW monster, and shoot timer = 0,
    ;
    lea     ($034F,A4),A0
    move.b  (A0,D2.W),D0
    cmpi.b  #$03,D0
    beq  _L_z04__TryShooting_TryShootingNow
    cmpi.b  #$01,D0
    beq  _L_z04__TryShooting_TryShootingNow
    cmpi.b  #$09,D0
    beq  _L_z04__TryShooting_TryShootingNow
    cmpi.b  #$0A,D0
    beq  _L_z04__TryShooting_TryShootingNow
    lea     ($0451,A4),A0
    move.b  (A0,D2.W),D0
    bne  _L_z04__TryShooting_TryShootingNow
    ; and a random value < $F8, then return.
    ;
    move.b  ($18,A4,D2.W),D0
    cmpi.b  #$F8,D0
    bcs  _L_z04__TryShooting_Exit
    even
_L_z04__TryShooting_TryShootingNow:
    ; Summary
    ;
    ; if temporarily invincible then
    ;   shoot timer := 0
    ; elif shoot timer > 0 then
    ;   decrement shoot timer
    ; elif wants to shoot then
    ;   shoot timer := $30
    ;
    ; qspeed := [01]
    ;
    ; if shoot timer <> 0 then
    ;   if shoot timer = $10 and no clock and not stunned then
    ;     shoot
    ;     if succeeded then
    ;       shoot timer := 0
    ;       qspeed := 0
    ;   else
    ;     qspeed := 0
    ;
    ; Push a 0 q-speed, in case the monster is in shooting time.
    move.b  ($0001,A4),D0
    move.b  D3,($0000,A4)
    move.b  D0,-(A5)  ; PHA
    moveq   #0,D3
    ; If not temporarily invincible,
    ;
    lea     ($04F0,A4),A0
    move.b  (A0,D2.W),D0
    bne  _L_z04__TryShooting_SetShootTimer
    ; then Y := shoot timer - 1
    ;
    moveq   #0,D3
    lea     ($0451,A4),A0
    move.b  (A0,D2.W),D3
    subq.b  #1,D3
    ; If Y register < 0, then shoot timer is 0.
    ; So, if "wants to shoot" flag is set, then set shoot timer to $30.
    ; Else go set a non-zero speed and return.
    ;
    bpl  _L_z04__TryShooting_SetShootTimer
    lea     ($0412,A4),A0
    move.b  (A0,D2.W),D0
    beq  _L_z04__TryShooting_SetSpeed
    moveq   #48,D3
    even
_L_z04__TryShooting_SetShootTimer:
    ; shoot timer := Y
    ;
    move.b  D3,D0
    lea     ($0451,A4),A0
    move.b  D0,(A0,D2.W)
    ; If new shoot timer = 0, go set a non-zero speed.
    ;
    beq  _L_z04__TryShooting_SetSpeed
    ; shoot timer <> 0
    ; If shoot timer <> $10, then go set a zero speed.
    ;
    cmpi.b  #$10,D3
    bne  _L_z04__TryShooting_ZeroSpeed
    ; If we have the magic clock, or the monster is stunned, then
    ; go set a zero speed.
    ;
    move.b  ($066C,A4),D0
    move.b  ($3D,A4,D2.W),D1
    or.b  D1,D0
    bne  _L_z04__TryShooting_ZeroSpeed
    ; Shoot.
    ;
    move.b  ($0000,A4),D0
    jsr     _ShootIfWanted2
    ; If it failed, go set a non-zero speed.
    ;
    bcc  _L_z04__TryShooting_SetSpeed
    ; It succeeded, so reset "wants to shoot" flag and the speed.
    ;
    moveq   #0,D0
    lea     ($0412,A4),A0
    move.b  D0,(A0,D2.W)
    even
_L_z04__TryShooting_ZeroSpeed:
    move.b  (A5)+,D0  ; PLA
    moveq   #0,D0
    move.b  D0,-(A5)  ; PHA
    even
_L_z04__TryShooting_SetSpeed:
    ; Set the speed to whatever was determined: 0 or the value passed in [01].
    ;
    move.b  (A5)+,D0  ; PLA
    lea     ($03BC,A4),A0
    move.b  D0,(A0,D2.W)
    even
_L_z04__TryShooting_Exit:
    rts

