    even
_L_z04_UpdateMonsterArrow_CheckBounce:
    cmpi.b  #$30,D0
    beq.s  __far_z_04_0023
    jmp  L1083E_Exit
__far_z_04_0023:
    jmp     BounceShot

    even
UpdateBoulderSet:
    ; If the object timer has not expired, then return.
    ;
    move.b  ($28,A4,D2.W),D0
    bne  _L_z04_UpdateBoulderSet_Exit
    ; If the maximum number (3) of boulders are active, then
    ; go set the timer to wait a random amount of time.
    ;
    move.b  ($0515,A4),D0
    cmpi.b  #$03,D0
    beq  _L_z04_UpdateBoulderSet_RandomizeTimer
    ; If no empty monster slot is found, then return.
    ;
    jsr     FindEmptyMonsterSlot
    beq  _L_z04_UpdateBoulderSet_Exit
    ; Set the boulder monster type, and increase the number
    ; of active boulders.
    ;
    moveq   #0,D2
    move.b  ($0059,A4),D2
    addq.b  #1,($0515,A4)
    moveq   #32,D0
    jsr     SetTypeAndClearObject
    ; Give the boulder a random X coordinate in the same half
    ; of the screen as the chase target.
    ;
    move.b  ($19,A4,D2.W),D0
    moveq   #0,D3
    move.b  ($0061,A4),D3
    cmpi.b  #$80,D3
    bcc  _L_z04_UpdateBoulderSet_RightHalf
    andi.b #$7F,D0
    jmp     _L_z04_UpdateBoulderSet_SetX

    even
_L_z04_UpdateBoulderSet_RightHalf:
    ori.b #$80,D0
    even
_L_z04_UpdateBoulderSet_SetX:
    move.b  D0,($70,A4,D2.W)
    ; Start at the top edge of the screen ($40).
    ;
    moveq   #64,D0
    lea     ($0084,A4),A0
    move.b  D0,(A0,D2.W)
    ; Set the boulder set's timer to ((Random + 8) AND $1F).
    ;
    moveq   #0,D2
    move.b  ($0340,A4),D2
    moveq   #8,D0
    andi    #$EE,CCR  ; CLC: clear C+X
    move.b  ($19,A4,D2.W),D1
    addx.b  D1,D0   ; ADC Random+1,X
    andi.b #$1F,D0
    move.b  D0,($28,A4,D2.W)
    rts

    even
_L_z04_UpdateBoulderSet_RandomizeTimer:
    ; Randomize the object timer.
    ;
    move.b  ($28,A4,D2.W),D0
    andi    #$EE,CCR  ; CLC: clear C+X
    move.b  ($19,A4,D2.W),D1
    addx.b  D1,D0   ; ADC Random+1,X
    move.b  D0,($28,A4,D2.W)
    even
_L_z04_UpdateBoulderSet_Exit:
    rts

    even
JumperYOffsets:
    dc.b    $00, $00, $00, $00, $00, $20, $20, $00
    dc.b    $00, $E0, $E0

; Logically, this array would be 33 bytes: 3 sets of 11 bytes,
; 1 byte for each 8-way direction
;
; But because Boulder does not need the upward accelerations,
; the elements for those are used for the starting speeds
; at 04:88F2.
;
    even
JumperYAccelerations:
    dc.b    $00, $40, $40, $00, $00, $40, $40, $00
    dc.b    $00, $30, $30, $00, $80, $80, $00, $00
    dc.b    $80, $80, $00, $00, $50, $50, $60, $60
    dc.b    $60, $60, $60, $60, $60

    even
JumperStartSpeedsHi:
    dc.b    $FD, $FC, $FE

    even
JumperYAccelerationBaseOffsets:
    dc.b    $00, $0B, $16

    even
UpdateTektiteOrBoulder:
    ; If the monster is shoved, then keep shoving it.
    ;
    lea     ($00C0,A4),A0
    move.b  (A0,D2.W),D0
    beq  _L_z04_UpdateTektiteOrBoulder_CheckStunned
; Unknown block
    dc.b    $4C, $B8, $EE

    even
_L_z04_UpdateTektiteOrBoulder_DrawAndCheckCollisions:
    jmp     Jumper_AnimateAndCheckCollisions

    even
_L_z04_UpdateTektiteOrBoulder_CheckStunned:
    ; If we have the magic clock, or the monster is stunned; 
    ; then go animate, draw, and check collisions.
    ;
    move.b  ($066C,A4),D0
    move.b  ($3D,A4,D2.W),D1
    or.b  D1,D0
    bne  _L_z04_UpdateTektiteOrBoulder_DrawAndCheckCollisions
    ; If state <> 0, go update the jump.
    ;
    lea     ($00AC,A4),A0
    move.b  (A0,D2.W),D0
    bne  _L_z04_UpdateTektiteOrBoulder_State1
    ; State 0. On the ground.
    ;
    ; If timer <> 0, then go animate, draw, and check collisions.
    ;
    move.b  ($28,A4,D2.W),D0
    bne  _L_z04_UpdateTektiteOrBoulder_Animate
    ; State = 0 and object timer expired. Time to jump.
    ;
    ; First, turn 1 step toward the chase target.
    ;
    jsr     TurnTowardsPlayer8
    ; If the facing direction has no horizontal component, then
    ; find the horizontal direction toward the chase target.
    ;
    ; Then combine it with the facing direction.
    ;
    lea     ($0098,A4),A0
    move.b  (A0,D2.W),D0
    andi.b #$03,D0
    bne  _L_z04_UpdateTektiteOrBoulder_SetStateJump
    moveq   #2,D3
    move.b  ($0061,A4),D0
    move.b  ($70,A4,D2.W),D1
    cmp.b   D1,D0
    bcs  _anon_z04_36
    subq.b  #1,D3
_anon_z04_36:
    move.b  D3,D0
    lea     ($0098,A4),A0
    move.b  (A0,D2.W),D1
    or.b  D1,D0
    lea     ($0098,A4),A0
    move.b  D0,(A0,D2.W)
    even
_L_z04_UpdateTektiteOrBoulder_SetStateJump:
    ; Set state 1 to jump.
    ;
    lea     ($00AC,A4),A0
    addq.b  #1,(A0,D2.W)
    even
_L_z04_UpdateTektiteOrBoulder_SetUpJump:
    ; If reversal count >= 2, then
    ; 1. invert the horizontal component of facing direction,
    ;    to face away from the chase target
    ; 2. reset the reversal count to 0.
    ;
    ; This prevents a jumper from getting stuck in a corner.
    ;
    ; For example, if a tektite's direction is down and right,
    ; and jumps into the top right corner of the room:
    ; 1. The right room boundary is hit. So the direction is
    ;    automatically reversed to up and left.
    ; 2. The next frame, the top room boundary is hit.
    ;    The direction is reversed to down and right.
    ;
    ; As you can see, an endless loop has been made.
    ;
    lea     ($0451,A4),A0
    move.b  (A0,D2.W),D0
    cmpi.b  #$02,D0
    bcs  _L_z04_UpdateTektiteOrBoulder_FinishSetUpJump
    lea     ($0098,A4),A0
    move.b  (A0,D2.W),D0
    eori.b #$03,D0
    lea     ($0098,A4),A0
    move.b  D0,(A0,D2.W)
    moveq   #0,D0
    lea     ($0451,A4),A0
    move.b  D0,(A0,D2.W)
    even
_L_z04_UpdateTektiteOrBoulder_FinishSetUpJump:
    ; If the object is a boulder, then make sure its facing direction
    ; has a down vertical component.
    ;
    jsr     Jumper_PointBoulderDownward
    ; For the given direction, get the Y offset of the destination
    ; of the jump.
    ;
    ; Add it to the object's Y, and store this destination Y.
    ;
    moveq   #0,D3
    lea     ($0098,A4),A0
    move.b  (A0,D2.W),D3
    lea     ($0084,A4),A0
    move.b  (A0,D2.W),D0
    andi    #$EE,CCR  ; CLC: clear C+X
    lea     (JumperYOffsets).l,A0
    move.b  (A0,D3.W),D1
    addx.b  D1,D0   ; ADC JumperYOffsets,Y
    lea     ($0444,A4),A0
    move.b  D0,(A0,D2.W)
    ; Set the starting speed, depending on the object type.
    ;
    jsr     Jumper_GetKind
    lea     (JumperStartSpeedsHi).l,A0
    move.b  (A0,D3.W),D0
    lea     ($0412,A4),A0
    move.b  D0,(A0,D2.W)
    ; Reset the vertical speed low byte.
    ; Then go animate, draw, and check collisions.
    ;
    jsr     Jumper_ResetVSpeedFrac
    even
_L_z04_UpdateTektiteOrBoulder_Animate:
    jmp     Jumper_AnimateAndCheckCollisions

    even
_L_z04_UpdateTektiteOrBoulder_State1:
    ; State 1. Jumping.
    ;
    ; Keep the object inside the bounds of the room.
    ;
    jsr     BoundFlyer
    ; If the object was blocked at the room boundary, then
    ; increase boundary reversal count, and go set up another jump.
    ;
    move.b  ($000F,A4),D0
    bne  _anon_z04_37
    lea     ($0451,A4),A0
    addq.b  #1,(A0,D2.W)
    jmp     _L_z04_UpdateTektiteOrBoulder_SetUpJump

_anon_z04_37:
    jsr     Jumper_PointBoulderDownward
    ; This step in the jump succeeded. So, reset the reversal count.
    ;
    moveq   #0,D0
    lea     ($0451,A4),A0
    move.b  D0,(A0,D2.W)
    ; Get the base offset for the kind of jumper the object is.
    ;
    jsr     Jumper_GetKind
    lea     (JumperYAccelerationBaseOffsets).l,A0
    move.b  (A0,D3.W),D0
    ; Get the acceleration by indexing with (base offset + direction).
    ;
    ; Note that the set of accelerations of Boulder (the third set)
    ; does not have $B elements like the tektites' sets.
    ;
    ; Boulder does not need the upward accelerations.
    ; So, the elements for those are used for the starting speeds
    ; at 04:88F2.
    ;
    andi    #$EE,CCR  ; CLC: clear C+X
    lea     ($0098,A4),A0
    move.b  (A0,D2.W),D1
    addx.b  D1,D0   ; ADC ObjDir,X
    moveq   #0,D3
    move.b  D0,D3
    lea     (JumperYAccelerations).l,A0
    move.b  (A0,D3.W),D0
    moveq   #2,D3
    jsr     Jumper_MoveY
    ; If the facing direction has a left component, then
    ; subtract 1 from the object's X.
    ;
    ; Else add 1.
    ;
    move.b  #$FF,D3
    lea     ($0098,A4),A0
    move.b  (A0,D2.W),D0
    andi.b #$02,D0
    bne  _anon_z04_38
    moveq   #1,D3
_anon_z04_38:
    move.b  D3,D0
    andi    #$EE,CCR  ; CLC: clear C+X
    move.b  ($70,A4,D2.W),D1
    addx.b  D1,D0   ; ADC ObjX,X
    move.b  D0,($70,A4,D2.W)
    ; If going up (negative v-speed high byte), then
    ; go animate, draw, and check collisions.
    ;
    lea     ($0412,A4),A0
    move.b  (A0,D2.W),D0
    bpl.s  __far_z_04_0024
    jmp  Jumper_AnimateAndCheckCollisions
__far_z_04_0024:
    ; Going down. We have to consider the target Y.
    ;
    ; If the absolute vertical distance to the target position >= 3,
    ; then go animate, draw, and check collisions.
    ;
    lea     ($0084,A4),A0
    move.b  (A0,D2.W),D0
    ori     #$11,CCR  ; SEC: set C+X
    lea     ($0444,A4),A0
    move.b  (A0,D2.W),D1
    eori    #$10,CCR  ; flip X: 6502 SBC polarity
    subx.b  D1,D0   ; SBC Jumper_ObjTargetY,X
    eori    #$10,CCR  ; restore X = 6502 C
    jsr     Abs
    cmpi.b  #$03,D0
    bcs.s  __far_z_04_0025
    jmp  Jumper_AnimateAndCheckCollisions
__far_z_04_0025:
    ; Distance < 3. Go to state 0.
    ;
    ; If the object is a boulder, then go reset timer, animate, draw.
    ;
    jsr     ResetObjState
    moveq   #0,D3
    lea     ($034F,A4),A0
    move.b  (A0,D2.W),D3
    cmpi.b  #$20,D3
    beq  _L_z04_UpdateTektiteOrBoulder_SetTimerAndAnimate
    ; Else calculate a timer value.
    ;
    ; t := (Random + $10)
    ; if t < $20 then
    ;   t := t - $40
    ;
    moveq   #16,D0
    andi    #$EE,CCR  ; CLC: clear C+X
    move.b  ($19,A4,D2.W),D1
    addx.b  D1,D0   ; ADC Random+1,X
    cmpi.b  #$20,D0
    bcc  _anon_z04_39
    ori     #$11,CCR  ; SEC: set C+X
    move.b  #$40,D1
    eori    #$10,CCR  ; flip X: 6502 SBC polarity
    subx.b  D1,D0   ; SBC #$40
    eori    #$10,CCR  ; restore X = 6502 C
_anon_z04_39:
    ; If the object is a blue tektite, then go use this t.
    ;
    moveq   #0,D3
    lea     ($034F,A4),A0
    move.b  (A0,D2.W),D3
    cmpi.b  #$0D,D3
    beq  _L_z04_UpdateTektiteOrBoulder_SetTimerAndAnimate
    ; t := t AND $7F
    ;
    andi.b #$7F,D0
    ; If Random < $A0, then go use this t.
    ;
    moveq   #0,D3
    move.b  ($19,A4,D2.W),D3
    cmpi.b  #$A0,D3
    bcs  _L_z04_UpdateTektiteOrBoulder_SetTimerAndAnimate
    ; t := t AND $F
    ;
    andi.b #$0F,D0
    even
_L_z04_UpdateTektiteOrBoulder_SetTimerAndAnimate:
    move.b  D0,($28,A4,D2.W)
    even
Jumper_AnimateAndCheckCollisions:
    jsr     Anim_FetchObjPosForSpriteDescriptor
    ; TODO: [0D] ?
    ; [0D] doesn't seem to be used.
    ;
    move.b  D0,($000D,A4)
    ; If the monster is a boulder, then go animate, draw, check collision.
    ;
    lea     ($034F,A4),A0
    move.b  (A0,D2.W),D0
    cmpi.b  #$20,D0
    beq  _L_z04_Jumper_AnimateAndCheckCollisions_DrawBoulder
    ; Draw a tektite.
    ;
    ; If state = 1, then go draw frame image 1, and check collisions.
    ;
    lea     ($00AC,A4),A0
    move.b  (A0,D2.W),D0
    bne  _L_z04_Jumper_AnimateAndCheckCollisions_DrawTektite
    ; If object timer < $21, go draw frame image 0, and check collisions.
    ;
    moveq   #0,D3
    move.b  ($28,A4,D2.W),D3
    cmpi.b  #$21,D3
    bcs  _L_z04_Jumper_AnimateAndCheckCollisions_DrawTektite
    ; Else cycle the animation counter, draw, and check collisions.
    ;
    ; The movement frame determines the frame image.
    ;
    moveq   #16,D0
    jsr     Anim_AdvanceAnimCounterAndSetObjPosForSpriteDescriptor
    lea     ($03E4,A4),A0
    move.b  (A0,D2.W),D0
    even
_L_z04_Jumper_AnimateAndCheckCollisions_DrawTektite:
    jmp     DrawObjectMirroredAndCheckCollisions

    even
_L_z04_Jumper_AnimateAndCheckCollisions_DrawBoulder:
    ; Draw a boulder.
    ;
    moveq   #6,D0
    jsr     Anim_AdvanceAnimCounterAndSetObjPosForSpriteDescriptor
    lea     ($03E4,A4),A0
    move.b  (A0,D2.W),D0
    jsr     DrawObjectNotMirroredAndCheckLinkCollision
    ; If the boulder's Y < $F0, return.
    ;
    lea     ($0084,A4),A0
    move.b  (A0,D2.W),D0
    cmpi.b  #$F0,D0
    bcc.s  __far_z_04_0026
    jmp  L10A10_Exit
__far_z_04_0026:
    ; Else the boulder is close enough to the bottom of the screen
    ; to destroy it.
    ;
    subq.b  #1,($0515,A4)
    jmp     DestroyMonster

; Returns:
; Y: 0: blue tektite
;    1: red tektite
;    2: boulder
;
    even
Jumper_GetKind:
    lea     ($034F,A4),A0
    move.b  (A0,D2.W),D0
    ori     #$11,CCR  ; SEC: set C+X
    move.b  #$0D,D1
    eori    #$10,CCR  ; flip X: 6502 SBC polarity
    subx.b  D1,D0   ; SBC #$0D
    eori    #$10,CCR  ; restore X = 6502 C
    moveq   #0,D3
    move.b  D0,D3
    cmpi.b  #$02,D3
    bcc.s  __far_z_04_0027
    jmp  L10A10_Exit
__far_z_04_0027:
    moveq   #2,D3
    even
L10A10_Exit:
    rts

    even
Jumper_PointBoulderDownward:
    lea     ($034F,A4),A0
    move.b  (A0,D2.W),D0
    cmpi.b  #$20,D0
    bne  _L_z04_Jumper_PointBoulderDownward_Exit
    lea     ($0098,A4),A0
    move.b  (A0,D2.W),D0
    andi.b #$03,D0
    ori.b #$04,D0
    lea     ($0098,A4),A0
    move.b  D0,(A0,D2.W)
    even
_L_z04_Jumper_PointBoulderDownward_Exit:
    rts

; Params:
; A: acceleration
; Y: max speed high byte
;
; [00] holds the acceleration
    even
Jumper_MoveY:
    move.b  D0,($0000,A4)
    move.b  D3,($0002,A4)
    ; Add the high speed byte to the Y coordinate.
    ;
    lea     ($0412,A4),A0
    move.b  (A0,D2.W),D0
    lea     ($0084,A4),A0
    move.b  (A0,D2.W),D1
    addx.b  D1,D0   ; ADC ObjY,X
    lea     ($0084,A4),A0
    move.b  D0,(A0,D2.W)
    ; Add the acceleration to the speed fraction (low byte).
    ;
    lea     ($041F,A4),A0
    move.b  (A0,D2.W),D0
    andi    #$EE,CCR  ; CLC: clear C+X
    move.b  ($0000,A4),D1
    addx.b  D1,D0   ; ADC $00
    lea     ($041F,A4),A0
    move.b  D0,(A0,D2.W)
    ; Carry over to the high speed byte.
    ;
    lea     ($0412,A4),A0
    move.b  (A0,D2.W),D0
    move.b  #$00,D1
    addx.b  D1,D0   ; ADC #$00 (X flag = 6502 C)
    lea     ($0412,A4),A0
    move.b  D0,(A0,D2.W)
    ; *Signed comparison*:
    ; If the high speed byte < high max speed byte, then return.
    ;
    ; Note that this is not a general purpose signed comparison,
    ; which would be more complicated. But it works because
    ; the deviation from 0 of both values is small.
    ;
    move.b  ($0002,A4),D1
    cmp.b   D1,D0
    bpl.s  __far_z_04_0028
    jmp  L10A52_Exit
__far_z_04_0028:
    ; Limit the speed to the max speed.
    ;
    lea     ($041F,A4),A0
    move.b  (A0,D2.W),D0
    cmpi.b  #$80,D0
    bcc.s  __far_z_04_0029
    jmp  L10A52_Exit
__far_z_04_0029:
    move.b  ($0002,A4),D0
    lea     ($0412,A4),A0
    move.b  D0,(A0,D2.W)
    even
Jumper_ResetVSpeedFrac:
    moveq   #0,D0
    lea     ($041F,A4),A0
    move.b  D0,(A0,D2.W)
    even
L10A52_Exit:
    rts

    even
BlueLeeverStateQSpeeds:
    dc.b    $08, $0A, $10, $20, $10, $0A

    even
BlueLeeverStateTimes:
    dc.b    $80, $20, $0F, $FF, $10, $60

    even
BlueLeeverStateAnimTimes:
    dc.b    $10, $0B, $01, $05, $01, $0B

    even
UpdateBlueLeever:
    move.b  #$A0,D0
    lea     ($041F,A4),A0
    move.b  D0,(A0,D2.W)
    jsr     Wanderer_TargetPlayer
    even
UpdateBurrower:
    ; If object timer <> 0, then go animate, draw, and check for collisions.
    ;
    move.b  ($28,A4,D2.W),D0
    bne  _L_z04_UpdateBurrower_Animate
    ; If not zora or state <> 1, go cycle the state.
    ;
    lea     ($034F,A4),A0
    move.b  (A0,D2.W),D0
    cmpi.b  #$11,D0
    bne  _L_z04_UpdateBurrower_CycleState
    moveq   #0,D3
    lea     ($00AC,A4),A0
    move.b  (A0,D2.W),D3
    subq.b  #1,D3
    bne  _L_z04_UpdateBurrower_CycleState
    ; Else is zora and state = 1.
    ;
    ; If zora's Y >= Link's Y, then set zora's frame image to
    ; 3 (back), else 2 (front).
    ;
    ; The frame image number is being assigned to ObjDir.
    ;
    moveq   #3,D3
    lea     ($0084,A4),A0
    move.b  (A0,D2.W),D0
    move.b  ($0084,A4),D1
    cmp.b   D1,D0
    bcc  _anon_z04_40
    subq.b  #1,D3
_anon_z04_40:
    lea     ($0098,A4),A0
    move.b  D3,(A0,D2.W)
    even
_L_z04_UpdateBurrower_CycleState:
    ; Cycle the state between 0 and 5.
    ;
    lea     ($00AC,A4),A0
    move.b  (A0,D2.W),D0
    andi    #$EE,CCR  ; CLC: clear C+X
    move.b  #$01,D1
    addx.b  D1,D0   ; ADC #$01 (X flag = 6502 C)
    cmpi.b  #$06,D0
    bcs  _anon_z04_41
    moveq   #0,D0
_anon_z04_41:
    lea     ($00AC,A4),A0
    move.b  D0,(A0,D2.W)
    ; Look up and set the speed and timer for the current state.
    ;
    moveq   #0,D3
    move.b  D0,D3
    lea     (BlueLeeverStateQSpeeds).l,A0
    move.b  (A0,D3.W),D0
    lea     ($03BC,A4),A0
    move.b  D0,(A0,D2.W)
    lea     (BlueLeeverStateTimes).l,A0
    move.b  (A0,D3.W),D0
    move.b  D0,($28,A4,D2.W)
    even
_L_z04_UpdateBurrower_Animate:
    ; Advance the animation counter; possibly setting a new
    ; value according to the new state.
    ;
    moveq   #0,D3
    lea     ($00AC,A4),A0
    move.b  (A0,D2.W),D3
    lea     (BlueLeeverStateAnimTimes).l,A0
    move.b  (A0,D3.W),D0
; Params:
; A: new value for animation counter, in case it rolls over
; X: object index
;
; Note:
; Advances the animation counter first.
;
    even
Burrower_AnimateDrawAndCheckCollisions:
    jsr     Anim_AdvanceAnimCounterAndSetObjPosForSpriteDescriptor
    ; If state = 0, return.
    ;
    lea     ($00AC,A4),A0
    move.b  (A0,D2.W),D0
    beq  _L_z04_Burrower_AnimateDrawAndCheckCollisions_Exit
    ; If is zora, and state >= 2 and < 5, then use frame image 2 or 3
    ; (front or back), which was stored in ObjDir above.
    ;
    moveq   #0,D3
    lea     ($034F,A4),A0
    move.b  (A0,D2.W),D3
    cmpi.b  #$11,D3
    bne  _L_z04_Burrower_AnimateDrawAndCheckCollisions_CalcFrameImage
    moveq   #0,D3
    lea     ($00AC,A4),A0
    move.b  (A0,D2.W),D3
    cmpi.b  #$02,D3
    bcs  _L_z04_Burrower_AnimateDrawAndCheckCollisions_CalcFrameImage
    cmpi.b  #$05,D3
    bcc  _L_z04_Burrower_AnimateDrawAndCheckCollisions_CalcFrameImage
    lea     ($0098,A4),A0
    move.b  (A0,D2.W),D0
    bne  _L_z04_Burrower_AnimateDrawAndCheckCollisions_Draw
    even
_L_z04_Burrower_AnimateDrawAndCheckCollisions_CalcFrameImage:
    ; Or else if is zora in state 1 or 5, then use one of
    ; the mound frame images:
    ;
    ; frame image := ((state - 1) * 2) + movement frame
    ;
    ; This yields 0/1 or 8/9, depending on the state.
    ;
    ; This formula is used for states 1 to 5 of non-zora burrowers.
    ;
    ori     #$11,CCR  ; SEC: set C+X
    move.b  #$01,D1
    eori    #$10,CCR  ; flip X: 6502 SBC polarity
    subx.b  D1,D0   ; SBC #$01
    eori    #$10,CCR  ; restore X = 6502 C
    lsl.b  #1,D0   ; ASL A
    andi    #$EE,CCR  ; CLC: clear C+X
    lea     ($03E4,A4),A0
    move.b  (A0,D2.W),D1
    addx.b  D1,D0   ; ADC ObjAnimFrame,X
    even
_L_z04_Burrower_AnimateDrawAndCheckCollisions_Draw:
    jsr     DrawObjectMirrored
    ; If not zora and state <> 3, 
    ; or zora and state <> 2, 3, 4;
    ; then return.
    ;
    lea     ($034F,A4),A0
    move.b  (A0,D2.W),D0
    cmpi.b  #$11,D0
    bne  _L_z04_Burrower_AnimateDrawAndCheckCollisions_NoState3Collisions
    lea     ($00AC,A4),A0
    move.b  (A0,D2.W),D0
    cmpi.b  #$02,D0
    beq  _L_z04_Burrower_AnimateDrawAndCheckCollisions_CheckCollisions
    cmpi.b  #$04,D0
    beq  _L_z04_Burrower_AnimateDrawAndCheckCollisions_CheckCollisions
    even
_L_z04_Burrower_AnimateDrawAndCheckCollisions_NoState3Collisions:
    lea     ($00AC,A4),A0
    move.b  (A0,D2.W),D0
    cmpi.b  #$03,D0
    bne  _L_z04_Burrower_AnimateDrawAndCheckCollisions_Exit
    even
_L_z04_Burrower_AnimateDrawAndCheckCollisions_CheckCollisions:
    jsr     CheckMonsterCollisions
    ; If not dying, then return.
    ;
    lea     ($0405,A4),A0
    move.b  (A0,D2.W),D0
    beq  _L_z04_Burrower_AnimateDrawAndCheckCollisions_Exit
    ; If monster is a red leever, then decrement the red leever count.
    ;
    lea     ($034F,A4),A0
    move.b  (A0,D2.W),D0
    cmpi.b  #$10,D0
    bne  _L_z04_Burrower_AnimateDrawAndCheckCollisions_Exit
    subq.b  #1,($0510,A4)
    even
_L_z04_Burrower_AnimateDrawAndCheckCollisions_Exit:
    rts

    even
RedLeeverStateQSpeeds:
    dc.b    $00, $00, $00, $20, $00, $00

    even
RedLeeverStateTimes:
    dc.b    $00, $10, $08, $FF, $08, $10

    even
RedLeeverStateAnimTimes:
    dc.b    $10, $08, $08, $05, $08, $08

    even
UpdateRedLeever:
    lea     ($00AC,A4),A0
    move.b  (A0,D2.W),D0
    beq  _anon_z04_42
    jmp     _L_z04_UpdateRedLeever_CheckOtherStates

_anon_z04_42:
    ; State 0.
    ;
    ; In state we determine whether to burst out of the ground.
    ; If the long timer has not expired, then return.
    ;
    move.b  ($004D,A4),D0
    bne  _L_z04_UpdateRedLeever_Exit
    ; Only allow two red leevers at a time.
    ;
    move.b  ($0510,A4),D0
    cmpi.b  #$02,D0
    bcc  _L_z04_UpdateRedLeever_Exit
    ; Face in the same direction as Link.
    ;
    move.b  ($0098,A4),D0
    lea     ($0098,A4),A0
    move.b  D0,(A0,D2.W)
    ; Randomly (>= $C0) face the opposite direction -- toward Link.
    ;
    move.b  ($19,A4,D2.W),D0
    cmpi.b  #$C0,D0
    bcs  _anon_z04_43
    jsr     ReverseObjDir
_anon_z04_43:
    ; If facing horizontally, go place the leever to the left or right of Link.
    ;
    lea     ($0098,A4),A0
    move.b  (A0,D2.W),D0
    andi.b #$0C,D0
    beq  _L_z04_UpdateRedLeever_PlaceHorizontally
    ; Begin with the leever's X set to Link's X.
    ;
    move.b  ($0070,A4),D0
    move.b  D0,($70,A4,D2.W)
    ; If facing down, then use Y offset $28.
    ; Else store Y offset -$28 in [00].
    ;
    moveq   #40,D3
    lea     ($0098,A4),A0
    move.b  (A0,D2.W),D0
    andi.b #$08,D0
    beq  _anon_z04_44
    move.b  #$D8,D3
_anon_z04_44:
    move.b  D3,($0000,A4)
    ; Add Link's Y and the vertical offset.
    ;
    move.b  ($0084,A4),D0
    andi    #$EE,CCR  ; CLC: clear C+X
    move.b  ($0000,A4),D1
    addx.b  D1,D0   ; ADC $00
    ; Sanitize the Y coordinate:
    ; (Y AND $F0) OR $D
    ;
    andi.b #$F0,D0
    ori.b #$0D,D0
    lea     ($0084,A4),A0
    move.b  D0,(A0,D2.W)
    ; If Y coordinate >= $5D (top of the third square row), then
    ; go see if the tile is valid to come out of.
    ;
    ; Else it's too close to the top edge of the screen. So, return.
    ;
    cmpi.b  #$5D,D0
    bcc  _L_z04_UpdateRedLeever_CheckSafeToSpawn
    even
_L_z04_UpdateRedLeever_Exit:
    rts

    even
_L_z04_UpdateRedLeever_PlaceHorizontally:
    ; Begin with the leever's Y set to Link's Y.
    ;
    move.b  ($0084,A4),D0
    lea     ($0084,A4),A0
    move.b  D0,(A0,D2.W)
    ; If Y coordinate < $5D (top of the third square row), then
    ; it's too close to the top edge of the screen. So, return.
    ;
    cmpi.b  #$5D,D0
    bcs  _L_z04_UpdateRedLeever_Exit
    ; If facing right, then use X offset $28.
    ; Else store X offset -$28 in [00].
    ;
    moveq   #40,D3
    lea     ($0098,A4),A0
    move.b  (A0,D2.W),D0
    andi.b #$02,D0
    beq  _anon_z04_45
    move.b  #$D8,D3
_anon_z04_45:
    move.b  D3,($0000,A4)
    ; [01] holds Link's X coordinate.
    ;
    move.b  ($0070,A4),D0
    move.b  D0,($0001,A4)
    ; Add Link's X and the horizontal offset.
    ;
    andi    #$EE,CCR  ; CLC: clear C+X
    move.b  ($0000,A4),D1
    addx.b  D1,D0   ; ADC $00
    ; AND the result with $F8, so it's aligned with a tile horizontally.
    ;
    andi.b #$F8,D0
    ; Assign that result to the leever's X coordinate and [02].
    ;
    move.b  D0,($70,A4,D2.W)
    move.b  D0,($0002,A4)
    ; If the leever's X [02] >= Link's X [01], then swap [02] and [01].
    ;
    move.b  ($0001,A4),D1
    cmp.b   D1,D0
    bcs  _L_z04_UpdateRedLeever_Subtract
    move.b  D0,-(A5)  ; PHA
    move.b  ($0001,A4),D0
    move.b  D0,($0002,A4)
    move.b  (A5)+,D0  ; PLA
    move.b  D0,($0001,A4)
    even
_L_z04_UpdateRedLeever_Subtract:
    ; The point is to get the absolute distance between the two.
    ;
    move.b  ($0001,A4),D0
    ori     #$11,CCR  ; SEC: set C+X
    move.b  ($0002,A4),D1
    eori    #$10,CCR  ; flip X: 6502 SBC polarity
    subx.b  D1,D0   ; SBC $02
    eori    #$10,CCR  ; restore X = 6502 C
    ; If the absolute distance >= $30, then return.
    ; It means that the leever's X coordinate wrapped around
    ; the left or right edge of the screen.
    ;
    cmpi.b  #$30,D0
    bcc  _L_z04_UpdateRedLeever_Exit
    even
_L_z04_UpdateRedLeever_CheckSafeToSpawn:
    ; The leever can't come out of an unwalkable tile. So, return.
    ;
    jsr     GetCollidableTileStill
    move.b  ($034A,A4),D1
    cmp.b   D1,D0
    bcc  _L_z04_UpdateRedLeever_Exit
    addq.b  #1,($0510,A4)
    ; Set animation counter to 1, so that it will roll over this frame
    ; and pick up whatever the new value is for state 1.
    ;
    moveq   #1,D0
    lea     ($03D0,A4),A0
    move.b  D0,(A0,D2.W)
    ; Set the long timer to 2, meaning 20 frames.
    ;
    lsl.b  #1,D0   ; ASL A
    move.b  D0,($004D,A4)
    jsr     RedLeever_CycleStateDrawAndCheckCollisions
    ; The leever has to face Link in order to move toward him.
    ;
    jsr     ReverseObjDir
    even
_L_z04_UpdateRedLeever_CheckOtherStates:
    ; If not in state 3, go check the object timer in order to draw and such.
    ;
    lea     ($00AC,A4),A0
    move.b  (A0,D2.W),D0
    cmpi.b  #$03,D0
    bne  _L_z04_UpdateRedLeever_AnimateIfTime
    ; State 3.
    ;
    ; If being shoved, go shove, animate, and draw the leever.
    ;
    lea     ($00C0,A4),A0
    move.b  (A0,D2.W),D0
    beq  _L_z04_UpdateRedLeever_CheckStunned
    jsr     Obj_Shove
    jmp     RedLeever_AnimateAndCheckCollisions

    even
_L_z04_UpdateRedLeever_CheckStunned:
    ; If we have the magic clock or the leever is stunned, then
    ; go animate, draw, and check for collisions.
    ;
    move.b  ($066C,A4),D0
    move.b  ($3D,A4,D2.W),D1
    or.b  D1,D0
    beq.s  __far_z_04_0030
    jmp  RedLeever_AnimateAndCheckCollisions
__far_z_04_0030:
    ; If the leever is blocked by a tile or the room boundary,
    ; then go to the next state, in addition to animating, drawing,
    ; and checking for collisions.
    ;
    lea     ($0098,A4),A0
    move.b  (A0,D2.W),D0
    move.b  D0,($000F,A4)
    jsr     GetCollidingTileMoving
    move.b  ($034A,A4),D1
    cmp.b   D1,D0
    bcs.s  __far_z_04_0031
    jmp  RedLeever_CycleStateDrawAndCheckCollisions
__far_z_04_0031:
    jsr     BoundByRoom
    bne.s  __far_z_04_0032
    jmp  RedLeever_CycleStateDrawAndCheckCollisions
__far_z_04_0032:
    ; Move.
    ;
    jsr     MoveObject
    ; Truncate the grid offset.
    ;
    lea     ($0394,A4),A0
    move.b  (A0,D2.W),D0
    andi.b #$0F,D0
    bne  _anon_z04_46
    lea     ($0394,A4),A0
    move.b  D0,(A0,D2.W)
_anon_z04_46:
    ; Set timer to $FF.
    ;
    move.b  #$FF,D0
    move.b  D0,($28,A4,D2.W)
    even
_L_z04_UpdateRedLeever_AnimateIfTime:
    ; If object timer has not expired, then
    ; go animate, draw, and check for collisions.
    ;
    move.b  ($28,A4,D2.W),D0
    beq.s  __far_z_04_0033
    jmp  RedLeever_AnimateAndCheckCollisions
__far_z_04_0033:
    even
RedLeever_CycleStateDrawAndCheckCollisions:
    ; Cycle the state between 0 and 5.
    ;
    ; If a cycle was completed (wrapped around to 0),
    ; then decrease the active red leever count.
    ;
    lea     ($00AC,A4),A0
    move.b  (A0,D2.W),D0
    andi    #$EE,CCR  ; CLC: clear C+X
    move.b  #$01,D1
    addx.b  D1,D0   ; ADC #$01 (X flag = 6502 C)
    cmpi.b  #$06,D0
    bcs  _anon_z04_47
    subq.b  #1,($0510,A4)
    moveq   #0,D0
_anon_z04_47:
    lea     ($00AC,A4),A0
    move.b  D0,(A0,D2.W)
    ; Look up and set the speed, timer, and animation counter
    ; for the current state.
    ;
    moveq   #0,D3
    move.b  D0,D3
    lea     (RedLeeverStateQSpeeds).l,A0
    move.b  (A0,D3.W),D0
    lea     ($03BC,A4),A0
    move.b  D0,(A0,D2.W)
    lea     (RedLeeverStateTimes).l,A0
    move.b  (A0,D3.W),D0
    move.b  D0,($28,A4,D2.W)
    even
RedLeever_AnimateAndCheckCollisions:
    moveq   #0,D3
    lea     ($00AC,A4),A0
    move.b  (A0,D2.W),D3
    lea     (RedLeeverStateAnimTimes).l,A0
    move.b  (A0,D3.W),D0
    jmp     Burrower_AnimateDrawAndCheckCollisions

; Unknown block
    dc.b    $60

    even
UpdateOctorock:
    ; If the monster is a fast octorock, use turn rate $A0.
    ; Else use turn rate $70.
    ;
    move.b  #$A0,D0
    moveq   #0,D3
    lea     ($034F,A4),A0
    move.b  (A0,D2.W),D3
    cmpi.b  #$09,D3
    bcc  _anon_z04_48
    moveq   #112,D0
_anon_z04_48:
    lea     ($041F,A4),A0
    move.b  D0,(A0,D2.W)
    jsr     Wanderer_TargetPlayer
    ; If the octorock is slow, then use q-speed $20.
    ; Else double it.
    ;
    moveq   #32,D0
    moveq   #0,D3
    lea     ($034F,A4),A0
    move.b  (A0,D2.W),D3
    cmpi.b  #$07,D3
    beq  _L_z04_UpdateOctorock_Shoot
    cmpi.b  #$09,D3
    beq  _L_z04_UpdateOctorock_Shoot
    lsl.b  #1,D0   ; ASL A
    even
_L_z04_UpdateOctorock_Shoot:
    ; Shoot a flying rock (object type $53).
    ;
    moveq   #83,D3
    jsr     _TryShooting
    jsr     Anim_FetchObjPosForSpriteDescriptor
    ; If facing down, then use frame image offset 2.
    ;
    lea     ($0098,A4),A0
    move.b  (A0,D2.W),D0
    moveq   #0,D3
    move.b  D0,D3
    andi.b #$0C,D0
    beq  _L_z04_UpdateOctorock_CheckHorizontal
    moveq   #2,D0
    cmpi.b  #$08,D3
    bne  _L_z04_UpdateOctorock_SaveOffset
    ; Else facing up. Use frame image offset 1.
    ;
    moveq   #1,D0
    bne  _L_z04_UpdateOctorock_SaveOffset
    even
_L_z04_UpdateOctorock_CheckHorizontal:
    ; If facing right, then set horizontal flipping, and use frame image offset 0.
    ;
    cmpi.b  #$01,D3
    bne  _anon_z04_49
    addq.b  #1,($000F,A4)
_anon_z04_49:
    ; Else facing left. Use frame image offset 0, but no horizontal flipping.
    ;
    moveq   #0,D0
    even
_L_z04_UpdateOctorock_SaveOffset:
    move.b  D0,-(A5)  ; PHA
    ; Decrement the animation counter, and roll over if needed.
    ;
    lea     ($03D0,A4),A0
    subq.b  #1,(A0,D2.W)
    bne  _L_z04_UpdateOctorock_CalcFinalOffset
    moveq   #6,D0
    lea     ($03D0,A4),A0
    move.b  D0,(A0,D2.W)
    ; There are actually 6 frame images divided into 2 sets.
    ; Each set depicts one animation frame. In each set there are
    ; 3 frame images: 1 for each direction (left, up, down).
    ;
    ; The movement frame will keep track of the base offset of
    ; the current set for the current animation frame: 0 or 3.
    ;
    ; So, XOR the movement frame with 3.
    ;
    lsr.b  #1,D0   ; LSR A
    lea     ($03E4,A4),A0
    move.b  (A0,D2.W),D1
    eor.b  D1,D0
    lea     ($03E4,A4),A0
    move.b  D0,(A0,D2.W)
    even
_L_z04_UpdateOctorock_CalcFinalOffset:
    ; Add the base offset and the directional offset, and save the result.
    ;
    move.b  (A5)+,D0  ; PLA
    andi    #$EE,CCR  ; CLC: clear C+X
    lea     ($03E4,A4),A0
    move.b  (A0,D2.W),D1
    addx.b  D1,D0   ; ADC ObjAnimFrame,X
    move.b  D0,-(A5)  ; PHA
    ; If facing vertically, go draw mirrored.
    ;
    lea     ($0098,A4),A0
    move.b  (A0,D2.W),D0
    andi.b #$0C,D0
    bne  _L_z04_UpdateOctorock_DrawMirrored
    ; Else draw not mirrored.
    ;
    move.b  (A5)+,D0  ; PLA
    jsr     DrawObjectNotMirrored
    jmp     CheckMonsterCollisions

    even
_L_z04_UpdateOctorock_DrawMirrored:
    move.b  (A5)+,D0  ; PLA
; Params:
; A: frame image
; X: object index
; [00]: object X
; [01]: object Y
;
    even
DrawObjectMirroredAndCheckCollisions:
    jsr     DrawObjectMirrored
    jmp     CheckMonsterCollisions

    even
UpdateGhini:
    move.b  #$FF,D0
    jsr     UpdateCommonWanderer
    jsr     DrawGhiniAndCheckCollisions
    jsr     CheckMonsterCollisions
    ; If the monster is still alive, then return.
    ;
    lea     ($0405,A4),A0
    move.b  (A0,D2.W),D0
    beq  _L_z04_UpdateGhini_Exit
    ; For each object slot from $B to 1:
    ; If the object is a flying ghini ($22),
    ; then kill it by setting metastate to $11.
    ;
    moveq   #11,D3
    even
_L_z04_UpdateGhini_LoopObject:
    lea     ($034F,A4),A0
    move.b  (A0,D3.W),D0
    cmpi.b  #$22,D0
    bne  _anon_z04_50
    moveq   #17,D0
    lea     ($0405,A4),A0
    move.b  D0,(A0,D3.W)
_anon_z04_50:
    subq.b  #1,D3
    bne  _L_z04_UpdateGhini_LoopObject
    even
_L_z04_UpdateGhini_Exit:
    rts

    even
DrawGhiniAndCheckCollisions:
    jsr     Anim_FetchObjPosForSpriteDescriptor
    move.b  D0,($000D,A4)
    ; If the direction has an "up" component, then keep the
    ; frame image 0, and go figure out horizontal flipping.
    ;
    lea     ($0098,A4),A0
    move.b  (A0,D2.W),D0
    andi.b #$08,D0
    bne  _L_z04_DrawGhiniAndCheckCollisions_CheckHorizontalFlip
    ; Else make the frame image 1 for the "down" frame.
    ; Note that this is the frame image to use, even if there's no
    ; down component in the direction.
    ;
    addq.b  #1,($000D,A4)
    ; If right is a component of the direction, then go set horizontal
    ; flipping. Else leave horizontal flipping = 0.
    ;
    lea     ($0098,A4),A0
    move.b  (A0,D2.W),D0
    andi.b #$01,D0
    beq  _L_z04_DrawGhiniAndCheckCollisions_DrawAndCheckCollisions
    bne  _L_z04_DrawGhiniAndCheckCollisions_SetHorizontalFlip
    even
_L_z04_DrawGhiniAndCheckCollisions_CheckHorizontalFlip:
    ; Set horizontal flipping if right is a direction component.
    ; This essentially the same test as above, but for when we jump
    ; from the "up" test.
    ;
    lea     ($0098,A4),A0
    move.b  (A0,D2.W),D0
    andi.b #$02,D0
    beq  _L_z04_DrawGhiniAndCheckCollisions_DrawAndCheckCollisions
    even
_L_z04_DrawGhiniAndCheckCollisions_SetHorizontalFlip:
    addq.b  #1,($000F,A4)
    even
_L_z04_DrawGhiniAndCheckCollisions_DrawAndCheckCollisions:
    move.b  ($000D,A4),D0
; Params:
; A: frame image
; X: object index
; [00]: object X
; [01]: object Y
; [0F]: flip horizontally
;
; Returns:
; [00]: 0 for Link slot
; [06]: 1 if objects collide
; [09]: 0 for Link damage type (none)
; [0C]: 1 if objects collide
; [034B]: ShotCollidesWithLink
;
    even
DrawObjectNotMirroredAndCheckLinkCollision:
    jsr     DrawObjectNotMirrored
    jmp     CheckLinkCollision

    even
SecretArmosRoomIds:
    dc.b    $24, $0B, $1C, $22, $34, $3D, $4E

    even
SecretArmosXs:
    dc.b    $E0, $B0, $B0, $30, $40, $90, $A0

    even
InitArmosOrFlyingGhini:
    ; In UpdateObject, this object was flagged "initialized".
    ; But if it's still fading in (timer > 0), then flag it "uninitialized".
    ;
    move.b  ($28,A4,D2.W),D0
    lea     ($0492,A4),A0
    move.b  D0,(A0,D2.W)
    ; If it's still fading in, then go finish some initialization needed
    ; for fading in.
    ;
    bne  _L_z04_InitArmosOrFlyingGhini_FinishInit
    ; Once the object timer reaches 0; if the object is flying ghini,
    ; go finish initializing it.
    ;
    lea     ($034F,A4),A0
    move.b  (A0,D2.W),D0
    cmpi.b  #$22,D0
    beq  _L_z04_InitArmosOrFlyingGhini_FinishInit
    ; Else we have an armos.
    ;
    ; Store stairs tile $70 in [00] for use later.
    ;
    moveq   #112,D0
    move.b  D0,($0000,A4)
    ; Look for the current room ID in an array of room ID's that
    ; have armos secrets.
    ;
    moveq   #6,D3
    even
_L_z04_InitArmosOrFlyingGhini_LoopArmosRoom:
    move.b  ($00EB,A4),D0
    ; If this element does not match the current room ID, go loop again.
    ;
    lea     (SecretArmosRoomIds).l,A0
    move.b  (A0,D3.W),D1
    cmp.b   D1,D0
    bne  _L_z04_InitArmosOrFlyingGhini_NextLoopArmosRoom
    ; The secret (usually stairs) is under one of the armoses.
    ;
    ; If the armos's X coordinate does not match the one needed
    ; for the current room in the list, then go loop again.
    ;
    move.b  ($70,A4,D2.W),D0
    lea     (SecretArmosXs).l,A0
    move.b  (A0,D3.W),D1
    cmp.b   D1,D0
    bne  _L_z04_InitArmosOrFlyingGhini_NextLoopArmosRoom
    ; If the armos's Y coordinate <> $80, go loop again.
    ;
    lea     ($0084,A4),A0
    move.b  (A0,D2.W),D0
    cmpi.b  #$80,D0
    bne  _L_z04_InitArmosOrFlyingGhini_NextLoopArmosRoom
    ; If the loop index <> 0, go use the stairs tile to patch the floor.
    ;
    cmpi.b  #$00,D3
    bne  _L_z04_InitArmosOrFlyingGhini_UseChosenTile
    ; The room ID at index 0 is $24. Instead of stairs, this room
    ; has the power bracelet.
    ;
    ; Set up the room item with the armos's coordinates.
    ;
    move.b  D0,($0097,A4)
    move.b  ($70,A4,D2.W),D0
    move.b  D0,($0083,A4)
    ; This resets the room item's state, which activates it.
    ;
    move.b  D3,($00BF,A4)
    ; Set the room item ID.
    ;
    moveq   #20,D0
    move.b  D0,($00AB,A4)
    ; If the bracelet has not been taken, then play the "secret found" tune.
    ;
    ; Either way, quit the loop, and replace the tile with a floor tile.
    ;
    ; Note that, if the item was already taken, then the room item
    ; object will stay activated. But in E6EA (MoveAndDrawRoomItem),
    ; it will be ignored, because that routine checks whether
    ; the item was taken.
    ;
    jsr     GetRoomFlagUWItemState
    bne  _L_z04_InitArmosOrFlyingGhini_UseFloorTile
    jsr     PlaySecretFoundTune
    bne  _L_z04_InitArmosOrFlyingGhini_UseFloorTile
    even
_L_z04_InitArmosOrFlyingGhini_NextLoopArmosRoom:
    ; Bottom of the loop.
    ;
    subq.b  #1,D3
    bpl  _L_z04_InitArmosOrFlyingGhini_LoopArmosRoom
    even
_L_z04_InitArmosOrFlyingGhini_UseFloorTile:
    ; Not found, or found the power bracelet.
    ; Use a floor tile $26 to replace the armos.
    ;
    moveq   #38,D0
    move.b  D0,($0000,A4)
    even
_L_z04_InitArmosOrFlyingGhini_UseChosenTile:
    move.b  ($0000,A4),D0
    ; If the replacement tile is a stairs tile, then play the "secret found" tune.
    ;
    move.b  D0,-(A5)  ; PHA
    cmpi.b  #$70,D0
    bne  _anon_z04_51
    jsr     PlaySecretFoundTune
_anon_z04_51:
    ; Replace the tile where the armos was.
    ;
    addq.b  #1,($00F7,A4)
    move.b  (A5)+,D0  ; PLA
    jsr     ChangeTileObjTiles
    ; Because the armos object is aligned to the square grid
    ; (because it was made from a square),
    ; set its grid offset to 3 to compensate.
    ;
    ; Most objects are aligned to the grid vertically when the
    ; low nibble is $D.
    ;
    moveq   #3,D0
    lea     ($0394,A4),A0
    move.b  D0,(A0,D2.W)
    ; Set a speed (q-speed fraction) randomly:
    ; $20 if random value < $80
    ; $60 otherwise
    ;
    moveq   #32,D0
    moveq   #0,D3
    move.b  ($19,A4,D2.W),D3
    cmpi.b  #$80,D3
    bcs  _anon_z04_52
    moveq   #96,D0
_anon_z04_52:
    lea     ($03BC,A4),A0
    move.b  D0,(A0,D2.W)
    even
_L_z04_InitArmosOrFlyingGhini_FinishInit:
    ; Facing and input directions down.
    ;
    moveq   #4,D0
    lea     ($03F8,A4),A0
    move.b  D0,(A0,D2.W)
    lea     ($0098,A4),A0
    move.b  D0,(A0,D2.W)
    ; Every other frame, return without drawing.
    ;
    move.b  ($28,A4,D2.W),D0
    lsr.b  #1,D0   ; LSR A
    bcs  _anon_z04_53
    ; Finish initializing based on type.
    ;
    lea     ($034F,A4),A0
    move.b  (A0,D2.W),D0
    cmpi.b  #$22,D0
    bne.s  __far_z_04_0034
    jmp  L_EndInitFlyingGhini
__far_z_04_0034:
    jsr     DrawArmosAndCheckCollisions
_anon_z04_53:
    rts

    even
L_EndInitFlyingGhini:
    jsr     DrawGhiniAndCheckCollisions
    ; If we're finally leaving the object flagged "initialized",
    ; then reset metastate and initialize this as a flyer.
    ;
    lea     ($0492,A4),A0
    move.b  (A0,D2.W),D0
    bne  _anon_z04_53
    jsr     ResetObjMetastateAndTimer
    jmp     EndInitFlyer

    even
UpdateArmos:
    jsr     UpdateGoriya
    ; If it's still shoved, then don't animate. Only go draw.
    ;
    lea     ($00C0,A4),A0
    move.b  (A0,D2.W),D0
    beq.s  __far_z_04_0035
    jmp  DrawArmosAndCheckCollisions
__far_z_04_0035:
    ; Animate.
    ;
    ; Decrement the animation counter. But if it hasn't reached 0,
    ; then only go draw.
    ;
    lea     ($03D0,A4),A0
    subq.b  #1,(A0,D2.W)
    beq.s  __far_z_04_0036
    jmp  DrawArmosAndCheckCollisions
__far_z_04_0036:
    ; Armos animation frames last 6 screen frames.
    ;
    moveq   #6,D0
    lea     ($03D0,A4),A0
    move.b  D0,(A0,D2.W)
    ; Armos doesn't simply flip horizontally to animate. That would
    ; change the position of the shield. To keep fixed it in place,
    ; there are separate frame images for each animation frame.
    ;
    ; Frame images 0 and 1 depict the first animation frame, facing front and back.
    ; Frame images 2 and 3 depict the second animation frame, facing front and back.
    ;
    ; Here flip between the two sets by XOR'ing with 2.
    ; Then choose the direction at the point of drawing below.
    ;
    lea     ($03E4,A4),A0
    move.b  (A0,D2.W),D0
    eori.b #$02,D0
    lea     ($03E4,A4),A0
    move.b  D0,(A0,D2.W)
    even
DrawArmosAndCheckCollisions:
    jsr     Anim_FetchObjPosForSpriteDescriptor
    moveq   #0,D3
    lea     ($0098,A4),A0
    move.b  (A0,D2.W),D3
    ; If facing up, then use the second frame image in the set ("back").
    ; Else use the second.
    ;
    cmpi.b  #$08,D3
    bne  _anon_z04_54
    moveq   #1,D0
_anon_z04_54:
    andi    #$EE,CCR  ; CLC: clear C+X
    lea     ($03E4,A4),A0
    move.b  (A0,D2.W),D1
    addx.b  D1,D0   ; ADC ObjAnimFrame,X
    jsr     DrawObjectNotMirrored
    ; If the armos is still fading in, then go for check collision with Link,
    ; but not with weapons.
    ;
    move.b  ($28,A4,D2.W),D0
    bne  _L_z04_DrawArmosAndCheckCollisions_CheckLinkCollision
    ; Else check for all collisions.
    ;
    jsr     CheckMonsterCollisions
    ; If the armos has died, then set object type to $5D (dead dummy).
    ;
    lea     ($0405,A4),A0
    move.b  (A0,D2.W),D0
    beq  _anon_z04_55
    moveq   #93,D0
    lea     ($034F,A4),A0
    move.b  D0,(A0,D2.W)
_anon_z04_55:
    rts

    even
_L_z04_DrawArmosAndCheckCollisions_CheckLinkCollision:
    jmp     CheckLinkCollision

    even
UpdatePondFairy:
    jsr     DrawFairy
    ; If not in state 0, then go handle states 1 to 3.
    ;
    move.b  ($00AD,A4),D0
    beq.s  __far_z_04_0037
    jmp  PondFairy_HandleOtherStates
__far_z_04_0037:
    ; State 0.
    ;
    ; If Link is not at the edge of the pond (Y=$AD), then return.
    ;
    move.b  ($0084,A4),D0
    cmpi.b  #$AD,D0
    bne  _L_z04_UpdatePondFairy_Exit
    ; If Link's X < $70 or >= $81, then return.
    ;
    move.b  ($0070,A4),D0
    cmpi.b  #$70,D0
    bcs  _L_z04_UpdatePondFairy_Exit
    cmpi.b  #$81,D0
    bcc  _L_z04_UpdatePondFairy_Exit
    ; Link is at the edge of the pond. Advance to state 1,
    ; halt Link, and start filling hearts.
    ;
    addq.b  #1,($00AD,A4)
    moveq   #64,D0
    move.b  D0,($00AC,A4)
    move.b  D0,($0063,A4)
    even
_L_z04_UpdatePondFairy_Exit:
    rts

    even
PondFairy_HandleOtherStates:
    cmpi.b  #$01,D0
    bne  _L_z04_PondFairy_HandleOtherStates_CheckState2
    ; State 1. Flying and filling hearts.
    ;
    ; If still filling hearts, then go draw Link and hearts.
    ;
    move.b  ($0063,A4),D0
    bne  _L_z04_PondFairy_HandleOtherStates_DrawLinkAndHearts
    ; If not filling hearts anymore, then go to state 2,
    ; and set Link's object timer to $50, to keep showing hearts
    ; a little while after we finish filling hearts.
    ;
    addq.b  #1,($00AD,A4)
    moveq   #80,D0
    move.b  D0,($0029,A4)
    even
_L_z04_PondFairy_HandleOtherStates_CheckState2:
    ; If state <> 2 (so, it's 3), then return.
    ;
    ; Note that the first time here is when we fall thru from 8DBC.
    ; In this case, A has $50 -- the value that Link's object timer
    ; was set to, and we'll return.
    ;
    cmpi.b  #$02,D0
    bne  _L_z04_PondFairy_HandleOtherStates_Exit
    ; State = 2.
    ;
    ; If Link's timer <> 0, then go draw Link and hearts.
    ;
    move.b  ($0029,A4),D0
    bne  _L_z04_PondFairy_HandleOtherStates_DrawLinkAndHearts
    ; Else go to state 3, and unhalt Link.
    ;
    addq.b  #1,($00AD,A4)
    moveq   #0,D0
    move.b  D0,($00AC,A4)
    even
_L_z04_PondFairy_HandleOtherStates_DrawLinkAndHearts:
    ; TODO: but why, since Link is halted?
    ;
    ; Reset the input direction, so that Link doesn't animate
    ; when drawing him.
    moveq   #0,D3
    move.b  D3,($03F8,A4)
    ; Save and reset Link's state.
    ;
    ; TODO: but why, since Link is halted?
    ;
    move.b  ($00AC,A4),D0
    move.b  D0,-(A5)  ; PHA
    move.b  D3,($00AC,A4)
    jsr     Link_EndMoveAndAnimate_Bank4
    ; Restore Link's state.
    ;
    move.b  (A5)+,D0  ; PLA
    move.b  D0,($00AC,A4)
    jsr     PondFairy_MoveHearts
    ; Restore the object slot.
    ;
    moveq   #0,D2
    move.b  ($0340,A4),D2
    even
_L_z04_PondFairy_HandleOtherStates_Exit:
    rts

    even
PondHeartStartAngles:
    dc.b    $14, $10, $0C, $08, $04, $00, $1C

    even
PondFairy_MoveHearts:
    ; Loop over each heart from object slot 2 to 9.
    ;
    ; Even though they are not standalone objects, their info
    ; is stored in those object slots.
    ;
    moveq   #2,D2
    even
_L_z04_PondFairy_MoveHearts_LoopHeart:
    ; If the current heart's state <> 0, then go move it.
    ; Else we have to wait for it to come out at the right time.
    ;
    lea     ($00AC,A4),A0
    move.b  (A0,D2.W),D0
    bne  _L_z04_PondFairy_MoveHearts_MoveHeart
    ; The current heart's state = 0.
    ;
    ; If object slot = 2, then go make it appear. This is the first
    ; heart to show up.
    ;
    cmpi.b  #$02,D2
    beq  _L_z04_PondFairy_MoveHearts_SetUpHeart
    ; Object slot <> 2. If the state of the heart in slot 2 = 0, then
    ; go start over.
    ;
    ; TODO:
    ; Is it possible to jump from here? This looks like an infinite loop.
    ;
    move.b  ($00AE,A4),D0
    beq  _L_z04_PondFairy_MoveHearts_LoopHeart
    ; Look up the starting angle of this heart with the index
    ; (object slot - 3). If the first heart has not reached this angle,
    ; then loop again.
    ;
    move.b  D2,D0
    ori     #$11,CCR  ; SEC: set C+X
    move.b  #$03,D1
    eori    #$10,CCR  ; flip X: 6502 SBC polarity
    subx.b  D1,D0   ; SBC #$03
    eori    #$10,CCR  ; restore X = 6502 C
    moveq   #0,D3
    move.b  D0,D3
    move.b  ($0396,A4),D0
    lea     (PondHeartStartAngles).l,A0
    move.b  (A0,D3.W),D1
    cmp.b   D1,D0
    bne  _L_z04_PondFairy_MoveHearts_NextLoopHeart
    even
_L_z04_PondFairy_MoveHearts_SetUpHeart:
    ; Set up this heart. Set its state to 1.
    ;
    lea     ($00AC,A4),A0
    addq.b  #1,(A0,D2.W)
    ; TODO: ?
    ;
    move.b  #$80,D0
    lea     ($0098,A4),A0
    move.b  D0,(A0,D2.W)
    ; Starting angle $18 (N).
    ;
    moveq   #24,D0
    lea     ($0394,A4),A0
    move.b  D0,(A0,D2.W)
    ; This heart is right above the fairy. Set its X the same as the fairy's.
    ;
    move.b  ($0071,A4),D0
    move.b  D0,($70,A4,D2.W)
    ; This heart is right above the fairy. Set its Y $1C pixels above the fairy.
    ;
    move.b  ($0085,A4),D0
    ori     #$11,CCR  ; SEC: set C+X
    move.b  #$1C,D1
    eori    #$10,CCR  ; flip X: 6502 SBC polarity
    subx.b  D1,D0   ; SBC #$1C
    eori    #$10,CCR  ; restore X = 6502 C
    lea     ($0084,A4),A0
    move.b  D0,(A0,D2.W)
    even
_L_z04_PondFairy_MoveHearts_MoveHeart:
    ; Decrease the angle by $00.60.
    ;
    moveq   #0,D0
    move.b  D0,($000B,A4)
    moveq   #96,D0
    jsr     DecreaseObjectAngle
    ; Rotate the heart's location by the change in angle.
    ; Use 6 for the number of bits of sine/cosine to use
    ; for a large ring.
    ;
    moveq   #6,D0
    moveq   #0,D3
    move.b  D0,D3
    jsr     RotateObjectLocation
    lea     ($0084,A4),A0
    move.b  D0,(A0,D2.W)
    move.b  D2,D0
    move.b  D0,-(A5)  ; PHA
    jsr     Anim_SetSpriteDescriptorRedPaletteRow
    jsr     Anim_FetchObjPosForSpriteDescriptor
    ; The variable for the currently updating object slot has to be
    ; set to the heart's object slot for this drawing routine to work.
    ;
    moveq   #0,D2
    move.b  ($0340,A4),D2
    jsr     DrawObjectNotMirrored
    move.b  (A5)+,D0  ; PLA
    moveq   #0,D2
    move.b  D0,D2
    even
_L_z04_PondFairy_MoveHearts_NextLoopHeart:
    ; Bottom of the loop.
    ; Increase the object slot.
    ;
    addq.b  #1,D2
    cmpi.b  #$0A,D2
    bne  _L_z04_PondFairy_MoveHearts_LoopHeart
    rts

    even
RockPushDirections:
; Also used for the gravestone.
    dc.b    $08, $04

    even
UpdateRockOrGravestone:
    lea     ($00AC,A4),A0
    move.b  (A0,D2.W),D0
    bne  _L_z04_UpdateRockOrGravestone_State1
    ; State 0.
    ;
    ; If this is not a gravestone (but it's a rock), and there is no
    ; bracelet, then return.
    ;
    lea     ($034F,A4),A0
    move.b  (A0,D2.W),D0
    cmpi.b  #$65,D0
    beq  _L_z04_UpdateRockOrGravestone_CheckQuest
    move.b  ($0665,A4),D0
    beq  _L_z04_UpdateRockOrGravestone_Exit
    even
_L_z04_UpdateRockOrGravestone_CheckQuest:
    ; If there is a mismatch between the current quest and the quest
    ; needed for the secret in this room, then return.
    ;
    jsr     IsQuestSecretMismatch
    bcs  _L_z04_UpdateRockOrGravestone_Exit
    ; The gravestone and rocks can only be pushed vertically.
    ; Return, if X's don't match.
    ;
    move.b  ($0070,A4),D0
    move.b  ($70,A4,D2.W),D1
    cmp.b   D1,D0
    bne  _L_z04_UpdateRockOrGravestone_Exit
    ; If the difference between Link's (Y + 3) and the block's Y
    ; is positive; then go use it along with a flag that indicates that
    ; Link is "down" from the object.
    ;
    moveq   #0,D3
    move.b  ($0084,A4),D0
    andi    #$EE,CCR  ; CLC: clear C+X
    move.b  #$03,D1
    addx.b  D1,D0   ; ADC #$03 (X flag = 6502 C)
    ori     #$11,CCR  ; SEC: set C+X
    lea     ($0084,A4),A0
    move.b  (A0,D2.W),D1
    eori    #$10,CCR  ; flip X: 6502 SBC polarity
    subx.b  D1,D0   ; SBC ObjY,X
    eori    #$10,CCR  ; restore X = 6502 C
    bpl  _L_z04_UpdateRockOrGravestone_CheckDistance
    ; Else negate it, and indicate Link is "up" from the object.
    ;
    addq.b  #1,D3
    eori.b #$FF,D0
    andi    #$EE,CCR  ; CLC: clear C+X
    move.b  #$01,D1
    addx.b  D1,D0   ; ADC #$01 (X flag = 6502 C)
    even
_L_z04_UpdateRockOrGravestone_CheckDistance:
    ; If the distance >= $11, return.
    ;
    cmpi.b  #$11,D0
    bcc  _L_z04_UpdateRockOrGravestone_Exit
    ; If the input direction has no vertical component, then return.
    ;
    move.b  ($03F8,A4),D0
    andi.b #$0C,D0
    beq  _L_z04_UpdateRockOrGravestone_Exit
    ; If this vertical input direction does not match the one needed
    ; to push the rock or gravestone, then return.
    ;
    lea     (RockPushDirections).l,A0
    move.b  (A0,D3.W),D1
    cmp.b   D1,D0
    bne  _L_z04_UpdateRockOrGravestone_Exit
    ; Set it to the object's direction. Go to the next state.
    ;
    lea     ($0098,A4),A0
    move.b  D0,(A0,D2.W)
    lea     ($00AC,A4),A0
    addq.b  #1,(A0,D2.W)
    ; Store current room ID.
    ;
    move.b  ($00EB,A4),D0
    lea     ($0412,A4),A0
    move.b  D0,(A0,D2.W)
    ; Change from a gravestone tile to the gray floor tile.
    ; The gravestone object will be drawn above it.
    ;
    addq.b  #1,($00F7,A4)
    moveq   #38,D0
    jsr     ChangeTileObjTiles
    even
_L_z04_UpdateRockOrGravestone_Exit:
    rts

    even
_L_z04_UpdateRockOrGravestone_State1:
    ; State 1.
    ;
    ; Move in the object's direction.
    ;
    lea     ($0098,A4),A0
    move.b  (A0,D2.W),D0
    move.b  D0,($000F,A4)
    jsr     MoveObject
    ; Draw the sprites one pixel above the object's location.
    ;
    jsr     Anim_FetchObjPosForSpriteDescriptor
    subq.b  #1,($0001,A4)
    jsr     DrawObjectNotMirrored
    ; If the object's grid offset (distance moved) <> $10 nor -$10,
    ; then return.
    ;
    lea     ($0394,A4),A0
    move.b  (A0,D2.W),D0
    cmpi.b  #$10,D0
    beq  _anon_z04_56
    cmpi.b  #$F0,D0
    bne  _L_z04_UpdateRockOrGravestone_Exit
_anon_z04_56:
    ; Flag the room visited.
    ;
    move.b  ($00EB,A4),D0
    move.b  D0,-(A5)  ; PHA
    lea     ($0412,A4),A0
    move.b  (A0,D2.W),D0
    move.b  D0,($00EB,A4)
    jsr     MarkRoomVisited
    move.b  (A5)+,D0  ; PLA
    move.b  D0,($00EB,A4)
    ; If object is a rock ($62), go use a rock tile ($C8).
    ;
    move.b  #$C8,D0
    moveq   #0,D3
    lea     ($034F,A4),A0
    move.b  (A0,D2.W),D3
    cmpi.b  #$62,D3
    beq  _L_z04_UpdateRockOrGravestone_ReplaceTiles
    ; If the object is a gravestone ($65), go use a gravestone tile ($BC).
    ;
    move.b  #$BC,D0
    cmpi.b  #$65,D3
    beq  _L_z04_UpdateRockOrGravestone_ReplaceTiles
    ; Else use an armos tile ($C0). Dead code?
    ;
    move.b  #$C0,D0
    even
_L_z04_UpdateRockOrGravestone_ReplaceTiles:
    ; Change the tiles at the end location.
    ;
    addq.b  #1,($00F7,A4)
    jsr     ChangeTileObjTiles
    ; Store the stairs tile in [00] for use in revealing the secret.
    ;
    moveq   #112,D0
    move.b  D0,($0000,A4)
    ; Get the position of the stairs in this room, and set it for the object.
    ;
    moveq   #0,D3
    lea     ($0412,A4),A0
    move.b  (A0,D2.W),D3
    jsr     GetShortcutOrItemXYForRoom
    move.b  D0,($70,A4,D2.W)
    lea     ($0084,A4),A0
    move.b  D3,(A0,D2.W)
    move.b  ($0000,A4),D0
; Params:
; A: the first tile of tile object
; X: object index
;
    even
RevealSecretTileObj:
    addq.b  #1,($00F7,A4)
    jsr     ChangeTileObjTiles
    jsr     DestroyMonster_Bank4
    jmp     PlaySecretFoundTune

    even
UpdateRockWall:
    ; If the secret in this room does not apply to the current quest,
    ; then return.
    ;
    jsr     IsQuestSecretMismatch
    bcs  _L_z04_UpdateRockWall_Exit
    ; If there is no detonating bomb (state $13) in slots $10 and $11,
    ; then return.
    ;
    moveq   #16,D3
    lea     ($00AC,A4),A0
    move.b  (A0,D3.W),D0
    cmpi.b  #$13,D0
    beq  _L_z04_UpdateRockWall_FoundBomb
    addq.b  #1,D3
    lea     ($00AC,A4),A0
    move.b  (A0,D3.W),D0
    cmpi.b  #$13,D0
    bne  _L_z04_UpdateRockWall_Exit
    even
_L_z04_UpdateRockWall_FoundBomb:
    ; Store the bomb's object slot in [00].
    ;
    move.b  D3,($0000,A4)
    ; If the tile object and weapon collide, then reveal the secret.
    ;
    jsr     CheckTileObjWeaponCollision
    beq  _L_z04_UpdateRockWall_Exit
    moveq   #36,D0
    jsr     RevealAndFlagSecretTileObj
    even
_L_z04_UpdateRockWall_Exit:
    rts

    even
UpdateTree:
    ; If the secret in this room does not apply to the current quest,
    ; then return.
    ;
    jsr     IsQuestSecretMismatch
    bcc.s  __far_z_04_0038
    jmp  L10F3E_Exit
__far_z_04_0038:
    ; If there is no standing fire (state $22) in slots $10 and $11,
    ; then return.
    ;
    moveq   #16,D3
    lea     ($00AC,A4),A0
    move.b  (A0,D3.W),D0
    cmpi.b  #$22,D0
    beq  _L_z04_UpdateTree_FoundFire
    addq.b  #1,D3
    lea     ($00AC,A4),A0
    move.b  (A0,D3.W),D0
    cmpi.b  #$22,D0
    beq.s  __far_z_04_0039
    jmp  L10F3E_Exit
__far_z_04_0039:
    even
_L_z04_UpdateTree_FoundFire:
    ; Store the fire's object slot in [00].
    ;
    move.b  D3,($0000,A4)
    ; If the standing fire's timer >= 2, return.
    ;
    move.b  ($28,A4,D3.W),D0
    cmpi.b  #$02,D0
    bcs.s  __far_z_04_0040
    jmp  L10F3E_Exit
__far_z_04_0040:
    ; If the tile object and weapon collide, then reveal the secret.
    ;
    jsr     CheckTileObjWeaponCollision
    bne.s  __far_z_04_0041
    jmp  L10F3E_Exit
__far_z_04_0041:
; Params:
; X: object index of the tile object
;
;
; First tile of stairs
    even
RevealAndFlagSecretStairsObj:
    moveq   #112,D0
; Params:
; A: the first tile of tile object
; X: object index
;
    even
RevealAndFlagSecretTileObj:
    jsr     RevealSecretTileObj
    ; Flag the secret found in this room.
    ;
    jsr     GetRoomFlags
    ori.b #$80,D0
    move.b  ($00,A4),D1   ; ptr lo
    move.b  ($01,A4),D4  ; ptr hi
    andi.w  #$00FF,D1         ; zero-extend lo byte
    lsl.w   #8,D4
    or.w    D1,D4
    ext.l   D4
    add.l   #NES_RAM,D4
    movea.l D4,A0
    move.b  D0,(A0,D3.W)     ; STA ($nn),Y
    even
L10F3E_Exit:
    rts

; Params:
; X: object index
; Y: weapon object index
; [00]: weapon object index
;
; Returns:
; A: 1 if objects collide
;
; Put the midpoint coordinate of the weapon in [04] and [05].
;
    even
CheckTileObjWeaponCollision:
    move.b  ($70,A4,D3.W),D0
    andi    #$EE,CCR  ; CLC: clear C+X
    move.b  #$08,D1
    addx.b  D1,D0   ; ADC #$08 (X flag = 6502 C)
    move.b  D0,($0004,A4)
    lea     ($0084,A4),A0
    move.b  (A0,D3.W),D0
    andi    #$EE,CCR  ; CLC: clear C+X
    move.b  #$08,D1
    addx.b  D1,D0   ; ADC #$08 (X flag = 6502 C)
    move.b  D0,($0005,A4)
    ; Put the tile object's midpoint coordinates in [02] and [03].
    ;
    jsr     GetObjectMiddle
    moveq   #16,D0
    jmp     DoObjectsCollide

    even
SecretQuestNumbers:
    dc.b    $00, $00, $01

; Returns:
; C: 1 if there is a mismatch between current quest
;    and quest number for the secret in the room
;
;
; The quest secret is in the high two bits.
;
    even
IsQuestSecretMismatch:
    move.b  ($04CD,A4),D0
    lsr.b  #1,D0   ; LSR A
    lsr.b  #1,D0   ; LSR A
    lsr.b  #1,D0   ; LSR A
    lsr.b  #1,D0   ; LSR A
    lsr.b  #1,D0   ; LSR A
    lsr.b  #1,D0   ; LSR A
    ; If it's 0, then return C=0.
    ;
    beq  _L_z04_IsQuestSecretMismatch_ReturnFalse
    ; Look up a quest number (0 or 1) indexed by quest secret (0 or 1).
    ;
    moveq   #0,D3
    move.b  D0,D3
    lea     (SecretQuestNumbers).l,A0
    move.b  (A0,D3.W),D0
    ; If the save slot's quest number matches the room's
    ; secret quest number, then return C=0.
    ;
    moveq   #0,D3
    move.b  ($0016,A4),D3
    lea     ($062D,A4),A0
    move.b  (A0,D3.W),D1
    cmp.b   D1,D0
    beq  _L_z04_IsQuestSecretMismatch_ReturnFalse
    ; Else return C=1. There is a mismatch in quest numbers.
    ;
    ori     #$11,CCR  ; SEC: set C+X
    rts

    even
_L_z04_IsQuestSecretMismatch_ReturnFalse:
    andi    #$EE,CCR  ; CLC: clear C+X
    rts

    even
RaftDirections:
    dc.b    $04, $08

    even
UpdateDock:
    ; If missing the raft, then return.
    ;
    move.b  ($0660,A4),D0
    beq  _L_z04_UpdateDock_Exit
    lea     ($00AC,A4),A0
    move.b  (A0,D2.W),D0
    bne  _L_z04_UpdateDock_HandleOtherStates
    ; State 0
    ;
    ; Choose an X coordinate for the dock:
    ; $80 in room $55
    ; $60 in the other room ($3F)
    ;
    move.b  #$80,D0
    moveq   #0,D3
    move.b  ($00EB,A4),D3
    cmpi.b  #$55,D3
    beq  _anon_z04_57
    moveq   #96,D0
_anon_z04_57:
    ; If the player is not aligned with the dock, return.
    ;
    move.b  ($0070,A4),D1
    cmp.b   D1,D0
    bne  _L_z04_UpdateDock_Exit
    ; Set the dock object's X.
    ;
    move.b  D0,($70,A4,D2.W)
    ; Determine whether Link is coming or going.
    ; If Y = $3D, then he's at the top edge of the screen. Use state 1.
    ;
    moveq   #1,D3
    move.b  ($0084,A4),D0
    cmpi.b  #$3D,D0
    beq  _L_z04_UpdateDock_SetState
    ; But if Y = $7D, then he's at the dock. Use state 2.
    ; Otherwise, return.
    ;
    addq.b  #1,D3
    cmpi.b  #$7D,D0
    bne  _L_z04_UpdateDock_Exit
    even
_L_z04_UpdateDock_SetState:
    lea     ($00AC,A4),A0
    move.b  D3,(A0,D2.W)
    ; Show the raft beneath Link: 6 pixels down.
    ;
    andi    #$EE,CCR  ; CLC: clear C+X
    move.b  #$06,D1
    addx.b  D1,D0   ; ADC #$06 (X flag = 6502 C)
    lea     ($0084,A4),A0
    move.b  D0,(A0,D2.W)
    ; Play the "secret found" tune, and halt Link.
    ;
    jsr     PlaySecretFoundTune
    moveq   #64,D0
    move.b  D0,($00AC,A4)
    ; Set Link's direction based on the raft's state.
    ;
    lea     (RaftDirections-1).l,A0
    move.b  (A0,D3.W),D0
    move.b  D0,($0098,A4)
    even
_L_z04_UpdateDock_Exit:
    rts

    even
_L_z04_UpdateDock_HandleOtherStates:
    ; Is state = 1?
    ;
    moveq   #0,D3
    lea     ($00AC,A4),A0
    move.b  (A0,D2.W),D3
    subq.b  #1,D3
    beq  _L_z04_UpdateDock_State1
    ; State 2. Up
    ;
    lea     ($0084,A4),A0
    subq.b  #1,(A0,D2.W)
    subq.b  #1,($0084,A4)
    ; If Link's Y = $3D, then leave the room.
    ; Else go draw.
    ;
    move.b  ($0084,A4),D0
    cmpi.b  #$3D,D0
    bne  _L_z04_UpdateDock_Draw
    move.b  D2,D0
    move.b  D0,-(A5)  ; PHA
    jsr     GoToNextModeFromPlay
    move.b  (A5)+,D0  ; PLA
    moveq   #0,D2
    move.b  D0,D2
    jmp     _L_z04_UpdateDock_ResetLinkAndRaftStateAndDraw

    even
_L_z04_UpdateDock_State1:
    ; State 1. Down
    ;
    lea     ($0084,A4),A0
    addq.b  #1,(A0,D2.W)
    addq.b  #1,($0084,A4)
    ; If Link's Y <> $7F, go draw.
    ; Note that Y is below $7D, which would trigger going up.
    ;
    move.b  ($0084,A4),D0
    cmpi.b  #$7F,D0
    bne  _L_z04_UpdateDock_Draw
    ; Link's grid offset at $7F must be 2 ($7F - $7D).
    ;
    moveq   #2,D0
    move.b  D0,($0394,A4)
    even
_L_z04_UpdateDock_ResetLinkAndRaftStateAndDraw:
    moveq   #0,D0
    move.b  D0,($00AC,A4)
    lea     ($00AC,A4),A0
    move.b  D0,(A0,D2.W)
    even
_L_z04_UpdateDock_Draw:
    move.b  D2,D0
    move.b  D0,-(A5)  ; PHA
    jsr     Link_EndMoveAndAnimate_Bank4
    move.b  (A5)+,D0  ; PLA
    moveq   #0,D2
    move.b  D0,D2
    ; TODO: Why animate the raft?
    ;
    jsr     AnimateObjectWalking
    moveq   #0,D0
    moveq   #9,D3
    jmp     Anim_WriteStaticItemSpritesWithAttributes

    even
UpdateFlyingGhini:
    ; If we have the magic clock, then don't move.
    ;
    move.b  ($066C,A4),D0
    bne  _anon_z04_58
    jsr     ControlFlyingGhiniFlight
    jsr     MoveFlyer
_anon_z04_58:
    jsr     Anim_FetchObjPosForSpriteDescriptor
    ; Get the low bit of the flying distance traveled.
    ; But this doesn't seem to be used.
    ; The following call clobbers the A register.
    ;
    lea     ($0437,A4),A0
    move.b  (A0,D2.W),D0
    andi.b #$01,D0
    jmp     DrawGhiniAndCheckCollisions

    even
ControlFlyingGhiniFlight:
    lea     ($0444,A4),A0
    move.b  (A0,D2.W),D0
    jsr     _m68k_tablejump  ; M68K-native table dispatch (replaces JSR TableJump)
    even
ControlFlyingGhiniFlight_JumpTable:
    dc.l    Flyer_SpeedUp   ; jump table entry (32-bit for _m68k_tablejump)
    dc.l    Flyer_GhiniDecideState   ; jump table entry (32-bit for _m68k_tablejump)
    dc.l    Flyer_Chase   ; jump table entry (32-bit for _m68k_tablejump)
    dc.l    Flyer_Wander   ; jump table entry (32-bit for _m68k_tablejump)
    dc.l    Flyer_SlowDown   ; jump table entry (32-bit for _m68k_tablejump)
    dc.l    Flyer_Delay   ; jump table entry (32-bit for _m68k_tablejump)

    even
Flyer_GhiniDecideState:
    ; Go to the next state randomly:
    ; Random >= $A0: 2
    ; Random >= $08: 3
    ; Else:          4
    ;
    ; Set up 6 turns.
    ;
    moveq   #2,D3
    move.b  ($18,A4,D2.W),D0
    cmpi.b  #$A0,D0
    bcc  _anon_z04_59
    addq.b  #1,D3
    cmpi.b  #$08,D0
    bcc  _anon_z04_59
    addq.b  #1,D3
_anon_z04_59:
    jmp     Flyer_SetFlyingStateAnd6Turns

    even
UpdatePeahat:
    ; If the object is being shoved, then shove it and go draw
    ; and check for collisions.
    ;
    lea     ($00C0,A4),A0
    move.b  (A0,D2.W),D0
    beq  _anon_z04_60
    jsr     Obj_Shove
    even
_L_z04_UpdatePeahat_L_DrawAndCheckCollisions:
    jmp     _L_z04_UpdatePeahat_DrawAndCheckCollisions

_anon_z04_60:
    ; If we have the clock or the object is stunned, go draw
    ; and check for collisions.
    ;
    move.b  ($066C,A4),D0
    move.b  ($3D,A4,D2.W),D1
    or.b  D1,D0
    bne  _L_z04_UpdatePeahat_L_DrawAndCheckCollisions
    ; Else move around.
    ;
    jsr     ControlPeahatFlight
    jsr     MoveFlyer
    even
_L_z04_UpdatePeahat_DrawAndCheckCollisions:
    jsr     Anim_FetchObjPosForSpriteDescriptor
    ; Take low bit of the flying distance traveled as the frame image.
    ; So, the faster it moves, the faster it animates.
    ;
    lea     ($0437,A4),A0
    move.b  (A0,D2.W),D0
    andi.b #$01,D0
    jsr     DrawObjectMirrored
    ; In flying state 5, check for all collisions (so it can get hurt).
    ; In all other states, only check for collisions with Link.
    ;
    lea     ($0444,A4),A0
    move.b  (A0,D2.W),D0
    cmpi.b  #$05,D0
    beq  _anon_z04_61
    jmp     CheckLinkCollision

_anon_z04_61:
    jmp     CheckMonsterCollisions

    even
ControlPeahatFlight:
    lea     ($0444,A4),A0
    move.b  (A0,D2.W),D0
    jsr     _m68k_tablejump  ; M68K-native table dispatch (replaces JSR TableJump)
    even
ControlPeahatFlight_JumpTable:
    dc.l    Flyer_SpeedUp   ; jump table entry (32-bit for _m68k_tablejump)
    dc.l    Flyer_PeahatDecideState   ; jump table entry (32-bit for _m68k_tablejump)
    dc.l    Flyer_Chase   ; jump table entry (32-bit for _m68k_tablejump)
    dc.l    Flyer_Wander   ; jump table entry (32-bit for _m68k_tablejump)
    dc.l    Flyer_SlowDown   ; jump table entry (32-bit for _m68k_tablejump)
    dc.l    Flyer_Delay   ; jump table entry (32-bit for _m68k_tablejump)

    even
Flyer_PeahatDecideState:
    ; Go to the next state randomly:
    ; Random >= $B0: 2
    ; Random >= $20: 3
    ; Else:          4
    ;
    ; Set up 6 turns.
    ;
    moveq   #2,D3
    move.b  ($18,A4,D2.W),D0
    cmpi.b  #$B0,D0
    bcs.s  __far_z_04_0042
    jmp  Flyer_SetFlyingStateAnd6Turns
__far_z_04_0042:
    addq.b  #1,D3
    cmpi.b  #$20,D0
    bcs.s  __far_z_04_0043
    jmp  Flyer_SetFlyingStateAnd6Turns
__far_z_04_0043:
    addq.b  #1,D3
    even
Flyer_SetFlyingStateAnd6Turns:
    move.b  D3,D0
    lea     ($0444,A4),A0
    move.b  D0,(A0,D2.W)
    moveq   #6,D0
    lea     ($042C,A4),A0
    move.b  D0,(A0,D2.W)
    rts

    even
PlaySecretFoundTune:
    moveq   #4,D0
    move.b  D0,($0602,A4)
    rts

; Unknown block
    dc.b    $FF, $FF, $FF, $FF, $FF, $FF, $FF, $FF
    dc.b    $FF, $FF, $FF, $FF, $FF, $FF, $FF, $FF
    dc.b    $FF, $FF, $FF, $FF, $FF, $FF, $FF, $FF
    dc.b    $FF

    even
WallmasterDirsAndAttrsLeft:
    dc.b    $01, $01, $08, $08, $08, $02, $02, $02
    dc.b    $C1, $C1, $C4, $C4, $C4, $C2, $C2, $C2

    even
WallmasterDirsAndAttrsRight:
    dc.b    $42, $42, $48, $48, $48, $41, $41, $41
    dc.b    $82, $82, $84, $84, $84, $81, $81, $81

    even
WallmasterDirsAndAttrsTop:
    dc.b    $C4, $C4, $C2, $C2, $C2, $C8, $C8, $C8
    dc.b    $84, $84, $81, $81, $81, $88, $88, $88

    even
WallmasterDirsAndAttrsBottom:
    dc.b    $48, $48, $42, $42, $42, $44, $44, $44
    dc.b    $08, $08, $01, $01, $01, $04, $04, $04

    even
WallmasterInitialXs:
    dc.b    $00, $F0

    even
WallmasterInitialYs:
    dc.b    $3D, $DD

    even
UpdateWallmaster:
    lea     ($00AC,A4),A0
    move.b  (A0,D2.W),D0
    beq  _anon_z04_62
    jmp     L_Wallmaster_State1

_anon_z04_62:
    ; State 0.
    ;
    ; If Link's object timer is active, then return.
    ;
    move.b  ($0029,A4),D0
    bne  _L_z04_UpdateWallmaster_Exit
    ; If Link is halted, then return.
    ;
    move.b  ($00AC,A4),D0
    cmpi.b  #$40,D0
    bne  _L_z04_UpdateWallmaster_State0
    even
_L_z04_UpdateWallmaster_Exit:
    rts

    even
_L_z04_UpdateWallmaster_State0:
    ; State 0. Idle/Waiting inside wall
    ;
    ; If  (Link's X < $29 or >= $C8)
    ; and (Link's Y < $6D or >= $B5),
    ; then return.
    ;
    move.b  ($0070,A4),D0
    cmpi.b  #$29,D0
    bcs  _anon_z04_63
    cmpi.b  #$C8,D0
    bcs  _L_z04_UpdateWallmaster_CheckLeftAndRight
_anon_z04_63:
    move.b  ($0084,A4),D0
    cmpi.b  #$6D,D0
    bcs  _L_z04_UpdateWallmaster_Exit
    cmpi.b  #$B5,D0
    bcc  _L_z04_UpdateWallmaster_Exit
    even
_L_z04_UpdateWallmaster_CheckLeftAndRight:
    ; Check whether Wallmaster should come out of the left or right wall.
    ;
    ; If Link's X <> $20 nor $D0, then go check the top and bottom walls.
    ;
    move.b  ($0070,A4),D0
    cmpi.b  #$20,D0
    beq  _anon_z04_64
    cmpi.b  #$D0,D0
    bne  _L_z04_UpdateWallmaster_CheckTopAndBottom
_anon_z04_64:
    ; Store Link's X as the major coordinate in [01],
    ; and Link's Y as the minor coordinate [00].
    ;
    move.b  ($0084,A4),D0
    move.b  D0,($0000,A4)
    move.b  ($0070,A4),D0
    move.b  D0,($0001,A4)
    ; Pass "up" as decreasing direction along wall in [02].
    ;
    moveq   #8,D0
    move.b  D0,($0002,A4)
    moveq   #32,D3
    moveq   #0,D0
    jsr     Wallmaster_CalcStartPosition
    ; Set Y coordinate to initial minor value returned.
    ;
    move.b  ($0004,A4),D0
    lea     ($0084,A4),A0
    move.b  D0,(A0,D2.W)
    ; Look up and set X coordinate according to the index returned.
    ;
    lea     (WallmasterInitialXs).l,A0
    move.b  (A0,D3.W),D0
    jmp     _L_z04_UpdateWallmaster_SetUpToEmerge

    even
_L_z04_UpdateWallmaster_CheckTopAndBottom:
    ; Check whether Wallmaster should come out of the top or bottom wall.
    ;
    ; If Link's Y <> $5D nor $BD, then return.
    ;
    move.b  ($0084,A4),D0
    cmpi.b  #$5D,D0
    beq  _anon_z04_65
    cmpi.b  #$BD,D0
    bne  _L_z04_UpdateWallmaster_Exit
_anon_z04_65:
    ; Store Link's Y as the major coordinate in [01],
    ; and Link's X as the minor coordinate [00].
    ;
    move.b  ($0070,A4),D0
    move.b  D0,($0000,A4)
    move.b  ($0084,A4),D0
    move.b  D0,($0001,A4)
    ; Pass "left" as decreasing direction along wall in [02].
    ;
    moveq   #2,D0
    move.b  D0,($0002,A4)
    moveq   #93,D3
    moveq   #32,D0
    jsr     Wallmaster_CalcStartPosition
    ; Look up and set Y coordinate according to the index returned.
    ;
    lea     (WallmasterInitialYs).l,A0
    move.b  (A0,D3.W),D0
    lea     ($0084,A4),A0
    move.b  D0,(A0,D2.W)
    ; Set X coordinate to initial minor value returned.
    ;
    move.b  ($0004,A4),D0
    even
_L_z04_UpdateWallmaster_SetUpToEmerge:
    move.b  D0,($70,A4,D2.W)
    ; Look up and set the facing direction for the first step.
    ;
    moveq   #0,D3
    lea     ($0412,A4),A0
    move.b  (A0,D2.W),D3
    lea     (WallmasterDirsAndAttrsLeft).l,A0
    move.b  (A0,D3.W),D0
    andi.b #$0F,D0
    lea     ($0098,A4),A0
    move.b  D0,(A0,D2.W)
    ; TODO: why object 1 timer?
    ;
    ; Set object slot 1's timer to $60, this monster's QSpeed to $18,
    ; and animation counter to 8.
    ;
    moveq   #96,D0
    move.b  D0,($0029,A4)
    moveq   #24,D0
    lea     ($03BC,A4),A0
    move.b  D0,(A0,D2.W)
    moveq   #8,D0
    lea     ($03D0,A4),A0
    move.b  D0,(A0,D2.W)
    ; Reset grid offset, tiles crossed, and movement frame.
    ;
    moveq   #0,D0
    lea     ($0394,A4),A0
    move.b  D0,(A0,D2.W)
    lea     ($041F,A4),A0
    move.b  D0,(A0,D2.W)
    lea     ($03E4,A4),A0
    move.b  D0,(A0,D2.W)
    ; Start Wallmaster state 1.
    ;
    lea     ($00AC,A4),A0
    addq.b  #1,(A0,D2.W)
    rts

    even
L_Wallmaster_State1:
    ; If the monster has been shoved, then shove it and go draw.
    ;
    lea     ($00C0,A4),A0
    move.b  (A0,D2.W),D0
    beq  _L_z04_L_Wallmaster_State1_CheckStunned
    jsr     Obj_Shove
    even
_L_z04_L_Wallmaster_State1_DrawAndCheckCollisions:
    jmp     _L_z04_L_Wallmaster_State1_Wallmaster_DrawAndCheckCollisions

    even
_L_z04_L_Wallmaster_State1_CheckStunned:
    ; If we have the magic clock or the monster is stunned, then
    ; go draw and check collisions.
    ;
    move.b  ($066C,A4),D0
    move.b  ($3D,A4,D2.W),D1
    or.b  D1,D0
    bne  _L_z04_L_Wallmaster_State1_DrawAndCheckCollisions
    lea     ($0098,A4),A0
    move.b  (A0,D2.W),D0
    move.b  D0,($000F,A4)
    jsr     MoveObject
    ; If grid offset <> $10 nor $F0 (so not square aligned), then
    ; go draw and check collisions.
    ;
    lea     ($0394,A4),A0
    move.b  (A0,D2.W),D0
    cmpi.b  #$10,D0
    beq  _anon_z04_66
    cmpi.b  #$F0,D0
    bne  _L_z04_L_Wallmaster_State1_Wallmaster_DrawAndCheckCollisions
_anon_z04_66:
    ; Truncate grid offset.
    ;
    moveq   #0,D0
    lea     ($0394,A4),A0
    move.b  D0,(A0,D2.W)
    ; Advance the step.
    ;
    lea     ($0412,A4),A0
    addq.b  #1,(A0,D2.W)
    ; Set facing direction to the one for this new step.
    ;
    moveq   #0,D3
    lea     ($0412,A4),A0
    move.b  (A0,D2.W),D3
    lea     (WallmasterDirsAndAttrsLeft).l,A0
    move.b  (A0,D3.W),D0
    andi.b #$0F,D0
    lea     ($0098,A4),A0
    move.b  D0,(A0,D2.W)
    ; Increase the count of tiles crossed.
    ;
    lea     ($041F,A4),A0
    addq.b  #1,(A0,D2.W)
    ; If the monster has crossed less than 7 tiles, then
    ; go draw and check collisions.
    ;
    lea     ($041F,A4),A0
    move.b  (A0,D2.W),D0
    cmpi.b  #$07,D0
    bcs  _L_z04_L_Wallmaster_State1_Wallmaster_DrawAndCheckCollisions
    ; It has reached the end of a trip.
    ;
    ; If Wallmaster did not capture Link, then go set state to 0 and return.
    ;
    lea     ($042C,A4),A0
    move.b  (A0,D2.W),D0
    beq  _L_z04_L_Wallmaster_State1_SetState
    ; At the end of a trip where Link was captured:
    ; 1. hide the special sprites used by Wallmaster
    ; 2. go to mode 3 "unfurl" to go the level's entrance
    ; 3. reset Link's state, so he's idle
    ;
    jsr     HideSpritesOverLink
    moveq   #3,D0
    move.b  D0,($0012,A4)
    moveq   #0,D0
    move.b  D0,($00AC,A4)
    move.b  D0,($0011,A4)
    move.b  D0,($0013,A4)
    even
_L_z04_L_Wallmaster_State1_SetState:
    lea     ($00AC,A4),A0
    move.b  D0,(A0,D2.W)
    rts

    even
_L_z04_L_Wallmaster_State1_Wallmaster_DrawAndCheckCollisions:
    ; If Link was captured, then go draw Link and Wallmaster specially.
    ;
    lea     ($042C,A4),A0
    move.b  (A0,D2.W),D0
    bne  _L_z04_L_Wallmaster_State1_DrawWithCapturedLink
    jsr     CheckMonsterCollisions
    ; If after checking object collisions, Link was captured, then
    ; halt Link and keep him from being shoved.
    ;
    lea     ($042C,A4),A0
    move.b  (A0,D2.W),D0
    beq  _anon_z04_67
    moveq   #64,D0
    move.b  D0,($00AC,A4)
    moveq   #0,D0
    move.b  D0,($00C0,A4)
_anon_z04_67:
    ; Remember the index of the first sprite that will be used to draw,
    ; because the drawing routine will cycle the sprites.
    ;
    move.b  ($0341,A4),D0
    move.b  D0,-(A5)  ; PHA
    jsr     Wallmaster_PrepareToDraw
    lea     ($03E4,A4),A0
    move.b  (A0,D2.W),D0
    jsr     DrawObjectNotMirrored
    move.b  (A5)+,D0  ; PLA
    ; Store the offset of the left sprite record in [00],
    ; and the right one in [01].
    ;
    moveq   #0,D3
    move.b  D0,D3
    lea     (SpriteOffsets).l,A0
    move.b  (A0,D3.W),D0
    move.b  D0,($0000,A4)
    lea     (SpriteOffsets+1).l,A0
    move.b  (A0,D3.W),D0
    even
_L_z04_L_Wallmaster_State1_PatchSprites:
    move.b  D0,($0001,A4)
    jsr     Wallmaster_PutSpritesBehindBgIfNeeded
    ; The default image is the hand open.
    ; If animation frame = 0, then return.
    ;
    moveq   #0,D2
    move.b  ($0340,A4),D2
    lea     ($03E4,A4),A0
    move.b  (A0,D2.W),D0
    beq  _L_z04_L_Wallmaster_State1_Exit
    ; Animation frame 1 uses Wallmaster frame image 1, which
    ; uses tiles $9C/$9D on the left and $9E/$9F on the right.
    ; The right side is correctly the right side of a closed hand.
    ; But the left side is Keese. So, we have to patch the left
    ; side to use the common left side of the hand -- $AC/$AD.
    ;
    ; Keep in mind that left and right sprites might be flipped.
    ;
    moveq   #0,D3
    move.b  ($0000,A4),D3
    lea     ($0201,A4),A0
    move.b  (A0,D3.W),D0
    cmpi.b  #$9C,D0
    beq  _anon_z04_68
    moveq   #0,D3
    move.b  ($0001,A4),D3
_anon_z04_68:
    move.b  #$AC,D0
    lea     ($0201,A4),A0
    move.b  D0,(A0,D3.W)
    even
_L_z04_L_Wallmaster_State1_Exit:
    rts

    even
_L_z04_L_Wallmaster_State1_DrawWithCapturedLink:
    ; Draw Wallmaster with captured Link.
    ;
    ; First, put Link right where the monster is.
    ;
    move.b  ($70,A4,D2.W),D0
    move.b  D0,($0070,A4)
    lea     ($0084,A4),A0
    move.b  (A0,D2.W),D0
    move.b  D0,($0084,A4)
    jsr     Link_EndMoveAndAnimate_Bank4
    jsr     ShowLinkSpritesBehindHorizontalDoors
    moveq   #0,D2
    move.b  ($0340,A4),D2
    jsr     Wallmaster_PrepareToDraw
    ; Force animation frame 1: hand closed.
    ;
    moveq   #1,D0
    lea     ($03E4,A4),A0
    move.b  D0,(A0,D2.W)
    jsr     DrawObjectNotMirroredOverLink
    ; Store the offsets of the sprites to show over Link
    ; ($10 and $11) in [00] and [01] for use in patching the right sprite.
    ;
    moveq   #64,D0
    move.b  D0,($0000,A4)
    moveq   #68,D0
    ; Go patch up the sprites.
    ;
    jmp     _L_z04_L_Wallmaster_State1_PatchSprites

    even
Wallmaster_PrepareToDraw:
    moveq   #8,D0
    jsr     Anim_AdvanceAnimCounterAndSetObjPosForSpriteDescriptor
    ; For the current step, look up the sprite flipping attributes.
    ;
    moveq   #0,D3
    lea     ($0412,A4),A0
    move.b  (A0,D2.W),D3
    lea     (WallmasterDirsAndAttrsLeft).l,A0
    move.b  (A0,D3.W),D0
    andi.b #$F0,D0
    ori.b #$01,D0
    jsr     Anim_SetSpriteDescriptorAttributes
    ; If the sprite attributes for this step have horizontal flipping ($40),
    ; then mask it off, and turn on horizontal flipping with [0F].
    ;
    andi.b #$40,D0
    beq  _anon_z04_69
    move.b  ($0004,A4),D0
    andi.b #$8F,D0
    jsr     Anim_SetSpriteDescriptorAttributes
    addq.b  #1,($000F,A4)
_anon_z04_69:
    rts

; Params:
; A: offset of first instruction for left wall (0)
;    or top wall ($20)
; Y: Link's minimum major coordinate
; [00]: Link's coordinate along minor axis
; [01]: Link's coordinate along major axis
; [02]: a decreasing direction along the wall (left or up)
;
; Returns:
; Y: index of initial major coordinate of Wallmaster
; [04]: initial minor coordinate of Wallmaster
;
; Store the initial offset for this axis.
;
    even
Wallmaster_CalcStartPosition:
    lea     ($0412,A4),A0
    move.b  D0,(A0,D2.W)
    move.b  D3,($0003,A4)
    ; If Link is still (input dir = 0), then use distance $24, else $32.
    ;
    moveq   #36,D0
    moveq   #0,D3
    move.b  ($03F8,A4),D3
    beq  _anon_z04_70
    moveq   #50,D0
_anon_z04_70:
    ; If Link is facing in the direction passed in (which decreases), then:
    ; 1. negate the distance
    ; 2. add 8 to the instruction offset to access
    ;    the opposite direction for the same wall
    ;
    moveq   #0,D3
    move.b  ($0098,A4),D3
    move.b  ($0002,A4),D1
    cmp.b   D1,D3
    bne  _anon_z04_71
    move.b  D0,-(A5)  ; PHA
    lea     ($0412,A4),A0
    move.b  (A0,D2.W),D0
    andi    #$EE,CCR  ; CLC: clear C+X
    move.b  #$08,D1
    addx.b  D1,D0   ; ADC #$08 (X flag = 6502 C)
    lea     ($0412,A4),A0
    move.b  D0,(A0,D2.W)
    move.b  (A5)+,D0  ; PLA
    eori.b #$FF,D0
    andi    #$EE,CCR  ; CLC: clear C+X
    move.b  #$01,D1
    addx.b  D1,D0   ; ADC #$01 (X flag = 6502 C)
_anon_z04_71:
    ; Add the distance and Link's minor coordinate to calculate
    ; Wallmaster's initial minor coordinate to store in [04].
    ; In general, the monster will be put in front of Link.
    ;
    andi    #$EE,CCR  ; CLC: clear C+X
    move.b  ($0000,A4),D1
    addx.b  D1,D0   ; ADC $00
    move.b  D0,($0004,A4)
    ; By default, will return index 0 to choose the minimum value
    ; for Wallmaster's initial major coordinate. This will be returned,
    ; if Link is at the wall with a smaller major coordinate.
    ;
    moveq   #0,D3
    ; If Link's major coordinate <> the minimum major coordinate, then
    ; he's on the farther wall. Add $10 to the instruction offset 
    ; to access the block for the other direction along the same axis,
    ; and increment the index for the Wallmaster's initial major coordinate.
    ;
    move.b  ($0001,A4),D0
    move.b  ($0003,A4),D1
    cmp.b   D1,D0
    beq  _anon_z04_72
    lea     ($0412,A4),A0
    move.b  (A0,D2.W),D0
    andi    #$EE,CCR  ; CLC: clear C+X
    move.b  #$10,D1
    addx.b  D1,D0   ; ADC #$10 (X flag = 6502 C)
    lea     ($0412,A4),A0
    move.b  D0,(A0,D2.W)
    addq.b  #1,D3
_anon_z04_72:
    rts

    even
Wallmaster_PutSpritesBehindBgIfNeeded:
    moveq   #0,D3
    move.b  ($0000,A4),D3
    jsr     Wallmaster_PutSpriteBehindBgIfNeeded
    moveq   #0,D3
    move.b  ($0001,A4),D3
    even
Wallmaster_PutSpriteBehindBgIfNeeded:
    ; Loop twice, from 1 to 0, in order to check the left and right
    ; extents of the sprite (X and X+8).
    ;
    moveq   #1,D2
    even
_L_z04_Wallmaster_PutSpriteBehindBgIfNeeded_LoopExtent:
    ; If sprite X + extent >= $E9 or < $18, then
    ; add priority attribute to show this sprite behind the background.
    ;
    lea     ($0203,A4),A0
    move.b  (A0,D3.W),D0
    andi    #$EE,CCR  ; CLC: clear C+X
    lea     (SpriteRelativeExtents).l,A0
    move.b  (A0,D2.W),D1
    addx.b  D1,D0   ; ADC SpriteRelativeExtents,X
    cmpi.b  #$E9,D0
    bcc  _L_z04_Wallmaster_PutSpriteBehindBgIfNeeded_AddPriorityBit
    cmpi.b  #$18,D0
    bcc  _anon_z04_73
    even
_L_z04_Wallmaster_PutSpriteBehindBgIfNeeded_AddPriorityBit:
    lea     ($0202,A4),A0
    move.b  (A0,D3.W),D0
    ori.b #$20,D0
    lea     ($0202,A4),A0
    move.b  D0,(A0,D3.W)
_anon_z04_73:
    subq.b  #1,D2
    bpl  _L_z04_Wallmaster_PutSpriteBehindBgIfNeeded_LoopExtent
    rts

    even
InitRope:
    ; Rope has $10 HP in quest 1, $40 HP in quest 2.
    ;
    moveq   #16,D0
    lea     ($0485,A4),A0
    move.b  D0,(A0,D2.W)
    moveq   #0,D3
    move.b  ($0016,A4),D3
    lea     ($062D,A4),A0
    move.b  (A0,D3.W),D0
    beq  _anon_z04_74
    moveq   #64,D0
    lea     ($0485,A4),A0
    move.b  D0,(A0,D2.W)
_anon_z04_74:
    jmp     InitWalker

    even
UpdateRope:
    ; Set the input direction to the facing direction.
    ;
    lea     ($0098,A4),A0
    move.b  (A0,D2.W),D0
    lea     ($03F8,A4),A0
    move.b  D0,(A0,D2.W)
    move.b  D0,-(A5)  ; PHA
    ; If we have the clock, or the monster is stunned, then don't move.
    ;
    move.b  ($066C,A4),D0
    move.b  ($3D,A4,D2.W),D1
    or.b  D1,D0
    bne  _L_z04_UpdateRope_CheckSpeed
    jsr     Walker_Move
    ; Truncate the grid offset at $10.
    ;
    lea     ($0394,A4),A0
    move.b  (A0,D2.W),D0
    andi.b #$0F,D0
    bne  _anon_z04_75
    lea     ($0394,A4),A0
    move.b  D0,(A0,D2.W)
_anon_z04_75:
    ; If not rushing (qspeed <> $60) and timer = 0, then
    ; set timer to a random value up to $3F, and turn to face
    ; an unblocked direction.
    ;
    lea     ($03BC,A4),A0
    move.b  (A0,D2.W),D0
    cmpi.b  #$60,D0
    beq  _L_z04_UpdateRope_CheckSpeed
    move.b  ($28,A4,D2.W),D0
    bne  _L_z04_UpdateRope_CheckSpeed
    move.b  ($18,A4,D2.W),D0
    andi.b #$3F,D0
    move.b  D0,($28,A4,D2.W)
    jsr     _FaceUnblockedDir
    even
_L_z04_UpdateRope_CheckSpeed:
    move.b  (A5)+,D0  ; PLA
    ; If the facing direction has changed, then set qspeed to $20 (slow).
    ;
    lea     ($0098,A4),A0
    move.b  (A0,D2.W),D1
    cmp.b   D1,D0
    beq  _anon_z04_76
    moveq   #32,D0
    lea     ($03BC,A4),A0
    move.b  D0,(A0,D2.W)
_anon_z04_76:
    ; If qspeed <> $20 or grid offset <> 0, then go draw.
    ;
    lea     ($03BC,A4),A0
    move.b  (A0,D2.W),D0
    cmpi.b  #$20,D0
    bne  _L_z04_UpdateRope_Animate
    lea     ($0394,A4),A0
    move.b  (A0,D2.W),D0
    bne  _L_z04_UpdateRope_Animate
    ; If the absolute horizontal distance between Link and the monster >= 8,
    ; then go see if the vertical distance is smaller.
    ;
    move.b  ($0070,A4),D0
    ori     #$11,CCR  ; SEC: set C+X
    move.b  ($70,A4,D2.W),D1
    eori    #$10,CCR  ; flip X: 6502 SBC polarity
    subx.b  D1,D0   ; SBC ObjX,X
    eori    #$10,CCR  ; restore X = 6502 C
    jsr     Abs
    cmpi.b  #$08,D0
    bcc  _L_z04_UpdateRope_CheckVertical
    ; Face up.
    ;
    moveq   #8,D0
    lea     ($0098,A4),A0
    move.b  D0,(A0,D2.W)
    ; But, if Link is down from the monster, then face down.
    ;
    move.b  ($0084,A4),D0
    lea     ($0084,A4),A0
    move.b  (A0,D2.W),D1
    cmp.b   D1,D0
    bcs  _L_z04_UpdateRope_Rush
    even
_L_z04_UpdateRope_FlipDir:
    lea     ($0098,A4),A0
    move.b  (A0,D2.W),D1
    lsr.b  #1,D1   ; LSR ObjDir,X
    move.b  D1,(A0,D2.W)
    even
_L_z04_UpdateRope_Rush:
    ; Make the rope rush (qspeed $60).
    ;
    moveq   #96,D0
    lea     ($03BC,A4),A0
    move.b  D0,(A0,D2.W)
    even
_L_z04_UpdateRope_Animate:
    moveq   #10,D0
    jsr     Anim_AdvanceAnimCounterAndSetObjPosForSpriteDescriptor
    ; If facing left, then flip horizontally.
    ;
    lea     ($0098,A4),A0
    move.b  (A0,D2.W),D0
    andi.b #$02,D0
    lsr.b  #1,D0   ; LSR A
    move.b  D0,($000F,A4)
    moveq   #2,D0
    jsr     Anim_SetSpriteDescriptorAttributes
    ; In the second quest, ropes always flash.
    ; So, set sprite attributes to all the cycled palette rows.
    ;
    moveq   #0,D3
    move.b  ($0016,A4),D3
    lea     ($062D,A4),A0
    move.b  (A0,D3.W),D0
    beq  _L_z04_UpdateRope_Draw
    move.b  ($0015,A4),D0
    andi.b #$03,D0
    jsr     Anim_SetSpriteDescriptorAttributes
    even
_L_z04_UpdateRope_Draw:
    ; The frame image is based on the movement frame.
    ;
    lea     ($03E4,A4),A0
    move.b  (A0,D2.W),D0
    jsr     DrawObjectNotMirrored
    jmp     CheckMonsterCollisions

    even
_L_z04_UpdateRope_CheckVertical:
    ; If the absolute vertical distance between Link and the monster >= 8,
    ; then go draw.
    ;
    move.b  ($0084,A4),D0
    ori     #$11,CCR  ; SEC: set C+X
    lea     ($0084,A4),A0
    move.b  (A0,D2.W),D1
    eori    #$10,CCR  ; flip X: 6502 SBC polarity
    subx.b  D1,D0   ; SBC ObjY,X
    eori    #$10,CCR  ; restore X = 6502 C
    jsr     Abs
    cmpi.b  #$08,D0
    bcc  _L_z04_UpdateRope_Animate
    ; Face left.
    ;
    moveq   #2,D0
    lea     ($0098,A4),A0
    move.b  D0,(A0,D2.W)
    ; But, if Link is right of the monster, then face right.
    ; Either way, go increase speed and draw.
    ;
    move.b  ($0070,A4),D0
    move.b  ($70,A4,D2.W),D1
    cmp.b   D1,D0
    bcc  _L_z04_UpdateRope_FlipDir
    bcc  _L_z04_UpdateRope_Rush
    even
UpdateStalfos:
    move.b  #$80,D0
    jsr     UpdateCommonWanderer
    jsr     CheckMonsterCollisions
    moveq   #8,D0
    jsr     AnimateAndDrawCommonObject
    moveq   #32,D0
    move.b  D0,($0001,A4)
    ; If in the first quest, return. Stalfos can't shoot in this quest.
    ;
    moveq   #0,D3
    move.b  ($0016,A4),D3
    lea     ($062D,A4),A0
    move.b  (A0,D3.W),D0
    beq  _L_z04_UpdateStalfos_Exit
    ; Second quest.
    ;
    ; If shoot timer = 0 and Random < $F8, then return.
    ;
    lea     ($0451,A4),A0
    move.b  (A0,D2.W),D0
    bne  _L_z04_UpdateStalfos_PrepareToShoot
    move.b  ($18,A4,D2.W),D0
    cmpi.b  #$F8,D0
    bcs  _L_z04_UpdateStalfos_Exit
    even
_L_z04_UpdateStalfos_PrepareToShoot:
    move.b  ($0001,A4),D0
    move.b  D0,-(A5)  ; PHA
    ; If temporarily invincible, then go reset shoot timer.
    ;
    moveq   #0,D3
    lea     ($04F0,A4),A0
    move.b  (A0,D2.W),D0
    bne  _L_z04_UpdateStalfos_SetShootTimer
    ; If shoot timer >= 1, then decrement and go set shoot timer.
    ;
    moveq   #0,D3
    lea     ($0451,A4),A0
    move.b  (A0,D2.W),D3
    subq.b  #1,D3
    bpl  _L_z04_UpdateStalfos_SetShootTimer
    ; If stalfos does not want to shoot, then go set the qspeed.
    ;
    lea     ($0412,A4),A0
    move.b  (A0,D2.W),D0
    beq  _L_z04_UpdateStalfos_SetSpeed
    ; Else not temporarily invincible, and shoot timer = 0,
    ; and wants to shoot.
    ;
    ; Set shoot timer to $30.
    ;
    moveq   #48,D3
    even
_L_z04_UpdateStalfos_SetShootTimer:
    move.b  D3,D0
    lea     ($0451,A4),A0
    move.b  D0,(A0,D2.W)
    ; If shoot timer = 0, then we're not shooting.
    ; Go set the qspeed.
    ;
    beq  _L_z04_UpdateStalfos_SetSpeed
    ; If shoot timer <> $10, or we have the magic clock, or stunned;
    ; then go reset qspeed.
    ;
    cmpi.b  #$10,D3
    bne  _L_z04_UpdateStalfos_ZeroSpeed
    move.b  ($066C,A4),D0
    move.b  ($3D,A4,D2.W),D1
    or.b  D1,D0
    bne  _L_z04_UpdateStalfos_ZeroSpeed
    ; Try to shoot a sword shot.
    ;
    moveq   #87,D0
    move.b  D0,($0000,A4)
    jsr     _ShootIfWanted
    ; If failed, then go set the qspeed.
    ;
    bcc  _L_z04_UpdateStalfos_CheckResult
    ; TODO:
    ; Else set timer to $80, and decrement [0437][X].
    ;
    move.b  #$80,D0
    move.b  D0,($28,A4,D2.W)
    lea     ($0437,A4),A0
    subq.b  #1,(A0,D2.W)
    even
_L_z04_UpdateStalfos_CheckResult:
    ; We jump here if shooting failed. Jump again to set the qspeed.
    ;
    bcc  _L_z04_UpdateStalfos_SetSpeed
    ; Shooting succeeded.
    ; Reset "wants to shoot" flag and the speed.
    ;
    moveq   #0,D0
    lea     ($0412,A4),A0
    move.b  D0,(A0,D2.W)
    even
_L_z04_UpdateStalfos_ZeroSpeed:
    move.b  (A5)+,D0  ; PLA
