InitMoldorm:
    ; Loop to make 10 moldrom segments, from 9 to 0, indexed by Y register.
    ; Object slots $A to 1 will be used.
    ;
    moveq   #9,D3
_anon_z04_77:
    ; Start at position ($80, $70).
    ;
    move.b  #$80,D0
    move.b  D0,($71,A4,D3.W)
    moveq   #112,D0
    lea     ($0085,A4),A0
    move.b  D0,(A0,D3.W)
    ; Start with no direction, no deferred bounce direction,
    ; and ready to update.
    ;
    moveq   #0,D0
    lea     ($0099,A4),A0
    move.b  D0,(A0,D3.W)
    lea     ($03BD,A4),A0
    move.b  D0,(A0,D3.W)
    lea     ($0406,A4),A0
    move.b  D0,(A0,D3.W)
    lea     ($0493,A4),A0
    move.b  D0,(A0,D3.W)
    ; Copy object attributes from the first monster slot.
    ;
    move.b  ($04C0,A4),D0
    lea     ($04C0,A4),A0
    move.b  D0,(A0,D3.W)
    ; Copy HP from the first monster slot.
    ;
    move.b  ($0486,A4),D0
    lea     ($0486,A4),A0
    move.b  D0,(A0,D3.W)
    ; Start with flying speed $80, and in flying state 2.
    ;
    move.b  #$80,D0
    lea     ($0420,A4),A0
    move.b  D0,(A0,D3.W)
    moveq   #2,D0
    lea     ($0445,A4),A0
    move.b  D0,(A0,D3.W)
    moveq   #65,D0
    lea     ($0350,A4),A0
    move.b  D0,(A0,D3.W)
    ; Bottom of the loop.
    ;
    subq.b  #1,D3
    bpl  _anon_z04_77
    ; Choose a random 8-way direction for the head segments
    ; in slots 4 and 9.
    ;
    move.b  ($001D,A4),D0
    andi.b #$07,D0
    moveq   #0,D3
    move.b  D0,D3
    lea     (Directions8).l,A0
    move.b  (A0,D3.W),D0
    move.b  D0,($009D,A4)
    move.b  D0,($0385,A4)
    move.b  ($0022,A4),D0
    andi.b #$07,D0
    moveq   #0,D3
    move.b  D0,D3
    lea     (Directions8).l,A0
    move.b  (A0,D3.W),D0
    move.b  D0,($00A2,A4)
    move.b  D0,($038A,A4)
    ; Set minimum number of turns 1 for flying states.
    ;
    ; By setting this, the first time that a flight control routine
    ; (Flyer_Chase, Flyer_Wander) is called and returns;
    ; that flying state will immediately end, and object timer
    ; will be left 0: ready for moldorm to decide a flying state
    ; randomly and set timer to $10.
    ;
    moveq   #1,D0
    move.b  D0,($0431,A4)
    move.b  D0,($0436,A4)
    move.b  #$80,D0
    move.b  D0,($04D1,A4)
    moveq   #8,D0
    move.b  D0,($034E,A4)
    rts

    even
