InitDodongo:
    moveq   #32,D0
    move.b  D0,($0601,A4)
    ; Randomly face left or right.
    ;
    moveq   #1,D3
    move.b  ($18,A4,D2.W),D0
    cmpi.b  #$80,D0
    bcs  _anon_z04_78
