DigdoggerCornerOffsetsX:
    dc.b    $00, $10, $00, $F0

    even
DigdoggerCornerOffsetsY:
    dc.b    $00, $10, $F0, $10

; Params:
; Y: flute state
;
; If flute state = 2, go switch between big and little appearance.
;
    even
L_Digdogger_AfterFlute:
    subq.b  #1,D3
    bne  _L_z04_L_Digdogger_AfterFlute_SplitUp
    ; Flute state = 1.
    ;
    ; If this is a child digdogger, then go turn and move as usual.
    ;
    lea     ($046B,A4),A0
    move.b  (A0,D2.W),D0
    beq.s  __far_z_04_0050
    jmp  L_Digdogger_Turn
__far_z_04_0050:
    ; Set object timer to $40, and increase flute state to 2.
    ; Then go check collisions as a big digdogger.
    ;
    moveq   #64,D0
    move.b  D0,($28,A4,D2.W)
    addq.b  #1,($051B,A4)
    jmp     CheckBigDigdoggerCollisions

    even
_L_z04_L_Digdogger_AfterFlute_SplitUp:
    ; If the timer = 0, then skip the block below, and go split up.
    ;
    move.b  ($28,A4,D2.W),D0
    beq  _L_z04_L_Digdogger_AfterFlute_MakeChildren
    ; Every 8 frames, switch between behaving as a big and little digdogger.
    ;
    ; TODO:
    ; But is this possible, given the following?
    ; a. all object timers run concurrently
    ; b. all object updates are paused until the flute timer expires
    ; c. the flute timer lasts longer
    ;
    andi.b #$07,D0
    bne  _anon_z04_84
    lea     ($046B,A4),A0
    move.b  (A0,D2.W),D0
    eori.b #$01,D0
    lea     ($046B,A4),A0
    move.b  D0,(A0,D2.W)
    bne.s  __far_z_04_0051
    jmp  CheckBigDigdoggerCollisions
__far_z_04_0051:
_anon_z04_84:
    jmp     L_Digdogger_DrawAsLittle

    even
_L_z04_L_Digdogger_AfterFlute_MakeChildren:
    ; Decrement flute state to 1.
    ;
    subq.b  #1,($051B,A4)
    ; Loop to make a number of child digdoggers.
    ;
    move.b  ($0507,A4),D0
    move.b  D0,($0000,A4)
    move.b  D0,($034E,A4)
    move.b  D2,D0
    move.b  D0,-(A5)  ; PHA
    even
_L_z04_L_Digdogger_AfterFlute_LoopMakeChild:
    ; Initialize a child digdogger (type $18) in the next object slot.
    ;
    addq.b  #1,D2
    jsr     InitDigdogger1
    moveq   #24,D0
    lea     ($034F,A4),A0
    move.b  D0,(A0,D2.W)
    ; Start with a target speed of $0100.
    ; The low byte is still 0 from when room data was reset.
    ;
    lea     ($0444,A4),A0
    addq.b  #1,(A0,D2.W)
    ; Flag this a child digdogger.
    ;
    moveq   #1,D0
    lea     ($046B,A4),A0
    move.b  D0,(A0,D2.W)
    ; The speed will increase.
    ;
    moveq   #0,D0
    lea     ($045E,A4),A0
    move.b  D0,(A0,D2.W)
    ; Copy the parent's coordinates to the child.
    ;
    move.b  ($0071,A4),D0
    move.b  D0,($70,A4,D2.W)
    move.b  ($0085,A4),D0
    lea     ($0084,A4),A0
    move.b  D0,(A0,D2.W)
    ; Bottom of the loop.
    ; Decrement [00] until 0.
    ;
    subq.b  #1,($0000,A4)
    bne  _L_z04_L_Digdogger_AfterFlute_LoopMakeChild
    move.b  (A5)+,D0  ; PLA
    moveq   #0,D2
    move.b  D0,D2
    jsr     PlayBossDeathCry
    ; Destroy the big digdogger by resetting the object type.
    ;
    moveq   #0,D0
    lea     ($034F,A4),A0
    move.b  D0,(A0,D2.W)
    ; Don't let the digdogger disappear until the next frame when
    ; the children can draw themselves. Go draw the big digdogger
    ; as a little one.
    ;
    ; This will work, even though the object type was reset. No
    ; other object data has not been touched. Also, the code block
    ; we'll jump to temporarily sets the object type.
    ;
    jmp     L_Digdogger_DrawAsLittle

    even
L_Digdogger_TurnTowardLink:
    jsr     TurnTowardsPlayer8
    jmp     L_Digdogger_Move

    even
UpdateDigdogger:
    ; If we have the magic clock, or the monster is stunned,
    ; then go check room boundaries and object collisions, and draw.
    ;
    move.b  ($066C,A4),D0
    move.b  ($3D,A4,D2.W),D1
    or.b  D1,D0
    beq.s  __far_z_04_0052
    jmp  L_Digdogger_DrawAndCheckCollisions
__far_z_04_0052:
    ; If the flute was used, then go start splitting up,
    ; or handling a child digdogger.
    ;
    moveq   #0,D3
    move.b  ($051B,A4),D3
    beq.s  __far_z_04_0053
    jmp  L_Digdogger_AfterFlute
__far_z_04_0053:
    even
L_Digdogger_Turn:
    jsr     Digdogger_ChangeSpeed
    ; If the object timer has expired, then set it to $10,
    ; and randomly choose to turn toward Link or randomly.
    ;
    move.b  ($28,A4,D2.W),D0
    beq.s  __far_z_04_0054
    jmp  L_Digdogger_Move
__far_z_04_0054:
    moveq   #16,D0
    move.b  D0,($28,A4,D2.W)
    move.b  ($18,A4,D2.W),D0
    cmpi.b  #$80,D0
    bcs.s  __far_z_04_0055
    jmp  L_Digdogger_TurnTowardLink
__far_z_04_0055:
    jsr     TurnRandomlyDir8
    even
L_Digdogger_Move:
    jsr     Digdogger_Move
    even
L_Digdogger_DrawAndCheckCollisions:
    ; If this is a child, then finish updating this little digdogger.
    ;
    lea     ($046B,A4),A0
    move.b  (A0,D2.W),D0
    bne.s  __far_z_04_0056
    jmp  CheckBigDigdoggerCollisions
__far_z_04_0056:
    jsr     BoundFlyer
    jsr     CheckMonsterCollisions
    jmp     Digdogger_Draw

    even
CheckBigDigdoggerCollisions:
    ; Save the original coordinates.
    ;
    move.b  ($70,A4,D2.W),D0
    move.b  D0,-(A5)  ; PHA
    lea     ($0084,A4),A0
    move.b  (A0,D2.W),D0
    move.b  D0,-(A5)  ; PHA
    ; Reset the index of the current part.
    ;
    moveq   #0,D0
    lea     ($0478,A4),A0
    move.b  D0,(A0,D2.W)
    even
_L_z04_CheckBigDigdoggerCollisions_LoopCornerCollision:
    ; Digdogger is big, but room boundary checks and
    ; object collision checks assume a 16x16 monster or smaller.
    ; Therefore, we have to check these things four times,
    ; in different corners of the boss.
    ;
    ; Loop 4 times, from 0 to 3.
    ;
    moveq   #0,D3
    lea     ($0478,A4),A0
    move.b  (A0,D2.W),D3
    ; Change the coordinates to one corner.
    ;
    move.b  ($70,A4,D2.W),D0
    andi    #$EE,CCR  ; CLC: clear C+X
    lea     (DigdoggerCornerOffsetsX).l,A0
    move.b  (A0,D3.W),D1
    addx.b  D1,D0   ; ADC DigdoggerCornerOffsetsX,Y
    move.b  D0,($70,A4,D2.W)
    lea     ($0084,A4),A0
    move.b  (A0,D2.W),D0
    andi    #$EE,CCR  ; CLC: clear C+X
    lea     (DigdoggerCornerOffsetsY).l,A0
    move.b  (A0,D3.W),D1
    addx.b  D1,D0   ; ADC DigdoggerCornerOffsetsY,Y
    lea     ($0084,A4),A0
    move.b  D0,(A0,D2.W)
    ; Check the room boundary and object collisions in this temporary location.
    ;
    jsr     BoundFlyer
    jsr     CheckMonsterCollisions
    ; Increase the loop index, and loop again until it = 4.
    ;
    lea     ($0478,A4),A0
    addq.b  #1,(A0,D2.W)
    lea     ($0478,A4),A0
    move.b  (A0,D2.W),D0
    cmpi.b  #$04,D0
    bcs  _L_z04_CheckBigDigdoggerCollisions_LoopCornerCollision
    ; Restore the original coordinates.
    ;
    move.b  (A5)+,D0  ; PLA
    lea     ($0084,A4),A0
    move.b  D0,(A0,D2.W)
    move.b  (A5)+,D0  ; PLA
    move.b  D0,($70,A4,D2.W)
    jsr     Digdogger_Draw
    even
L_Digdogger_DrawAsLittle:
    ; Save the original coordinates.
    ;
    move.b  ($70,A4,D2.W),D0
    move.b  D0,-(A5)  ; PHA
    lea     ($0084,A4),A0
    move.b  (A0,D2.W),D0
    move.b  D0,-(A5)  ; PHA
    ; Add 8 to Y and X.
    ;
    andi    #$EE,CCR  ; CLC: clear C+X
    move.b  #$08,D1
    addx.b  D1,D0   ; ADC #$08 (X flag = 6502 C)
    lea     ($0084,A4),A0
    move.b  D0,(A0,D2.W)
    move.b  ($70,A4,D2.W),D0
    andi    #$EE,CCR  ; CLC: clear C+X
    move.b  #$08,D1
    addx.b  D1,D0   ; ADC #$08 (X flag = 6502 C)
    move.b  D0,($70,A4,D2.W)
    ; Save the child flag and object type.
    ;
    lea     ($046B,A4),A0
    move.b  (A0,D2.W),D0
    move.b  D0,-(A5)  ; PHA
    lea     ($034F,A4),A0
    move.b  (A0,D2.W),D0
    move.b  D0,-(A5)  ; PHA
    ; Change object type to $18 (Little Digdogger),
    ; and child flag to 1, in order to draw as a little digdogger.
    ;
    moveq   #24,D0
    lea     ($034F,A4),A0
    move.b  D0,(A0,D2.W)
    moveq   #1,D0
    lea     ($046B,A4),A0
    move.b  D0,(A0,D2.W)
    jsr     Digdogger_Draw
    ; Restore the child flag and object type.
    ;
    move.b  (A5)+,D0  ; PLA
    lea     ($034F,A4),A0
    move.b  D0,(A0,D2.W)
    move.b  (A5)+,D0  ; PLA
    lea     ($046B,A4),A0
    move.b  D0,(A0,D2.W)
    ; Restore the original coordinates.
    ;
    move.b  (A5)+,D0  ; PLA
    lea     ($0084,A4),A0
    move.b  D0,(A0,D2.W)
    move.b  (A5)+,D0  ; PLA
    move.b  D0,($70,A4,D2.W)
    rts

    even
Digdogger_ChangeSpeed:
    lea     ($045E,A4),A0
    move.b  (A0,D2.W),D0
    jsr     _m68k_tablejump  ; M68K-native table dispatch (replaces JSR TableJump)
    even
Digdogger_ChangeSpeed_JumpTable:
    dc.l    Digdogger_SpeedUp   ; jump table entry (32-bit for _m68k_tablejump)
    dc.l    Digdogger_SlowDown   ; jump table entry (32-bit for _m68k_tablejump)

    even
Digdogger_SpeedUp:
    ; Add 1 to 16-bit speed.
    ;
    lea     ($041F,A4),A0
    addq.b  #1,(A0,D2.W)
    bne  _anon_z04_85
    lea     ($042C,A4),A0
    addq.b  #1,(A0,D2.W)
_anon_z04_85:
    ; If the 16-bit speed has not reached the 16-bit target speed, then return.
    ;
    lea     ($041F,A4),A0
    move.b  (A0,D2.W),D0
    lea     ($0437,A4),A0
    move.b  (A0,D2.W),D1
    cmp.b   D1,D0
    beq.s  __far_z_04_0057
    jmp  L116EA_Exit
__far_z_04_0057:
    lea     ($042C,A4),A0
    move.b  (A0,D2.W),D0
    lea     ($0444,A4),A0
    move.b  (A0,D2.W),D1
    cmp.b   D1,D0
    beq.s  __far_z_04_0058
    jmp  L116EA_Exit
__far_z_04_0058:
    ; Set speed flag to 1 meaning decelerate.
    ;
    lea     ($045E,A4),A0
    addq.b  #1,(A0,D2.W)
    ; Go set target speed to $0040 (or $0140 if this is a child).
    ;
    moveq   #64,D0
    jmp     SetTargetSpeed

    even
Digdogger_SlowDown:
    ; Subtract 1 from 16-bit speed.
    ;
    lea     ($041F,A4),A0
    subq.b  #1,(A0,D2.W)
    lea     ($041F,A4),A0
    move.b  (A0,D2.W),D0
    cmpi.b  #$FF,D0
    bne  _anon_z04_86
; Unknown block
    dc.b    $DE, $2C, $04

_anon_z04_86:
    ; If the 16-bit speed has not reached the 16-bit target speed, then return.
    ;
    lea     ($041F,A4),A0
    move.b  (A0,D2.W),D0
    lea     ($0437,A4),A0
    move.b  (A0,D2.W),D1
    cmp.b   D1,D0
    beq.s  __far_z_04_0059
    jmp  L116EA_Exit
__far_z_04_0059:
    lea     ($042C,A4),A0
    move.b  (A0,D2.W),D0
    lea     ($0444,A4),A0
    move.b  (A0,D2.W),D1
    cmp.b   D1,D0
    beq.s  __far_z_04_0060
    jmp  L116EA_Exit
__far_z_04_0060:
    ; Set speed flag to 0 meaning accelerate.
    ;
    lea     ($045E,A4),A0
    subq.b  #1,(A0,D2.W)
    ; Set target speed to $0080.
    ;
    move.b  #$80,D0
    even
SetTargetSpeed:
    lea     ($0437,A4),A0
    move.b  D0,(A0,D2.W)
    moveq   #0,D0
    lea     ($0444,A4),A0
    move.b  D0,(A0,D2.W)
    ; But if this is a child, then make the target speed $0180.
    ;
    lea     ($046B,A4),A0
    move.b  (A0,D2.W),D0
    bne.s  __far_z_04_0061
    jmp  L116EA_Exit
__far_z_04_0061:
    lea     ($0444,A4),A0
    addq.b  #1,(A0,D2.W)
    even
L116EA_Exit:
    rts

    even
Digdogger_Move:
    ; This calculation is the same one used in Manhandla to
    ; manifest the fractional speed over several frames.
    ;
    ; To summarize, the formula is:
    ;
    ;   (SA=speed accumulator, SH=speed high, SL=speed low)
    ;
    ;   SA := SA + (SL AND $E0)
    ;   [03] := SH + carry
    ;
    ; See 04:A28E Manhandla_Move.
    ;
    lea     ($041F,A4),A0
    move.b  (A0,D2.W),D0
    andi.b #$E0,D0
    andi    #$EE,CCR  ; CLC: clear C+X
    lea     ($0412,A4),A0
    move.b  (A0,D2.W),D1
    addx.b  D1,D0   ; ADC $0412,X
    lea     ($0412,A4),A0
    move.b  D0,(A0,D2.W)
    ; Assign (high speed byte + carry) to [03].
    ;
    lea     ($042C,A4),A0
    move.b  (A0,D2.W),D0
    move.b  #$00,D1
    addx.b  D1,D0   ; ADC #$00 (X flag = 6502 C)
    move.b  D0,($0003,A4)
    ; Change coordinates by the speed amount/offset in [03]
    ; according to the direction.
    ;
    ; Start with a mask of $A1 in [02]:
    ; - low nibble represents the right direction
    ; - high nibble is used to set or clear carry as we go along
    ;
    move.b  #$A1,D0
    move.b  D0,($0002,A4)
    ; If direction has a right component (1), then add offset to X coordinate.
    ;
    lea     ($0098,A4),A0
    move.b  (A0,D2.W),D0
    move.b  ($0002,A4),D1
    and.b   D0,D1   ; BIT: set Z/N/V from D1 AND A
    beq  _L_z04_Digdogger_Move_Left
    move.b  ($70,A4,D2.W),D0
    andi    #$EE,CCR  ; CLC: clear C+X
    move.b  ($0003,A4),D1
    addx.b  D1,D0   ; ADC $03
    move.b  D0,($70,A4,D2.W)
    even
_L_z04_Digdogger_Move_Left:
    ; If direction has a left component (2), then subtract offset from X coordinate.
    ;
    lea     ($0098,A4),A0
    move.b  (A0,D2.W),D0
    move.b  ($0002,A4),D1
    lsl.b  #1,D1   ; ASL $02
    move.b  D1,($0002,A4)
    move.b  ($0002,A4),D1
    and.b   D0,D1   ; BIT: set Z/N/V from D1 AND A
    beq  _L_z04_Digdogger_Move_Down
    move.b  ($70,A4,D2.W),D0
    move.b  ($0003,A4),D1
    eori    #$10,CCR  ; flip X: 6502 SBC polarity
    subx.b  D1,D0   ; SBC $03
    eori    #$10,CCR  ; restore X = 6502 C
    move.b  D0,($70,A4,D2.W)
    even
_L_z04_Digdogger_Move_Down:
    ; If direction has a down component (4), then add offset to Y coordinate.
    ;
    lea     ($0098,A4),A0
    move.b  (A0,D2.W),D0
    move.b  ($0002,A4),D1
    lsl.b  #1,D1   ; ASL $02
    move.b  D1,($0002,A4)
    move.b  ($0002,A4),D1
    and.b   D0,D1   ; BIT: set Z/N/V from D1 AND A
    beq  _L_z04_Digdogger_Move_Up
    lea     ($0084,A4),A0
    move.b  (A0,D2.W),D0
    move.b  ($0003,A4),D1
    addx.b  D1,D0   ; ADC $03
    lea     ($0084,A4),A0
    move.b  D0,(A0,D2.W)
    even
_L_z04_Digdogger_Move_Up:
    ; If direction has an up component (8), then subtract offset from Y coordinate.
    ;
    lea     ($0098,A4),A0
    move.b  (A0,D2.W),D0
    move.b  ($0002,A4),D1
    lsl.b  #1,D1   ; ASL $02
    move.b  D1,($0002,A4)
    move.b  ($0002,A4),D1
    and.b   D0,D1   ; BIT: set Z/N/V from D1 AND A
    beq  _L_z04_Digdogger_Move_End
    lea     ($0084,A4),A0
    move.b  (A0,D2.W),D0
    move.b  ($0003,A4),D1
    eori    #$10,CCR  ; flip X: 6502 SBC polarity
    subx.b  D1,D0   ; SBC $03
    eori    #$10,CCR  ; restore X = 6502 C
    lea     ($0084,A4),A0
    move.b  D0,(A0,D2.W)
    even
_L_z04_Digdogger_Move_End:
    jmp     Anim_FetchObjPosForSpriteDescriptor

    even
DigdoggerSpriteOffsetsX:
    dc.b    $00, $10, $00, $10

    even
DigdoggerSpriteOffsetsY:
    dc.b    $00, $00, $10, $10

    even
DigdoggerSpriteAttrs:
    dc.b    $03, $03, $83, $83

    even
Digdogger_Draw:
    moveq   #6,D0
    jsr     Anim_AdvanceAnimCounterAndSetObjPosForSpriteDescriptor
    ; If this is a child digdogger, then go draw it.
    ;
    lea     ($046B,A4),A0
    move.b  (A0,D2.W),D0
    bne  _L_z04_Digdogger_Draw_DrawLittle
    ; For each part of the big digdogger, from 0 to 3,
    ; indexed by Y register:
    ;
    moveq   #0,D3
    even
_L_z04_Digdogger_Draw_LoopPart:
    ; Store in [00] the X coordinate offset for the current corner.
    ;
    move.b  ($70,A4,D2.W),D0
    andi    #$EE,CCR  ; CLC: clear C+X
    lea     (DigdoggerSpriteOffsetsX).l,A0
    move.b  (A0,D3.W),D1
    addx.b  D1,D0   ; ADC DigdoggerSpriteOffsetsX,Y
    move.b  D0,($0000,A4)
    ; Store in [01] the Y coordinate offset for the current corner.
    ;
    lea     ($0084,A4),A0
    move.b  (A0,D2.W),D0
    andi    #$EE,CCR  ; CLC: clear C+X
    lea     (DigdoggerSpriteOffsetsY).l,A0
    move.b  (A0,D3.W),D1
    addx.b  D1,D0   ; ADC DigdoggerSpriteOffsetsY,Y
    move.b  D0,($0001,A4)
    ; Load and set the sprite attributes for this part.
    ; Vertical flipping is set appropriately here.
    ;
    lea     (DigdoggerSpriteAttrs).l,A0
    move.b  (A0,D3.W),D0
    jsr     Anim_SetSpriteDescriptorAttributes
    move.b  D3,D0
    move.b  D0,-(A5)  ; PHA
    ; Parts at odd indexes are flipped horizontally.
    ;
    andi.b #$01,D0
    move.b  D0,($000F,A4)
    moveq   #0,D0
    jsr     DrawObjectNotMirrored
    move.b  (A5)+,D0  ; PLA
    moveq   #0,D3
    move.b  D0,D3
    ; Bottom of the loop.
    ; Increment Y register until = 4.
    ;
    addq.b  #1,D3
    cmpi.b  #$04,D3
    bne  _L_z04_Digdogger_Draw_LoopPart
    rts

    even
_L_z04_Digdogger_Draw_DrawLittle:
    ; A little digdogger is easy to draw.
    ;
    jsr     Anim_SetSpriteDescriptorLevelPaletteRow
    lea     ($03E4,A4),A0
    move.b  (A0,D2.W),D0
    jmp     DrawObjectMirrored

    even
UpdateAquamentus:
    move.b  ($066C,A4),D0
    bne  _anon_z04_87
    jsr     Aquamentus_Move
    jsr     Aquamentus_Shoot
_anon_z04_87:
    jsr     Aquamentus_Draw
    jsr     CheckMonsterCollisions
    jsr     PlayBossHitCryIfNeeded
    even
CheckBossHitReaction:
    jsr     PlayBossDeathCryIfNeeded
    jmp     ResetShoveInfo

    even
AquamentusSpeeds:
    dc.b    $01, $FF

    even
Aquamentus_Move:
    ; The monster uses grid offset to mean distance remaining.
    ; If there's more distance to cover, then go move.
    ;
    lea     ($0394,A4),A0
    move.b  (A0,D2.W),D0
    bne  _L_z04_Aquamentus_Move_Move
    ; Set a random distance to move of 7 or $F pixels.
    ;
    move.b  ($18,A4,D2.W),D0
    move.b  D0,-(A5)  ; PHA
    andi.b #$0F,D0
    ori.b #$07,D0
    lea     ($0394,A4),A0
    move.b  D0,(A0,D2.W)
    move.b  (A5)+,D0  ; PLA
    ; Randomly head left or right.
    ;
    andi.b #$01,D0
    moveq   #0,D3
    move.b  D0,D3
    addq.b  #1,D3
    lea     ($0098,A4),A0
    move.b  D3,(A0,D2.W)
    rts

    even
_L_z04_Aquamentus_Move_Move:
    ; 7 of 8 screen frames return without moving.
    ;
    move.b  ($0015,A4),D0
    andi.b #$07,D0
    bne  _L_z04_Aquamentus_Move_Exit
    ; If the boss crossed the left limit, then
    ; put it back at the left limit ($88), and face right.
    ;
    move.b  ($70,A4,D2.W),D0
    cmpi.b  #$88,D0
    bcc  _L_z04_Aquamentus_Move_CheckRightLimit
    move.b  #$88,D0
    move.b  D0,($70,A4,D2.W)
    moveq   #1,D0
    lea     ($0098,A4),A0
    move.b  D0,(A0,D2.W)
    bne  _L_z04_Aquamentus_Move_SetRemainingDistance
    even
_L_z04_Aquamentus_Move_CheckRightLimit:
    ; If the boss crossed the right limit, then
    ; put it back at the right limit ($C7), and face left.
    ;
    cmpi.b  #$C8,D0
    bcs  _L_z04_Aquamentus_Move_ApplySpeed
    move.b  #$C7,D0
    move.b  D0,($70,A4,D2.W)
    moveq   #2,D0
    lea     ($0098,A4),A0
    move.b  D0,(A0,D2.W)
    even
_L_z04_Aquamentus_Move_SetRemainingDistance:
    ; Set the distance remaining to 7 pixels.
    ;
    moveq   #7,D0
    lea     ($0394,A4),A0
    move.b  D0,(A0,D2.W)
    even
_L_z04_Aquamentus_Move_ApplySpeed:
    ; Use (direction - 1) to index the speeds.
    ; This yields 0 for right, 1 for left.
    ;
    moveq   #0,D3
    lea     ($0098,A4),A0
    move.b  (A0,D2.W),D3
    subq.b  #1,D3
    ; Add the speed to the X coordinate.
    ;
    move.b  ($70,A4,D2.W),D0
    andi    #$EE,CCR  ; CLC: clear C+X
    lea     (AquamentusSpeeds).l,A0
    move.b  (A0,D3.W),D1
    addx.b  D1,D0   ; ADC AquamentusSpeeds,Y
    move.b  D0,($70,A4,D2.W)
    ; Decrement the distance remaining.
    ;
    lea     ($0394,A4),A0
    subq.b  #1,(A0,D2.W)
    even
_L_z04_Aquamentus_Move_Exit:
    rts

    even
Aquamentus_Shoot:
    ; If the object timer <> 0, then
    ; go modify fireballs that might still be flying.
    ;
    move.b  ($28,A4,D2.W),D0
    bne  _L_z04_Aquamentus_Shoot_SpreadOutFireballs
    ; The boss's object timer has expired. Time to shoot fireballs.
    ;
    ; Set the timer to a random time, at least $70 frames.
    ;
    move.b  ($18,A4,D2.W),D0
    ori.b #$70,D0
    move.b  D0,($28,A4,D2.W)
    ; Shoot the middle fireball. Its vertical displacement is 0.
    ;
    jsr     ShootFireball55
    moveq   #0,D0
    lea     ($0478,A4),A0
    move.b  D0,(A0,D3.W)
    ; Shoot the lower fireball. Its vertical displacement is 1.
    ;
    jsr     ShootFireball55
    moveq   #1,D0
    lea     ($0478,A4),A0
    move.b  D0,(A0,D3.W)
    ; Shoot the upper fireball. Its vertical displacement is -1.
    ;
    jsr     ShootFireball55
    move.b  #$FF,D0
    lea     ($0478,A4),A0
    move.b  D0,(A0,D3.W)
    rts

    even
_L_z04_Aquamentus_Shoot_SpreadOutFireballs:
    ; Make the fireballs spread out.
    ;
    ; For each object slot from $B to 1:
    ;
    moveq   #11,D2
    even
_L_z04_Aquamentus_Shoot_LoopObject:
    ; If type <> $55, loop again.
    ;
    lea     ($034F,A4),A0
    move.b  (A0,D2.W),D0
    cmpi.b  #$55,D0
    bne  _L_z04_Aquamentus_Shoot_NextLoopObject
    ; Every other screen frame, loop again.
    ;
    move.b  ($0015,A4),D0
    lsr.b  #1,D0   ; LSR A
    bcs  _L_z04_Aquamentus_Shoot_NextLoopObject
    ; Add the displacement for this fireball to its Y coordinate.
    ;
    lea     ($0084,A4),A0
    move.b  (A0,D2.W),D0
    andi    #$EE,CCR  ; CLC: clear C+X
    lea     ($0478,A4),A0
    move.b  (A0,D2.W),D1
    addx.b  D1,D0   ; ADC Aquamentus_ObjFireballOffset,X
    lea     ($0084,A4),A0
    move.b  D0,(A0,D2.W)
    even
_L_z04_Aquamentus_Shoot_NextLoopObject:
    ; Bottom of the loop.
    ;
    subq.b  #1,D2
    bpl  _L_z04_Aquamentus_Shoot_LoopObject
    ; Restore the boss's slot number.
    ;
    moveq   #0,D2
    move.b  ($0340,A4),D2
    rts

; Params:
; X: object index
;
    even
ShootFireball55:
    moveq   #85,D0
    jmp     ShootFireball

    even
AquamentusTiles:
    dc.b    $CC, $C4, $C8, $C2, $C6, $CA, $CC, $C4
    dc.b    $C8, $CE, $D0, $D2

    even
AquamentusSpriteOffsetsY:
    dc.b    $00, $00, $00, $10, $10, $10

    even
AquamentusSpriteOffsetsX:
    dc.b    $00, $08, $10, $00, $08, $10

    even
Aquamentus_Draw:
    ; Every $10 screen frames, switch animation frames.
    ; Each frame has 6 tiles (representing the top of 6 sprites).
    ; The last tile of frame 0 is at index 5.
    ; The last tile of frame 1 is at index $B.
    ;
    moveq   #5,D3
    move.b  ($0015,A4),D0
    andi.b #$10,D0
    bne  _anon_z04_88
    moveq   #11,D3
_anon_z04_88:
    move.b  D3,($000A,A4)
    ; For each sprite, from 5 to 0, indexed by [0B]:
    ;
    moveq   #5,D0
    move.b  D0,($000B,A4)
    even
_L_z04_Aquamentus_Draw_LoopSprite:
    moveq   #0,D3
    move.b  ($000B,A4),D3
    ; Add the current sprite's offset to the boss's X coordinate.
    ; Store it in [00].
    ;
    move.b  ($70,A4,D2.W),D0
    andi    #$EE,CCR  ; CLC: clear C+X
    lea     (AquamentusSpriteOffsetsX).l,A0
    move.b  (A0,D3.W),D1
    addx.b  D1,D0   ; ADC AquamentusSpriteOffsetsX,Y
    move.b  D0,($0000,A4)
    ; Add the current sprite's offset to the boss's Y coordinate.
    ; Store it in [01].
    ;
    lea     ($0084,A4),A0
    move.b  (A0,D2.W),D0
    andi    #$EE,CCR  ; CLC: clear C+X
    lea     (AquamentusSpriteOffsetsY).l,A0
    move.b  (A0,D3.W),D1
    addx.b  D1,D0   ; ADC AquamentusSpriteOffsetsY,Y
    move.b  D0,($0001,A4)
    ; Calculate sprite attributes:
    ; [03] := (invincibility timer AND 3) XOR 3
    ;
    ; If the boss is temporarily invincible, then
    ; this makes it flash by cycling all the palette rows.
    ;
    ; Otherwise invincibility timer = 0. So [03] becomes 3:
    ; the attribute value for a normal sprite with palette row 7 (level).
    ;
    lea     ($04F0,A4),A0
    move.b  (A0,D2.W),D0
    andi.b #$03,D0
    eori.b #$03,D0
    move.b  D0,($0003,A4)
    moveq   #0,D3
    move.b  ($000A,A4),D3
    ; Look up the tile for this sprite.
    ; If it's not the first one (face), then go write the sprite record.
    ;
    lea     (AquamentusTiles).l,A0
    move.b  (A0,D3.W),D0
    move.b  (AquamentusTiles).l,D1
    cmp.b   D1,D0
    bne  _L_z04_Aquamentus_Draw_WriteSprite
    ; Else it's the first one (the face tile).
    ; For timer >= $20, use it as is ($CC). Otherwise, use tile $C0.
    ;
    ; $CC/CD shows the closed mouth face.
    ; $C0/C1 shows the open mouth face.
    ;
    moveq   #0,D3
    move.b  ($28,A4,D2.W),D3
    cmpi.b  #$20,D3
    bcc  _L_z04_Aquamentus_Draw_WriteSprite
    move.b  #$C0,D0
    even
_L_z04_Aquamentus_Draw_WriteSprite:
    jsr     WriteBossSprite
    ; Bottom of the loop.
    ; Decrement tile index and loop index.
    ;
    subq.b  #1,($000A,A4)
    subq.b  #1,($000B,A4)
    bpl  _L_z04_Aquamentus_Draw_LoopSprite
    rts

; Params:
; A: tile
; [00]: X
; [01]: Y
; [03]: sprite attributes
;
; Save the tile
    even
WriteBossSprite:
    move.b  D0,-(A5)  ; PHA
    moveq   #0,D3
    move.b  ($0341,A4),D3
    lea     (SpriteOffsets).l,A0
    move.b  (A0,D3.W),D0
    moveq   #0,D3
    move.b  D0,D3
    move.b  (A5)+,D0  ; PLA
    lea     ($0201,A4),A0
    move.b  D0,(A0,D3.W)
    move.b  ($0000,A4),D0
    lea     ($0203,A4),A0
    move.b  D0,(A0,D3.W)
    move.b  ($0001,A4),D0
    jmp     Anim_EndWriteSprite

    even
UpdateDodongo:
    jsr     UpdateDodongoState
    jsr     Dodongo_CheckCollisions
    jsr     Dodongo_CheckBombHit
    jmp     Dodongo_Draw

; Unknown block
    dc.b    $10, $F0, $10, $FF, $F0

    even
DodongoBloatedWaitTimes:
    dc.b    $20, $40, $40

    even
UpdateDodongoState:
    lea     ($00AC,A4),A0
    move.b  (A0,D2.W),D0
    jsr     _m68k_tablejump  ; M68K-native table dispatch (replaces JSR TableJump)
    even
UpdateDodongoState_JumpTable:
    dc.l    UpdateDodongoState0_Move   ; jump table entry (32-bit for _m68k_tablejump)
    dc.l    UpdateDodongoState1_Bloated   ; jump table entry (32-bit for _m68k_tablejump)
    dc.l    UpdateDodongoState2_Stunned   ; jump table entry (32-bit for _m68k_tablejump)

    even
UpdateDodongoState0_Move:
    ; If facing left, then push X offset 0 on the stack.
    ; Else push X offset -$10, and add $10 to X coordinate.
    ;
    ; We would like to use one set of coordinates only.
    ; But movement would break down, if we did; because
    ; Dodongo is so long.
    ;
    ; So, when not facing left, we temporarily shift the
    ; X coordinate to be closer to the other side of the monster.
    ;
    moveq   #0,D3
    lea     ($0098,A4),A0
    move.b  (A0,D2.W),D0
    andi.b #$0D,D0
    beq  _L_z04_UpdateDodongoState0_Move_Move
    move.b  ($70,A4,D2.W),D0
    andi    #$EE,CCR  ; CLC: clear C+X
    move.b  #$10,D1
    addx.b  D1,D0   ; ADC #$10 (X flag = 6502 C)
    move.b  D0,($70,A4,D2.W)
    move.b  #$F0,D3
    even
_L_z04_UpdateDodongoState0_Move_Move:
    move.b  D3,D0
    move.b  D0,-(A5)  ; PHA
    moveq   #32,D0
    lea     ($041F,A4),A0
    move.b  D0,(A0,D2.W)
    jsr     Wanderer_TargetPlayer
    ; Pop the offset and add it to the X coordinate.
    ;
    ; This brings the X coordinate back to the unique value
    ; that represents the position.
    ;
    move.b  (A5)+,D0  ; PLA
    andi    #$EE,CCR  ; CLC: clear C+X
    move.b  ($70,A4,D2.W),D1
    addx.b  D1,D0   ; ADC ObjX,X
    move.b  D0,($70,A4,D2.W)
    ; If X coordinate < $20, then face right.
    ;
    cmpi.b  #$20,D0
    bcc  _anon_z04_89
    moveq   #1,D0
    lea     ($0098,A4),A0
    move.b  D0,(A0,D2.W)
_anon_z04_89:
    rts

    even
UpdateDodongoState2_Stunned:
    ; Take action depending on the value of stun timer:
    ; 0:     set stun timer to $20 
    ; 1:     go back to state 0
    ; other: return
    ;
    moveq   #0,D3
    move.b  ($3D,A4,D2.W),D3
    subq.b  #1,D3
    bne.s  __far_z_04_0062
    jmp  UpdateDodongoState1_Bloated_Sub_End
__far_z_04_0062:
    bpl  _anon_z04_90
    moveq   #32,D0
    move.b  D0,($3D,A4,D2.W)
_anon_z04_90:
    rts

    even
UpdateDodongoState1_Bloated:
    lea     ($042C,A4),A0
    move.b  (A0,D2.W),D0
    jsr     _m68k_tablejump  ; M68K-native table dispatch (replaces JSR TableJump)
    even
UpdateDodongoState1_Bloated_JumpTable:
    dc.l    UpdateDodongoState1_Bloated_Sub_Wait   ; jump table entry (32-bit for _m68k_tablejump)
    dc.l    UpdateDodongoState1_Bloated_Sub_Wait   ; jump table entry (32-bit for _m68k_tablejump)
    dc.l    UpdateDodongoState1_Bloated_Sub_Wait   ; jump table entry (32-bit for _m68k_tablejump)
    dc.l    UpdateDodongoState1_Bloated_Sub_Die   ; jump table entry (32-bit for _m68k_tablejump)
    dc.l    UpdateDodongoState1_Bloated_Sub_End   ; jump table entry (32-bit for _m68k_tablejump)

    even
UpdateDodongoState1_Bloated_Sub_Wait:
    ; Bloated timer =>
    ; 0:     fall thru to set a new timer and check bomb hits
    ; 1:     go advance the substate
    ; other: go decrement Bloated timer
    ;
    moveq   #0,D3
    lea     ($045E,A4),A0
    move.b  (A0,D2.W),D3
    subq.b  #1,D3
    beq  _L_z04_UpdateDodongoState1_Bloated_Sub_Wait_AdvanceSubstate
    bmi.s  __far_z_04_0063
    jmp  L_Dodongo_DecrementBloatedTimer
__far_z_04_0063:
    ; Set the bloated timer according to the substate.
    ;
    moveq   #0,D3
    lea     ($042C,A4),A0
    move.b  (A0,D2.W),D3
    lea     (DodongoBloatedWaitTimes).l,A0
    move.b  (A0,D3.W),D0
    lea     ($045E,A4),A0
    move.b  D0,(A0,D2.W)
    ; If substate <> 0, go decrement bloated timer.
    ;
    cmpi.b  #$00,D3
    beq.s  __far_z_04_0064
    jmp  L_Dodongo_DecrementBloatedTimer
__far_z_04_0064:
    ; Deactivate the bomb in the first bomb slot ($10).
    ;
    moveq   #16,D3
    moveq   #0,D0
    lea     ($00AC,A4),A0
    move.b  D0,(A0,D3.W)
    ; Increment the number of bomb hits.
    ;
    lea     ($0437,A4),A0
    move.b  (A0,D2.W),D0
    andi    #$EE,CCR  ; CLC: clear C+X
    move.b  #$01,D1
    addx.b  D1,D0   ; ADC #$01 (X flag = 6502 C)
    lea     ($0437,A4),A0
    move.b  D0,(A0,D2.W)
    jmp     L_Dodongo_DecrementBloatedTimer

    even
_L_z04_UpdateDodongoState1_Bloated_Sub_Wait_AdvanceSubstate:
    ; Advance the substate.
    ;
    lea     ($042C,A4),A0
    addq.b  #1,(A0,D2.W)
    ; If new bloated substate < 2, then go decrement the bloated timer.
    ;
    lea     ($042C,A4),A0
    move.b  (A0,D2.W),D0
    cmpi.b  #$02,D0
    bcc.s  __far_z_04_0065
    jmp  L_Dodongo_DecrementBloatedTimer
__far_z_04_0065:
    ; New bloated substate >= 2.
    ;
    ; If bomb hits < 2, then set bloated substate 4,
    ; which will transition to state 0 (moving).
    ;
    ; Note that if the bomb hits >= 2, then:
    ; - If new substate = 2, then substate 2 will wait,
    ;   and then transition to substate 3.
    ; - If new substate = 3, then the next frame the monster will die.
    ;
    moveq   #0,D3
    lea     ($0437,A4),A0
    move.b  (A0,D2.W),D3
    cmpi.b  #$02,D3
    bcs.s  __far_z_04_0066
    jmp  L_Dodongo_DecrementBloatedTimer
__far_z_04_0066:
    moveq   #4,D0
    lea     ($042C,A4),A0
    move.b  D0,(A0,D2.W)
    even
L_Dodongo_DecrementBloatedTimer:
    ; Either way, decrement the bloated timer.
    ;
    lea     ($045E,A4),A0
    subq.b  #1,(A0,D2.W)
    rts

    even
UpdateDodongoState1_Bloated_Sub_Die:
    jsr     UpdateDeadDummy
    jsr     PlayBossDeathCry
    even
UpdateDodongoState1_Bloated_Sub_End:
    jsr     ResetObjState
    lea     ($042C,A4),A0
    move.b  D0,(A0,D2.W)
    rts

    even
Dodongo_CheckCollisions:
    ; Check for collisions using a regular monster size.
    ;
    jsr     Dodongo_CheckCollisionsStandardSize
    ; If harmed, then go die.
    ;
    lea     ($04F0,A4),A0
    move.b  (A0,D2.W),D0
    bne  _L_z04_Dodongo_CheckCollisions_Die
    ; If facing vertically, then return.
    ;
    lea     ($0098,A4),A0
    move.b  (A0,D2.W),D0
    cmpi.b  #$04,D0
    bcs.s  __far_z_04_0067
    jmp  L11989_Exit
__far_z_04_0067:
    ; Save the X coordinate.
    ; Then add $10 to check the right-hand side.
    ;
    move.b  ($70,A4,D2.W),D0
    move.b  D0,-(A5)  ; PHA
    andi    #$EE,CCR  ; CLC: clear C+X
    move.b  #$10,D1
    addx.b  D1,D0   ; ADC #$10 (X flag = 6502 C)
    move.b  D0,($70,A4,D2.W)
    jsr     Dodongo_CheckCollisionsStandardSize
    ; Restore the X coordinate.
    ;
    move.b  (A5)+,D0  ; PLA
    move.b  D0,($70,A4,D2.W)
    ; If not harmed, then return.
    ;
    lea     ($04F0,A4),A0
    move.b  (A0,D2.W),D0
    bne.s  __far_z_04_0068
    jmp  L11989_Exit
__far_z_04_0068:
    even
_L_z04_Dodongo_CheckCollisions_Die:
    jsr     UpdateDodongoState1_Bloated_Sub_Die
    ; Drop a bomb from this fight.
    ;
    moveq   #10,D0
    move.b  D0,($0050,A4)
    move.b  D0,($0051,A4)
    even
L11989_Exit:
    rts

    even
Dodongo_CheckCollisionsStandardSize:
    move.b  #$FF,D0
    lea     ($04B2,A4),A0
    move.b  D0,(A0,D2.W)
    jsr     CheckMonsterCollisions
    ; If state <> 2 (stunned), then return.
    ;
    lea     ($00AC,A4),A0
    move.b  (A0,D2.W),D0
    cmpi.b  #$02,D0
    beq.s  __far_z_04_0069
    jmp  L11989_Exit
__far_z_04_0069:
    ; Take out the bit for the sword in the invincibility mask.
    ; Check for collision with Link's sword.
    ;
    move.b  #$FE,D0
    lea     ($04B2,A4),A0
    move.b  D0,(A0,D2.W)
    jsr     GetObjectMiddle
    moveq   #13,D3
    jmp     CheckMonsterSwordCollision

    even
DodongoMouthNegativeLimits0:
    dc.b    $F0, $00, $F8, $FF, $F8

    even
DodongoMouthPositiveLimits0:
    dc.b    $00, $10, $08, $FF, $08

    even
DodongoMouthNegativeLimits1:
    dc.b    $FC, $FC, $F0, $FF, $00

    even
DodongoMouthPositiveLimits1:
    dc.b    $04, $04, $00, $FF, $10

    even
Dodongo_CheckBombHit:
    ; If state <> 0 (not moving), then return.
    ;
    lea     ($00AC,A4),A0
    move.b  (A0,D2.W),D0
    bne  _L_z04_Dodongo_CheckBombHit_Exit
    ; If facing vertically, then store (X + 8) in [00].
    ; Else store (X + $10).
    ;
    move.b  ($70,A4,D2.W),D0
    andi    #$EE,CCR  ; CLC: clear C+X
    move.b  #$08,D1
    addx.b  D1,D0   ; ADC #$08 (X flag = 6502 C)
    moveq   #0,D3
    lea     ($0098,A4),A0
    move.b  (A0,D2.W),D3
    cmpi.b  #$04,D3
    bcc  _anon_z04_91
    move.b  #$08,D1
    addx.b  D1,D0   ; ADC #$08 (X flag = 6502 C)
_anon_z04_91:
    move.b  D0,($0000,A4)
    ; Store (Y + 8) in [01].
    ;
    lea     ($0084,A4),A0
    move.b  (A0,D2.W),D0
    move.b  #$08,D1
    addx.b  D1,D0   ; ADC #$08 (X flag = 6502 C)
    move.b  D0,($0001,A4)
    ; Only check the first bomb slot ($10).
    ;
    ; Store the bomb's (X + 8) in [02].
    ;
    moveq   #16,D3
    move.b  ($70,A4,D3.W),D0
    move.b  #$08,D1
    addx.b  D1,D0   ; ADC #$08 (X flag = 6502 C)
    move.b  D0,($0002,A4)
    ; Store the bomb's (Y + 8) in [03].
    ;
    lea     ($0084,A4),A0
    move.b  (A0,D3.W),D0
    move.b  #$08,D1
    addx.b  D1,D0   ; ADC #$08 (X flag = 6502 C)
    move.b  D0,($0003,A4)
    ; But, if there's no bomb, then return.
    ;
    lea     ($00AC,A4),A0
    move.b  (A0,D3.W),D0
    beq  _L_z04_Dodongo_CheckBombHit_Exit
    ; If the bomb has not exploded (state $12), then
    ; go see if Dodongo will eat it.
    ;
    cmpi.b  #$12,D0
    bne.s  __far_z_04_0070
    jmp  Dodongo_TryEatBomb
__far_z_04_0070:
    ; If the object in the slot is actually a fire, then return.
    ;
    cmpi.b  #$20,D0
    bcc  _L_z04_Dodongo_CheckBombHit_Exit
    ; The bomb already blew up.
    ; If the dust cloud is in range of the monster,
    ; then set stunned state (2).
    ;
    moveq   #0,D3
    jsr     Dodongo_IsBombInRange
    bne  _L_z04_Dodongo_CheckBombHit_Exit
    moveq   #2,D0
    lea     ($00AC,A4),A0
    move.b  D0,(A0,D2.W)
    even
_L_z04_Dodongo_CheckBombHit_Exit:
    rts

    even
Dodongo_TryEatBomb:
    ; Try to eat the bomb.
    ;
    ; If the bomb is not in range of the monster, then return.
    ;
    ; This is a coarse test, to see if the bomb is over any part of the monster.
    ;
    moveq   #1,D3
    jsr     Dodongo_IsBombInRange
    bne  _L_z04_Dodongo_TryEatBomb_Exit
    ; Will loop from 1 to 0, indexed by [00].
    ;
    moveq   #1,D0
    move.b  D0,($0000,A4)
    ; Shift facing direction right 1 to make an index. Value 3 is unused.
    ;
    lea     ($0098,A4),A0
    move.b  (A0,D2.W),D0
    lsr.b  #1,D0   ; LSR A
    moveq   #0,D3
    move.b  D0,D3
    ; Now we have to see if it's near the mouth. But the mouth
    ; position depends on the orientation of the monster.
    ;
    ; Start with the horizontal distance.
    ;
    move.b  ($0004,A4),D0
    even
_L_z04_Dodongo_TryEatBomb_LoopLimit:
    ; Look up the limits for the given direction.
    ;
    ; If the distance from the bomb < negative limit,
    ; or >= positive limit, then return.
    ;
    ; Note that these are simple signed comparisons that work,
    ; because the operands are in a small range.
    ;
    lea     (DodongoMouthNegativeLimits0).l,A0
    move.b  (A0,D3.W),D1
    cmp.b   D1,D0
    bmi  _L_z04_Dodongo_TryEatBomb_Exit
    lea     (DodongoMouthPositiveLimits0).l,A0
    move.b  (A0,D3.W),D1
    cmp.b   D1,D0
    bpl  _L_z04_Dodongo_TryEatBomb_Exit
    ; Add $A to the index to look into the second set for vertical limits.
    ;
    move.b  D3,D0
    andi    #$EE,CCR  ; CLC: clear C+X
    move.b  #$0A,D1
    addx.b  D1,D0   ; ADC #$0A (X flag = 6502 C)
    moveq   #0,D3
    move.b  D0,D3
    ; Bottom of the loop.
    ;
    ; Load the vertical distance for the next iteration.
    ; Decrement loop counter.
    ;
    move.b  ($0005,A4),D0
    subq.b  #1,($0000,A4)
    bpl  _L_z04_Dodongo_TryEatBomb_LoopLimit
    ; If we get here, then the bomb was within range of the mouth.
    ; Go to state 1 (bloated).
    ;
    lea     ($00AC,A4),A0
    addq.b  #1,(A0,D2.W)
    ; Deactivate the bomb, and reset the bloated substate.
    ;
    moveq   #16,D3
    moveq   #0,D0
    lea     ($00AC,A4),A0
    move.b  D0,(A0,D3.W)
    lea     ($042C,A4),A0
    move.b  D0,(A0,D2.W)
    even
_L_z04_Dodongo_TryEatBomb_Exit:
    rts

    even
DodongoBombPositiveLimits:
    dc.b    $0C, $11

    even
DodongoBombNegativeLimits:
    dc.b    $F4, $F0

; Params:
; Y: limit index (0 for dust cloud, 1 for the bomb)
; [00]: monster hotspot X
; [01]: monster hotspot Y
; [02]: bomb hotspot X
; [03]: bomb hotspot Y
;
; Returns:
; A: 0 if the bomb is in range of the monster
; Z: 1 if the bomb is in range of the monster
; [04]: horizontal distance
; [05]: vertical distance
;
; Store the positive limit in [06], and the negative one in [07].
;
    even
Dodongo_IsBombInRange:
    lea     (DodongoBombPositiveLimits).l,A0
    move.b  (A0,D3.W),D0
    move.b  D0,($0006,A4)
    lea     (DodongoBombNegativeLimits).l,A0
    move.b  (A0,D3.W),D0
    move.b  D0,($0007,A4)
    ; Set [08] to 3. It will be shifted right once for each axis that
    ; the bomb is near enough the monster.
    ;
    moveq   #3,D0
    move.b  D0,($0008,A4)
    ; For each coordinate (Y/X), from 1 to 0, indexed by Y register:
    ;
    moveq   #1,D3
    even
_L_z04_Dodongo_IsBombInRange_LoopAxis:
    ; Subtract the bomb's coordinate from the boss's,
    ; The loop index determines the coordinate.
    ;
    move.b  ($00,A4,D3.W),D0
    ori     #$11,CCR  ; SEC: set C+X
    move.b  ($02,A4,D3.W),D1
    eori    #$10,CCR  ; flip X: 6502 SBC polarity
    subx.b  D1,D0   ; SBC $0002,Y
    eori    #$10,CCR  ; restore X = 6502 C
    ; If the distance >= positive offset, or < negative offset;
    ; then loop again.
    ;
    move.b  ($0006,A4),D1
    cmp.b   D1,D0
    bpl  _L_z04_Dodongo_IsBombInRange_NextLoopAxis
    move.b  ($0007,A4),D1
    cmp.b   D1,D0
    bmi  _L_z04_Dodongo_IsBombInRange_NextLoopAxis
    ; The distance is close enough in this axis.
    ;
    ; Store the distance in this axis in [05] or [04],
    ; depending on the loop index.
    ;
    move.b  D0,($04,A4,D3.W)
    ; Shift [08] right, because we're in range in this axis.
    ;
    move.b  ($0008,A4),D1
    lsr.b  #1,D1   ; LSR $08
    move.b  D1,($0008,A4)
    even
_L_z04_Dodongo_IsBombInRange_NextLoopAxis:
    subq.b  #1,D3
    bpl  _L_z04_Dodongo_IsBombInRange_LoopAxis
    ; If close enough in both axes, then [08] will be 0.
    ;
    move.b  ($0008,A4),D0
    rts

; Two sets of frame image numbers: 1 set for each animation frame.
; Each set contains 5 frame image numbers, indexed by direction.
;
; But these are not typical direction indexes. Instead a
; 5-way index is used.
; A direction shifted right once becomes a 5-way index.
; The fourth element is unused.
;
    even
DodongoFrameImages:
    dc.b    $00, $01, $06, $FF, $08, $02, $03, $06
    dc.b    $FF, $08

    even
DodongoFrameHFlips:
    dc.b    $00, $40, $00, $FF, $00, $00, $40, $40
    dc.b    $FF, $40

    even
DodongoFrameImagesBloated:
    dc.b    $04, $05, $07, $FF, $09, $04, $05, $07
    dc.b    $FF, $09

    even
DodongoFrameHFlipsBloated:
    dc.b    $00, $40, $00, $FF, $00, $00, $40, $00
    dc.b    $FF, $00

    even
Dodongo_Draw:
    jsr     Anim_SetSpriteDescriptorLevelPaletteRow
    ; Make a 5-way direction index out of the facing direction
    ; by shifting right once, and store it in [00].
    ;
    lea     ($0098,A4),A0
    move.b  (A0,D2.W),D0
    lsr.b  #1,D0   ; LSR A
    move.b  D0,($0000,A4)
    ; If state = 0, go handle animating the two frames of this state.
    ;
    moveq   #0,D3
    lea     ($00AC,A4),A0
    move.b  (A0,D2.W),D3
    beq  _L_z04_Dodongo_Draw_DrawWalkingFast
    ; If state > 1, then the monster is stunned (state 2).
    ; So, go switch frames every $20 screen frames.
    ;
    moveq   #32,D0
    subq.b  #1,D3
    bne  _L_z04_Dodongo_Draw_DrawWalking
    ; State = 1. Bloated.
    ;
    ; In substate 0, go animate as usual for walking.
    ;
    moveq   #0,D3
    lea     ($042C,A4),A0
    move.b  (A0,D2.W),D3
    beq  _L_z04_Dodongo_Draw_DrawWalkingFast
    ; If in bloated substates 2 or 3 (last wait or die), then
    ; go fade the boss; so that some frames are not drawn.
    ;
    cmpi.b  #$02,D3
    beq  _L_z04_Dodongo_Draw_DrawFaded
    cmpi.b  #$03,D3
    beq  _L_z04_Dodongo_Draw_DrawFaded
    ; State 1, substate 1
    ;
    ; Add $14 to the frame image index to index into the bloated
    ; frame images and H-flips.
    ;
    move.b  ($0000,A4),D0
    andi    #$EE,CCR  ; CLC: clear C+X
    move.b  #$14,D1
    addx.b  D1,D0   ; ADC #$14 (X flag = 6502 C)
    moveq   #0,D3
    move.b  D0,D3
    jmp     _L_z04_Dodongo_Draw_PrepareToDraw

    even
_L_z04_Dodongo_Draw_DrawFaded:
    ; In bloated substates 2 and 3:
    ; Every two screen frames, don't draw for two frames. Return.
    ;
    move.b  ($0015,A4),D0
    andi.b #$02,D0
    bne.s  __far_z_04_0071
    jmp  L11B00_Exit
__far_z_04_0071:
    moveq   #0,D3
    move.b  ($0000,A4),D3
    jmp     _L_z04_Dodongo_Draw_PrepareToDraw

    even
_L_z04_Dodongo_Draw_DrawWalkingFast:
    ; Every 8 screen frames, switch between 2 animation frames.
    ;
    moveq   #8,D0
    even
_L_z04_Dodongo_Draw_DrawWalking:
    moveq   #0,D3
    move.b  ($0000,A4),D3
    move.b  ($0015,A4),D1
    and.b  D1,D0
    beq  _L_z04_Dodongo_Draw_PrepareToDraw
    ; For animation frame 1, add 5 to the index in Y register,
    ; in order to index into the second set of frame image numbers.
    ;
    move.b  D3,D0
    andi    #$EE,CCR  ; CLC: clear C+X
    move.b  #$05,D1
    addx.b  D1,D0   ; ADC #$05 (X flag = 6502 C)
    moveq   #0,D3
    move.b  D0,D3
    even
_L_z04_Dodongo_Draw_PrepareToDraw:
    ; Start preparing sprites.
    ;
    jsr     Anim_FetchObjPosForSpriteDescriptor
    move.b  D3,D0
    move.b  D0,-(A5)  ; PHA
    ; Get the horizontal flipping and frame image number for this frame image.
    ;
    lea     (DodongoFrameHFlips).l,A0
    move.b  (A0,D3.W),D0
    move.b  D0,($000F,A4)
    lea     (DodongoFrameImages).l,A0
    move.b  (A0,D3.W),D0
    ; Frame image numbers 7 and 9 are vertical bloated frame images.
    ; They are drawn mirrored.
    ;
    cmpi.b  #$07,D0
    beq  _anon_z04_92
    cmpi.b  #$09,D0
    bne  _L_z04_Dodongo_Draw_DrawLeftSide
_anon_z04_92:
    jsr     DrawObjectMirrored
    jmp     _L_z04_Dodongo_Draw_DrawRightSide

    even
_L_z04_Dodongo_Draw_DrawLeftSide:
    ; No other frame images are mirrored.
    ;
    jsr     DrawObjectNotMirrored
    even
_L_z04_Dodongo_Draw_DrawRightSide:
    move.b  (A5)+,D0  ; PLA
    moveq   #0,D3
    move.b  D0,D3
    ; If facing vertically, then return. There's no other side to draw.
    ;
    lea     ($0098,A4),A0
    move.b  (A0,D2.W),D0
    andi.b #$03,D0
    bne.s  __far_z_04_0072
    jmp  L11B00_Exit
__far_z_04_0072:
    ; Else draw the right side.
    ;
    ; Keep the Y coordinate in [01].
    ; But, store (X + $10) in [00].
    ;
    move.b  ($70,A4,D2.W),D0
    andi    #$EE,CCR  ; CLC: clear C+X
    move.b  #$10,D1
    addx.b  D1,D0   ; ADC #$10 (X flag = 6502 C)
    move.b  D0,($0000,A4)
    jsr     Anim_SetSpriteDescriptorLevelPaletteRow
    ; XOR'ing the low bit swaps the left and right frame numbers.
    ;
    ; So, if we had animation frame 1, direction left:
    ; - 5-way direction index = 1 (2 >> 1)
    ; - frame image index = 6 (1 + 5)
    ;   (dodongo/walk/right/right half/anim frame 1)
    ; - frame number = 3 (look up element 6 in frame image array)
    ; - horizontal flip = true (loop up element 6 in H-flip array)
    ;
    ; So, 3 would have been the frame number used above for
    ; the left side.
    ;
    ; Here, the frame number is 2 (3 XOR 1), meaning
    ; (dodongo/walk/right/left half/anim frame 1). The horizontal
    ; flipping flag is unchanged. So, this left half frame is shown correctly
    ; on the right.
    ;
    lea     (DodongoFrameImages).l,A0
    move.b  (A0,D3.W),D0
    eori.b #$01,D0
    jmp     DrawObjectNotMirrored

; Returns:
; A: 3
; [04]: left sprite attributes
; [05]: right sprite attributes
;
    even
Anim_SetSpriteDescriptorLevelPaletteRow:
    moveq   #3,D0
    jsr     Anim_SetSpriteDescriptorAttributes
    even
L11B00_Exit:
    rts

; Unknown block
    dc.b    $FF, $FF, $FF, $FF, $FF, $FF, $FF, $FF
    dc.b    $FF, $FF, $FF, $FF, $FF, $FF, $FF, $FF
    dc.b    $FF, $FF, $FF, $FF, $FF, $FF, $FF, $FF
    dc.b    $FF, $FF, $FF, $FF, $FF, $FF, $FF

    even
InitDarknut:
    move.b  #$F6,D0
    lea     ($04B2,A4),A0
    move.b  D0,(A0,D2.W)
    ; If the darknut is red, then move at q-speed $20 (0.5 pixels a frame).
    ;
    moveq   #32,D0
    moveq   #0,D3
    lea     ($034F,A4),A0
    move.b  (A0,D2.W),D3
    cmpi.b  #$0B,D3
    beq  _anon_z04_93
    ; Else move a blue darknut at q-speed $28 (0.625 pixels a frame).
    ;
    moveq   #40,D0
_anon_z04_93:
    lea     ($03BC,A4),A0
    move.b  D0,(A0,D2.W)
    jmp     InitWalker

    even
UpdateGibdo:
    move.b  #$80,D0
    jsr     UpdateCommonWanderer
    jsr     CheckMonsterCollisions
    moveq   #8,D0
    jsr     Anim_AdvanceAnimCounterAndSetObjPosForSpriteDescriptor
    jsr     Anim_SetObjHFlipForSpriteDescriptor
    moveq   #0,D0
    jmp     DrawObjectNotMirrored

    even
UpdateDarknut:
    move.b  #$80,D0
    jsr     UpdateCommonWanderer
    jsr     CheckMonsterCollisions
    ; Darknuts are never stunned.
    ;
    moveq   #0,D0
    move.b  D0,($3D,A4,D2.W)
    moveq   #8,D0
    jsr     Anim_AdvanceAnimCounterAndSetObjPosForSpriteDescriptor
    ; If facing left, then enable horizontal flipping.
    ;
    lea     ($0098,A4),A0
    move.b  (A0,D2.W),D0
    cmpi.b  #$02,D0
    bne  _anon_z04_94
    addq.b  #1,($000F,A4)
_anon_z04_94:
    ; Shift right 2, yielding: 2 up, 1 down, 0 horizontal
    ; This is the base frame image.
    ;
    lsr.b  #1,D0   ; LSR A
    lsr.b  #1,D0   ; LSR A
    ; If movement frame = 1, add 3 to frame image to access
    ; the second animation frame's images.
    ;
    moveq   #0,D3
    lea     ($03E4,A4),A0
    move.b  (A0,D2.W),D3
    beq  _anon_z04_95
    andi    #$EE,CCR  ; CLC: clear C+X
    move.b  #$03,D1
    addx.b  D1,D0   ; ADC #$03 (X flag = 6502 C)
    ; Also if movement frame = 1, and facing up, then flip horizontally.
    ;
    ; Down has two frame images, but up only has one. By flipping
    ; horizontally, you get two frame images.
    ;
    moveq   #0,D3
    lea     ($0098,A4),A0
    move.b  (A0,D2.W),D3
    cmpi.b  #$08,D3
    bne  _anon_z04_95
    addq.b  #1,($000F,A4)
_anon_z04_95:
    jsr     DrawObjectNotMirrored
    rts

    even
PolsVoiceWalkSpeedsX:
    dc.b    $01, $FF, $00, $00, $01, $FF, $00, $00
    dc.b    $01, $FF

    even
PolsVoiceWalkSpeedsY:
    dc.b    $00, $00, $00, $01, $01, $01, $00, $FF
    dc.b    $FF, $FF

    even
PolsVoiceInitialJumpSpeeds:
    dc.b    $FD, $FD, $FF, $FF, $FF, $FF, $FF, $FC

    even
PolsVoiceDestinationYOffsets:
    dc.b    $00, $00, $20, $20, $20, $20, $20, $E0

    even
PolsVoiceDirections:
    dc.b    $01, $02, $04, $08

    even
UpdatePolsVoice:
    cmpi.b  #$01,D2
    bne  _anon_z04_96
_anon_z04_96:
    ; If we have the magic clock, or is stunned, then
    ; go draw and check collisions.
    ;
    move.b  ($066C,A4),D0
    move.b  ($3D,A4,D2.W),D1
    or.b  D1,D0
    bne  _L_z04_UpdatePolsVoice_DrawAndCheckCollisions
    ; Every odd screen frame, go straight to drawing
    ; and checking collisions.
    ;
    move.b  ($0015,A4),D0
    lsr.b  #1,D0   ; LSR A
    bcc.s  __far_z_04_0073
    jmp  L_PolsVoice_DrawAndCheckCollisions
__far_z_04_0073:
    ; Otherwise move horizontally.
    ;
    jsr     PolsVoice_MoveX
    ; If state <> 0, then the monster is jumping.
    ; Go handle vertical movement.
    ;
    lea     ($00AC,A4),A0
    move.b  (A0,D2.W),D0
    beq  _L_z04_UpdatePolsVoice_State0
    jsr     UpdatePolsVoiceState1_Jumping
    jmp     _L_z04_UpdatePolsVoice_CheckWalkability

    even
_L_z04_UpdatePolsVoice_State0:
    ; State 0. Walking.
    ;
    ; If grid offset = 0, then no more distance to cover.
    ; So, go change to state 1 -- jumping.
    ;
    lea     ($0394,A4),A0
    move.b  (A0,D2.W),D0
    beq  _L_z04_UpdatePolsVoice_SetState1
    ; Decrement grid offset / distance remaining.
    ;
    lea     ($0394,A4),A0
    subq.b  #1,(A0,D2.W)
    ; Move vertically.
    ; Add the Y offset for the current direction to the Y coordinate.
    ;
    lea     ($0084,A4),A0
    move.b  (A0,D2.W),D0
    andi    #$EE,CCR  ; CLC: clear C+X
    lea     (PolsVoiceWalkSpeedsY).l,A0
    move.b  (A0,D3.W),D1
    addx.b  D1,D0   ; ADC PolsVoiceWalkSpeedsY,Y
    lea     ($0084,A4),A0
    move.b  D0,(A0,D2.W)
    even
_L_z04_UpdatePolsVoice_CheckWalkability:
    ; If the square the monster is over is walkable, then
    ; go draw and check object collisions.
    ;
    jsr     PolsVoice_IsSquareWalkable
    bcc  _L_z04_UpdatePolsVoice_DrawAndCheckCollisions
    ; If the unwalkable tile is a block, or >= $F4 (water, screen edge bricks),
    ; then go change to state 1.
    ;
    lea     ($041F,A4),A0
    move.b  (A0,D2.W),D0
    andi.b #$FC,D0
    cmpi.b  #$B0,D0
    beq  _L_z04_UpdatePolsVoice_SetState1
    cmpi.b  #$F4,D0
    bcc  _L_z04_UpdatePolsVoice_SetState1
    ; Else blocked by something else.
    ;
    ; If facing horizontally, then go flip the direction, move, and draw.
    ;
    lea     ($0098,A4),A0
    move.b  (A0,D2.W),D0
    andi.b #$03,D0
    bne  _L_z04_UpdatePolsVoice_FlipHorizontally
    ; Else facing vertically. Flip the direction.
    ; Go draw.
    ;
    lea     ($0098,A4),A0
    move.b  (A0,D2.W),D0
    eori.b #$0C,D0
    lea     ($0098,A4),A0
    move.b  D0,(A0,D2.W)
    jmp     L_PolsVoice_DrawAndCheckCollisions

    even
_L_z04_UpdatePolsVoice_FlipHorizontally:
    ; Facing horizontally. Flip the direction.
    ; Move two pixels, and go draw.
    ;
    eori.b #$03,D0
    lea     ($0098,A4),A0
    move.b  D0,(A0,D2.W)
    jsr     PolsVoice_MoveX
    jsr     PolsVoice_MoveX
    even
_L_z04_UpdatePolsVoice_DrawAndCheckCollisions:
    jmp     L_PolsVoice_DrawAndCheckCollisions

    even
_L_z04_UpdatePolsVoice_SetState1:
    ; If already in state 1, then go draw and check collisions.
    ;
    lea     ($00AC,A4),A0
    move.b  (A0,D2.W),D0
    beq.s  __far_z_04_0074
    jmp  L_PolsVoice_DrawAndCheckCollisions
__far_z_04_0074:
    ; Go to state 1.
    ;
    lea     ($00AC,A4),A0
    addq.b  #1,(A0,D2.W)
    ; Subtract 1 from facing direction to make an index.
    ;
    moveq   #0,D3
    lea     ($0098,A4),A0
    move.b  (A0,D2.W),D3
    subq.b  #1,D3
    ; If Y coordinate < $78, make the index 3 for down.
    ;
    lea     ($0084,A4),A0
    move.b  (A0,D2.W),D0
    cmpi.b  #$78,D0
    bcc  _anon_z04_97
    moveq   #3,D3
_anon_z04_97:
    ; If Y coordinate >= $A8, make the index 7 for up.
    ;
    cmpi.b  #$A8,D0
    bcs  _anon_z04_98
    moveq   #7,D3
_anon_z04_98:
    ; Set the vertical speed for the beginning of the jump.
    ;
    lea     (PolsVoiceInitialJumpSpeeds).l,A0
    move.b  (A0,D3.W),D0
    lea     ($0412,A4),A0
    move.b  D0,(A0,D2.W)
    ; Look up the Y offset for the current direction.
    ; Add it to object Y to set the destination Y of the jump.
    ;
    lea     ($0084,A4),A0
    move.b  (A0,D2.W),D0
    andi    #$EE,CCR  ; CLC: clear C+X
    lea     (PolsVoiceDestinationYOffsets).l,A0
    move.b  (A0,D3.W),D1
    addx.b  D1,D0   ; ADC PolsVoiceDestinationYOffsets,Y
    lea     ($042C,A4),A0
    move.b  D0,(A0,D2.W)
    ; Turn the index into a direction again by adding 1.
    ; Store the facing direction.
    ;
    addq.b  #1,D3
    lea     ($0098,A4),A0
    move.b  D3,(A0,D2.W)
    even
L_PolsVoice_DrawAndCheckCollisions:
    moveq   #8,D0
    jsr     Anim_AdvanceAnimCounterAndSetObjPosForSpriteDescriptor
    lea     ($03E4,A4),A0
    move.b  (A0,D2.W),D0
    jsr     DrawObjectMirrored
    ; Pols Voice is invincible to everything but the sword,
    ; during normal collision detection.
    ;
    ; The arrow is a special case.
    ;
    move.b  #$FE,D0
    lea     ($04B2,A4),A0
    move.b  D0,(A0,D2.W)
    jsr     CheckMonsterCollisions
    rts

    even
UpdatePolsVoiceState1_Jumping:
    ; Add acceleration $38 to low speed byte (vertical).
    ;
    lea     ($0444,A4),A0
    move.b  (A0,D2.W),D0
    andi    #$EE,CCR  ; CLC: clear C+X
    move.b  #$38,D1
    addx.b  D1,D0   ; ADC #$38 (X flag = 6502 C)
    lea     ($0444,A4),A0
    move.b  D0,(A0,D2.W)
    ; Add Carry to high speed byte (vertical).
    ;
    lea     ($0412,A4),A0
    move.b  (A0,D2.W),D0
    move.b  #$00,D1
    addx.b  D1,D0   ; ADC #$00 (X flag = 6502 C)
    lea     ($0412,A4),A0
    move.b  D0,(A0,D2.W)
    ; Add high speed byte to Y coordinate.
    ;
    andi    #$EE,CCR  ; CLC: clear C+X
    lea     ($0084,A4),A0
    move.b  (A0,D2.W),D1
    addx.b  D1,D0   ; ADC ObjY,X
    lea     ($0084,A4),A0
    move.b  D0,(A0,D2.W)
    ; If the speed is still negative, then return.
    ;
    lea     ($0412,A4),A0
    move.b  (A0,D2.W),D0
    bmi  _L_z04_UpdatePolsVoiceState1_Jumping_Exit
    ; If Y coordinate still < target Y, then return.
    ;
    lea     ($0084,A4),A0
    move.b  (A0,D2.W),D0
    lea     ($042C,A4),A0
    move.b  (A0,D2.W),D1
    cmp.b   D1,D0
    bcs  _L_z04_UpdatePolsVoiceState1_Jumping_Exit
    ; Else reached the destination. Go to state 0.
    ;
    moveq   #0,D0
    lea     ($00AC,A4),A0
    move.b  D0,(A0,D2.W)
    ; Reset 16-bit vertical speed.
    ;
    lea     ($0444,A4),A0
    move.b  D0,(A0,D2.W)
    lea     ($0412,A4),A0
    move.b  D0,(A0,D2.W)
    ; Choose a random direction to face in.
    ;
    move.b  ($18,A4,D2.W),D0
    andi.b #$03,D0
    moveq   #0,D3
    move.b  D0,D3
    lea     (PolsVoiceDirections).l,A0
    move.b  (A0,D3.W),D0
    lea     ($0098,A4),A0
    move.b  D0,(A0,D2.W)
    ; Randomly set distance-to-move to $30 or $70.
    ;
    move.b  ($18,A4,D2.W),D0
    andi.b #$40,D0
    move.b  #$30,D1
    addx.b  D1,D0   ; ADC #$30 (X flag = 6502 C)
    lea     ($0394,A4),A0
    move.b  D0,(A0,D2.W)
    ; Align the monster with a square horizontally.
    ;
    ; If in the left half of a square, align with that square.
    ; If in the right half, align with the next square.
    ;
    move.b  ($70,A4,D2.W),D0
    andi    #$EE,CCR  ; CLC: clear C+X
    move.b  #$08,D1
    addx.b  D1,D0   ; ADC #$08 (X flag = 6502 C)
    andi.b #$F0,D0
    move.b  D0,($70,A4,D2.W)
    ; Align the monster with a square vertically.
    ;
    ; If in the top half of a square, align with that square.
    ; If in the bottom half, align with the next square.
    ;
    lea     ($0084,A4),A0
    move.b  (A0,D2.W),D0
    andi    #$EE,CCR  ; CLC: clear C+X
    move.b  #$08,D1
    addx.b  D1,D0   ; ADC #$08 (X flag = 6502 C)
    andi.b #$F0,D0
    ; Make sure the lower nibble of Y is $D as usual.
    ;
    ori     #$11,CCR  ; SEC: set C+X
    move.b  #$03,D1
    eori    #$10,CCR  ; flip X: 6502 SBC polarity
    subx.b  D1,D0   ; SBC #$03
    eori    #$10,CCR  ; restore X = 6502 C
    lea     ($0084,A4),A0
    move.b  D0,(A0,D2.W)
    even
_L_z04_UpdatePolsVoiceState1_Jumping_Exit:
    rts

; Returns:
; C: 0 if walkable
; [041F][X]: tile
;
    even
PolsVoice_IsSquareWalkable:
    jsr     PolsVoice_GetCollidingTile
    ; If there's an unwalkable tile at the usual hotspot, then return.
    ;
    bcs  _L_z04_PolsVoice_IsSquareWalkable_Exit
    ; Save the original object X, and temporarily add $E to it.
    ;
    move.b  ($70,A4,D2.W),D0
    move.b  D0,-(A5)  ; PHA
    andi    #$EE,CCR  ; CLC: clear C+X
    move.b  #$0E,D1
    addx.b  D1,D0   ; ADC #$0E (X flag = 6502 C)
    move.b  D0,($70,A4,D2.W)
    ; Save the original Y, and temporarily add 6 to it.
    ;
    lea     ($0084,A4),A0
    move.b  (A0,D2.W),D0
    move.b  D0,-(A5)  ; PHA
    andi    #$EE,CCR  ; CLC: clear C+X
    move.b  #$06,D1
    addx.b  D1,D0   ; ADC #$06 (X flag = 6502 C)
    lea     ($0084,A4),A0
    move.b  D0,(A0,D2.W)
    ; Check again at relative hotspot ($E, $E).
    ;
    jsr     PolsVoice_GetCollidingTile
    ; Restore the original coordinates.
    ;
    move.b  (A5)+,D0  ; PLA
    lea     ($0084,A4),A0
    move.b  D0,(A0,D2.W)
    move.b  (A5)+,D0  ; PLA
    move.b  D0,($70,A4,D2.W)
    even
_L_z04_PolsVoice_IsSquareWalkable_Exit:
    rts

; Returns:
; C: 0 if walkable
; [041F][X]: tile
;
; Use offset 0 from the hotspot.
;
; TODO: But where is [0F] set?
;
    even
PolsVoice_GetCollidingTile:
    moveq   #0,D3
    jsr     GetCollidableTile
    lea     ($049E,A4),A0
    move.b  (A0,D2.W),D0
    ; Return C=0 if walkable.
    ;
    move.b  ($034A,A4),D1
    cmp.b   D1,D0
    ; Remember the tile that the monster is over.
    ;
    lea     ($041F,A4),A0
    move.b  D0,(A0,D2.W)
    eori    #$01,CCR  ; normalize C to 6502 polarity before RTS
    rts

; Returns:
; Y: facing direction - 1 (so, 0 to 7)
;
; Add the X offset for the current direction to the X coordinate.
;
    even
PolsVoice_MoveX:
    moveq   #0,D3
    lea     ($0098,A4),A0
    move.b  (A0,D2.W),D3
    subq.b  #1,D3
    move.b  ($70,A4,D2.W),D0
    andi    #$EE,CCR  ; CLC: clear C+X
    lea     (PolsVoiceWalkSpeedsX).l,A0
    move.b  (A0,D3.W),D1
    addx.b  D1,D0   ; ADC PolsVoiceWalkSpeedsX,Y
    move.b  D0,($70,A4,D2.W)
    rts

    even
UpdateLikeLike:
    ; If the monster captured Link, then go handle it.
    ;
    lea     ($042C,A4),A0
    move.b  (A0,D2.W),D0
    bne  _L_z04_UpdateLikeLike_HandleCaptured
    move.b  #$80,D0
    jsr     UpdateCommonWanderer
    ; Like-like has a 4 animation frame cycle unlike most monsters
    ; which have 2.
    ;
    lea     ($03D0,A4),A0
    subq.b  #1,(A0,D2.W)
    bne  _L_z04_UpdateLikeLike_Draw
    moveq   #8,D0
    lea     ($03D0,A4),A0
    move.b  D0,(A0,D2.W)
    moveq   #0,D3
    lea     ($03E4,A4),A0
    move.b  (A0,D2.W),D3
    addq.b  #1,D3
    move.b  D3,D0
    andi.b #$03,D0
    lea     ($03E4,A4),A0
    move.b  D0,(A0,D2.W)
    even
_L_z04_UpdateLikeLike_Draw:
    ; Draw.
    ;
    jsr     Anim_FetchObjPosForSpriteDescriptor
    lea     ($03E4,A4),A0
    move.b  (A0,D2.W),D0
    jsr     DrawObjectMirrored
    ; Check collisions. If Link was not captured, then return.
    ;
    jsr     CheckMonsterCollisions
    lea     ($042C,A4),A0
    move.b  (A0,D2.W),D0
    beq  _L_z04_UpdateLikeLike_Exit
    ; The monster captured Link.
    ; Put the monster at the same location as him.
    ;
    move.b  ($0070,A4),D0
    move.b  D0,($70,A4,D2.W)
    move.b  ($0084,A4),D0
    lea     ($0084,A4),A0
    move.b  D0,(A0,D2.W)
    ; Reset Link's timer, metastate, and shove info.
    ;
    moveq   #0,D0
    move.b  D0,($0028,A4)
    move.b  D0,($0405,A4)
    move.b  D0,($00C0,A4)
    move.b  D0,($00D3,A4)
    ; Restart the monster's movement frame cycle: frame 0, counter 4
    ;
    lea     ($03E4,A4),A0
    move.b  D0,(A0,D2.W)
    moveq   #4,D0
    lea     ($03D0,A4),A0
    move.b  D0,(A0,D2.W)
    ; Now Link can't move.
    ;
    addq.b  #1,($0512,A4)
    even
_L_z04_UpdateLikeLike_Exit:
    rts

    even
_L_z04_UpdateLikeLike_HandleCaptured:
    ; Animate up to frame 3. Then stay there.
    ;
    moveq   #2,D0
    lea     ($03E4,A4),A0
    move.b  (A0,D2.W),D1
    cmp.b   D1,D0
    bcs  _L_z04_UpdateLikeLike_IncCaptureTime
    lea     ($03D0,A4),A0
    subq.b  #1,(A0,D2.W)
    bne  _L_z04_UpdateLikeLike_IncCaptureTime
    lsl.b  #1,D0   ; ASL A
    lea     ($03D0,A4),A0
    move.b  D0,(A0,D2.W)
    lea     ($03E4,A4),A0
    addq.b  #1,(A0,D2.W)
    even
_L_z04_UpdateLikeLike_IncCaptureTime:
    ; Increment capture time.
    ;
    lea     ($042C,A4),A0
    addq.b  #1,(A0,D2.W)
    ; Once capture time >= $60 screen frames, remove the magic shield.
    ;
    lea     ($042C,A4),A0
    move.b  (A0,D2.W),D0
    cmpi.b  #$60,D0
    bcs  _L_z04_UpdateLikeLike_DrawAfterCapture
    moveq   #0,D0
    move.b  D0,($0676,A4)
    ; Set a value above $60 over and over.
    ;
    move.b  #$C0,D0
    lea     ($042C,A4),A0
    move.b  D0,(A0,D2.W)
    even
_L_z04_UpdateLikeLike_DrawAfterCapture:
    ; In this state, we have to draw Like-like over Link.
    ; So, don't use the usual sprite writing code that cycles sprites.
    ;
    jsr     Anim_FetchObjPosForSpriteDescriptor
    lea     ($03E4,A4),A0
    move.b  (A0,D2.W),D0
    jsr     DrawObjectMirroredOverLink
    ; Check object collisions.
    ; If this monster hasn't died, then return.
    ;
    jsr     CheckMonsterCollisions
    lea     ($0405,A4),A0
    move.b  (A0,D2.W),D0
    beq  _L_z04_UpdateLikeLike_Exit
    ; But once it has died, then let Link move again.
    ;
    moveq   #0,D0
    move.b  D0,($0512,A4)
    jmp     HideSpritesOverLink

    even
UpdateVire:
    jsr     UpdateVireState
    ; If state >= 2, then go split up into 2 keeses.
    ;
    lea     ($00AC,A4),A0
    move.b  (A0,D2.W),D0
    cmpi.b  #$02,D0
    bcc  _L_z04_UpdateVire_SplitUp
    jsr     CheckVireCollisions
    jmp     DrawVire

    even
_L_z04_UpdateVire_SplitUp:
    ; As with Zol, we'll destroy one monster, and make two.
    ; So, increase object count by 1.
    ;
    addq.b  #1,($034E,A4)
    jsr     DestroyMonster
    ; Two times, look for an empty monster slot.
    ; If one is found, then use the "shoot" operation to create a red keese.
    ;
    moveq   #1,D3
    even
_L_z04_UpdateVire_LoopMakeKeese:
    move.b  D3,D0
    move.b  D0,-(A5)  ; PHA
    jsr     FindEmptyMonsterSlot
    beq  _L_z04_UpdateVire_NextLoopMakeKeese
    moveq   #28,D0
    move.b  D0,($0000,A4)
    jsr     Shoot
    even
_L_z04_UpdateVire_NextLoopMakeKeese:
    move.b  (A5)+,D0  ; PLA
    moveq   #0,D3
    move.b  D0,D3
    subq.b  #1,D3
    bpl  _L_z04_UpdateVire_LoopMakeKeese
    rts

    even
UpdateVireState:
    lea     ($00AC,A4),A0
    move.b  (A0,D2.W),D0
    jsr     _m68k_tablejump  ; M68K-native table dispatch (replaces JSR TableJump)
    even
UpdateVireState_JumpTable:
    dc.l    UpdateVireState0   ; jump table entry (32-bit for _m68k_tablejump)
    dc.l    UpdateZolState1_Shove   ; jump table entry (32-bit for _m68k_tablejump)

    even
VireJumpOffsets:
    dc.b    $00, $FD, $FE, $FF, $FF, $00, $FF, $00
    dc.b    $00, $01, $00, $01, $01, $02, $03, $00

    even
UpdateVireState0:
    move.b  #$80,D0
    jsr     UpdateCommonWanderer
    ; If we have the clock, or monster is stunned; then return.
    ;
    move.b  ($066C,A4),D0
    move.b  ($3D,A4,D2.W),D1
    or.b  D1,D0
    bne  _L_z04_UpdateVireState0_Exit
    ; If going vertically, then return.
    ;
    lea     ($0098,A4),A0
    move.b  (A0,D2.W),D0
    andi.b #$03,D0
    beq  _L_z04_UpdateVireState0_Exit
    ; Get the absolute value of the grid offset (0 to $F);
    ; so it becomes an index into the jump offset array.
    ;
    lea     ($0394,A4),A0
    move.b  (A0,D2.W),D0
    jsr     Abs
    moveq   #0,D3
    move.b  D0,D3
    ; Add the vertical offset; so that as the vire moves left or right,
    ; it jumps.
    ;
    lea     ($0084,A4),A0
    move.b  (A0,D2.W),D0
    andi    #$EE,CCR  ; CLC: clear C+X
    lea     (VireJumpOffsets).l,A0
    move.b  (A0,D3.W),D1
    addx.b  D1,D0   ; ADC VireJumpOffsets,Y
    lea     ($0084,A4),A0
    move.b  D0,(A0,D2.W)
    even
_L_z04_UpdateVireState0_Exit:
    rts

    even
CheckVireCollisions:
    ; If state <> 0, then the vire's going to split up.
    ; So, no need to check collisions. Return.
    ;
    lea     ($00AC,A4),A0
    move.b  (A0,D2.W),D0
    bne  _L_z04_CheckVireCollisions_Exit
    jsr     CheckMonsterCollisions
    ; If it was killed, then return.
    ;
    lea     ($0405,A4),A0
    move.b  (A0,D2.W),D0
    bne  _L_z04_CheckVireCollisions_Exit
    ; If temporarily invincible, then it was harmed.
    ; Advance the state to split up.
    ;
    lea     ($04F0,A4),A0
    move.b  (A0,D2.W),D0
    beq  _L_z04_CheckVireCollisions_Exit
    lea     ($00AC,A4),A0
    addq.b  #1,(A0,D2.W)
    even
_L_z04_CheckVireCollisions_Exit:
    rts

    even
DrawVire:
    moveq   #10,D0
    jsr     Anim_AdvanceAnimCounterAndSetObjPosForSpriteDescriptor
    ; The movement frame is the fram image number, unless facing up.
    ; In this case, add 2 to the frame image.
    ;
    lea     ($0098,A4),A0
    move.b  (A0,D2.W),D0
    andi.b #$08,D0
    lsr.b  #1,D0   ; LSR A
    lsr.b  #1,D0   ; LSR A
    andi    #$EE,CCR  ; CLC: clear C+X
    lea     ($03E4,A4),A0
    move.b  (A0,D2.W),D1
    addx.b  D1,D0   ; ADC ObjAnimFrame,X
    jmp     DrawObjectMirrored

; Description:
; Blue Wizzrobe has two states: walking and teleporting.
; When walking, the object timer is set. When teleporting,
; the teleporting distance remaining is set.
;
; If we have the magic clock, then only go draw and check collisions.
;
    even
UpdateBlueWizzrobe:
    move.b  ($066C,A4),D0
    beq.s  __far_z_04_0075
    jmp  L_Wizzrobe_DrawAndCheckCollisions
__far_z_04_0075:
    jsr     BlueWizzrobe_WalkOrTeleport
    jsr     BlueWizzrobe_TryShooting
    even
Wizzrobe_DrawAndCheckCollisionsIntermittently:
    ; If the teleporting distance remaining is even, then draw
    ; and check collisions, else return.
    ;
    ; This means that when 0, the monster is walking.
    ; So, draw and check collisions every frame.
    ;
    ; When not 0, the monster is teleporting, and must be drawn
    ; translucently -- every other frame.
    ;
    lea     ($0394,A4),A0
    move.b  (A0,D2.W),D0
    lsr.b  #1,D0   ; LSR A
    bcc.s  __far_z_04_0076
    jmp  L11E17_Exit
__far_z_04_0076:
    even
L_Wizzrobe_DrawAndCheckCollisions:
    jmp     Wizzrobe_DrawAndCheckCollisions

    even
BlueWizzrobe_WalkOrTeleport:
    ; If timer has not expired, then go walk.
    ;
    move.b  ($28,A4,D2.W),D0
    bne  _L_z04_BlueWizzrobe_WalkOrTeleport_Walk
    ; Timer = 0. Only teleporting now.
    ;
    ; If there is still distance to go while translucent, then
    ; decrement the distance remaining, and move.
    ;
    lea     ($0394,A4),A0
    move.b  (A0,D2.W),D0
    beq  _L_z04_BlueWizzrobe_WalkOrTeleport_WalkAgain
    lea     ($0394,A4),A0
    subq.b  #1,(A0,D2.W)
    jmp     BlueWizzrobe_MoveAndCheckTile

    even
_L_z04_BlueWizzrobe_WalkOrTeleport_WalkAgain:
    ; Distance remaining = 0. Still teleporting.
    ;
    jsr     BlueWizzrobe_AlignWithNearestSquareAndRandomizeTimer
    jmp     BlueWizzrobe_TurnTowardLink

    even
_L_z04_BlueWizzrobe_WalkOrTeleport_Walk:
    ; Timer:
    ;   >= $10: Turn if needed and move every other frame
    ;   > 1:    Do nothing
    ;   = 1:    Choose a place to teleport to.
    ;
    ; Notice that walking is slower than teleporting; and there is
    ; a pause of $10 frames at the end.
    ;
    cmpi.b  #$10,D0
    bcs.s  __far_z_04_0077
    jmp  GoEveryOtherFrame
__far_z_04_0077:
    cmpi.b  #$01,D0
    beq.s  __far_z_04_0078
    jmp  L11E17_Exit
__far_z_04_0078:
    jsr     BlueWizzrobe_ChooseTeleportTarget
    even
L11E17_Exit:
    rts

    even
GoEveryOtherFrame:
    ; Every other frame, advance the turn counter, turn if needed,
    ; and move.
    ;
    move.b  ($0015,A4),D0
    lsr.b  #1,D0   ; LSR A
    bcc.s  __far_z_04_0079
    jmp  L_BlueWizzrobe_TurnTowardLinkIfNeeded
__far_z_04_0079:
    even
BlueWizzrobe_TurnSometimesAndMoveAndCheckTile:
    jsr     BlueWizzrobe_AdvanceCounterAndTurnTowardLinkIfNeeded
    even
BlueWizzrobe_MoveAndCheckTile:
    jsr     BlueWizzrobe_Move
    jsr     Wizzrobe_GetCollidableTile
    ; If walkable, then return.
    ;
    bcc  _L_z04_BlueWizzrobe_MoveAndCheckTile_Exit
    ; Go handle a wall, if the tile is not a block nor water.
    ;
    lea     ($041F,A4),A0
    move.b  (A0,D2.W),D0
    andi.b #$FC,D0
    cmpi.b  #$B0,D0
    beq  _L_z04_BlueWizzrobe_MoveAndCheckTile_HitBlockOrWater
    cmpi.b  #$F4,D0
    bcs  _L_z04_BlueWizzrobe_MoveAndCheckTile_HitWall
    even
_L_z04_BlueWizzrobe_MoveAndCheckTile_HitBlockOrWater:
    ; If the monster was already teleporting, then return,
    ; so that it moves again next frame.
    ;
    lea     ($0394,A4),A0
    move.b  (A0,D2.W),D0
    beq.s  __far_z_04_0080
    jmp  L11E17_Exit
__far_z_04_0080:
    ; Else go start teleporting thru this obstacle.
    ;
    jmp     BeginTeleporting

    even
_L_z04_BlueWizzrobe_MoveAndCheckTile_HitWall:
    ; The monster hit a wall.
    ; If facing direction has a vertical component, then flip it.
    ;
    moveq   #0,D3
    lea     ($0098,A4),A0
    move.b  (A0,D2.W),D3
    move.b  D3,D0
    andi.b #$0C,D0
    beq  _L_z04_BlueWizzrobe_MoveAndCheckTile_CheckHorizontal
    move.b  D3,D0
    eori.b #$0C,D0
    lea     ($0098,A4),A0
    move.b  D0,(A0,D2.W)
    moveq   #0,D3
    move.b  D0,D3
    even
_L_z04_BlueWizzrobe_MoveAndCheckTile_CheckHorizontal:
    ; If facing direction has a horizontal component, then flip it.
    ;
    move.b  D3,D0
    andi.b #$03,D0
    beq  _L_z04_BlueWizzrobe_MoveAndCheckTile_Move
    move.b  D3,D0
    eori.b #$03,D0
    lea     ($0098,A4),A0
    move.b  D0,(A0,D2.W)
    even
_L_z04_BlueWizzrobe_MoveAndCheckTile_Move:
    jmp     BlueWizzrobe_Move

    even
_L_z04_BlueWizzrobe_MoveAndCheckTile_Exit:
    rts

; Description:
; Increment the turn counter. Then turn toward Link
; when the turn counter is a multiple of $40.
;
; Increment the turn counter.
;
    even
BlueWizzrobe_AdvanceCounterAndTurnTowardLinkIfNeeded:
    lea     ($0412,A4),A0
    addq.b  #1,(A0,D2.W)
; Description:
; When the counter is a multiple of $40, switch between facing
; toward Link horizontally or vertically. All other times, return.
;
    even
L_BlueWizzrobe_TurnTowardLinkIfNeeded:
    lea     ($0412,A4),A0
    move.b  (A0,D2.W),D0
    andi.b #$3F,D0
    beq.s  __far_z_04_0081
    jmp  L11EAF_Exit
__far_z_04_0081:
    even
BlueWizzrobe_TurnTowardLink:
    ; If the multiple of $40 is even, then turn horizontally,
    ; else vertically.
    ;
    lea     ($0412,A4),A0
    move.b  (A0,D2.W),D0
    andi.b #$40,D0
    bne  _L_z04_BlueWizzrobe_TurnTowardLink_TurnVertically
    ; If the monster's X >= Link's X, then choose left, else right.
    ;
    moveq   #2,D0
    moveq   #0,D3
    move.b  ($70,A4,D2.W),D3
    move.b  ($0070,A4),D1
    cmp.b   D1,D3
    bcc  _anon_z04_99
    lsr.b  #1,D0   ; LSR A
_anon_z04_99:
    jmp     _L_z04_BlueWizzrobe_TurnTowardLink_SetDir

    even
_L_z04_BlueWizzrobe_TurnTowardLink_TurnVertically:
    ; If the monster's Y >= Link's Y, then choose up, else down.
    ;
    moveq   #8,D0
    moveq   #0,D3
    lea     ($0084,A4),A0
    move.b  (A0,D2.W),D3
    move.b  ($0084,A4),D1
    cmp.b   D1,D3
    bcc  _L_z04_BlueWizzrobe_TurnTowardLink_SetDir
    lsr.b  #1,D0   ; LSR A
    even
_L_z04_BlueWizzrobe_TurnTowardLink_SetDir:
    ; If the direction chosen = facing direction, then return.
    ;
    lea     ($0098,A4),A0
    move.b  (A0,D2.W),D1
    cmp.b   D1,D0
    bne.s  __far_z_04_0082
    jmp  L11EAF_Exit
__far_z_04_0082:
    ; Else face toward Link.
    ;
    lea     ($0098,A4),A0
    move.b  D0,(A0,D2.W)
    jmp     BlueWizzrobe_AlignWithNearestSquare

    even
BlueWizzrobeTeleportOffsetsX:
    dc.b    $00, $01, $FF, $00, $00, $01, $FF, $00
    dc.b    $00, $01, $FF

    even
BlueWizzrobeTeleportOffsetsY:
    dc.b    $00, $00, $00, $00, $01, $01, $01, $00
    dc.b    $FF, $FF, $FF

    even
BlueWizzrobe_Move:
    ; TODO:
    ; Consider calling this function something like MoveSimple8.
    ; Also, consider deleting the references to BlueWizzrobe in
    ; teleport offsets above.
    ;
    ; Index the offsets using the direction value directly.
    ;
    moveq   #0,D3
    lea     ($0098,A4),A0
    move.b  (A0,D2.W),D3
    move.b  ($70,A4,D2.W),D0
    andi    #$EE,CCR  ; CLC: clear C+X
    lea     (BlueWizzrobeTeleportOffsetsX).l,A0
    move.b  (A0,D3.W),D1
    addx.b  D1,D0   ; ADC BlueWizzrobeTeleportOffsetsX,Y
    move.b  D0,($70,A4,D2.W)
    lea     ($0084,A4),A0
    move.b  (A0,D2.W),D0
    andi    #$EE,CCR  ; CLC: clear C+X
    lea     (BlueWizzrobeTeleportOffsetsY).l,A0
    move.b  (A0,D3.W),D1
    addx.b  D1,D0   ; ADC BlueWizzrobeTeleportOffsetsY,Y
    lea     ($0084,A4),A0
    move.b  D0,(A0,D2.W)
    even
L11EAF_Exit:
    rts

    even
BlueWizzrobeTeleportMaxOffsetsX:
    dc.b    $E0, $20, $E0, $20

    even
BlueWizzrobeTeleportMaxOffsetsY:
    dc.b    $E0, $E0, $20, $20

    even
BlueWizzrobeTeleportDirs:
    dc.b    $0A, $09, $06, $05

    even
BlueWizzrobe_ChooseTeleportTarget:
    ; Choose a random value between 0 and 3 that will be used
    ; to test and set a direction to move in.
    ;
    move.b  ($18,A4,D2.W),D0
    andi.b #$03,D0
    moveq   #0,D3
    move.b  D0,D3
    ; The random value implies a random direction.
    ; Save the original X coordinate; and add to it the offset for
    ; the random direction.
    ;
    move.b  ($70,A4,D2.W),D0
    move.b  D0,-(A5)  ; PHA
    andi    #$EE,CCR  ; CLC: clear C+X
    lea     (BlueWizzrobeTeleportMaxOffsetsX).l,A0
    move.b  (A0,D3.W),D1
    addx.b  D1,D0   ; ADC BlueWizzrobeTeleportMaxOffsetsX,Y
    move.b  D0,($70,A4,D2.W)
    ; Save the original Y coordinate; and add to it the offset for
    ; the random direction.
    ;
    lea     ($0084,A4),A0
    move.b  (A0,D2.W),D0
    move.b  D0,-(A5)  ; PHA
    andi    #$EE,CCR  ; CLC: clear C+X
    lea     (BlueWizzrobeTeleportMaxOffsetsY).l,A0
    move.b  (A0,D3.W),D1
    addx.b  D1,D0   ; ADC BlueWizzrobeTeleportMaxOffsetsY,Y
    lea     ($0084,A4),A0
    move.b  D0,(A0,D2.W)
    move.b  D3,D0
    move.b  D0,-(A5)  ; PHA
    ; Test the walkability in the random direction chosen.
    ;
    lea     (BlueWizzrobeTeleportDirs).l,A0
    move.b  (A0,D3.W),D0
    moveq   #0,D3
    move.b  D0,D3
    jsr     Wizzrobe_GetCollidableTileForDir
    move.b  (A5)+,D0  ; PLA
    moveq   #0,D3
    move.b  D0,D3
    move.b  (A5)+,D0  ; PLA
    lea     ($0084,A4),A0
    move.b  D0,(A0,D2.W)
    move.b  (A5)+,D0  ; PLA
    move.b  D0,($70,A4,D2.W)
    ; If not walkable, then all we can do is align with the nearest square.
    ;
    bcc.s  __far_z_04_0083
    jmp  BlueWizzrobe_AlignWithNearestSquareAndRandomizeTimer
__far_z_04_0083:
    ; Set the random diagonal direction.
    ;
    lea     (BlueWizzrobeTeleportDirs).l,A0
    move.b  (A0,D3.W),D0
    lea     ($0098,A4),A0
    move.b  D0,(A0,D2.W)
    even
BeginTeleporting:
    ; Will move $20 pixels horizontally and vertically.
    ;
    moveq   #32,D0
    lea     ($0394,A4),A0
    move.b  D0,(A0,D2.W)
    ; Flip bit 6 of turn counter; so that we change the axis to turn toward.
    ;
    lea     ($0412,A4),A0
    move.b  (A0,D2.W),D0
    eori.b #$40,D0
    lea     ($0412,A4),A0
    move.b  D0,(A0,D2.W)
    ; Reset the timer to note that the monster is teleporting.
    ; Align with the nearest square.
    ;
    moveq   #0,D0
    beq  _anon_z04_100
    even
BlueWizzrobe_AlignWithNearestSquareAndRandomizeTimer:
    ; Set a random timer >= $70.
    ;
    move.b  ($18,A4,D2.W),D0
    ori.b #$70,D0
_anon_z04_100:
    move.b  D0,($28,A4,D2.W)
    even
BlueWizzrobe_AlignWithNearestSquare:
    ; If in the left half of a square, jump to the left edge.
    ; Else jump to the next square.
    ;
    move.b  ($70,A4,D2.W),D0
    andi    #$EE,CCR  ; CLC: clear C+X
    move.b  #$08,D1
    addx.b  D1,D0   ; ADC #$08 (X flag = 6502 C)
    andi.b #$F0,D0
    move.b  D0,($70,A4,D2.W)
    ; If in the top half of a square, jump to the top edge.
    ; Else jump to the next square.
    ;
    lea     ($0084,A4),A0
    move.b  (A0,D2.W),D0
    andi    #$EE,CCR  ; CLC: clear C+X
    move.b  #$08,D1
    addx.b  D1,D0   ; ADC #$08 (X flag = 6502 C)
; Params:
; A: Y coordinate, square ($10) aligned
;
    even
RedWizzrobe_AlignAndSetY:
    andi.b #$F0,D0
    ori     #$11,CCR  ; SEC: set C+X
    move.b  #$03,D1
    eori    #$10,CCR  ; flip X: 6502 SBC polarity
    subx.b  D1,D0   ; SBC #$03
    eori    #$10,CCR  ; restore X = 6502 C
    lea     ($0084,A4),A0
    move.b  D0,(A0,D2.W)
    eori    #$01,CCR  ; normalize C to 6502 polarity before RTS
    rts

    even
WizzrobeCollisionOffsetsX:
    dc.b    $0F, $00, $00, $04, $08, $00, $00, $04
    dc.b    $08, $00

    even
WizzrobeCollisionOffsetsY:
    dc.b    $04, $04, $00, $08, $08, $08, $00, $F8
    dc.b    $00, $00

; Params:
; X: object index
;
; Returns:
; C: 0 if walkable
;
    even
Wizzrobe_GetCollidableTile:
    moveq   #0,D3
    lea     ($0098,A4),A0
    move.b  (A0,D2.W),D3
; Params:
; X: object index
; Y: 8-way direction
;
; Returns:
; C: 0 if walkable
;
; Subtract 1 from direction to make an 8-way direction index.
;
    even
Wizzrobe_GetCollidableTileForDir:
    subq.b  #1,D3
    ; Look up and add the collision offset to the monster's X coordinate.
    ;
    move.b  ($70,A4,D2.W),D0
    move.b  D0,-(A5)  ; PHA
    andi    #$EE,CCR  ; CLC: clear C+X
    lea     (WizzrobeCollisionOffsetsX).l,A0
    move.b  (A0,D3.W),D1
    addx.b  D1,D0   ; ADC WizzrobeCollisionOffsetsX,Y
    move.b  D0,($70,A4,D2.W)
    ; Look up and add the collision offset to the monster's Y coordinate.
    ;
    lea     ($0084,A4),A0
    move.b  (A0,D2.W),D0
    move.b  D0,-(A5)  ; PHA
    andi    #$EE,CCR  ; CLC: clear C+X
    lea     (WizzrobeCollisionOffsetsY).l,A0
    move.b  (A0,D3.W),D1
    addx.b  D1,D0   ; ADC WizzrobeCollisionOffsetsY,Y
    lea     ($0084,A4),A0
    move.b  D0,(A0,D2.W)
    jsr     Wizzrobe_GetBaseCollidableTile
    move.b  (A5)+,D0  ; PLA
    lea     ($0084,A4),A0
    move.b  D0,(A0,D2.W)
    move.b  (A5)+,D0  ; PLA
    move.b  D0,($70,A4,D2.W)
    rts

; Params:
; X: object index
;
; Returns:
; C: 0 if walkable
;
    even
Wizzrobe_GetBaseCollidableTile:
    jsr     GetCollidableTileStill
    lea     ($049E,A4),A0
    move.b  (A0,D2.W),D0
    ; Return C=0 if walkable.
    ;
    move.b  ($034A,A4),D1
    cmp.b   D1,D0
    ; Store the last collided tile.
    ;
    lea     ($041F,A4),A0
    move.b  D0,(A0,D2.W)
    eori    #$01,CCR  ; normalize C to 6502 polarity before RTS
    rts

    even
BlueWizzrobe_TryShooting:
    ; Once every $20 frames, and when not fading, we'll try to shoot.
    ; Otherwise, return.
    ;
    lea     ($0394,A4),A0
    move.b  (A0,D2.W),D0
    beq.s  __far_z_04_0084
    jmp  L11F7E_Exit
__far_z_04_0084:
    move.b  ($0015,A4),D0
    andi.b #$1F,D0
    beq.s  __far_z_04_0085
    jmp  L11F7E_Exit
__far_z_04_0085:
    ; If Link and the monster are not within the same square row,
    ; then go see about the same square column.
    ;
    lea     ($0084,A4),A0
    move.b  (A0,D2.W),D0
    andi.b #$F0,D0
    move.b  D0,($0000,A4)
    move.b  ($0084,A4),D0
    andi.b #$F0,D0
    move.b  ($0000,A4),D1
    cmp.b   D1,D0
    beq.s  __far_z_04_0086
    jmp  BlueWizzrobe_CheckSquareColumn
__far_z_04_0086:
    ; If the monster is to the right of Link, then choose left.
    ; Else choose right.
    ;
    moveq   #2,D0
    moveq   #0,D3
    move.b  ($70,A4,D2.W),D3
    move.b  ($0070,A4),D1
    cmp.b   D1,D3
    bcc  _anon_z04_101
    lsr.b  #1,D0   ; LSR A
_anon_z04_101:
    ; If the direction chosen = the monster's facing direction,
    ; then go shoot.
    ;
    lea     ($0098,A4),A0
    move.b  (A0,D2.W),D1
    cmp.b   D1,D0
    bne.s  __far_z_04_0087
    jmp  ShootMagicShot58
__far_z_04_0087:
    even
L11F7E_Exit:
    rts

    even
BlueWizzrobe_CheckSquareColumn:
    ; If Link and the monster are not within the same square column,
    ; then return.
    ;
    move.b  ($70,A4,D2.W),D0
    andi.b #$F0,D0
    move.b  D0,($0000,A4)
    move.b  ($0070,A4),D0
    move.b  ($0000,A4),D1
    cmp.b   D1,D0
    beq.s  __far_z_04_0088
    jmp  L11F7E_Exit
__far_z_04_0088:
    ; If the monster is down from Link, then choose up.
    ; Else choose down.
    ;
    moveq   #8,D0
    moveq   #0,D3
    lea     ($0084,A4),A0
    move.b  (A0,D2.W),D3
    move.b  ($0084,A4),D1
    cmp.b   D1,D3
    bcc  _anon_z04_102
    lsr.b  #1,D0   ; LSR A
_anon_z04_102:
    ; If the direction chosen <> the monster's facing direction,
    ; then return.
    ;
    lea     ($0098,A4),A0
    move.b  (A0,D2.W),D1
    cmp.b   D1,D0
    beq.s  __far_z_04_0089
    jmp  L11F7E_Exit
__far_z_04_0089:
    even
ShootMagicShot58:
    moveq   #88,D0
; Params:
; A: shot object type
;
    even
ShootMagicShot:
    move.b  D0,($0000,A4)
    ; If we have the magic clock, then return.
    ;
    move.b  ($066C,A4),D0
    beq.s  __far_z_04_0090
    jmp  L11F7E_Exit
__far_z_04_0090:
    ; Else play the magic sound, shoot, and return.
    ;
    moveq   #4,D0
    move.b  D0,($0604,A4)
    jmp     ShootLimited

    even
UpdateRedWizzrobe:
    ; If we have the magic clock, then go check collisions and draw.
    ;
    move.b  ($066C,A4),D0
    beq  _anon_z04_103
    jmp     Wizzrobe_DrawAndCheckCollisions

_anon_z04_103:
    ; Else increase animation counter and decrease state every frame.
    ;
    lea     ($0412,A4),A0
    addq.b  #1,(A0,D2.W)
    lea     ($00AC,A4),A0
    subq.b  #1,(A0,D2.W)
    ; Shift the state right 6 times to get the index (0 to 3) of a state routine.
    ;
    lea     ($00AC,A4),A0
    move.b  (A0,D2.W),D0
    lsr.b  #1,D0   ; LSR A
    lsr.b  #1,D0   ; LSR A
    lsr.b  #1,D0   ; LSR A
    lsr.b  #1,D0   ; LSR A
    lsr.b  #1,D0   ; LSR A
    lsr.b  #1,D0   ; LSR A
    jsr     _m68k_tablejump  ; M68K-native table dispatch (replaces JSR TableJump)
    even
UpdateRedWizzrobe_JumpTable:
    dc.l    UpdateRedWizzrobe_0   ; jump table entry (32-bit for _m68k_tablejump)
    dc.l    UpdateRedWizzrobe_1   ; jump table entry (32-bit for _m68k_tablejump)
    dc.l    UpdateRedWizzrobe_2   ; jump table entry (32-bit for _m68k_tablejump)
    dc.l    UpdateRedWizzrobe_3   ; jump table entry (32-bit for _m68k_tablejump)

    even
RedWizzrobeOffsetsX:
    dc.b    $00, $00, $E0, $20, $00, $00, $C0, $40
    dc.b    $00, $00, $D0, $30, $00, $00, $B0, $50

    even
RedWizzrobeOffsetsY:
    dc.b    $E0, $20, $00, $00, $C0, $40, $00, $00
    dc.b    $D0, $30, $00, $00, $B0, $50, $00, $00

    even
RedWizzrobeDirections:
    dc.b    $04, $08, $01, $02

    even
UpdateRedWizzrobe_1:
    ; Handle state group 1 ($40 to $7F).
    ;
    ; If state = $7F, make it $4F.
    ; $7F is the first frame of state group ($40 to $7F).
    ; By doing this, we skip $30 frames.
    ;
    lea     ($00AC,A4),A0
    move.b  (A0,D2.W),D0
    cmpi.b  #$7F,D0
    bne  _anon_z04_104
    moveq   #79,D0
    lea     ($00AC,A4),A0
    move.b  D0,(A0,D2.W)
_anon_z04_104:
    ; Increment the fade counter. Depending on the low bit,
    ; the monster will be drawn every other frame.
    ;
    lea     ($0394,A4),A0
    addq.b  #1,(A0,D2.W)
    jmp     Wizzrobe_DrawAndCheckCollisionsIntermittently

    even
UpdateRedWizzrobe_3:
    ; Handle state group 3 ($C0 to $FF).
    ;
    ; If state <> $FF, go fade as in state group 1.
    ;
    moveq   #0,D3
    lea     ($00AC,A4),A0
    move.b  (A0,D2.W),D3
    addq.b  #1,D3
    beq.s  __far_z_04_0091
    jmp  UpdateRedWizzrobe_1
__far_z_04_0091:
    ; State $FF.
    ;
    ; Face in a random direction.
    ;
    move.b  ($18,A4,D2.W),D0
    move.b  D0,-(A5)  ; PHA
    andi.b #$03,D0
    moveq   #0,D3
    move.b  D0,D3
    lea     (RedWizzrobeDirections).l,A0
    move.b  (A0,D3.W),D0
    lea     ($0098,A4),A0
    move.b  D0,(A0,D2.W)
    move.b  (A5)+,D0  ; PLA
    ; Use a random value from 0 to $F to index into an array of offsets.
    ;
    andi.b #$0F,D0
    moveq   #0,D3
    move.b  D0,D3
    move.b  ($0070,A4),D0
    ; Add the X offset and Link's X to set the monster's position.
    ;
    lea     (RedWizzrobeOffsetsX).l,A0
    move.b  (A0,D3.W),D1
    addx.b  D1,D0   ; ADC RedWizzrobeOffsetsX,Y
    andi.b #$F0,D0
    move.b  D0,($70,A4,D2.W)
    ; Add the Y offset and Link's Y to set the monster's position.
    ;
    move.b  ($0084,A4),D0
    andi    #$EE,CCR  ; CLC: clear C+X
    move.b  #$03,D1
    addx.b  D1,D0   ; ADC #$03 (X flag = 6502 C)
    lea     (RedWizzrobeOffsetsY).l,A0
    move.b  (A0,D3.W),D1
    addx.b  D1,D0   ; ADC RedWizzrobeOffsetsY,Y
    jsr     RedWizzrobe_AlignAndSetY
    ; If Y coordinate >= $5D and < $C4, then the monster
    ; is not in a wall. So, check tile collision.
    ;
    cmpi.b  #$5D,D0
    bcs  _anon_z04_105
    cmpi.b  #$C4,D0
    bcc  _anon_z04_105
    jsr     Wizzrobe_GetCollidableTile
    ; If walkable, then return.
    ; Else increase state to 0, in order to check again next frame.
    ;
    bcs.s  __far_z_04_0092
    jmp  UpdateRedWizzrobe_0
__far_z_04_0092:
_anon_z04_105:
    lea     ($00AC,A4),A0
    addq.b  #1,(A0,D2.W)
    even
UpdateRedWizzrobe_0:
    rts

    even
UpdateRedWizzrobe_2:
    ; Handle state group 2 ($80 to $BF).
    ;
    ; If state = $B0, then shoot a magic shot $59.
    ;
    lea     ($00AC,A4),A0
    move.b  (A0,D2.W),D0
    cmpi.b  #$B0,D0
    beq.s  __far_z_04_0093
    jmp  Wizzrobe_DrawAndCheckCollisions
__far_z_04_0093:
    moveq   #89,D0
    jsr     ShootMagicShot
    even
Wizzrobe_DrawAndCheckCollisions:
    ; Invincible to everything but sword and bomb.
    ;
    move.b  #$F6,D0
    lea     ($04B2,A4),A0
    move.b  D0,(A0,D2.W)
    jsr     GetObjectMiddle
    ; If invincibility timer = 0, then check collisions with weapons.
    ;
    lea     ($04F0,A4),A0
    move.b  (A0,D2.W),D0
    bne  _anon_z04_106
    moveq   #14,D3
    jsr     CheckMonsterSwordShotOrMagicShotCollision
    moveq   #16,D3
    jsr     CheckMonsterBombOrFireCollision
    moveq   #17,D3
    jsr     CheckMonsterBombOrFireCollision
    moveq   #13,D3
    jsr     CheckMonsterSwordCollision
_anon_z04_106:
    ; In this state, the monster can always harm Link,
    ; even if it can't be harmed.
    ;
    jsr     CheckLinkCollision
    ; Every 4 frames switch between two frame images.
    ;
    lea     ($0412,A4),A0
    move.b  (A0,D2.W),D0
    lsr.b  #1,D0   ; LSR A
    lsr.b  #1,D0   ; LSR A
    andi.b #$01,D0
    move.b  D0,-(A5)  ; PHA
    jsr     Anim_FetchObjPosForSpriteDescriptor
    ; If facing up, then go add 2 to frame image number, and draw mirrored.
    ;
    lea     ($0098,A4),A0
    move.b  (A0,D2.W),D0
    andi.b #$08,D0
    bne  _anon_z04_107
    ; If facing left, then flip horizontally.
    ;
    lea     ($0098,A4),A0
    move.b  (A0,D2.W),D0
    lsr.b  #1,D0   ; LSR A
    andi.b #$01,D0
    move.b  D0,($000F,A4)
    move.b  (A5)+,D0  ; PLA
    jmp     DrawObjectNotMirrored

_anon_z04_107:
    move.b  (A5)+,D0  ; PLA
    andi    #$EE,CCR  ; CLC: clear C+X
    move.b  #$02,D1
    addx.b  D1,D0   ; ADC #$02 (X flag = 6502 C)
    jmp     DrawObjectMirrored

    even
GleeokSegmentYs:
    dc.b    $6F, $74, $79, $7E, $83, $88

    even
InitGleeok:
    moveq   #16,D0
    move.b  D0,($0601,A4)
    ; Loop 6 times to initialize each segment of 4 necks.
    ;
    moveq   #5,D2
_anon_z04_108:
    ; Set the X of the current segment of each neck to $7C.
    ;
    moveq   #124,D0
    lea     ($0438,A4),A0
    move.b  D0,(A0,D2.W)
    lea     ($0452,A4),A0
    move.b  D0,(A0,D2.W)
    lea     ($046C,A4),A0
    move.b  D0,(A0,D2.W)
    lea     ($0395,A4),A0
    move.b  D0,(A0,D2.W)
    move.b  D0,($71,A4,D2.W)
    ; Look up and set the Y of the current segment of each neck.
    ;
    lea     (GleeokSegmentYs).l,A0
    move.b  (A0,D2.W),D0
    lea     ($0445,A4),A0
    move.b  D0,(A0,D2.W)
    lea     ($045F,A4),A0
    move.b  D0,(A0,D2.W)
    lea     ($0479,A4),A0
    move.b  D0,(A0,D2.W)
    lea     ($03BD,A4),A0
    move.b  D0,(A0,D2.W)
    lea     ($0085,A4),A0
    move.b  D0,(A0,D2.W)
    ; Set HP of each neck to $A0.
    ;
    ; Because there's only one HP value for each neck,
    ; it's stored right in the object slot -- unlike coordinates.
    ;
    ; Also, note that even though these aren't independent objects
    ; in the object slots -- because object type = 0 -- the values in
    ; these object slots will be useful during collision detection.
    ;
    move.b  #$A0,D0
    lea     ($0486,A4),A0
    move.b  D0,(A0,D2.W)
    ; Reset metastate and unintialized flag, so that this neck is ready to go.
    ;
    moveq   #0,D0
    lea     ($0406,A4),A0
    move.b  D0,(A0,D2.W)
    lea     ($0494,A4),A0
    move.b  D0,(A0,D2.W)
    ; Invincible to everything but the sword.
    ;
    move.b  #$FE,D0
    lea     ($04B3,A4),A0
    move.b  D0,(A0,D2.W)
    ; Bottom of the loop.
    ;
    subq.b  #1,D2
    bpl  _anon_z04_108
    ; Set speed flags to $FF (non-0/decelerate):
    ; * neck 0 X
    ; * neck 1 Y
    ; * neck 2 X
    ; * neck 3 Y
    ;
    ; Leave the other other speed flags 0 (accelerate).
    ;
    move.b  D2,(Gleook_HeadInfo0+GLEEOK_SPEEDX).l
    move.b  D2,(Gleook_HeadInfo1+GLEEOK_SPEEDY).l
    move.b  D2,(Gleook_HeadInfo2+GLEEOK_SPEEDX).l
    move.b  D2,(Gleook_HeadInfo3+GLEEOK_SPEEDY).l
    ; Set the V-direction counter of all necks to 3.
    ;
    moveq   #3,D0
    move.b  D0,(Gleook_HeadInfo0+GLEEOK_DIRCOUNTERV).l
    move.b  D0,(Gleook_HeadInfo1+GLEEOK_DIRCOUNTERV).l
    move.b  D0,(Gleook_HeadInfo2+GLEEOK_DIRCOUNTERV).l
    move.b  D0,(Gleook_HeadInfo3+GLEEOK_DIRCOUNTERV).l
    ; Set the H-direction counter of all necks to 6.
    ;
    lsl.b  #1,D0   ; ASL A
    move.b  D0,(Gleook_HeadInfo0+GLEEOK_DIRCOUNTERH).l
    move.b  D0,(Gleook_HeadInfo1+GLEEOK_DIRCOUNTERH).l
    move.b  D0,(Gleook_HeadInfo2+GLEEOK_DIRCOUNTERH).l
    move.b  D0,(Gleook_HeadInfo3+GLEEOK_DIRCOUNTERH).l
    ; Set neck 1 head delay timer to 12.
    ;
    lsl.b  #1,D0   ; ASL A
    move.b  D0,(Gleook_HeadInfo1+GLEEOK_DELAY).l
    ; Set neck 2 head delay timer to 24.
    ;
    lsl.b  #1,D0   ; ASL A
    move.b  D0,(Gleook_HeadInfo2+GLEEOK_DELAY).l
    ; Set neck 3 head delay timer to 36.
    ;
    move.b  (Gleook_HeadInfo1+GLEEOK_DELAY).l,D1
    addx.b  D1,D0   ; ADC Gleook_HeadInfo1+GLEEOK_DELAY
    move.b  D0,(Gleook_HeadInfo3+GLEEOK_DELAY).l
    ; Leave neck 0 head delay timer as 0.
    ;
    rts

    even
ManhandlaBaseFrameImagesAndAttrs:
    dc.b    $00, $80, $02, $42, $04

    even
ManhandlaSegmentOffsetsX:
    dc.b    $00, $00

    even
ManhandlaSegmentOffsetsY:
    dc.b    $F0, $10, $00, $00, $00

    even
InitManhandla:
    moveq   #64,D0
    move.b  D0,($0601,A4)
    ; Choose a random 8-way direction.
    ;
    move.b  ($18,A4,D2.W),D0
    andi.b #$07,D0
    moveq   #0,D3
    move.b  D0,D3
    lea     (Directions8).l,A0
    move.b  (A0,D3.W),D0
    lea     ($0098,A4),A0
    move.b  D0,(A0,D2.W)
    ; For 5 segments, from 4 to 0, indexed by Y register:
    ; Object slots 5 to 1 are accessed.
    ;
    moveq   #4,D3
_anon_z04_109:
    ; Copy the direction from the base segment.
    ;
    move.b  ($0099,A4),D0
    lea     ($0099,A4),A0
    move.b  D0,(A0,D3.W)
    ; All segments are considered Manhandla.
    ;
    moveq   #60,D0
    lea     ($0350,A4),A0
    move.b  D0,(A0,D3.W)
    ; Set the segment invincible to fire and boomerang.
    ;
    move.b  #$E2,D0
    lea     ($04B3,A4),A0
    move.b  D0,(A0,D3.W)
    ; Look up and store the base frame image and sprite attributes byte.
    ;
    ; While updating, the low bit will be flipped on and off
    ; for each animation frame.
    ;
    lea     (ManhandlaBaseFrameImagesAndAttrs).l,A0
    move.b  (A0,D3.W),D0
    lea     ($0479,A4),A0
    move.b  D0,(A0,D3.W)
    ; All segments start out autonomous, and can update immediately.
    ;
    moveq   #0,D0
    lea     ($0406,A4),A0
    move.b  D0,(A0,D3.W)
    lea     ($0493,A4),A0
    move.b  D0,(A0,D3.W)
    ; Copy object attributes and HP from the base segment.
    ;
    move.b  ($04C0,A4),D0
    lea     ($04C0,A4),A0
    move.b  D0,(A0,D3.W)
    move.b  ($0486,A4),D0
    lea     ($0486,A4),A0
    move.b  D0,(A0,D3.W)
    ; Look up the offset of this segment. Add it to the position of
    ; the base segment.
    ;
    ; The position of the base segment in slot 5 is calculated first.
    ; Its base position is the spawn position.
    ;
    move.b  ($0075,A4),D0
    andi    #$EE,CCR  ; CLC: clear C+X
    lea     (ManhandlaSegmentOffsetsX).l,A0
    move.b  (A0,D3.W),D1
    addx.b  D1,D0   ; ADC ManhandlaSegmentOffsetsX,Y
    move.b  D0,($71,A4,D3.W)
    move.b  ($0089,A4),D0
    andi    #$EE,CCR  ; CLC: clear C+X
    lea     (ManhandlaSegmentOffsetsY).l,A0
    move.b  (A0,D3.W),D1
    addx.b  D1,D0   ; ADC ManhandlaSegmentOffsetsY,Y
    lea     ($0085,A4),A0
    move.b  D0,(A0,D3.W)
    ; Set low speed byte $80.
    ;
    move.b  #$80,D0
    lea     ($0420,A4),A0
    move.b  D0,(A0,D3.W)
    subq.b  #1,D3
    bpl  _anon_z04_109
    rts

    even
InitGohma:
    moveq   #32,D0
    move.b  D0,($0601,A4)
    ; Invincible to everything but arrows.
    ;
    move.b  #$FB,D0
    lea     ($04B2,A4),A0
    move.b  D0,(A0,D2.W)
    ; Set shoot timer to 1, so that Gohma doesn't shoot right away.
    ;
    lea     ($0380,A4),A0
    addq.b  #1,(A0,D2.W)
    ; Start at location ($80, $70).
    ;
    move.b  #$80,D0
    move.b  D0,($70,A4,D2.W)
    moveq   #112,D0
    lea     ($0084,A4),A0
    move.b  D0,(A0,D2.W)
    jmp     ResetObjMetastateAndTimer

    even
InitGleeokHead:
    jsr     InitBlueKeese
    ; Set flying speed $BF and maximum $E0.
    ;
    move.b  #$E0,D0
    move.b  D0,($04D1,A4)
    move.b  #$BF,D0
    lea     ($041F,A4),A0
    move.b  D0,(A0,D2.W)
    rts

    even
UpdateManhandla:
    ; If this segment is not the base, then skip turning and speeding up.
    ;
    cmpi.b  #$05,D2
    bne  _L_z04_UpdateManhandla_MoveBase
    ; If no segment just died, then skip increasing the speed.
    ;
    move.b  ($0383,A4),D0
    beq  _L_z04_UpdateManhandla_BounceIfNeeded
    ; For each segment from 4 to 0, indexed by Y register:
    ;
    moveq   #4,D3
    even
_L_z04_UpdateManhandla_LoopSegment:
    ; Add $80 to the low speed byte of this segment.
    ;
    lea     ($0420,A4),A0
    move.b  (A0,D3.W),D0
    andi    #$EE,CCR  ; CLC: clear C+X
    move.b  #$80,D1
    addx.b  D1,D0   ; ADC #$80 (X flag = 6502 C)
    lea     ($0420,A4),A0
    move.b  D0,(A0,D3.W)
    ; Carry to the high speed byte of this segment.
    ;
    lea     ($042D,A4),A0
    move.b  (A0,D3.W),D0
    move.b  #$00,D1
    addx.b  D1,D0   ; ADC #$00 (X flag = 6502 C)
    lea     ($042D,A4),A0
    move.b  D0,(A0,D3.W)
    subq.b  #1,D3
    bpl  _L_z04_UpdateManhandla_LoopSegment
    ; Reset the "a segment just died" flag.
    ;
    moveq   #0,D0
    move.b  D0,($0383,A4)
    even
_L_z04_UpdateManhandla_BounceIfNeeded:
    ; If there's a bounce direction, then assign it to the facing
    ; direction of all segments.
    ;
    move.b  ($0385,A4),D0
    beq  _L_z04_UpdateManhandla_TurnIfNeeded
    jsr     Manhandla_SetAllSegmentsDirection
    even
_L_z04_UpdateManhandla_TurnIfNeeded:
    ; If object timer = 0, then
    ; 1. set timer to $10
    ; 2. randomly choose to turn toward Link or turn randomly
    ; 3. assign the base's direction to all segments and bounce direction
    ;
    move.b  ($28,A4,D2.W),D0
    bne  _L_z04_UpdateManhandla_MoveBase
    moveq   #16,D0
    move.b  D0,($28,A4,D2.W)
    move.b  ($18,A4,D2.W),D0
    cmpi.b  #$80,D0
    bcc  _L_z04_UpdateManhandla_TurnTowardLink
    jsr     TurnRandomlyDir8
    even
_L_z04_UpdateManhandla_CopyDirToHands:
    move.b  ($009D,A4),D0
    move.b  D0,($0385,A4)
    jsr     Manhandla_SetAllSegmentsDirection
    even
_L_z04_UpdateManhandla_MoveBase:
    ; If this segment is the base, then remember the
    ; facing direction before moving.
    ;
    ; This is a continuation of the code above,
    ; which is also only for the base.
    ;
    cmpi.b  #$05,D2
    bne  _anon_z04_110
    lea     ($0098,A4),A0
    move.b  (A0,D2.W),D0
    move.b  D0,($0384,A4)
_anon_z04_110:
    jsr     Manhandla_Move
    jsr     Manhandla_CheckCollisions
    ; If the direction changed after moving, then
    ; copy it to the bounce direction.
    ;
    lea     ($0098,A4),A0
    move.b  (A0,D2.W),D0
    move.b  ($0384,A4),D1
    cmp.b   D1,D0
    beq  _anon_z04_111
    move.b  D0,($0385,A4)
_anon_z04_111:
    ; Store in [00] the animation frame that you get from the frame accumulator:
    ; frame := ((accumulator AND $10) >> 4
    ;
    lea     ($0451,A4),A0
    move.b  (A0,D2.W),D0
    andi.b #$10,D0
    lsr.b  #1,D0   ; LSR A
    lsr.b  #1,D0   ; LSR A
    lsr.b  #1,D0   ; LSR A
    lsr.b  #1,D0   ; LSR A
    move.b  D0,($0000,A4)
    ; Copy the animation frame bit into the "frame image and
    ; sprite attributes" byte.
    ;
    lea     ($0478,A4),A0
    move.b  (A0,D2.W),D0
    andi.b #$FE,D0
    move.b  ($0000,A4),D1
    or.b  D1,D0
    lea     ($0478,A4),A0
    move.b  D0,(A0,D2.W)
    ; If this segment is the base, then go draw.
    ;
    cmpi.b  #$05,D2
    beq  _L_z04_UpdateManhandla_Draw
    ; If the old and new "frame image and sprite attributes" variables
    ; are the same, then go draw.
    ;
    ; The previous frame value begins with value 0, because all
    ; room data was reset on entry.
    ;
    lea     ($0478,A4),A0
    move.b  (A0,D2.W),D0
    lea     ($0437,A4),A0
    move.b  (A0,D2.W),D1
    cmp.b   D1,D0
    beq  _L_z04_UpdateManhandla_Draw
    ; Copy the new value to the old variable, so that they're the same.
    ;
    lea     ($0437,A4),A0
    move.b  D0,(A0,D2.W)
    ; If animation frame = 1, then go draw.
    ;
    ; The low bit of "frame image and sprite attributes" byte
    ; represents the animation frame.
    ;
    lsr.b  #1,D0   ; LSR A
    bcs  _L_z04_UpdateManhandla_Draw
    ; If the random value for the next slot up < $E0,
    ; or there's an object in slot 7; then go draw.
    ;
    ; The second condition keeps the number of fireballs <= 4.
    ;
    move.b  ($19,A4,D2.W),D0
    cmpi.b  #$E0,D0
    bcs  _L_z04_UpdateManhandla_Draw
    move.b  ($0356,A4),D0
    bne  _L_z04_UpdateManhandla_Draw
    moveq   #86,D0
    jsr     ShootFireball
    even
_L_z04_UpdateManhandla_Draw:
    jmp     Manhandla_Draw

    even
_L_z04_UpdateManhandla_TurnTowardLink:
    jsr     TurnTowardsPlayer8
    jmp     _L_z04_UpdateManhandla_CopyDirToHands

    even
Manhandla_CheckCollisions:
    ; Check collisions, but never let them interfere with movement.
    ;
    lea     ($0098,A4),A0
    move.b  (A0,D2.W),D0
    move.b  D0,-(A5)  ; PHA
    move.b  ($28,A4,D2.W),D0
    move.b  D0,-(A5)  ; PHA
    jsr     CheckMonsterCollisions
    move.b  (A5)+,D0  ; PLA
    move.b  D0,($28,A4,D2.W)
    move.b  (A5)+,D0  ; PLA
    lea     ($0098,A4),A0
    move.b  D0,(A0,D2.W)
    ; Don't let the base segment be temporarily invincible.
    ;
    cmpi.b  #$05,D2
    bne  _anon_z04_112
    moveq   #0,D0
    lea     ($04F0,A4),A0
    move.b  D0,(A0,D2.W)
_anon_z04_112:
    jsr     PlayBossHitCryIfNeeded
    ; If still alive, then return.
    ;
    lea     ($0405,A4),A0
    move.b  (A0,D2.W),D0
    beq  _L_z04_Manhandla_CheckCollisions_Exit
    jsr     ResetShoveInfo
    ; Don't let the base die on its own.
    ; If this is the base, then reset metastate, and return.
    ;
    ; The base only dies once the last hand dies.
    ;
    cmpi.b  #$05,D2
    bne  _L_z04_Manhandla_CheckCollisions_CountHands
    lea     ($0405,A4),A0
    move.b  D0,(A0,D2.W)
    jmp     _L_z04_Manhandla_CheckCollisions_Exit

    even
_L_z04_Manhandla_CheckCollisions_CountHands:
    ; At this point, we have a hand that just died.
    ;
    ; For each hand, from 3 to 0, indexed by 0:
    ;
    moveq   #3,D3
    ; Count how many are allocated.
    ; This includes the current dead one, and the other living ones.
    ; Store the count in [00].
    ;
    moveq   #0,D0
    move.b  D0,($0000,A4)
    even
_L_z04_Manhandla_CheckCollisions_LoopHand:
    lea     ($0350,A4),A0
    move.b  (A0,D3.W),D0
    cmpi.b  #$3C,D0
    bne  _anon_z04_113
    addq.b  #1,($0000,A4)
_anon_z04_113:
    subq.b  #1,D3
    bpl  _L_z04_Manhandla_CheckCollisions_LoopHand
    ; Decrease by 1, to account for the current dead one.
    ;
    subq.b  #1,($0000,A4)
    ; If the count >= 0 (signed comparison), then
    ; go change this hand object to the dead dummy.
    ;
    bmi  _anon_z04_114
    bne  _L_z04_Manhandla_CheckCollisions_MakeDeadDummy
_anon_z04_114:
    ; The last hand died. So, kill the base.
    ;
    ; Change the base segment's object type to the dead dummy.
    ; Immediately set metastate to $10, instead of waiting for
    ; the dead dummy object's update routine to do it.
    ; Also set its timer to $10.
    ;
    jsr     PlayBossDeathCry
    moveq   #93,D0
    move.b  D0,($0354,A4)
    moveq   #16,D0
    move.b  D0,($040A,A4)
    move.b  D0,($002D,A4)
    even
_L_z04_Manhandla_CheckCollisions_FlagHandDied:
    ; Set the "segment just died" flag.
    ;
    addq.b  #1,($0383,A4)
    even
_L_z04_Manhandla_CheckCollisions_Exit:
    rts

    even
_L_z04_Manhandla_CheckCollisions_MakeDeadDummy:
    moveq   #93,D0
    lea     ($034F,A4),A0
    move.b  D0,(A0,D2.W)
    jmp     _L_z04_Manhandla_CheckCollisions_FlagHandDied

; Params:
; A: direction
;
    even
Manhandla_SetAllSegmentsDirection:
    moveq   #4,D3
_anon_z04_115:
    lea     ($0099,A4),A0
    move.b  D0,(A0,D3.W)
    subq.b  #1,D3
    bpl  _anon_z04_115
    rts

    even
Manhandla_Move:
    ; Implement a way of manifesting the fractional part of the speed
    ; in the movement.
    ;
    ; Let's say the 16-bit speed is $0140. If we only took the high
    ; byte to add to the coordinates, then the effective speed would
    ; be 1 pixel a frame instead of 1.25.
    ;
    ; By keeping a speed accumulator, we can turn speed $0140
    ; into 1.25 pixels a frame over four frames, using this calculation:
    ;
    ;   (SA=speed accumulator, SH=speed high, SL=speed low)
    ;
    ;   SA := SA + (SL AND $E0)
    ;   [03] := SH + carry
    ;
    ; AND'ing the low speed byte with $E0 isn't strictly needed.
    ;
    lea     ($041F,A4),A0
    move.b  (A0,D2.W),D0
    andi.b #$E0,D0
    andi    #$EE,CCR  ; CLC: clear C+X
    lea     ($0412,A4),A0
    move.b  (A0,D2.W),D1
    addx.b  D1,D0   ; ADC Manhandla_ObjSpeedAccum,X
    lea     ($0412,A4),A0
    move.b  D0,(A0,D2.W)
    ; Assign (high speed byte + carry) to [03].
    ;
    lea     ($042C,A4),A0
    move.b  (A0,D2.W),D0
    move.b  #$00,D1
    addx.b  D1,D0   ; ADC #$00 (X flag = 6502 C)
    move.b  D0,($0003,A4)
    ; Change coordinates by the speed amount/offset in [03]
    ; according to the direction.
    ;
    ; Start with a mask of $A1 in [02]:
    ; - low nibble represents the right direction
    ; - high nibble is used to set or clear carry as we go along
    ;
    move.b  #$A1,D0
    move.b  D0,($0002,A4)
    ; If direction has a right component (1), then add offset to X coordinate.
    ;
    lea     ($0098,A4),A0
    move.b  (A0,D2.W),D0
    move.b  ($0002,A4),D1
    and.b   D0,D1   ; BIT: set Z/N/V from D1 AND A
    beq  _L_z04_Manhandla_Move_Left
    move.b  ($70,A4,D2.W),D0
    andi    #$EE,CCR  ; CLC: clear C+X
    move.b  ($0003,A4),D1
    addx.b  D1,D0   ; ADC $03
    move.b  D0,($70,A4,D2.W)
    even
_L_z04_Manhandla_Move_Left:
    ; If direction has a left component (2), then subtract offset from X coordinate.
    ;
    lea     ($0098,A4),A0
    move.b  (A0,D2.W),D0
    move.b  ($0002,A4),D1
    lsl.b  #1,D1   ; ASL $02
    move.b  D1,($0002,A4)
    move.b  ($0002,A4),D1
    and.b   D0,D1   ; BIT: set Z/N/V from D1 AND A
    beq  _L_z04_Manhandla_Move_Down
    move.b  ($70,A4,D2.W),D0
    move.b  ($0003,A4),D1
    eori    #$10,CCR  ; flip X: 6502 SBC polarity
    subx.b  D1,D0   ; SBC $03
    eori    #$10,CCR  ; restore X = 6502 C
    move.b  D0,($70,A4,D2.W)
    even
_L_z04_Manhandla_Move_Down:
    ; If direction has a down component (4), then add offset to Y coordinate.
    ;
    lea     ($0098,A4),A0
    move.b  (A0,D2.W),D0
    move.b  ($0002,A4),D1
    lsl.b  #1,D1   ; ASL $02
    move.b  D1,($0002,A4)
    move.b  ($0002,A4),D1
    and.b   D0,D1   ; BIT: set Z/N/V from D1 AND A
    beq  _L_z04_Manhandla_Move_Up
    lea     ($0084,A4),A0
    move.b  (A0,D2.W),D0
    move.b  ($0003,A4),D1
    addx.b  D1,D0   ; ADC $03
    lea     ($0084,A4),A0
    move.b  D0,(A0,D2.W)
    even
_L_z04_Manhandla_Move_Up:
    ; If direction has an up component (8), then subtract offset from Y coordinate.
    ;
    lea     ($0098,A4),A0
    move.b  (A0,D2.W),D0
    move.b  ($0002,A4),D1
    lsl.b  #1,D1   ; ASL $02
    move.b  D1,($0002,A4)
    move.b  ($0002,A4),D1
    and.b   D0,D1   ; BIT: set Z/N/V from D1 AND A
    beq  _L_z04_Manhandla_Move_IncFrameAccum
    lea     ($0084,A4),A0
    move.b  (A0,D2.W),D0
    move.b  ($0003,A4),D1
    eori    #$10,CCR  ; flip X: 6502 SBC polarity
    subx.b  D1,D0   ; SBC $03
    eori    #$10,CCR  ; restore X = 6502 C
    lea     ($0084,A4),A0
    move.b  D0,(A0,D2.W)
    even
_L_z04_Manhandla_Move_IncFrameAccum:
    ; To the frame accumulator, add:
    ; - a random value between 0 and 3
    ; - [03] the effective high speed byte calculated for this screen frame
    ;
    move.b  ($19,A4,D2.W),D0
    andi.b #$03,D0
    andi    #$EE,CCR  ; CLC: clear C+X
    move.b  ($0003,A4),D1
    addx.b  D1,D0   ; ADC $03
    lea     ($0451,A4),A0
    move.b  (A0,D2.W),D1
    addx.b  D1,D0   ; ADC Manhandla_ObjFrameAccum,X
    lea     ($0451,A4),A0
    move.b  D0,(A0,D2.W)
    jsr     BoundFlyer
    ; TODO:
    ; I don't see why this is needed.
    ;
    jmp     Anim_FetchObjPosForSpriteDescriptor

    even
Manhandla_Draw:
    jsr     Anim_FetchObjPosForSpriteDescriptor
    ; Push the "frame image and sprite attributes" value.
    ;
    lea     ($0478,A4),A0
    move.b  (A0,D2.W),D0
    move.b  D0,-(A5)  ; PHA
    ; Bit 7 is the sprite attribute for vertical flipping, and can be
    ; passed along as is.
    ;
    andi.b #$80,D0
    ori.b #$01,D0
    jsr     Anim_SetSpriteDescriptorAttributes
    move.b  (A5)+,D0  ; PLA
    move.b  D0,-(A5)  ; PHA
    ; If bit 6 is set, then enable horizontal flipping in [0F].
    ;
    andi.b #$40,D0
    beq  _anon_z04_116
    addq.b  #1,($000F,A4)
_anon_z04_116:
    move.b  (A5)+,D0  ; PLA
    ; If the low nibble = 2 or 3, then go draw not mirrored.
    ; These are the 2 frame images of the horizontal hands.
    ;
    ; Else draw the base and vertical hands mirrored.
    ;
    andi.b #$0F,D0
    cmpi.b  #$02,D0
    beq  _anon_z04_117
    cmpi.b  #$03,D0
    beq  _anon_z04_117
    jmp     DrawObjectMirrored

_anon_z04_117:
    jmp     DrawObjectNotMirrored

    even
UpdateGohma:
    ; If flagged not to continue straight, then choose a random facing direction.
    ;
    lea     ($0451,A4),A0
    move.b  (A0,D2.W),D0
    bne  _L_z04_UpdateGohma_Move
    ; If Random:
    ;   >= $B0: right
    ;   >= $60: left
    ;   Else:   down
    ;
    moveq   #1,D0
    moveq   #0,D3
    move.b  ($18,A4,D2.W),D3
    cmpi.b  #$B0,D3
    bcc  _L_z04_UpdateGohma_ChangeDir
    lsl.b  #1,D0   ; ASL A
    cmpi.b  #$60,D3
    bcc  _L_z04_UpdateGohma_ChangeDir
    lsl.b  #1,D0   ; ASL A
    even
_L_z04_UpdateGohma_ChangeDir:
    lea     ($0098,A4),A0
    move.b  D0,(A0,D2.W)
    ; Now we can go straight without changing direction for some time.
    ;
    lea     ($0451,A4),A0
    addq.b  #1,(A0,D2.W)
    ; Go animate the eye.
    ;
    jmp     _L_z04_UpdateGohma_AnimateEye

    even
_L_z04_UpdateGohma_Move:
    ; Add $80 to the movement accumulator.
    ;
    lea     ($041F,A4),A0
    move.b  (A0,D2.W),D0
    andi    #$EE,CCR  ; CLC: clear C+X
    move.b  #$80,D1
    addx.b  D1,D0   ; ADC #$80 (X flag = 6502 C)
    lea     ($041F,A4),A0
    move.b  D0,(A0,D2.W)
    ; If movement accumulator didn't overflow, then go animate the eye.
    ;
    bcc  _L_z04_UpdateGohma_AnimateEye
    ; Increase the distance traveled, and move 1.
    ;
    lea     ($0412,A4),A0
    addq.b  #1,(A0,D2.W)
    ; Set a direction mask in [02], starting with right (1).
    ;
    moveq   #1,D0
    move.b  D0,($0002,A4)
    ; If Gohma's facing direction has a right component, then add 1 to X.
    ;
    lea     ($0098,A4),A0
    move.b  (A0,D2.W),D0
    move.b  ($0002,A4),D1
    and.b   D0,D1   ; BIT: set Z/N/V from D1 AND A
    beq  _anon_z04_118
    addq.b  #1,($70,A4,D2.W)
_anon_z04_118:
    ; If Gohma's facing direction has a left component, then subtract 1 from X.
    ;
    move.b  ($0002,A4),D1
    lsl.b  #1,D1   ; ASL $02
    move.b  D1,($0002,A4)
    move.b  ($0002,A4),D1
    and.b   D0,D1   ; BIT: set Z/N/V from D1 AND A
    beq  _anon_z04_119
    subq.b  #1,($70,A4,D2.W)
_anon_z04_119:
    ; If Gohma's facing direction has a down component, then add 1 to Y.
    ;
    move.b  ($0002,A4),D1
    lsl.b  #1,D1   ; ASL $02
    move.b  D1,($0002,A4)
    move.b  ($0002,A4),D1
    and.b   D0,D1   ; BIT: set Z/N/V from D1 AND A
    beq  _anon_z04_120
    lea     ($0084,A4),A0
    addq.b  #1,(A0,D2.W)
_anon_z04_120:
    ; If Gohma's facing direction has an up component, then subtract 1 from Y.
    ;
    move.b  ($0002,A4),D1
    lsl.b  #1,D1   ; ASL $02
    move.b  D1,($0002,A4)
    move.b  ($0002,A4),D1
    and.b   D0,D1   ; BIT: set Z/N/V from D1 AND A
    beq  _anon_z04_121
    lea     ($0084,A4),A0
    subq.b  #1,(A0,D2.W)
_anon_z04_121:
    ; If Gohma has not traveled $20 pixels, then go animate the eye.
    ;
    lea     ($0412,A4),A0
    move.b  (A0,D2.W),D0
    cmpi.b  #$20,D0
    bne  _L_z04_UpdateGohma_AnimateEye
    ; Gohma has traveled $20 pixels. Reset the distance traveled.
    ; Reverse the facing direction, and increase the number of sprints.
    ;
    moveq   #0,D0
    lea     ($0412,A4),A0
    move.b  D0,(A0,D2.W)
    jsr     ReverseObjDir8
    lea     ($045E,A4),A0
    move.b  (A0,D2.W),D0
    lea     ($045E,A4),A0
    addq.b  #1,(A0,D2.W)
    ; If the previous number of sprints was odd, then flag that Gohma
    ; should randomly change direction.
    ;
    lsr.b  #1,D0   ; LSR A
    bcc  _L_z04_UpdateGohma_AnimateEye
    moveq   #0,D0
    lea     ($0451,A4),A0
    move.b  D0,(A0,D2.W)
    even
_L_z04_UpdateGohma_AnimateEye:
    ; Animate the eye.
    ;
    ; First, if the counter for when to open the eye next = 0, then
    ; set it to a random value at least $C0; and set the timer for
    ; keeping the eye open to $80.
    ;
    ; Note that $C0 is not a number of frames, because it's changed
    ; every other frame.
    ;
    lea     ($042C,A4),A0
    move.b  (A0,D2.W),D0
    bne  _L_z04_UpdateGohma_DecNextOpenEyeCounter
    move.b  #$80,D0
    lea     ($0444,A4),A0
    move.b  D0,(A0,D2.W)
    move.b  #$C0,D0
    move.b  ($18,A4,D2.W),D1
    or.b  D1,D0
    lea     ($042C,A4),A0
    move.b  D0,(A0,D2.W)
    even
_L_z04_UpdateGohma_DecNextOpenEyeCounter:
    ; Decrement the next-open-eye counter.
    ;
    move.b  ($0015,A4),D0
    lsr.b  #1,D0   ; LSR A
    bcc  _anon_z04_122
    lea     ($042C,A4),A0
    subq.b  #1,(A0,D2.W)
_anon_z04_122:
    ; If open eye timer = 0, then the eye is closed.
    ; Go animate it differently.
    ;
    lea     ($0444,A4),A0
    move.b  (A0,D2.W),D0
    beq  _L_z04_UpdateGohma_AnimateClosedEye
    ; Else decrement the open eye timer.
    ;
    lea     ($0444,A4),A0
    subq.b  #1,(A0,D2.W)
    ; If open eye timer >= $70 and < $10, then the eye is fully open.
    ; So, set its frame image to 2. Else use 3 for a half open eye.
    ;
    moveq   #2,D3
    cmpi.b  #$70,D0
    bcc  _anon_z04_123
    cmpi.b  #$10,D0
    bcs  _anon_z04_123
    addq.b  #1,D3
_anon_z04_123:
    move.b  D3,D0
    even
_L_z04_UpdateGohma_SetEyeStateAndShoot:
    lea     ($046B,A4),A0
    move.b  D0,(A0,D2.W)
    even
_L_z04_UpdateGohma_ShootAnimateCollide:
    ; Decrement the shoot timer.
    ;
    lea     ($0380,A4),A0
    subq.b  #1,(A0,D2.W)
    ; If it became 0, then set it to $41, and shoot fireball $56.
    ;
    bne  _L_z04_UpdateGohma_AnimateAndCheckCollisions
    moveq   #65,D0
    lea     ($0380,A4),A0
    move.b  D0,(A0,D2.W)
    moveq   #86,D0
    jsr     ShootFireball
    even
_L_z04_UpdateGohma_AnimateAndCheckCollisions:
    ; Pass the frame image for the eye.
    ;
    lea     ($046B,A4),A0
    move.b  (A0,D2.W),D0
    jsr     Gohma_AnimateAndDraw
    jmp     Gohma_CheckCollisions

    even
_L_z04_UpdateGohma_AnimateClosedEye:
    ; Here the eye is closed. So animate it this way.
    ; Increment the animation counter, and if <> 8, then
    ; go shoot, draw, and check collisions.
    ;
    lea     ($0478,A4),A0
    addq.b  #1,(A0,D2.W)
    lea     ($0478,A4),A0
    move.b  (A0,D2.W),D0
    cmpi.b  #$08,D0
    bne  _L_z04_UpdateGohma_ShootAnimateCollide
    ; Roll over the eye animation counter to 0.
    ; Clear bit 1 and invert bit 0 to switch between frame images 0 and 1.
    ;
    moveq   #0,D0
    lea     ($0478,A4),A0
    move.b  D0,(A0,D2.W)
    lea     ($046B,A4),A0
    move.b  (A0,D2.W),D0
    andi.b #$01,D0
    eori.b #$01,D0
    ; Go set eye state/frame image, shoot, draw, and check collisions
    ;
    jmp     _L_z04_UpdateGohma_SetEyeStateAndShoot

    even
GohmaLegOffsetsX:
    dc.b    $F0, $10

; Params:
; A: eye frame image
;
; Draw the eye with the frame image passed in.
;
    even
Gohma_AnimateAndDraw:
    move.b  D0,-(A5)  ; PHA
    jsr     Anim_FetchObjPosForSpriteDescriptor
    jsr     Gohma_SetSpriteAttributes
    move.b  (A5)+,D0  ; PLA
    jsr     DrawObjectMirrored
    moveq   #16,D0
    jsr     Anim_AdvanceAnimCounterAndSetObjPosForSpriteDescriptor
    ; Draw the right legs.
    ;
    moveq   #1,D3
    jsr     Gohma_DrawLegsOneSide
    ; Draw the left legs.
    ;
    moveq   #0,D3
; Params:
; Y: side: 0 for left, 1 for right
;
; Add the horizontal offset for the current side to Gohma's X to
; store the sprite's X in [00].
;
    even
Gohma_DrawLegsOneSide:
    move.b  ($70,A4,D2.W),D0
    andi    #$EE,CCR  ; CLC: clear C+X
    lea     (GohmaLegOffsetsX).l,A0
    move.b  (A0,D3.W),D1
    addx.b  D1,D0   ; ADC GohmaLegOffsetsX,Y
    move.b  D0,($0000,A4)
    ; The object's Y is the sprite's.
    ;
    lea     ($0084,A4),A0
    move.b  (A0,D2.W),D0
    move.b  D0,($0001,A4)
    jsr     Gohma_SetSpriteAttributes
    ; There are only two frame images for legs: left and right.
    ; There are two animation frames. They are animated as follows:
    ;
    ; Frame 0:
    ; ((leg index + frame number) AND 1) = 0 or 1
    ; horizontal flipping = frame number = 0
    ; 
    ; Frame 1:
    ; ((leg index + frame number) AND 1) = 1 or 0
    ; horizontal flipping = frame number = 1
    ;
    jsr     Anim_SetObjHFlipForSpriteDescriptor
    move.b  D3,D0
    andi    #$EE,CCR  ; CLC: clear C+X
    lea     ($03E4,A4),A0
    move.b  (A0,D2.W),D1
    addx.b  D1,D0   ; ADC ObjAnimFrame,X
    andi.b #$01,D0
    andi    #$EE,CCR  ; CLC: clear C+X
    move.b  #$04,D1
    addx.b  D1,D0   ; ADC #$04 (X flag = 6502 C)
    jmp     DrawObjectNotMirrored

; Returns:
; [04]: left side sprite attributes
; [05]: right side sprite attributes
;
    even
Gohma_SetSpriteAttributes:
    lea     ($034F,A4),A0
    move.b  (A0,D2.W),D0
    ori     #$11,CCR  ; SEC: set C+X
    move.b  #$32,D1
    eori    #$10,CCR  ; flip X: 6502 SBC polarity
    subx.b  D1,D0   ; SBC #$32
    eori    #$10,CCR  ; restore X = 6502 C
    jmp     Anim_SetSpriteDescriptorAttributes

    even
Gohma_CheckCollisions:
    ; Save the boss's X coordinate.
    ;
    move.b  ($70,A4,D2.W),D0
    move.b  D0,-(A5)  ; PHA
    ; Subtract $10 from the X coordinate, so we start checking collisions
    ; on the left side.
    ;
    ori     #$11,CCR  ; SEC: set C+X
    move.b  #$10,D1
    eori    #$10,CCR  ; flip X: 6502 SBC polarity
    subx.b  D1,D0   ; SBC #$10
    eori    #$10,CCR  ; restore X = 6502 C
    move.b  D0,($70,A4,D2.W)
    ; Check object collisions in 5 parts, 8 pixels apart,
    ; from left to right, indexed by [0F].
    ;
    moveq   #5,D0
    move.b  D0,($000F,A4)
    even
_L_z04_Gohma_CheckCollisions_LoopSprite:
    jsr     CheckMonsterCollisions
    ; Add 8 to the X coordinate for the next part.
    ;
    move.b  ($70,A4,D2.W),D0
    andi    #$EE,CCR  ; CLC: clear C+X
    move.b  #$08,D1
    addx.b  D1,D0   ; ADC #$08 (X flag = 6502 C)
    move.b  D0,($70,A4,D2.W)
    subq.b  #1,($000F,A4)
    bne  _L_z04_Gohma_CheckCollisions_LoopSprite
    ; Restore the boss's X coordinate.
    ;
    move.b  (A5)+,D0  ; PLA
    move.b  D0,($70,A4,D2.W)
    rts

    even
Gohma_HandleWeaponCollision:
    ; TODO:
    ; If hit by an arrow, then set the arrow to spark
    ;
    cmpi.b  #$12,D3
    bne  _L_z04_Gohma_HandleWeaponCollision_CheckHitEye
    moveq   #40,D0
    lea     ($00AC,A4),A0
    move.b  D0,(A0,D3.W)
    moveq   #4,D0
    lea     ($03D0,A4),A0
    move.b  D0,(A0,D3.W)
    even
_L_z04_Gohma_HandleWeaponCollision_CheckHitEye:
    ; If it did not hit part 3 nor 4, then go play the parry sound effect.
    ;
    move.b  ($000F,A4),D0
    cmpi.b  #$03,D0
    beq  _L_z04_Gohma_HandleWeaponCollision_CheckEyeOpen
    cmpi.b  #$04,D0
    bne  _L_z04_Gohma_HandleWeaponCollision_PlayParryTune
    even
_L_z04_Gohma_HandleWeaponCollision_CheckEyeOpen:
    ; If the state of the eye is not 3, then go parry.
    ;
    lea     ($046B,A4),A0
    move.b  (A0,D2.W),D0
    cmpi.b  #$03,D0
    bne  _L_z04_Gohma_HandleWeaponCollision_PlayParryTune
    ; If the direction of the arrow is not up, then go parry.
    ;
    lea     ($0098,A4),A0
    move.b  (A0,D3.W),D0
    cmpi.b  #$08,D0
    bne  _L_z04_Gohma_HandleWeaponCollision_PlayParryTune
    ; TODO:
    ;
    moveq   #2,D0
    move.b  D0,($0601,A4)
    ; Deal damage and cry out.
    ;
    jsr     DealDamage
    jsr     PlayBossDeathCryIfNeeded
    even
_L_z04_Gohma_HandleWeaponCollision_PlayParryTune:
    moveq   #1,D0
    move.b  D0,($0604,A4)
    rts

    even
UpdateGleeokHead:
    jsr     ControlGleeokHeadFlight
    jsr     MoveFlyer
    ; If the low bit of the distance traveled is clear,
    ; and Random < $20,
    ; and there's no object (fireball) in slot $B,
    ; then shoot a fireball $56.
    ;
    lea     ($0437,A4),A0
    move.b  (A0,D2.W),D0
    andi.b #$01,D0
    bne  _anon_z04_124
    move.b  ($19,A4,D2.W),D0
    cmpi.b  #$20,D0
    bcc  _anon_z04_124
    move.b  ($035A,A4),D0
    bne  _anon_z04_124
    moveq   #86,D0
    jsr     ShootFireball
_anon_z04_124:
    moveq   #1,D0
    jsr     Anim_AdvanceAnimCounterAndSetObjPosForSpriteDescriptor
    lea     ($03E4,A4),A0
    move.b  (A0,D2.W),D0
    jsr     DrawObjectMirrored
    jsr     CheckMonsterCollisions
    ; Reset object state, shove info, and invincibility timer,
    ; because this monster can't get hurt nor die.
    ;
    jsr     ResetObjMetastate
    jsr     SetShoveInfoWith0
    lea     ($04F0,A4),A0
    move.b  D0,(A0,D2.W)
    rts

    even
ControlGleeokHeadFlight:
    lea     ($0444,A4),A0
    move.b  (A0,D2.W),D0
    jsr     _m68k_tablejump  ; M68K-native table dispatch (replaces JSR TableJump)
    even
ControlGleeokHeadFlight_JumpTable:
    dc.l    Flyer_SpeedUp   ; jump table entry (32-bit for _m68k_tablejump)
    dc.l    Flyer_GleeokHeadDecideState   ; jump table entry (32-bit for _m68k_tablejump)
    dc.l    Flyer_Chase   ; jump table entry (32-bit for _m68k_tablejump)
    dc.l    Flyer_Wander   ; jump table entry (32-bit for _m68k_tablejump)

    even
Flyer_GleeokHeadDecideState:
    ; Go to the next flying state randomly:
    ; Random < $D0: 2
    ; Else:         3
    ;
    ; Set up 6 turns.
    ;
    moveq   #2,D3
    move.b  ($19,A4,D2.W),D0
    cmpi.b  #$D0,D0
    bcs  _anon_z04_125
    addq.b  #1,D3
_anon_z04_125:
    jmp     Flyer_SetStateAndTurns

    even
GleeokNeckXAddrsLo:
    dc.b    $38, $52, $6C, $95

    even
GleeokNeckXAddrsHi:
    dc.b    $04, $04, $04, $03

    even
GleeokNeckYAddrsLo:
    dc.b    $45, $5F, $79, $BD

    even
GleeokNeckYAddrsHi:
    dc.b    $04, $04, $04, $03

    even
GleeokNeckMiscAddrsLo:
    dc.b    $20, $2D, $81, $A9

    even
GleeokNeckMiscAddrsHi:
    dc.b    $04, $04, $03, $03

    even
UpdateGleeok:
    jsr     Gleeok_DrawBody
    ; Calculate the index of the last neck of this kind of gleeok.
    ; Subtract $42 (Gleeok1) from ObjType[1].
    ;
    move.b  ($0350,A4),D0
    ori     #$11,CCR  ; SEC: set C+X
    move.b  #$42,D1
    eori    #$10,CCR  ; flip X: 6502 SBC polarity
    subx.b  D1,D0   ; SBC #$42
    eori    #$10,CCR  ; restore X = 6502 C
    ; For each neck, counting down:
    ;
    move.b  D0,($04D7,A4)
    even
_L_z04_UpdateGleeok_LoopNeck:
    ; If the bit for this neck is in the dead neck mask,
    ; then go loop again.
    ;
    moveq   #0,D3
    move.b  ($04D7,A4),D3
    lea     (LevelMasks).l,A0
    move.b  (A0,D3.W),D0
    move.b  ($0511,A4),D1
    and.b   D0,D1   ; BIT: set Z/N/V from D1 AND A
    beq  _anon_z04_126
    jmp     _L_z04_UpdateGleeok_NextLoopNeck

_anon_z04_126:
    ; Get the addresses of this neck's segment data arrays.
    ;
    jsr     Gleeok_FetchNeckAddrs
    even
_L_z04_UpdateGleeok_LoadNeckBytes:
    ; Load neck data.
    ;
    ; For each segment from 5 to 0, indexed by Y register:
    ; - load coordinates into object slots 6 to 1
    ; - load miscellany into an array at [0413]
    ;
    move.b  ($00,A4),D1   ; ptr lo
    move.b  ($01,A4),D4  ; ptr hi
    andi.w  #$00FF,D1         ; zero-extend lo byte
    lsl.w   #8,D4
    or.w    D1,D4             ; D4 = NES ptr addr
    ext.l   D4
    add.l   #NES_RAM,D4       ; → Genesis addr
    movea.l D4,A0
    move.b  (A0,D3.W),D0     ; LDA ($nn),Y
    move.b  D0,($71,A4,D3.W)
    move.b  ($02,A4),D1   ; ptr lo
    move.b  ($03,A4),D4  ; ptr hi
    andi.w  #$00FF,D1         ; zero-extend lo byte
    lsl.w   #8,D4
    or.w    D1,D4             ; D4 = NES ptr addr
    ext.l   D4
    add.l   #NES_RAM,D4       ; → Genesis addr
    movea.l D4,A0
    move.b  (A0,D3.W),D0     ; LDA ($nn),Y
    lea     ($0085,A4),A0
    move.b  D0,(A0,D3.W)
    move.b  ($04,A4),D1   ; ptr lo
    move.b  ($05,A4),D4  ; ptr hi
    andi.w  #$00FF,D1         ; zero-extend lo byte
    lsl.w   #8,D4
    or.w    D1,D4             ; D4 = NES ptr addr
    ext.l   D4
    add.l   #NES_RAM,D4       ; → Genesis addr
    movea.l D4,A0
    move.b  (A0,D3.W),D0     ; LDA ($nn),Y
    lea     ($0413,A4),A0
    move.b  D0,(A0,D3.W)
    subq.b  #1,D3
    bpl  _L_z04_UpdateGleeok_LoadNeckBytes
    ; Each screen frame, one neck is chosen to move and try to shoot.
    ;
    move.b  ($0015,A4),D0
    andi.b #$03,D0
    move.b  D0,($0000,A4)
    move.b  ($0000,A4),D1
    cmp.b   D1,D2
    bne  _L_z04_UpdateGleeok_DrawAndCheckCollisions
    jsr     Gleeok_MoveNeck
    jsr     Gleeok_MoveHead
    ; The head is in object slot 5. Set it for when we want to shoot,
