    move.b  ($0089,A4),D0
    ori     #$11,CCR  ; SEC: set C+X
    move.b  ($0085,A4),D1
    eori    #$10,CCR  ; flip X: 6502 SBC polarity
    subx.b  D1,D0   ; SBC ObjY+1
    eori    #$10,CCR  ; restore X = 6502 C
    jsr     Abs
    lsr.b  #1,D0   ; LSR A
    lsr.b  #1,D0   ; LSR A
    ; Calculate and store the second and third tier vertical distances.
    ;
