    move.b  ($72,A4,D2.W),D0
    moveq   #0,D3
    move.b  D0,D3
    addq.b  #1,D3
    addq.b  #1,D3
    move.b  ($71,A4,D2.W),D1
    cmp.b   D1,D0
    bcs  _anon_z04_127
