Gleeok_WriteHeadOrBaseSpriteAndCheckCollisions:
    moveq   #3,D3
    move.b  D3,($0003,A4)
    move.b  D0,-(A5)  ; PHA
    ; To calculate the base offset of the sprite record:
    ; offset := neck index * 8
    ;
    ; This ends up pointing to one of the first 8 eight sprites,
    ; at an even index.
    ;
    move.b  ($04D7,A4),D0
