    ; add $20. This moves the offset to the second set of 8 sprites.
    ;
    cmpi.b  #$05,D2
    beq  _anon_z04_139
    andi    #$EE,CCR  ; CLC: clear C+X
    move.b  #$20,D1
    addx.b  D1,D0   ; ADC #$20 (X flag = 6502 C)
