    bcc.s  __far_z_04_0110
    jmp  L127FA_Exit
__far_z_04_0110:
    ; The counter reached 4. So, reset it.
    ; Then check the individual direction counters.
    ;
    moveq   #0,D0
    move.b  D0,($0417,A4)
    ; Increment the horizontal direction counter.
    ; If >= $C, then reset the counter, and flip direction.
    ;
    addq.b  #1,($0413,A4)
    move.b  ($0413,A4),D0
    cmpi.b  #$0C,D0
    bcs  _L_z04_Gleeok_MoveHead_CheckVertical
    moveq   #0,D0
    move.b  D0,($0413,A4)
