; Params:
; A: a value to change
; Y: 0 => increment, 1 => decrement
;
; Returns:
; A: original value +/- 1
;
    even
Gleeok_ChangeCoordinateBySpeedFlag:
    bne  _L_z04_Gleeok_ChangeCoordinateBySpeedFlag_Subtract
