L_Gleeok_DecAnimTimerAndDraw:
    ; Decrement animation timer, and go draw.
    ;
    subq.b  #1,($04E6,A4)
    jmp     L_Gleeok_WriteSprites

    even
Gleeok_DrawBody:
    ; The animation timer controls when the animation frame changes.
    ; If it has not expired, then go decrement it and draw.
    ;
    move.b  ($04E6,A4),D0
    beq.s  __far_z_04_0112
    jmp  L_Gleeok_DecAnimTimerAndDraw
__far_z_04_0112:
    ; The animation timer has expired. There are two choices for arming it.
    ;
    ; When writhing after a hit, Gleeok animates faster.
    ; So, when the writhing counter <> 0, set a shorter time (6).
    ; Otherwise, set a longer time ($10).
    ;
    moveq   #16,D0
    moveq   #0,D3
    move.b  ($0510,A4),D3
    beq  _anon_z04_144
    subq.b  #1,($0510,A4)
    moveq   #6,D0
_anon_z04_144:
    move.b  D0,($04E6,A4)
    ; Cycle the animation frame from 0 to 3.
    ;
    move.b  ($04E7,A4),D0
    andi    #$EE,CCR  ; CLC: clear C+X
    move.b  #$01,D1
    addx.b  D1,D0   ; ADC #$01 (X flag = 6502 C)
    andi.b #$03,D0
    move.b  D0,($04E7,A4)
    even
L_Gleeok_WriteSprites:
    ; For each row, from 0 to 1, indexed by [06]:
    ;
    moveq   #0,D0
    move.b  D0,($0006,A4)
    ; Get the base tile offset for the current animation frame.
    ;
    moveq   #0,D3
    move.b  ($04E7,A4),D3
    moveq   #0,D2
    lea     (GleeokBodyBaseTileOffsets).l,A0
    move.b  (A0,D3.W),D2
    even
_L_z04_L_Gleeok_WriteSprites_LoopDrawRow:
    ; For each column from 0 to 2, indexed by [07]:
    ;
    moveq   #0,D0
    move.b  D0,($0007,A4)
    even
_L_z04_L_Gleeok_WriteSprites_LoopDrawColumn:
    ; Point to the next rolling sprite record.
    ;
    moveq   #0,D3
    move.b  ($0341,A4),D3
    lea     (SpriteOffsets).l,A0
    move.b  (A0,D3.W),D0
    moveq   #0,D3
    move.b  D0,D3
    ; Set sprite's Y to ($57 + row * $10).
    ;
    move.b  ($0006,A4),D0
    lsl.b  #1,D0   ; ASL A
    lsl.b  #1,D0   ; ASL A
    lsl.b  #1,D0   ; ASL A
    lsl.b  #1,D0   ; ASL A
    move.b  #$57,D1
    addx.b  D1,D0   ; ADC #$57 (X flag = 6502 C)
    lea     ($0200,A4),A0
    move.b  D0,(A0,D3.W)
    ; Look up and set the tile for this spot.
    ;
    lea     (GleeokBodyTiles0).l,A0
    move.b  (A0,D2.W),D0
    lea     ($0201,A4),A0
    move.b  D0,(A0,D3.W)
