    ; cycled palette rows.
    ;
    ; Else use level palette row 7.
    ;
    move.b  ($04F5,A4),D0
    bne  _anon_z04_145
    moveq   #3,D0
_anon_z04_145:
    andi.b #$03,D0
    lea     ($0202,A4),A0
    move.b  D0,(A0,D3.W)
    ; Set sprite's X to ($74 + column * 8).
    ;
    move.b  ($0007,A4),D0
    lsl.b  #1,D0   ; ASL A
    lsl.b  #1,D0   ; ASL A
    lsl.b  #1,D0   ; ASL A
    move.b  #$74,D1
    addx.b  D1,D0   ; ADC #$74 (X flag = 6502 C)
    lea     ($0203,A4),A0
    move.b  D0,(A0,D3.W)
    ; Increment the index for fetching tiles.
    ;
    addq.b  #1,D2
    jsr     CycleCurSpriteIndex
    ; Bottom of the column loop.
    ; Increment the column until it = 3.
    ;
    addq.b  #1,($0007,A4)
    move.b  ($0007,A4),D0
    cmpi.b  #$03,D0
    bcs  _L_z04_L_Gleeok_WriteSprites_LoopDrawColumn
    ; Bottom of the row loop.
    ; Increment the row until it = 2.
    ;
    addq.b  #1,($0006,A4)
    move.b  ($0006,A4),D0
    cmpi.b  #$02,D0
    bcs  _L_z04_L_Gleeok_WriteSprites_LoopDrawRow
    rts

