    move.b  D0,($0601,A4)
    moveq   #16,D0
    jsr     PlaySample
    jmp     ResetObjMetastateAndTimer

    even
UpdateZelda:
    jsr     Person_Draw
    lea     ($00AC,A4),A0
    move.b  (A0,D2.W),D0
    beq.s  __far_z_04_0113
    jmp  UpdateZelda_State1
__far_z_04_0113:
    ; State 0.
    ;
    ; If Link's X < $70 or >= $81, or Link's Y <> $95, then return.
    ;
    move.b  ($0070,A4),D0
    cmpi.b  #$70,D0
    bcc.s  __far_z_04_0114
    jmp  L129B7_Exit
__far_z_04_0114:
    cmpi.b  #$81,D0
    bcs.s  __far_z_04_0115
    jmp  L129B7_Exit
__far_z_04_0115:
    move.b  ($0084,A4),D0
    cmpi.b  #$95,D0
    beq.s  __far_z_04_0116
    jmp  L129B7_Exit
__far_z_04_0116:
    ; Else Link is near enough to Zelda.
    ; Go to state 1, and halt Link.
    ;
    lea     ($00AC,A4),A0
    addq.b  #1,(A0,D2.W)
    moveq   #64,D0
    move.b  D0,($00AC,A4)
    ; Put Link at location ($88, $88) and facing left.
    ;
    move.b  #$88,D0
    move.b  D0,($0070,A4)
    move.b  D0,($0084,A4)
    moveq   #2,D0
    move.b  D0,($0098,A4)
    ; Play the Zelda fanfare.
    ;
    moveq   #6,D0
    move.b  D0,($0600,A4)
    ; Set a delay of $80 frames at the beginning of the next state.
    ;
    move.b  #$80,D0
    move.b  D0,($28,A4,D2.W)
    even
L129B7_Exit:
    rts

    even
UpdateZelda_State1:
    ; State 1.
    ;
    ; Draw Link, then return if the object timer <> 0.
    ;
    jsr     Link_EndMoveAndDraw_Bank4
    move.b  ($28,A4,D2.W),D0
    beq.s  __far_z_04_0117
    jmp  L129B7_Exit
__far_z_04_0117:
    ; Go to mode $13.
    ;
    move.b  D0,($0011,A4)
    move.b  D0,($0013,A4)
    move.b  D0,($00AC,A4)
    moveq   #19,D0
    move.b  D0,($0012,A4)
    ; Mode $13 will start with a curtain furling effect.
    ; Set up the decreasing column ($20), and the increasing column (1).
    ; Prepare the background by filling the tile map with blank tile $24.
    ;
    moveq   #32,D0
    move.b  D0,($007C,A4)
    moveq   #1,D0
    move.b  D0,($007D,A4)
    moveq   #36,D0
    move.b  D0,($000A,A4)
    jmp     FillTileMap

    even
UpdateGuardFire:
    moveq   #6,D0
    jsr     AnimateAndDrawCommonObject
    jsr     CheckMonsterCollisions
    ; If the object has not been killed, then return.
    ; Else change the object type to dead dummy.
    ;
    lea     ($0405,A4),A0
    move.b  (A0,D2.W),D0
    bne.s  __far_z_04_0118
    jmp  L129EA_Exit
__far_z_04_0118:
    even
SetDeadDummyObjType:
    moveq   #93,D0
    lea     ($034F,A4),A0
    move.b  D0,(A0,D2.W)
    even
L129EA_Exit:
    rts

    even
UpdateLamnola:
    ; If the direction of this segment is not set, then it has not started
    ; moving yet. So, return.
    ;
    lea     ($0098,A4),A0
    move.b  (A0,D2.W),D0
    bne.s  __far_z_04_0119
    jmp  L129EA_Exit
__far_z_04_0119:
    ; If we have the magic clock, then go draw and check collisions.
    ;
    move.b  ($066C,A4),D0
    bne  _L_z04_UpdateLamnola_DrawAndCheckCollisions
    jsr     Lamnola_Move
    ; If the current segment is a head, then update the direction it's facing.
    ;
    cmpi.b  #$05,D2
    beq  _anon_z04_150
    cmpi.b  #$0A,D2
    bne  _L_z04_UpdateLamnola_DrawAndCheckCollisions
_anon_z04_150:
    jsr     Lamnola_UpdateHead
    even
_L_z04_UpdateLamnola_DrawAndCheckCollisions:
    move.b  ($70,A4,D2.W),D0
    move.b  D0,-(A5)  ; PHA
    ; Each segment is a full 16x16 object. But, it's drawn as a narrow,
    ; half-width object. So, center it by temporarily adding 4 to X.
    ;
    andi    #$EE,CCR  ; CLC: clear C+X
    move.b  #$04,D1
    addx.b  D1,D0   ; ADC #$04 (X flag = 6502 C)
    move.b  D0,($70,A4,D2.W)
    ; The speed is 1 or 2. By swapping them, you get sprite attributes
    ; to store in [03].
    ;
    move.b  ($04E6,A4),D0
    eori.b #$03,D0
    move.b  D0,($0003,A4)
    ; If the segment is a head, then use tile $9E, else $A0.
    ;
    move.b  #$9E,D0
    cmpi.b  #$05,D2
    beq  _L_z04_UpdateLamnola_Draw
    cmpi.b  #$0A,D2
    beq  _L_z04_UpdateLamnola_Draw
    move.b  #$A0,D0
    even
_L_z04_UpdateLamnola_Draw:
    jsr     Anim_WriteSprite
    move.b  (A5)+,D0  ; PLA
    move.b  D0,($70,A4,D2.W)
    lea     ($0098,A4),A0
    move.b  (A0,D2.W),D0
    move.b  D0,-(A5)  ; PHA
    jsr     CheckMonsterCollisions
    move.b  (A5)+,D0  ; PLA
    lea     ($0098,A4),A0
    move.b  D0,(A0,D2.W)
    ; If still alive, then return.
    ;
    lea     ($0405,A4),A0
    move.b  (A0,D2.W),D0
    bne.s  __far_z_04_0120
    jmp  L129EA_Exit
__far_z_04_0120:
    ; Otherwise, the segment is dead.
    ;
    jsr     ResetShoveInfo
    ; Set the current segment's HP to the initial value in anticipation
    ; of bringing this segment back to life.
    ;
    moveq   #32,D0
    lea     ($0485,A4),A0
    move.b  D0,(A0,D2.W)
    ; Find the tail of the lamnola that the current segment belongs to.
    ;
    ; From the lowest slot, look for one that has the original lamnola
    ; object type.
    ;
    ; The goal is to swap the current dead segment with the tail segment.
    ;
    move.b  #$FF,D3
    cmpi.b  #$06,D2
    bcs  _L_z04_UpdateLamnola_FindTail
    moveq   #4,D3
    even
_L_z04_UpdateLamnola_FindTail:
    addq.b  #1,D3
    lea     ($0350,A4),A0
    move.b  (A0,D3.W),D0
    move.b  ($04E7,A4),D1
    cmp.b   D1,D0
    bne  _L_z04_UpdateLamnola_FindTail
    ; Set the timer for the dead dummy object that will replace the tail.
    ;
    moveq   #17,D0
    move.b  D0,($29,A4,D3.W)
    ; Copy the current dead segment's invincibility timer, X, and Y
    ; to the tail segment.
    ;
    lea     ($04F0,A4),A0
    move.b  (A0,D2.W),D0
    lea     ($04F1,A4),A0
    move.b  D0,(A0,D3.W)
    move.b  ($70,A4,D2.W),D0
    move.b  D0,($71,A4,D3.W)
    lea     ($0084,A4),A0
    move.b  (A0,D2.W),D0
    lea     ($0085,A4),A0
    move.b  D0,(A0,D3.W)
    ; If the tail segment found is a head, then the whole lamnola died.
    ; So, return and leave it dead.
    ;
    cmpi.b  #$04,D3
    bne.s  __far_z_04_0121
    jmp  L129EA_Exit
__far_z_04_0121:
    cmpi.b  #$09,D3
    bne.s  __far_z_04_0122
    jmp  L129EA_Exit
__far_z_04_0122:
    ; Change the tail segment to the dead dummy object, and
    ; bring the current segment back to life.
    ;
    moveq   #93,D0
    lea     ($0350,A4),A0
    move.b  D0,(A0,D3.W)
    jmp     ResetObjMetastate

    even
L12A6F_Exit:
    rts

    even
Lamnola_UpdateHead:
    ; If X coordinate is not a multiple of 8, then return.
    ;
    move.b  ($70,A4,D2.W),D0
    andi.b #$07,D0
    beq.s  __far_z_04_0123
    jmp  L12A6F_Exit
__far_z_04_0123:
    ; If (Y + 3) is not a multiple of 8, then return.
    ; We had to account for the usual offset of 3.
    ;
    lea     ($0084,A4),A0
    move.b  (A0,D2.W),D0
    andi    #$EE,CCR  ; CLC: clear C+X
    move.b  #$03,D1
    addx.b  D1,D0   ; ADC #$03 (X flag = 6502 C)
    andi.b #$07,D0
    beq.s  __far_z_04_0124
    jmp  L12A6F_Exit
__far_z_04_0124:
    ; Will loop 4 times, propagating directions down the chain,
    ; by pulling from the bottom.
    ;
    moveq   #4,D0
    move.b  D0,($0000,A4)
    ; Choose the tail index of the lamnola that the current segment belongs to.
    ;
    moveq   #0,D3
    cmpi.b  #$05,D2
    beq  _L_z04_Lamnola_UpdateHead_PropagateDirs
    moveq   #5,D3
    even
_L_z04_Lamnola_UpdateHead_PropagateDirs:
    ; Loop over every segment under the head, starting from the tail.
    ; Copy the next segment's direction to the current one in this loop.
    ;
    lea     ($009A,A4),A0
    move.b  (A0,D3.W),D0
    lea     ($0099,A4),A0
    move.b  D0,(A0,D3.W)
    addq.b  #1,D3
    subq.b  #1,($0000,A4)
    bne  _L_z04_Lamnola_UpdateHead_PropagateDirs
    ; If this head segment is not aligned with a square, then return.
    ;
    move.b  ($70,A4,D2.W),D0
    andi.b #$0F,D0
    bne  _L_z04_Lamnola_UpdateHead_Exit
    ; If (Y + 3) is not a multiple of $10, then return.
    ; We had to account for the usual offset of 3.
    ;
    lea     ($0084,A4),A0
    move.b  (A0,D2.W),D0
    andi    #$EE,CCR  ; CLC: clear C+X
    move.b  #$03,D1
    addx.b  D1,D0   ; ADC #$03 (X flag = 6502 C)
    andi.b #$0F,D0
    bne  _L_z04_Lamnola_UpdateHead_Exit
    ; Store the opposite of the facing direction in [00].
    ;
    lea     ($0098,A4),A0
    move.b  (A0,D2.W),D0
    lsr.b  #1,D0   ; LSR A
    andi.b #$05,D0
    move.b  D0,($0000,A4)
    lea     ($0098,A4),A0
    move.b  (A0,D2.W),D0
    lsl.b  #1,D0   ; ASL A
    andi.b #$0A,D0
    move.b  ($0000,A4),D1
    or.b  D1,D0
    ; Make a mask of the inverted bits of the opposite direction.
    ;
    eori.b #$0F,D0
    move.b  D0,($050F,A4)
    ; There's a 50% chance of going to try to turn toward Link.
    ;
    move.b  ($18,A4,D2.W),D0
    cmpi.b  #$80,D0
    bcs  _L_z04_Lamnola_UpdateHead_TurnTowardLink
    ; Otherwise, we randomly choose a perpendicular direction.
    ; Load the monster's facing direction.
    ;
    lea     ($0098,A4),A0
    move.b  (A0,D2.W),D0
    ; Load the next random number into Y register.
    ;
    moveq   #0,D3
    move.b  ($19,A4,D2.W),D3
    ; Based on it, there's a 50% chance of skipping the loop,
    ; to keep moving straight.
    ;
    cmpi.b  #$80,D3
    bcc  _L_z04_Lamnola_UpdateHead_SetDirAndCheckTiles
    even
_L_z04_Lamnola_UpdateHead_LoopFindPerpendicular:
    ; Loop to rotate the direction bit over the mask.
    ; The goal is to calculate a direction perpendicular to the monster's
    ; facing direction.
    ;
    ; Shift right the copy of the direction.
    ; If the direction bit rolled off the low end, then roll it onto the high end.
    ;
    lsr.b  #1,D0   ; LSR A
    bcc  _anon_z04_151
    moveq   #8,D0
_anon_z04_151:
    ; If the current direction bit is masked off, then we've reached
    ; the opposite direction. Loop again.
    ;
    move.b  ($050F,A4),D1
    and.b   D0,D1   ; BIT: set Z/N/V from D1 AND A
    beq  _L_z04_Lamnola_UpdateHead_LoopFindPerpendicular
    ; If Y register >= $40, then break out of the loop.
    ; So, 75% of the time, if horizontal, then turn up, else left.
    ;
    cmpi.b  #$40,D3
    bcc  _L_z04_Lamnola_UpdateHead_SetDirAndCheckTiles
    ; Set Y register to $40 in order to break out of the loop next time;
    ; and loop again now.
    ; So, 25% of the time, if horizontal, then turn down, else right.
    ;
    moveq   #64,D3
    bcc  _L_z04_Lamnola_UpdateHead_LoopFindPerpendicular
    even
_L_z04_Lamnola_UpdateHead_SetDirAndCheckTiles:
    ; Change the facing direction to the direction found.
    ;
    lea     ($0098,A4),A0
    move.b  D0,(A0,D2.W)
    ; Set moving direction [0F] for boundary and tile checks.
    ;
    move.b  D0,($000F,A4)
    jsr     BoundByRoom
    ; If not blocked by the room boundary, then go check tile collision.
    ;
    move.b  ($000F,A4),D0
    bne  _L_z04_Lamnola_UpdateHead_CheckTileCollision
    even
_L_z04_Lamnola_UpdateHead_FindNonOpposite:
    ; Else it was blocked. So, load the facing direction in preparation
    ; for looking for any non-opposite direction that is not blocked.
    ;
    lea     ($0098,A4),A0
    move.b  (A0,D2.W),D0
    even
_L_z04_Lamnola_UpdateHead_LoopFindNonOpposite:
    ; Shift right the copy of the direction.
    ; If the direction bit rolled off the low end, then roll it onto the high end.
    ;
    lsr.b  #1,D0   ; LSR A
    bcc  _anon_z04_152
    moveq   #8,D0
_anon_z04_152:
    ; If the current direction bit is not masked off, then go check the
    ; room boundary in this direction.
    ; Else we've reached the opposite direction. Loop again.
    ;
    move.b  ($050F,A4),D1
    and.b   D0,D1   ; BIT: set Z/N/V from D1 AND A
    bne  _L_z04_Lamnola_UpdateHead_SetDirAndCheckTiles
    beq  _L_z04_Lamnola_UpdateHead_LoopFindNonOpposite
    even
_L_z04_Lamnola_UpdateHead_CheckTileCollision:
    ; We found a direction that was not blocked by the room boundary.
    ; Check tile collision. If blocked by a tile, then go look for another direction.
    ;
    jsr     GetCollidingTileMoving
    move.b  ($034A,A4),D1
    cmp.b   D1,D0
    bcc  _L_z04_Lamnola_UpdateHead_FindNonOpposite
    even
_L_z04_Lamnola_UpdateHead_Exit:
    ; TODO: confirm this
    ;
    ; If there were a room that had lamnolas, and they could get
    ; surrounded on 3 sides, then the loop above would get stuck in
    ; an infinite loop.
    ;
    ; But, the only room with that configuration has those blocks
    ; blocked off with a push block, which can only be pushed after
    ; all monsters are killed.
    ;
    rts

    even
_L_z04_Lamnola_UpdateHead_TurnTowardLink:
    ; Find the horizontal direction toward Link and store it in [02].
    ;
    moveq   #1,D0
    move.b  D0,($0002,A4)
    move.b  ($0070,A4),D0
    ori     #$11,CCR  ; SEC: set C+X
    move.b  ($70,A4,D2.W),D1
    eori    #$10,CCR  ; flip X: 6502 SBC polarity
    subx.b  D1,D0   ; SBC ObjX,X
    eori    #$10,CCR  ; restore X = 6502 C
    bcc  _anon_z04_153
    move.b  ($0002,A4),D1
    lsl.b  #1,D1   ; ASL $02
    move.b  D1,($0002,A4)
_anon_z04_153:
    ; Find the vertical direction toward Link and store it in [03].
    ;
    moveq   #4,D0
    move.b  D0,($0003,A4)
    move.b  ($0084,A4),D0
    ori     #$11,CCR  ; SEC: set C+X
    lea     ($0084,A4),A0
    move.b  (A0,D2.W),D1
    eori    #$10,CCR  ; flip X: 6502 SBC polarity
    subx.b  D1,D0   ; SBC ObjY,X
    eori    #$10,CCR  ; restore X = 6502 C
    bcc  _anon_z04_154
    move.b  ($0003,A4),D1
    lsl.b  #1,D1   ; ASL $03
    move.b  D1,($0003,A4)
_anon_z04_154:
    ; If the horizontal direction toward Link is not allowed, then
    ; go check the vertical direction.
    ;
    move.b  ($0002,A4),D0
    move.b  ($050F,A4),D1
    and.b   D0,D1   ; BIT: set Z/N/V from D1 AND A
    beq  _L_z04_Lamnola_UpdateHead_SetVertical
    ; If the horizontal direction toward Link is the same direction
    ; that Link is facing, then go test it for tile and room boundary collision.
    ;
    move.b  ($0098,A4),D1
    and.b   D0,D1   ; BIT: set Z/N/V from D1 AND A
    bne  _anon_z04_155
    even
_L_z04_Lamnola_UpdateHead_SetVertical:
    ; Load the vertical direction toward Link in order to test it for
    ; room boundary and tile collision.
    ;
    move.b  ($0003,A4),D0
_anon_z04_155:
    ; Go test this direction for collisions with tiles or the room boundary.
    ;
    jmp     _L_z04_Lamnola_UpdateHead_SetDirAndCheckTiles

    even
Lamnola_Move:
    ; This code is similar to 04:96EB Digdogger_Move.
    ;
    ; Change coordinates by the appropriate speed according to the direction.
    ;
    ; Start with a mask of $A1 in [02]:
    ; - low nibble represents the right direction
    ; - high nibble is used to set or clear carry as we go along
    ;
    move.b  #$A1,D0
    move.b  D0,($0002,A4)
    ; If direction has a right component (1), then add offset to X coordinate.
    ;
    lea     ($0098,A4),A0
    move.b  (A0,D2.W),D0
    move.b  ($0002,A4),D1
    and.b   D0,D1   ; BIT: set Z/N/V from D1 AND A
    beq  _L_z04_Lamnola_Move_Left
    move.b  ($70,A4,D2.W),D0
    andi    #$EE,CCR  ; CLC: clear C+X
    move.b  ($04E6,A4),D1
    addx.b  D1,D0   ; ADC Lamnola_Speed
    move.b  D0,($70,A4,D2.W)
    even
_L_z04_Lamnola_Move_Left:
    ; If direction has a left component (2), then subtract offset from X coordinate.
    ;
    lea     ($0098,A4),A0
    move.b  (A0,D2.W),D0
    move.b  ($0002,A4),D1
    lsl.b  #1,D1   ; ASL $02
    move.b  D1,($0002,A4)
    move.b  ($0002,A4),D1
    and.b   D0,D1   ; BIT: set Z/N/V from D1 AND A
    beq  _L_z04_Lamnola_Move_Down
    move.b  ($70,A4,D2.W),D0
    move.b  ($04E6,A4),D1
    eori    #$10,CCR  ; flip X: 6502 SBC polarity
    subx.b  D1,D0   ; SBC Lamnola_Speed
    eori    #$10,CCR  ; restore X = 6502 C
    move.b  D0,($70,A4,D2.W)
    even
_L_z04_Lamnola_Move_Down:
    ; If direction has a down component (4), then add offset to Y coordinate.
    ;
    lea     ($0098,A4),A0
    move.b  (A0,D2.W),D0
    move.b  ($0002,A4),D1
    lsl.b  #1,D1   ; ASL $02
    move.b  D1,($0002,A4)
    move.b  ($0002,A4),D1
    and.b   D0,D1   ; BIT: set Z/N/V from D1 AND A
    beq  _L_z04_Lamnola_Move_Up
    lea     ($0084,A4),A0
    move.b  (A0,D2.W),D0
    move.b  ($04E6,A4),D1
    addx.b  D1,D0   ; ADC Lamnola_Speed
    lea     ($0084,A4),A0
    move.b  D0,(A0,D2.W)
    even
_L_z04_Lamnola_Move_Up:
    ; If direction has an up component (8), then subtract offset from Y coordinate.
    ;
    lea     ($0098,A4),A0
    move.b  (A0,D2.W),D0
    move.b  ($0002,A4),D1
    lsl.b  #1,D1   ; ASL $02
    move.b  D1,($0002,A4)
    move.b  ($0002,A4),D1
    and.b   D0,D1   ; BIT: set Z/N/V from D1 AND A
    beq  _L_z04_Lamnola_Move_Exit
    lea     ($0084,A4),A0
    move.b  (A0,D2.W),D0
    move.b  ($04E6,A4),D1
    eori    #$10,CCR  ; flip X: 6502 SBC polarity
    subx.b  D1,D0   ; SBC Lamnola_Speed
    eori    #$10,CCR  ; restore X = 6502 C
    lea     ($0084,A4),A0
    move.b  D0,(A0,D2.W)
    even
_L_z04_Lamnola_Move_Exit:
    rts

; TODO:
; Was this intended to be an array of two elements?
;
    even
PatraManeuverTime:
    dc.b    $FF

; Unknown block
    dc.b    $50

    even
UpdatePatra:
    jsr     ControlPatraFlight
    ; Reset flying distance traveled, so that we know what offset to
    ; apply to the children.
    ;
    moveq   #0,D0
    lea     ($046B,A4),A0
    move.b  D0,(A0,D2.W)
    lea     ($0478,A4),A0
    move.b  D0,(A0,D2.W)
    jsr     MoveFlyer
    moveq   #2,D0
    jsr     AnimateAndDrawCommonObject
    ; Loop over the object slots of the 8 children.
    ; If any are found, then go check for collision with Link only.
    ;
    moveq   #8,D3
    even
_L_z04_UpdatePatra_LoopChildren:
    lea     ($0350,A4),A0
    move.b  (A0,D3.W),D0
    cmpi.b  #$25,D0
    beq  _L_z04_UpdatePatra_CheckLinkCollision
    cmpi.b  #$26,D0
    beq  _L_z04_UpdatePatra_CheckLinkCollision
    subq.b  #1,D3
    bne  _L_z04_UpdatePatra_LoopChildren
    ; If there are no children, then Link can harm Patra.
    ;
    jsr     CheckMonsterCollisions
    jsr     PlayBossHitCryIfNeeded
    jsr     PlayBossDeathCryIfNeeded
    jmp     _L_z04_UpdatePatra_TryChangeManeuver

    even
_L_z04_UpdatePatra_CheckLinkCollision:
    ; Else there are child patras left.
    ; Link cannot harm Patra, but it can harm Link.
    ;
    jsr     CheckLinkCollision
    even
_L_z04_UpdatePatra_TryChangeManeuver:
    ; If timer = 0 and the angle of patra child in slot 3 = 0, then
    ; flip the maneuver index.
    ;
    move.b  ($29,A4,D2.W),D0
    move.b  ($0397,A4),D1
    or.b  D1,D0
    bne  _L_z04_UpdatePatra_Exit
    lea     ($045E,A4),A0
    move.b  (A0,D2.W),D0
    eori.b #$01,D0
    lea     ($045E,A4),A0
    move.b  D0,(A0,D2.W)
    move.b  D3,D0
    ; TODO:
    ; for this to make sense, Y must be 0 or 1. But where is is set?
    ;
    lea     (PatraManeuverTime).l,A0
    move.b  (A0,D3.W),D0
    move.b  D0,($29,A4,D2.W)
    even
_L_z04_UpdatePatra_Exit:
    rts

    even
ControlPatraFlight:
    lea     ($0444,A4),A0
    move.b  (A0,D2.W),D0
    jsr     _m68k_tablejump  ; M68K-native table dispatch (replaces JSR TableJump)
    even
ControlPatraFlight_JumpTable:
    dc.l    Flyer_SpeedUp   ; jump table entry (32-bit for _m68k_tablejump)
    dc.l    Flyer_PatraDecideState   ; jump table entry (32-bit for _m68k_tablejump)
    dc.l    Flyer_Chase   ; jump table entry (32-bit for _m68k_tablejump)
    dc.l    Flyer_Wander   ; jump table entry (32-bit for _m68k_tablejump)

    even
Flyer_PatraDecideState:
    ; Go to the next state randomly:
    ; Random >= $40: 2
    ; Else:          3
    ;
    ; Set up 8 turns.
    ;
    moveq   #2,D3
    move.b  ($18,A4,D2.W),D0
    cmpi.b  #$40,D0
    bcc  _anon_z04_156
    addq.b  #1,D3
_anon_z04_156:
    move.b  D3,D0
    lea     ($0444,A4),A0
    move.b  D0,(A0,D2.W)
    moveq   #8,D0
    lea     ($042C,A4),A0
    move.b  D0,(A0,D2.W)
    rts

    even
PatraChildStartAngles:
    dc.b    $14, $10, $0C, $08, $04, $00, $1C

    even
PatraChild1RotationCosineBits:
    dc.b    $06

    even
PatraChild2RotationBits:
    dc.b    $05

    even
PatraChild1RotationSineBits:
    dc.b    $06, $06

    even
UpdatePatraChild:
    ; If state = 1, then go orbit.
    ;
    lea     ($00AC,A4),A0
    move.b  (A0,D2.W),D0
    beq.s  __far_z_04_0125
    jmp  PatraChild_State1
__far_z_04_0125:
    ; State = 0.
    ;
    ; If the current object slot is 2, then go initialize the patra child.
    ; This is the only patra child shown in the first fame.
    ;
    cmpi.b  #$02,D2
    beq  _L_z04_UpdatePatraChild_Ready
    ; The patra child in slot 2 is the last one to be updated.
    ; So all other patra children will see slot 2's state = 0, and return.
    ;
    ; This means that in the first frame, slot 2 is the only one to be
    ; shown.
    ;
    move.b  ($00AE,A4),D0
    beq  _L_z04_UpdatePatraChild_Exit
    ; In subsequent frames, patra children in slots >= 3 will reach
    ; here to wait to be shown at the top position (N) one at a time.
    ;
    move.b  D2,D0
    ; Subtract 3 from the object slot to get the angle where the
    ; patra child in object slot 2 should be for the current one to appear.
    ;
    ori     #$11,CCR  ; SEC: set C+X
    move.b  #$03,D1
    eori    #$10,CCR  ; flip X: 6502 SBC polarity
    subx.b  D1,D0   ; SBC #$03
    eori    #$10,CCR  ; restore X = 6502 C
    moveq   #0,D3
    move.b  D0,D3
    ; If the patra child in slot 2 has not reached the required angle,
    ; then return.
    ;
    move.b  ($0396,A4),D0
    lea     (PatraChildStartAngles).l,A0
    move.b  (A0,D3.W),D1
    cmp.b   D1,D0
    bne  _L_z04_UpdatePatraChild_Exit
    even
_L_z04_UpdatePatraChild_Ready:
    ; Once the patra child in the last slot (9) reaches here, advance
    ; the patra parent's state.
    ;
    cmpi.b  #$09,D2
    bne  _anon_z04_157
    addq.b  #1,($00AD,A4)
_anon_z04_157:
    ; Go to state 1 to orbit.
    ;
    lea     ($00AC,A4),A0
    addq.b  #1,(A0,D2.W)
    ; TODO: ?
    ;
    move.b  #$80,D0
    lea     ($0098,A4),A0
    move.b  D0,(A0,D2.W)
    ; Set angle $18 (N).
    ;
    moveq   #24,D0
    lea     ($0394,A4),A0
    move.b  D0,(A0,D2.W)
    ; This location is right above Patra.
    ; Set X coordinate to Patra's.
    ;
    move.b  ($0071,A4),D0
    move.b  D0,($70,A4,D2.W)
    ; If patra child type = $25, then the radius of its orbit is $2C.
    ; Else use radius $18. Store the chosen value in [00].
    ;
    moveq   #44,D0
    moveq   #0,D3
    lea     ($034F,A4),A0
    move.b  (A0,D2.W),D3
    cmpi.b  #$25,D3
    beq  _anon_z04_158
    moveq   #24,D0
_anon_z04_158:
    move.b  D0,($0000,A4)
    ; This location is right above Patra.
    ; Set Y coordinate to (Patra's Y - [00]).
    ;
    move.b  ($0085,A4),D0
    ori     #$11,CCR  ; SEC: set C+X
    move.b  ($0000,A4),D1
    eori    #$10,CCR  ; flip X: 6502 SBC polarity
    subx.b  D1,D0   ; SBC $00
    eori    #$10,CCR  ; restore X = 6502 C
    lea     ($0084,A4),A0
    move.b  D0,(A0,D2.W)
    even
_L_z04_UpdatePatraChild_Exit:
    rts

    even
PatraChild_State1:
    ; Add Patra's distance traveled since the last frame to this child's coordinates.
    ;
    move.b  ($70,A4,D2.W),D0
    andi    #$EE,CCR  ; CLC: clear C+X
    move.b  ($046C,A4),D1
    addx.b  D1,D0   ; ADC Flyer_ObjOffsetX+1
    move.b  D0,($70,A4,D2.W)
    lea     ($0084,A4),A0
    move.b  (A0,D2.W),D0
    andi    #$EE,CCR  ; CLC: clear C+X
    move.b  ($0479,A4),D1
    addx.b  D1,D0   ; ADC Flyer_ObjOffsetY+1
    lea     ($0084,A4),A0
    move.b  D0,(A0,D2.W)
    ; Reset [0B]. The high byte of the amount to subtract is 0.
    ;
    moveq   #0,D0
    move.b  D0,($000B,A4)
    ; If the monster is type $25 Patra Child1, then decrease the
    ; monster's angle by $70, else by $60 to go slower.
    ;
    moveq   #112,D0
    moveq   #0,D3
    lea     ($034F,A4),A0
    move.b  (A0,D2.W),D3
    cmpi.b  #$25,D3
    beq  _anon_z04_159
    moveq   #96,D0
_anon_z04_159:
    jsr     DecreaseObjectAngle
    ; Load Patra's maneuver index.
    ; It determines which counts of bits are looked up below.
    ;
    moveq   #0,D3
    move.b  ($045F,A4),D3
    ; If the monster is Patra Child 1 ($25), then look up two separate
    ; counts of bits to use for Y and X increment calculations in rotation.
    ; This leads to a large circle (6,6) and a wobbling ring (5,6).
    ;
    lea     ($034F,A4),A0
    move.b  (A0,D2.W),D0
    cmpi.b  #$25,D0
    bne  _L_z04_PatraChild_State1_UsePatraChild2Bits
    lea     (PatraChild1RotationCosineBits).l,A0
    move.b  (A0,D3.W),D0
    move.b  D0,-(A5)  ; PHA
    lea     (PatraChild1RotationSineBits).l,A0
    move.b  (A0,D3.W),D0
    moveq   #0,D3
    move.b  D0,D3
    move.b  (A5)+,D0  ; PLA
    jmp     _L_z04_PatraChild_State1_Rotate

    even
_L_z04_PatraChild_State1_UsePatraChild2Bits:
    ; Else it's Patra Child 2 ($26). Look up one value that will be used
    ; for both Y and X increment calculations in rotation. This leads to
    ; a small circle (5) and a large circle (6).
    ;
    lea     (PatraChild2RotationBits).l,A0
    move.b  (A0,D3.W),D0
    moveq   #0,D3
    move.b  D0,D3
    even
_L_z04_PatraChild_State1_Rotate:
    jsr     RotateObjectLocation
    lea     ($0084,A4),A0
    move.b  D0,(A0,D2.W)
    jsr     PatraChild_Draw
    ; If Patra's state still = 0, then the last patra child has not
    ; shown up yet. In this case don't check collisions yet, only return.
    ;
    move.b  ($00AD,A4),D0
    beq  _L_z04_PatraChild_State1_Exit
    jsr     CheckMonsterCollisions
    ; If the monster died, then change to the dead dummy object.
    ;
    lea     ($0405,A4),A0
    move.b  (A0,D2.W),D0
    beq  _L_z04_PatraChild_State1_Exit
    jsr     SetDeadDummyObjType
    even
_L_z04_PatraChild_State1_Exit:
    rts

    even
PatraChild_Draw:
    jsr     Anim_SetSpriteDescriptorRedPaletteRow
    ; 2 was returned from the routine above in A.
    ; Pass it as the animation counter value to the routine below.
    ;
    jsr     Anim_AdvanceAnimCounterAndSetObjPosForSpriteDescriptor
    lea     ($03E4,A4),A0
    move.b  (A0,D2.W),D0
    jmp     DrawObjectNotMirrored

    even
UpdateGanon:
    move.b  ($0445,A4),D0
    jsr     _m68k_tablejump  ; M68K-native table dispatch (replaces JSR TableJump)
    even
UpdateGanon_JumpTable:
    dc.l    Ganon_ScenePhase0   ; jump table entry (32-bit for _m68k_tablejump)
    dc.l    Ganon_ScenePhase1   ; jump table entry (32-bit for _m68k_tablejump)
    dc.l    Ganon_ScenePhase2   ; jump table entry (32-bit for _m68k_tablejump)

; Description:
; Lift up the Triforce of Courage while the room is dark.
;
; Lift the Triforce of Courage -- represented with a triforce piece.
;
    even
Ganon_ScenePhase0:
    moveq   #27,D0
    move.b  D0,($0505,A4)
    ; If Link's timer has not expired, then go do nothing until the last frame.
    ;
    move.b  ($0028,A4),D0
    bne  _L_z04_Ganon_ScenePhase0_CheckTimeToShout
    ; Once the timer expires, it's time to brighten the room.
    ;
    ; Save the current object slot.
    move.b  D2,D0
    move.b  D0,-(A5)  ; PHA
    jsr     UpdateCandle
    move.b  (A5)+,D0  ; PLA
    moveq   #0,D2
    move.b  D0,D2
    ; Turn off the room brightening flag, because we're controlling it
    ; here instead of in the Mode 5 object update loop.
    ;
    moveq   #0,D0
    move.b  D0,($051E,A4)
    ; On the first frame of the fade-to-light cycle, play the
    ; Triforce/Ganon song.
    ;
    move.b  ($051C,A4),D0
    cmpi.b  #$C0,D0
    bne  _L_z04_Ganon_ScenePhase0_CheckFadeCycle
    moveq   #2,D0
    move.b  D0,($0600,A4)
    even
_L_z04_Ganon_ScenePhase0_CheckFadeCycle:
    ; If the fade cycle has not ended, then go draw Ganon.
    ;
    move.b  ($051C,A4),D0
    andi.b #$0F,D0
    cmpi.b  #$04,D0
    beq.s  __far_z_04_0126
    jmp  Ganon_DrawBodyFrame0
__far_z_04_0126:
    ; Set Link's timer to $C0 for the next scene phase.
    ;
    move.b  #$C0,D0
    move.b  D0,($0028,A4)
    ; Set scene phase 1, and go draw Ganon.
    ;
    addq.b  #1,($0445,A4)
    beq.s  __far_z_04_0127
    jmp  Ganon_DrawBodyFrame0
__far_z_04_0127:
    even
_L_z04_Ganon_ScenePhase0_CheckTimeToShout:
    ; If timer = 1, then play Boss hit/hurt sound effect.
    ; In this case, I think it means Ganon is shouting.
    ;
    cmpi.b  #$01,D0
    bne  _anon_z04_160
    moveq   #2,D0
    move.b  D0,($0601,A4)
_anon_z04_160:
    rts

; Description:
; Lift up the Triforce of Courage while the room is light.
;
; Lift the Triforce of Courage -- represented with a triforce piece.
;
    even
Ganon_ScenePhase1:
    moveq   #27,D0
    move.b  D0,($0505,A4)
    ; If Link's timer hasn't expired, then go draw Ganon.
    ;
    move.b  ($0028,A4),D0
    beq.s  __far_z_04_0128
    jmp  Ganon_DrawBodyFrame0
__far_z_04_0128:
    ; Once the timer expires:
    ; 1. unhalt Link
    ; 2. clear the item to lift
    ; 3. play level 9 song
    ; 4. go to scene phase 2: fighting / not holding triforce
    ;
    move.b  D0,($00AC,A4)
    move.b  D0,($0505,A4)
    moveq   #32,D0
    move.b  D0,($0600,A4)
    addq.b  #1,($0445,A4)
    even
Ganon_DrawBodyFrame0:
    ; When holding the Triforce of Courage, only draw Ganon
    ; with animation frame 0.
    ;
    moveq   #0,D0
    lea     ($046B,A4),A0
    move.b  D0,(A0,D2.W)
    jmp     Ganon_DrawBody

; Description:
; Fighting Ganon.
;
; If Ganon is dying, go handle it.
;
    even
Ganon_ScenePhase2:
    lea     ($042C,A4),A0
    move.b  (A0,D2.W),D0
    beq.s  __far_z_04_0129
    jmp  Ganon_Dying
__far_z_04_0129:
    jsr     Ganon_CheckCollisions
    jsr     PlayBossHitCryIfNeeded
    ; Go handle the brown state specially.
    ;
    lea     ($00AC,A4),A0
    move.b  (A0,D2.W),D0
    beq.s  __far_z_04_0130
    jmp  Ganon_UpdateBrownState
__far_z_04_0130:
    ; State = 0: Blue
    ;
    ; If timer = 0, then go move around and shoot.
    ;
    move.b  ($28,A4,D2.W),D0
    bne.s  __far_z_04_0131
    jmp  Ganon_MoveAndShoot
__far_z_04_0131:
    ; If timer > 1, then Ganon is blue and visible. Only draw.
    ; Collisions were checked already.
    ;
    ; Else timer = 1. Fall thru and randomize Ganon's location,
    ; in anticipation of moving around when timer becomes 0 next frame.
    ;
    cmpi.b  #$01,D0
    beq.s  __far_z_04_0132
    jmp  L_Ganon_DrawBody
__far_z_04_0132:
; Description:
; Put Ganon at Y=$A0, and a random X of $30 or $B0.
;
    even
Ganon_RandomizeLocation:
    move.b  #$A0,D0
    lea     ($0084,A4),A0
    move.b  D0,(A0,D2.W)
    move.b  ($0015,A4),D0
    andi.b #$01,D0
    moveq   #0,D3
    move.b  D0,D3
    lea     (GanonStartXs).l,A0
    move.b  (A0,D3.W),D0
    move.b  D0,($70,A4,D2.W)
    rts

    even
Ganon_MoveAndShoot:
    ; Change the animation frame every screen frame; so that
    ; when Ganon is hit, he appears in a random pose.
    ;
    lea     ($046B,A4),A0
    addq.b  #1,(A0,D2.W)
    ; The animation cycle has 6 frames.
    ;
    lea     ($046B,A4),A0
    move.b  (A0,D2.W),D0
    cmpi.b  #$06,D0
    bne  _L_z04_Ganon_MoveAndShoot_Move
    moveq   #0,D0
    lea     ($046B,A4),A0
    move.b  D0,(A0,D2.W)
    even
_L_z04_Ganon_MoveAndShoot_Move:
    ; Move like a blue wizzrobe teleporting.
    ;
    moveq   #1,D0
    lea     ($0394,A4),A0
    move.b  D0,(A0,D2.W)
    jsr     BlueWizzrobe_TurnSometimesAndMoveAndCheckTile
    ; Shoot every $40 frames.
    ;
    move.b  ($0015,A4),D0
    andi.b #$3F,D0
    bne  _L_z04_Ganon_MoveAndShoot_Exit
    moveq   #86,D0
    jsr     ShootFireball
    even
_L_z04_Ganon_MoveAndShoot_Exit:
    rts

    even
GanonStartXs:
    dc.b    $30, $B0

    even
Ganon_UpdateBrownState:
    ; Every other frame decrement the state.
    ; But every frame draw Ganon either translucent or opaque.
    ;
    move.b  ($0015,A4),D0
    lsr.b  #1,D0   ; LSR A
    bcc  _L_z04_Ganon_UpdateBrownState_Draw
    lea     ($00AC,A4),A0
    subq.b  #1,(A0,D2.W)
    ; If the state becomes 0, then Ganon is blue again.
    ; Go switch his palette row to reflect it.
    ;
    bne  _L_z04_Ganon_UpdateBrownState_Draw
    jsr     Ganon_RandomizeLocation
    jmp     Ganon_AppendPaletteRowTransferRecord_Blue

    even
_L_z04_Ganon_UpdateBrownState_Draw:
    ; When state >= $30, draw Ganon opaque.
    ; When state goes below, draw him translucent.
    ;
    lea     ($00AC,A4),A0
    move.b  (A0,D2.W),D0
    cmpi.b  #$30,D0
    bcs.s  __far_z_04_0133
    jmp  L_Ganon_DrawBody
__far_z_04_0133:
    move.b  ($0015,A4),D0
    lsr.b  #1,D0   ; LSR A
    bcc  _anon_z04_161
    even
L_Ganon_DrawBody:
    jsr     Ganon_DrawBody
_anon_z04_161:
    rts

    even
Ganon_Dying:
    ; Ganon is dying.
    ; Increment Ganon phase every frame.
    ;
    lea     ($042C,A4),A0
    addq.b  #1,(A0,D2.W)
    ; If it just went from $FF to 0, then keep it at $FF.
    ;
    lea     ($042C,A4),A0
    move.b  (A0,D2.W),D0
    bne  _anon_z04_162
    move.b  #$FF,D0
    lea     ($042C,A4),A0
    move.b  D0,(A0,D2.W)
_anon_z04_162:
    ; If Ganon phase < $50, then go draw only.
    ;
    cmpi.b  #$50,D0
    bcc.s  __far_z_04_0134
    jmp  L_Ganon_DrawBody
__far_z_04_0134:
    ; If > $50, then go handle ashes only.
    ;
    bne  _L_z04_Ganon_Dying_HandleAshes
    ; Otherwise Ganon phase = $50.
    ; Set up the burst and ashes.
    ;
    jsr     Ganon_AppendPaletteRowTransferRecord_Triforce
    ; Ganon is now a pile of ashes at offset (7, 8) from where he was.
    ;
    move.b  ($70,A4,D2.W),D0
    move.b  #$07,D1
    addx.b  D1,D0   ; ADC #$07 (X flag = 6502 C)
    move.b  D0,($70,A4,D2.W)
    lea     ($0084,A4),A0
    move.b  (A0,D2.W),D0
    move.b  #$08,D1
    addx.b  D1,D0   ; ADC #$08 (X flag = 6502 C)
    lea     ($0084,A4),A0
    move.b  D0,(A0,D2.W)
    jsr     Ganon_SetUpBurstRays
    jsr     PlayBossDeathCry
    moveq   #2,D0
    move.b  D0,($0600,A4)
    even
_L_z04_Ganon_Dying_HandleAshes:
    jsr     Ganon_DrawAshes
    ; Keep drawing the burst artifacts while Ganon phase < $A0.
    ;
    lea     ($042C,A4),A0
    move.b  (A0,D2.W),D0
    cmpi.b  #$A0,D0
    bcc.s  __far_z_04_0135
    jmp  Ganon_DrawBurst
__far_z_04_0135:
    ; If > $A0, then there's nothing left to do, except return.
    ;
    bne  _L_z04_Ganon_Dying_Exit
    ; Otherwise Ganon phase = $A0.
    ; Activate the room item (triforce of power).
    ;
    jsr     Ganon_ActivateRoomItem
    ; Put it at Ganon's ashes' location.
    ;
    move.b  ($70,A4,D2.W),D0
    move.b  D0,($0083,A4)
    lea     ($0084,A4),A0
    move.b  (A0,D2.W),D0
    move.b  D0,($0097,A4)
    ; Increase the room kill count.
    ;
    addq.b  #1,($034F,A4)
    even
_L_z04_Ganon_Dying_Exit:
    rts

    even
GanonBurstDirs:
    dc.b    $01, $02, $04, $05, $06, $08, $09, $0A

    even
GanonBurstSpriteAttrs:
    dc.b    $00, $00, $40, $00, $80, $C0, $80, $00
    dc.b    $40, $00

    even
GanonBurstTiles:
    dc.b    $00, $00, $EE, $EE, $E8, $30, $30, $E8
    dc.b    $30, $30

    even
Ganon_SetUpBurstRays:
    ; Loop over 8 burst rays, from 7 to 0, indexed by Y register.
    ; Access object slots 9 to 2.
    ;
    moveq   #7,D3
    even
_L_z04_Ganon_SetUpBurstRays_LoopRay:
    ; Start each piece at offset (4, 4) from Ganon's location.
    ;
    move.b  ($70,A4,D2.W),D0
    andi    #$EE,CCR  ; CLC: clear C+X
    move.b  #$04,D1
    addx.b  D1,D0   ; ADC #$04 (X flag = 6502 C)
    move.b  D0,($72,A4,D3.W)
    lea     ($0084,A4),A0
    move.b  (A0,D2.W),D0
    move.b  #$04,D1
    addx.b  D1,D0   ; ADC #$04 (X flag = 6502 C)
    lea     ($0086,A4),A0
    move.b  D0,(A0,D3.W)
    ; Set the direction.
    ;
    lea     (GanonBurstDirs).l,A0
    move.b  (A0,D3.W),D0
    lea     ($009A,A4),A0
    move.b  D0,(A0,D3.W)
    subq.b  #1,D3
    bpl  _L_z04_Ganon_SetUpBurstRays_LoopRay
    rts

; Params:
; [00]: X
; [01]: Y
;
; Save the coordinates.
;
    even
Ganon_DrawCloud:
    move.b  ($0000,A4),D0
    move.b  D0,-(A5)  ; PHA
    move.b  ($0001,A4),D0
    move.b  D0,-(A5)  ; PHA
    ; If cloud distance < 6, then use frame image $C (medium).
    ; Else use frame image $D (low).
    ;
    moveq   #12,D0
    moveq   #0,D3
    lea     ($0478,A4),A0
    move.b  (A0,D2.W),D3
    cmpi.b  #$06,D3
    bcc  _anon_z04_163
    moveq   #13,D0
_anon_z04_163:
    moveq   #0,D3
    move.b  D3,($000F,A4)
    jsr     DrawObjectMirrored
    ; Restore the coordinates.
    ;
    move.b  (A5)+,D0  ; PLA
    move.b  D0,($0001,A4)
    move.b  (A5)+,D0  ; PLA
    move.b  D0,($0000,A4)
    rts

    even
Ganon_DrawBurst:
    ; If cloud distance <> 0, then decrement it once every 8 frames.
    ;
    lea     ($0478,A4),A0
    move.b  (A0,D2.W),D0
    beq  _L_z04_Ganon_DrawBurst_DrawClouds
    move.b  ($0015,A4),D0
    andi.b #$07,D0
    bne  _L_z04_Ganon_DrawBurst_DrawClouds
    lea     ($0478,A4),A0
    subq.b  #1,(A0,D2.W)
    even
_L_z04_Ganon_DrawBurst_DrawClouds:
    ; Draw the four clouds at diagonal corners.
    ;
    jsr     Ganon_GetCurCloudLeft
    jsr     Ganon_GetCurCloudTop
    jsr     Ganon_DrawCloud
    jsr     Ganon_GetCurCloudRight
    jsr     Ganon_DrawCloud
    jsr     Ganon_GetCurCloudLeft
    jsr     Ganon_GetCurCloudBottom
    jsr     Ganon_DrawCloud
    jsr     Ganon_GetCurCloudRight
    jsr     Ganon_DrawCloud
    ; Draw the top and bottom clouds.
    ;
    move.b  ($70,A4,D2.W),D0
    move.b  D0,($0000,A4)
    jsr     Ganon_GetCurCloudTop
    jsr     Ganon_DrawCloud
    jsr     Ganon_GetCurCloudBottom
    jsr     Ganon_DrawCloud
    ; Draw the left and right clouds.
    ;
    jsr     Ganon_GetCurCloudLeft
    lea     ($0084,A4),A0
    move.b  (A0,D2.W),D0
    move.b  D0,($0001,A4)
    jsr     Ganon_DrawCloud
    jsr     Ganon_GetCurCloudRight
    jsr     Ganon_DrawCloud
    ; Save the object index.
    ;
    move.b  ($0340,A4),D0
    move.b  D0,-(A5)  ; PHA
    ; Loop over the 8 burst rays in slots 2 to 9, to move and draw them.
    ;
    moveq   #2,D2
    even
_L_z04_Ganon_DrawBurst_LoopRay:
    move.b  D2,($0340,A4)
    ; If object slot < 5 or = 7, then move every frame.
    ; Else move 3 out of every 4 frames.
    ;
    ; This makes pieces spread out in somewhat of a circle,
    ; by making the pieces at cardinal directions move at
    ; full speed while the diagonal ones move a little slower.
    ;
    cmpi.b  #$05,D2
    bcs  _L_z04_Ganon_DrawBurst_Move
    cmpi.b  #$07,D2
    beq  _L_z04_Ganon_DrawBurst_Move
    move.b  ($0015,A4),D0
    andi.b #$03,D0
    beq  _anon_z04_164
    even
_L_z04_Ganon_DrawBurst_Move:
    jsr     BlueWizzrobe_Move
_anon_z04_164:
    jsr     Anim_FetchObjPosForSpriteDescriptor
    ; The frame counter will make the sprite flash.
    ; The array has the horizontal and vertical flipping attributes.
    ; Combine them into [03].
    ;
    move.b  ($0015,A4),D0
    andi.b #$03,D0
    lea     (GanonBurstSpriteAttrs).l,A0
    move.b  (A0,D2.W),D1
    or.b  D1,D0
    move.b  D0,($0003,A4)
    lea     (GanonBurstTiles).l,A0
    move.b  (A0,D2.W),D0
    jsr     Anim_WriteSprite
    ; Bottom of the loop.
    ; Increment object slot while <= 9.
    ;
    addq.b  #1,D2
    cmpi.b  #$0A,D2
    bcs  _L_z04_Ganon_DrawBurst_LoopRay
    ; Restore the object index.
    ;
    move.b  (A5)+,D0  ; PLA
    move.b  D0,($0340,A4)
    rts

; Returns:
; [00]: X coordinate
;
    even
Ganon_GetCurCloudLeft:
    move.b  ($70,A4,D2.W),D0
    ori     #$11,CCR  ; SEC: set C+X
    lea     ($0478,A4),A0
    move.b  (A0,D2.W),D1
    eori    #$10,CCR  ; flip X: 6502 SBC polarity
    subx.b  D1,D0   ; SBC Ganon_ObjCloudDist,X
    eori    #$10,CCR  ; restore X = 6502 C
    move.b  D0,($0000,A4)
    eori    #$01,CCR  ; normalize C to 6502 polarity before RTS
    rts

; Returns:
; [00]: X coordinate
;
    even
Ganon_GetCurCloudRight:
    move.b  ($70,A4,D2.W),D0
    andi    #$EE,CCR  ; CLC: clear C+X
    lea     ($0478,A4),A0
    move.b  (A0,D2.W),D1
    addx.b  D1,D0   ; ADC Ganon_ObjCloudDist,X
    move.b  D0,($0000,A4)
    rts

; Returns:
; [01]: Y coordinate
;
    even
Ganon_GetCurCloudTop:
    lea     ($0084,A4),A0
    move.b  (A0,D2.W),D0
    ori     #$11,CCR  ; SEC: set C+X
    lea     ($0478,A4),A0
    move.b  (A0,D2.W),D1
    eori    #$10,CCR  ; flip X: 6502 SBC polarity
    subx.b  D1,D0   ; SBC Ganon_ObjCloudDist,X
    eori    #$10,CCR  ; restore X = 6502 C
    move.b  D0,($0001,A4)
    eori    #$01,CCR  ; normalize C to 6502 polarity before RTS
    rts

; Returns:
; [01]: Y coordinate
;
    even
Ganon_GetCurCloudBottom:
    lea     ($0084,A4),A0
    move.b  (A0,D2.W),D0
    andi    #$EE,CCR  ; CLC: clear C+X
    lea     ($0478,A4),A0
    move.b  (A0,D2.W),D1
    addx.b  D1,D0   ; ADC Ganon_ObjCloudDist,X
    move.b  D0,($0001,A4)
    rts

    even
GanonFrameImages:
    dc.b    $06, $08, $07, $09, $00, $00, $01, $01
    dc.b    $02, $02, $03, $03, $04, $00, $05, $01
    dc.b    $04, $04, $05, $05, $00, $04, $01, $05

    even
GanonSpriteOffsetsX:
    dc.b    $00, $10, $00, $10

    even
GanonSpriteOffsetsY:
    dc.b    $00, $00, $10, $10

    even
GanonSpriteHFlips:
    dc.b    $00, $01, $00, $01

    even
Ganon_DrawBody:
    ; Loop over four 16x16 images that make up Ganon.
    ; There are 6 animation frames.
    ;
    moveq   #3,D3
    even
_L_z04_Ganon_DrawBody_LoopCorner:
    ; Add an offset to Ganon's X, and store the result in [00] -- the sprite's X.
    ;
    move.b  ($70,A4,D2.W),D0
    andi    #$EE,CCR  ; CLC: clear C+X
    lea     (GanonSpriteOffsetsX).l,A0
    move.b  (A0,D3.W),D1
    addx.b  D1,D0   ; ADC GanonSpriteOffsetsX,Y
    move.b  D0,($0000,A4)
    ; Add an offset to Ganon's Y, and store the result in [01] -- the sprite's Y.
    ;
    lea     ($0084,A4),A0
    move.b  (A0,D2.W),D0
    andi    #$EE,CCR  ; CLC: clear C+X
    lea     (GanonSpriteOffsetsY).l,A0
    move.b  (A0,D3.W),D1
    addx.b  D1,D0   ; ADC GanonSpriteOffsetsY,Y
    move.b  D0,($0001,A4)
    ; Each part has a horizontal flipping flag.
    ;
    lea     (GanonSpriteHFlips).l,A0
    move.b  (A0,D3.W),D0
    move.b  D0,($000F,A4)
    ; Save and copy the loop index (the current part) to [07].
    ;
    move.b  D3,D0
    move.b  D0,-(A5)  ; PHA
    move.b  D0,($0007,A4)
    ; Multiply the animation frame by 4, because of the 4 parts
    ; that make it up.
    ;
    lea     ($046B,A4),A0
    move.b  (A0,D2.W),D0
    lsl.b  #1,D0   ; ASL A
    lsl.b  #1,D0   ; ASL A
    ; Add [07] -- the index of the current part.
    ;
    ; Now you have an index into the frame image table, for the
    ; current image part of the current animation frame.
    ;
    move.b  ($0007,A4),D1
    addx.b  D1,D0   ; ADC $07
    moveq   #0,D3
    move.b  D0,D3
    lea     (GanonFrameImages).l,A0
    move.b  (A0,D3.W),D0
    jsr     DrawObjectNotMirrored
    move.b  (A5)+,D0  ; PLA
    ; Bottom of the part loop.
    ;
    moveq   #0,D3
    move.b  D0,D3
    subq.b  #1,D3
    bpl  _L_z04_Ganon_DrawBody_LoopCorner
    rts

    even
Ganon_CheckCollisions:
    ; Calculate Ganon's midpoint at offset ($10, $10) from his coordinates.
    ; Store in [02] and [03].
    ;
    move.b  ($70,A4,D2.W),D0
    andi    #$EE,CCR  ; CLC: clear C+X
    move.b  #$10,D1
    addx.b  D1,D0   ; ADC #$10 (X flag = 6502 C)
    move.b  D0,($0002,A4)
    lea     ($0084,A4),A0
    move.b  (A0,D2.W),D0
    andi    #$EE,CCR  ; CLC: clear C+X
    move.b  #$10,D1
    addx.b  D1,D0   ; ADC #$10 (X flag = 6502 C)
    move.b  D0,($0003,A4)
    ; Check for a collision with Link.
    ;
    ; We can't call CheckLinkCollision, because we need to
    ; customize Ganon's midpoint.
    ;
    ; So, we've calculated the midpoint hotspot. Now, skip collision
    ; detection, if Link is invincible. Initialize variables that will
    ; be returned from the partial collision check routine. Then
    ; call it.
    ;
    move.b  ($04F0,A4),D0
    bne  _L_z04_Ganon_CheckCollisions_SkipLinkCollision
    move.b  D0,($0006,A4)
    move.b  D0,($0009,A4)
    move.b  D0,($000C,A4)
    moveq   #0,D3
    move.b  D3,($0000,A4)
    jsr     CheckLinkCollisionPreinit
    even
_L_z04_Ganon_CheckCollisions_SkipLinkCollision:
    ; If Ganon is not in state 0, then he's brown.
    ; Go check collision with an arrow.
    ;
    lea     ($00AC,A4),A0
    move.b  (A0,D2.W),D0
    bne  _L_z04_Ganon_CheckCollisions_CheckArrowCollision
    ; If timer <> 0, then Ganon is visible.
    ; He can't be harmed like this. So, return.
    ;
    move.b  ($28,A4,D2.W),D0
    bne  _L_z04_Ganon_CheckCollisions_Exit
    moveq   #13,D3
    jsr     CheckMonsterSwordCollision
    ; If Ganon has died according to the usual collision check rules
    ; (HP = 0), then:
    ; 1. Restore HP to the initial value $F0
    ; 2. Set state to $FF to note that Ganon is vulnerable to silver arrows
    ; 3. Change palette row 7 to make Ganon brown
    ;
    lea     ($0405,A4),A0
    move.b  (A0,D2.W),D0
    beq  _L_z04_Ganon_CheckCollisions_CheckHarmed
    move.b  #$F0,D0
    lea     ($0485,A4),A0
    move.b  D0,(A0,D2.W)
    lea     ($00AC,A4),A0
    subq.b  #1,(A0,D2.W)
    jsr     Ganon_AppendPaletteRowTransferRecord_Brown
    even
_L_z04_Ganon_CheckCollisions_CheckHarmed:
    ; If Ganon was harmed, then play the sound effect
    ; and set timer to $40, so that he's visible for $40 frames.
    ;
    lea     ($04F0,A4),A0
    move.b  (A0,D2.W),D0
    beq  _L_z04_Ganon_CheckCollisions_UndoDeath
    jsr     PlayBossHitCryIfNeeded
    moveq   #64,D0
    move.b  D0,($28,A4,D2.W)
    even
_L_z04_Ganon_CheckCollisions_UndoDeath:
    ; Reset metastate, because Ganon cannot die this way.
    ;
    jsr     ResetObjMetastate
    ; Reset shove info and invincibility timer, because Ganon
    ; doesn't react at all as a usual monster.
    ;
    jsr     ResetShoveInfoAndInvincibilityTimer
    even
_L_z04_Ganon_CheckCollisions_Exit:
    rts

    even
_L_z04_Ganon_CheckCollisions_CheckArrowCollision:
    ; If the silver arrow is not in the inventory, then return.
    ;
    move.b  ($0659,A4),D0
    cmpi.b  #$02,D0
    bne  _L_z04_Ganon_CheckCollisions_Exit
    ; Reset the collision return value [06].
    ;
    moveq   #0,D0
    move.b  D0,($0006,A4)
    ; If there's no arrow in flight, then return.
    ;
    moveq   #18,D3
    lea     ($00AC,A4),A0
    move.b  (A0,D3.W),D0
    cmpi.b  #$10,D0
    bne  _L_z04_Ganon_CheckCollisions_Exit
    ; Check for collision with an arrow; and return if no collision.
    ;
    jsr     CheckMonsterArrowOrRodCollision
    move.b  ($0006,A4),D0
    beq  _L_z04_Ganon_CheckCollisions_Exit
    ; Set the Ganon phase to "dying".
    ;
    lea     ($042C,A4),A0
    addq.b  #1,(A0,D2.W)
    ; Now his body does flash.
    ;
    moveq   #40,D0
    lea     ($04F0,A4),A0
    move.b  D0,(A0,D2.W)
    ; Set initial cloud distance 8.
    ;
    moveq   #8,D0
    lea     ($0478,A4),A0
    move.b  D0,(A0,D2.W)
    rts

    even
GanonColorTransferRecord:
    dc.b    $3F, $1C, $04, $0F, $07, $17, $27, $FF

    even
GanonColorSets:
    dc.b    $07, $17, $30, $16, $2C, $3C, $27, $06
    dc.b    $16

    even
Ganon_AppendPaletteRowTransferRecord_Brown:
    moveq   #2,D3
    bne  _anon_z04_165
    even
Ganon_AppendPaletteRowTransferRecord_Blue:
    moveq   #5,D3
    bne  _anon_z04_165
    even
Ganon_AppendPaletteRowTransferRecord_Triforce:
    moveq   #8,D3
_anon_z04_165:
    move.b  D3,D0
    move.b  D0,-(A5)  ; PHA
    ; Get the length, to append to the dynamic transfer buf.
    ;
    moveq   #0,D2
    move.b  ($0301,A4),D2
    ; Copy the 8 bytes of the palette row transfer record template.
    ;
    moveq   #0,D3
    even
_L_z04_Ganon_AppendPaletteRowTransferRecord_Triforce_CopyBytes:
    lea     (GanonColorTransferRecord).l,A0
    move.b  (A0,D3.W),D0
    lea     ($0302,A4),A0
    move.b  D0,(A0,D2.W)
    addq.b  #1,D2
    addq.b  #1,D3
    cmpi.b  #$08,D3
    bne  _L_z04_Ganon_AppendPaletteRowTransferRecord_Triforce_CopyBytes
    move.b  D2,($0301,A4)
    move.b  (A5)+,D0  ; PLA
    moveq   #0,D3
    move.b  D0,D3
    ; Overwrite the last 3 colors in the record, with the ones
    ; ending at the index passed in.
    ;
    moveq   #2,D2
    even
_L_z04_Ganon_AppendPaletteRowTransferRecord_Triforce_OverwriteColors:
    lea     (GanonColorSets).l,A0
    move.b  (A0,D3.W),D0
    lea     ($0306,A4),A0
    move.b  D0,(A0,D2.W)
    subq.b  #1,D3
    subq.b  #1,D2
    bpl  _L_z04_Ganon_AppendPaletteRowTransferRecord_Triforce_OverwriteColors
    moveq   #0,D2
    move.b  ($0340,A4),D2
    rts

    even
Ganon_DrawAshes:
    jsr     Anim_FetchObjPosForSpriteDescriptor
    moveq   #11,D0
    jmp     DrawObjectNotMirrored

    even
Ganon_ActivateRoomItem:
    ; If the room item was already active or taken, then return.
    ;
    move.b  ($00BF,A4),D0
    beq  _L_z04_Ganon_ActivateRoomItem_Exit
    jsr     GetRoomFlagUWItemState
    bne  _L_z04_Ganon_ActivateRoomItem_Exit
    ; Activate the room item, by setting its state to 0.
    ;
    moveq   #0,D0
    move.b  D0,($00BF,A4)
    ; Play "item appears" tune.
    ;
    moveq   #2,D0
    move.b  D0,($0602,A4)
    even
_L_z04_Ganon_ActivateRoomItem_Exit:
    rts

; Unknown block
    dc.b    $FF, $FF, $FF, $FF, $FF, $FF, $FF, $FF
    dc.b    $FF, $FF, $FF, $FF, $FF, $FF, $FF, $FF
    dc.b    $FF, $FF, $FF, $FF, $FF, $FF, $FF, $FF
    dc.b    $FF, $FF, $FF, $FF, $FF, $FF, $FF, $FF
    dc.b    $FF, $FF, $FF, $FF, $FF, $FF, $FF, $FF
    dc.b    $FF, $FF, $FF, $FF, $FF, $FF, $FF, $FF
    dc.b    $FF, $FF, $FF, $FF, $FF, $FF, $FF, $FF
    dc.b    $FF, $FF, $FF, $FF, $FF, $FF, $FF, $FF
    dc.b    $FF, $FF, $FF, $FF, $FF, $FF

; Params:
; A: hit point doublet (byte)
; [00]: object type
;
; Returns:
; A: hit points for object type
;
    even
ExtractHitPointValue:
    move.b  D0,-(A5)  ; PHA
    ; Even object types only have to mask off the bottom nibble.
    ;
    move.b  ($0000,A4),D0
    lsr.b  #1,D0   ; LSR A
    bcs  _L_z04_ExtractHitPointValue_OddType
    move.b  (A5)+,D0  ; PLA
    andi.b #$F0,D0
    rts

    even
_L_z04_ExtractHitPointValue_OddType:
    move.b  (A5)+,D0  ; PLA
    ; Odd object types have to multiply by 16.
    ;
    lsl.b  #1,D0   ; ASL A
    lsl.b  #1,D0   ; ASL A
    lsl.b  #1,D0   ; ASL A
    lsl.b  #1,D0   ; ASL A
    rts

    even
PlayBossDeathCry:
    moveq   #2,D0
    move.b  D0,($0601,A4)
    move.b  #$80,D0
    move.b  D0,($0603,A4)
    rts

; Types of objects that do not drop items.
;
    even
NoDropMonsterTypes:
    dc.b    $5D, $14, $15, $1B, $1C, $1D, $17

    even
DropItemMonsterTypes0:
    dc.b    $07, $08, $0E, $04, $0F, $23

    even
DropItemMonsterTypes1:
    dc.b    $21, $22, $0D, $10, $13, $28, $2A, $27
    dc.b    $16

    even
DropItemMonsterTypes2:
    dc.b    $09, $0A, $03, $01, $12, $06, $0B, $24
    dc.b    $30

; Multiples of $A to index the base of each row of items in DropItemTable.
;
    even
DropItemSetBaseOffsets:
    dc.b    $00, $0A, $14, $1E

; Top drop an item, a random value must be less than the
; element for the monster group.
;
    even
DropItemRates:
    dc.b    $50, $98, $68, $68

; ID's for items dropped by monsters.
; WorldKillCycle addresses the column.
;
; Monsters are arranged in groups that determine the row.
; There are four rows.
;
    even
DropItemTable:
    dc.b    $22, $18, $22, $18, $23, $18, $22, $22
    dc.b    $18, $18, $0F, $18, $22, $18, $0F, $22
    dc.b    $21, $18, $18, $18, $22, $00, $18, $21
    dc.b    $18, $22, $00, $18, $00, $22, $22, $22
    dc.b    $23, $18, $22, $23, $22, $22, $22, $18

    even
SetUpDroppedItem:
    ; Reset [01] which holds the row number of the drop item table.
    ;
    moveq   #0,D0
    move.b  D0,($0001,A4)
    ; Compare dead object's type to array of 7 that don't drop items.
    ; If found, go destroy the monster.
    ;
    lea     ($0412,A4),A0
    move.b  (A0,D2.W),D0
    moveq   #6,D3
    even
_L_z04_SetUpDroppedItem_FindNoDropType:
    lea     (NoDropMonsterTypes).l,A0
    move.b  (A0,D3.W),D1
    cmp.b   D1,D0
    beq  _L_z04_SetUpDroppedItem_DestroyMonster
    subq.b  #1,D3
    bpl  _L_z04_SetUpDroppedItem_FindNoDropType
    ; Look for object type in array of 6. These use drop item table row 0.
    ;
    moveq   #5,D3
    even
_L_z04_SetUpDroppedItem_FindDrop0Type:
    lea     (DropItemMonsterTypes0).l,A0
    move.b  (A0,D3.W),D1
    cmp.b   D1,D0
    beq  _L_z04_SetUpDroppedItem_Found
    subq.b  #1,D3
    bpl  _L_z04_SetUpDroppedItem_FindDrop0Type
    ; Increment row number in [01] to 1.
    ;
    addq.b  #1,($0001,A4)
    ; Look for object type in array of 9. These use drop item table row 1.
    ;
    moveq   #8,D3
    even
_L_z04_SetUpDroppedItem_FindDrop1Type:
    lea     (DropItemMonsterTypes1).l,A0
    move.b  (A0,D3.W),D1
    cmp.b   D1,D0
    beq  _L_z04_SetUpDroppedItem_Found
    subq.b  #1,D3
    bpl  _L_z04_SetUpDroppedItem_FindDrop1Type
    ; Increment row number in [01] to 2.
    ;
    addq.b  #1,($0001,A4)
    ; Look for object type in array of 9. These use drop item table row 2.
    ;
    moveq   #8,D3
    even
_L_z04_SetUpDroppedItem_FindDrop2Type:
    lea     (DropItemMonsterTypes2).l,A0
    move.b  (A0,D3.W),D1
    cmp.b   D1,D0
    beq  _L_z04_SetUpDroppedItem_Found
    subq.b  #1,D3
    bpl  _L_z04_SetUpDroppedItem_FindDrop2Type
    ; Increment [01]. The rest use row 3.
    ;
    addq.b  #1,($0001,A4)
    even
_L_z04_SetUpDroppedItem_Found:
    ; If object slot = 1 and object is stalfos or gibdos, then
    ; go destroy the mosnter, because it might already be carrying
    ; a room item.
    ;
    cmpi.b  #$01,D2
    bne  _L_z04_SetUpDroppedItem_LookUpItem
    cmpi.b  #$2A,D0
    beq  _L_z04_SetUpDroppedItem_DestroyMonster
    cmpi.b  #$30,D0
    beq  _L_z04_SetUpDroppedItem_DestroyMonster
    even
_L_z04_SetUpDroppedItem_LookUpItem:
    ; Look up the base offset of the row in the drop item table.
    ; Add it and WorldKillCycle to look up the dropped item for
    ; this object type and store it in [00].
    ;
    moveq   #0,D3
    move.b  ($0001,A4),D3
    lea     (DropItemSetBaseOffsets).l,A0
    move.b  (A0,D3.W),D0
    andi    #$EE,CCR  ; CLC: clear C+X
    move.b  ($052A,A4),D1
    addx.b  D1,D0   ; ADC WorldKillCycle
    moveq   #0,D3
    move.b  D0,D3
    lea     (DropItemTable).l,A0
    move.b  (A0,D3.W),D0
    move.b  D0,($0000,A4)
    ; If the global kill count = $10, set the dropped item to a fairy.
    ;
    moveq   #35,D0
    moveq   #0,D3
    move.b  ($0627,A4),D3
    cmpi.b  #$10,D3
    beq  _L_z04_SetUpDroppedItem_SetHelpItem
    ; If help drop counter < $A, then use the dropped item ID as is.
    ; But there is a random chance that the item drop will be canceled.
    ;
    move.b  ($0050,A4),D0
    cmpi.b  #$0A,D0
    bcs  _L_z04_SetUpDroppedItem_RandomlyCancel
    ; Otherwise, the item will be guaranteed to be made.
    ; [51] HelpDropValue determines which kind:
    ; - 0:     5 rupees
    ; - other: bomb
    ;
    moveq   #15,D0
    moveq   #0,D3
    move.b  ($0051,A4),D3
    beq  _L_z04_SetUpDroppedItem_SetHelpItem
    moveq   #0,D0
    even
_L_z04_SetUpDroppedItem_SetHelpItem:
    move.b  D0,($0000,A4)
    ; The player has been helped with a dropped item. Reset the
    ; help drop variables.
    ;
    moveq   #0,D0
    move.b  D0,($0050,A4)
    move.b  D0,($0051,A4)
    beq  _L_z04_SetUpDroppedItem_Commit
    even
_L_z04_SetUpDroppedItem_RandomlyCancel:
    ; If the random value >= drop item rate for the monster's group,
    ; then go destroy the monster.
    ;
    moveq   #0,D3
    move.b  ($0001,A4),D3
    move.b  ($18,A4,D2.W),D0
    lea     (DropItemRates).l,A0
    move.b  (A0,D3.W),D1
    cmp.b   D1,D0
    bcc  _L_z04_SetUpDroppedItem_DestroyMonster
    even
_L_z04_SetUpDroppedItem_Commit:
    ; Set ObjItemLifetime to $FF.
    ;
    move.b  #$FF,D0
    lea     ($03A8,A4),A0
    move.b  D0,(A0,D2.W)
    ; Set ObjItemId.
    ;
    move.b  ($0000,A4),D0
    lea     ($00AC,A4),A0
    move.b  D0,(A0,D2.W)
    ; If the item is a fairy, we have to finish setting it up.
    ;
    cmpi.b  #$23,D0
    bne  _anon_z04_166
    jmp     SetUpFairyObject

_anon_z04_166:
    rts

    even
_L_z04_SetUpDroppedItem_DestroyMonster:
    jmp     DestroyMonster_Bank4

    even
ItemTakerObjSlots:
    dc.b    $00, $0F, $0D, $12

    even
UpdateItem:
    ; Every other frame, decrement the item lifetime.
    ;
    move.b  ($0015,A4),D0
    lsr.b  #1,D0   ; LSR A
    bcc  _anon_z04_167
    lea     ($03A8,A4),A0
    subq.b  #1,(A0,D2.W)
_anon_z04_167:
    ; If lifetime reached 0, go destroy the object.
    ;
    lea     ($03A8,A4),A0
    move.b  (A0,D2.W),D0
    bne.s  __far_z_04_0136
    jmp  DestroyMonster_Bank4
__far_z_04_0136:
    ; Draw the item. Fairies are animated separately.
    ;
    lea     ($00AC,A4),A0
    move.b  (A0,D2.W),D0
    cmpi.b  #$23,D0
    beq  _L_z04_UpdateItem_AnimateFairy
    jsr     AnimateItemObject
    jmp     _anon_z04_168

    even
_L_z04_UpdateItem_AnimateFairy:
    jsr     UpdateFairyObject
_anon_z04_168:
    ; If the player is halted, then return.
    ;
    move.b  ($00AC,A4),D0
    andi.b #$C0,D0
    cmpi.b  #$40,D0
    beq  _L_z04_UpdateItem_Exit
    ; In addition to Link, there are 3 objects that can pick up items: 
    ; * arrow
    ; * sword
    ; * boomerang
    ;
    ; For each weapon that's active, substitute it's location for
    ; Link's and try taking the item. Have Link himself check last.
    ;
    moveq   #4,D0
    move.b  D0,($000D,A4)
    even
_L_z04_UpdateItem_LoopItemTaker:
    ; Save Link's location.
    ;
    move.b  ($0070,A4),D0
    move.b  D0,-(A5)  ; PHA
    move.b  ($0084,A4),D0
    move.b  D0,-(A5)  ; PHA
    ; Set Link's location to this object's.
    ;
    moveq   #0,D3
    move.b  ($000D,A4),D3
    moveq   #0,D2
    lea     (ItemTakerObjSlots-1).l,A0
    move.b  (A0,D3.W),D2
    move.b  ($70,A4,D2.W),D0
    move.b  D0,($0070,A4)
    lea     ($0084,A4),A0
    move.b  (A0,D2.W),D0
    move.b  D0,($0084,A4)
    cmpi.b  #$00,D2
    beq  _L_z04_UpdateItem_TryToTake
    ; If the object whose place Link is taking is not active, then
    ; don't try to take the item.
    ;
    lea     ($00AC,A4),A0
    move.b  (A0,D2.W),D0
    beq  _L_z04_UpdateItem_SkipTaking
    bmi  _L_z04_UpdateItem_SkipTaking
    even
_L_z04_UpdateItem_TryToTake:
    ; Try to take the item.
    ;
    moveq   #0,D2
    move.b  ($0340,A4),D2
    lea     ($00AC,A4),A0
    move.b  (A0,D2.W),D0
    move.b  D0,($0004,A4)
    jsr     TryTakeItem
    even
_L_z04_UpdateItem_SkipTaking:
    ; Restore Link's location.
    ;
    move.b  (A5)+,D0  ; PLA
    move.b  D0,($0084,A4)
    move.b  (A5)+,D0  ; PLA
    move.b  D0,($0070,A4)
    moveq   #0,D2
    move.b  ($0340,A4),D2
    ; If item object's item type is invalid, then the item was taken.
    ; So, go destroy this object.
    ;
    lea     ($00AC,A4),A0
    move.b  (A0,D2.W),D0
    cmpi.b  #$FF,D0
    bne.s  __far_z_04_0137
    jmp  DestroyMonster_Bank4
__far_z_04_0137:
    subq.b  #1,($000D,A4)
    bne  _L_z04_UpdateItem_LoopItemTaker
    even
_L_z04_UpdateItem_Exit:
    rts

; Params:
; X: object index
;
    even
DestroyMonster_Bank4:
    moveq   #0,D0
    lea     ($034F,A4),A0
    move.b  D0,(A0,D2.W)
    jsr     SetShoveInfoWith0
    move.b  D0,($28,A4,D2.W)
    lea     ($00AC,A4),A0
    move.b  D0,(A0,D2.W)
    lea     ($04F0,A4),A0
    move.b  D0,(A0,D2.W)
    move.b  #$FF,D0
    lea     ($0492,A4),A0
    move.b  D0,(A0,D2.W)
    moveq   #1,D0
    lea     ($0405,A4),A0
    move.b  D0,(A0,D2.W)
    rts

; Params:
; A: shot object type
; X: shooter object index
;
; Returns:
; C: 1 if succeeded
; Y: shot slot
;
; Description:
; The shot starts in state $10.
;
    even
_ShootIfWanted:
    move.b  D0,($0000,A4)
    ; If the monster does not want to shoot, then return C=0.
    ;
    lea     ($0412,A4),A0
    move.b  (A0,D2.W),D0
    bne.s  __far_z_04_0138
    jmp  ReturnDidNotShoot
__far_z_04_0138:
; Params:
; [00]: shot object type
;
; Returns:
; C: 1 if succeeded
; Y: shot slot
;
; Description:
; The shot starts in state $10.
;
; If no slot is found, return C=0.
;
    even
ShootLimited:
    jsr     FindEmptyMonsterSlot
    bne.s  __far_z_04_0139
    jmp  ReturnDidNotShoot
__far_z_04_0139:
    ; If the object type to shoot is a true shot (projectile),
    ; and we're at the limit of active shots (4), then return C=0.
    ;
    move.b  ($0000,A4),D0
    cmpi.b  #$53,D0
    bcc.s  __far_z_04_0140
    jmp  Shoot
__far_z_04_0140:
    move.b  ($034C,A4),D0
    cmpi.b  #$04,D0
    bcs.s  __far_z_04_0141
    jmp  ReturnDidNotShoot
__far_z_04_0141:
    ; Else increase the number of active shots.
    ;
    addq.b  #1,($034C,A4)
; Params:
; [00]: shot object type
; [59]: EmptyMonsterSlot
;
; Returns:
; C: 1 if succeeded
; Y: shot slot
;
; Description:
; The shot starts in state $10.
;
    even
Shoot:
    moveq   #0,D2
    move.b  ($0059,A4),D2
    move.b  ($0000,A4),D0
    jsr     SetTypeAndClearObject
    ; Set state to $10 and reset timer, so that the shot moves right away.
    ;
    moveq   #0,D3
    move.b  ($0059,A4),D3
    moveq   #0,D2
    move.b  ($0340,A4),D2
    moveq   #16,D0
    lea     ($00AC,A4),A0
    move.b  D0,(A0,D3.W)
    moveq   #0,D0
    move.b  D0,($28,A4,D3.W)
    ; Set the shot's direction and coordinates the same as the thrower's.
    ;
    lea     ($0098,A4),A0
    move.b  (A0,D2.W),D0
    lea     ($0098,A4),A0
    move.b  D0,(A0,D3.W)
    move.b  ($70,A4,D2.W),D0
    move.b  D0,($70,A4,D3.W)
    lea     ($0084,A4),A0
    move.b  (A0,D2.W),D0
    lea     ($0084,A4),A0
    move.b  D0,(A0,D3.W)
    ; Return C=1.
    ;
    ori     #$11,CCR  ; SEC: set C+X
    rts

    even
ReturnDidNotShoot:
    ; Return C=0.
    ;
    andi    #$EE,CCR  ; CLC: clear C+X
    rts

    even
UpdateCandle:
    move.b  ($051F,A4),D0
    jsr     _m68k_tablejump  ; M68K-native table dispatch (replaces JSR TableJump)
    even
UpdateCandle_JumpTable:
    dc.l    UpdateCandle_Begin   ; jump table entry (32-bit for _m68k_tablejump)
    dc.l    UpdateCandle_Brightening   ; jump table entry (32-bit for _m68k_tablejump)
    dc.l    UpdateCandle_Done   ; jump table entry (32-bit for _m68k_tablejump)

    even
UpdateCandle_Begin:
    moveq   #0,D3
    move.b  ($00EB,A4),D3
    jsr     IsDarkRoom_Bank4
    bne.s  __far_z_04_0142
    jmp  UpdateCandle_Done
__far_z_04_0142:
    move.b  #$C0,D0
    move.b  D0,($051C,A4)
    addq.b  #1,($051E,A4)
    even
L_Candle_IncState:
    addq.b  #1,($051F,A4)
    even
UpdateCandle_Done:
    rts

    even
L_Candle_StopBrightening:
    ; Stop brightening the room, and go set the candle state to done.
    ;
    moveq   #0,D0
    move.b  D0,($051E,A4)
    bne.s  __far_z_04_0143
    jmp  L_Candle_IncState
__far_z_04_0143:
    even
UpdateCandle_Brightening:
    ; Animating a brightening cycle.
    ;
    jsr     AnimateWorldFading
    bne.s  __far_z_04_0144
    jmp  L_Candle_StopBrightening
__far_z_04_0144:
    rts

; Params:
; Y: room ID
;
; Returns:
; A: $80 if dark, else 0
;
    even
IsDarkRoom_Bank4:
    move.b  ($0010,A4),D0
    beq  _anon_z04_169
    lea     (NES_SRAM+$0A7E).l,A0
    move.b  (A0,D3.W),D0
    andi.b #$80,D0
_anon_z04_169:
    rts

    even
SetUpFairyObject:
    ; Play "fairy appears" tune. It's also "object taken".
    ;
    moveq   #8,D0
    move.b  D0,($0602,A4)
    jsr     ResetFlyerState
    ; Face up at first.
    ;
    moveq   #8,D0
    lea     ($0098,A4),A0
    move.b  D0,(A0,D2.W)
    ; Set flying speed fraction to $7F.
    ;
    moveq   #127,D0
    lea     ($041F,A4),A0
    move.b  D0,(A0,D2.W)
    ; Set maximum speed fraction to $A0.
    ;
    move.b  #$A0,D0
    move.b  D0,($04D1,A4)
    rts

    even
ResetFlyerState:
    moveq   #0,D0
    lea     ($0412,A4),A0
    move.b  D0,(A0,D2.W)
    lea     ($042C,A4),A0
    move.b  D0,(A0,D2.W)
    lea     ($0437,A4),A0
    move.b  D0,(A0,D2.W)
    lea     ($0444,A4),A0
    move.b  D0,(A0,D2.W)
    lea     ($04F0,A4),A0
    move.b  D0,(A0,D2.W)
    rts

; Params:
; X: object index
;
    even
UpdateFairyObject:
    jsr     ControlFairyFlight
    jsr     MoveFlyer
    even
DrawFairy:
    jsr     Anim_FetchObjPosForSpriteDescriptor
    jsr     Anim_SetSpriteDescriptorRedPaletteRow
    ; Every 4 frames, switch between the two sprite frames.
    ;
    lsl.b  #1,D0   ; ASL A
    move.b  ($0015,A4),D1
    and.b  D1,D0
    lsr.b  #1,D0   ; LSR A
    lsr.b  #1,D0   ; LSR A
    move.b  D0,($000C,A4)
    moveq   #20,D3
    jmp     Anim_WriteItemSprites

    even
ControlFairyFlight:
    lea     ($0444,A4),A0
    move.b  (A0,D2.W),D0
    jsr     _m68k_tablejump  ; M68K-native table dispatch (replaces JSR TableJump)
    even
ControlFairyFlight_JumpTable:
    dc.l    Flyer_SpeedUp   ; jump table entry (32-bit for _m68k_tablejump)
    dc.l    Flyer_FairyDecideState   ; jump table entry (32-bit for _m68k_tablejump)
    dc.l    Flyer_DoNothing   ; jump table entry (32-bit for _m68k_tablejump)
    dc.l    Flyer_Wander   ; jump table entry (32-bit for _m68k_tablejump)

    even
Flyer_FairyDecideState:
    ; Set up 6 turns, and go to state 3.
    ;
    moveq   #3,D0
    lea     ($0444,A4),A0
    move.b  D0,(A0,D2.W)
    moveq   #6,D0
    lea     ($042C,A4),A0
    move.b  D0,(A0,D2.W)
    even
Flyer_DoNothing:
    rts

    even
Directions8:
    dc.b    $08, $09, $01, $05, $04, $06, $02, $0A

    even
Flyer_Delay:
    ; Delay until ObjTimer[X] expires. Then go to flying state 0.
    ;
    move.b  ($28,A4,D2.W),D0
    bne  _anon_z04_170
    moveq   #0,D0
    lea     ($0444,A4),A0
    move.b  D0,(A0,D2.W)
_anon_z04_170:
    rts

    even
Flyer_SlowDown:
    ; Decrease speed each frame.
    ; When it goes below a threshold ($20), go to flying state 5.
    ;
    lea     ($041F,A4),A0
    subq.b  #1,(A0,D2.W)
    jmp     _anon_z04_171

    even
Flyer_SpeedUp:
    ; Increase speed each frame.
    ; When it reaches a threshold, go to flying state 1.
    ;
    lea     ($041F,A4),A0
    addq.b  #1,(A0,D2.W)
_anon_z04_171:
    lea     ($041F,A4),A0
    move.b  (A0,D2.W),D0
    andi.b #$E0,D0
    beq.s  __far_z_04_0145
    jmp  Flyer_CompareMaxSpeed
__far_z_04_0145:
    ; (whole_speed & $E0) = 0
    ; Set a random timer between $40 and $7F.
    ;
    move.b  ($18,A4,D2.W),D0
    andi.b #$3F,D0
    ori.b #$40,D0
    move.b  D0,($28,A4,D2.W)
