    ;
    moveq   #5,D0
    even
Flyer_SetFlyingState:
    lea     ($0444,A4),A0
    move.b  D0,(A0,D2.W)
_anon_z04_172:
    rts

    even
Flyer_CompareMaxSpeed:
    move.b  ($04D1,A4),D1
    cmp.b   D1,D0
    bcs  _anon_z04_172
    moveq   #1,D0
    jmp     Flyer_SetFlyingState

    even
MoveFlyer:
    ; Add (flying speed AND $E0) to flying position fraction.
    ;
    lea     ($041F,A4),A0
    move.b  (A0,D2.W),D0
    andi.b #$E0,D0
    andi    #$EE,CCR  ; CLC: clear C+X
    lea     ($0412,A4),A0
    move.b  (A0,D2.W),D1
    addx.b  D1,D0   ; ADC Flyer_ObjSpeedFrac,X
    lea     ($0412,A4),A0
    move.b  D0,(A0,D2.W)
    bcc  _L_z04_MoveFlyer_Exit
    ; Because this object can move in 8 directions,
    ; test the object's direction with each cardinal direction,
    ; to modify the coordinates accordingly.
    ;
    ; Test right.
    ;
    moveq   #1,D0
    move.b  D0,($0002,A4)
    lea     ($0098,A4),A0
    move.b  (A0,D2.W),D0
    move.b  ($0002,A4),D1
    and.b   D0,D1   ; BIT: set Z/N/V from D1 AND A
    beq  _L_z04_MoveFlyer_Left
    addq.b  #1,($70,A4,D2.W)
    lea     ($046B,A4),A0
    addq.b  #1,(A0,D2.W)
    even
_L_z04_MoveFlyer_Left:
    ; Test left.
    ;
    move.b  ($0002,A4),D1
    lsl.b  #1,D1   ; ASL $02
    move.b  D1,($0002,A4)
    move.b  ($0002,A4),D1
    and.b   D0,D1   ; BIT: set Z/N/V from D1 AND A
    beq  _L_z04_MoveFlyer_Down
    subq.b  #1,($70,A4,D2.W)
    lea     ($046B,A4),A0
    subq.b  #1,(A0,D2.W)
    even
_L_z04_MoveFlyer_Down:
    ; Test down.
    ;
    move.b  ($0002,A4),D1
    lsl.b  #1,D1   ; ASL $02
    move.b  D1,($0002,A4)
    move.b  ($0002,A4),D1
    and.b   D0,D1   ; BIT: set Z/N/V from D1 AND A
    beq  _L_z04_MoveFlyer_Up
    lea     ($0084,A4),A0
    addq.b  #1,(A0,D2.W)
    lea     ($0478,A4),A0
    addq.b  #1,(A0,D2.W)
    even
_L_z04_MoveFlyer_Up:
    ; Test up.
    ;
    move.b  ($0002,A4),D1
    lsl.b  #1,D1   ; ASL $02
    move.b  D1,($0002,A4)
    move.b  ($0002,A4),D1
    and.b   D0,D1   ; BIT: set Z/N/V from D1 AND A
    beq  _L_z04_MoveFlyer_End
    lea     ($0084,A4),A0
    subq.b  #1,(A0,D2.W)
    lea     ($0478,A4),A0
    subq.b  #1,(A0,D2.W)
    even
_L_z04_MoveFlyer_End:
    ; Increase the distance traveled; and keep the object within
    ; the bounds of the room.
    ;
    lea     ($0437,A4),A0
    addq.b  #1,(A0,D2.W)
    jsr     BoundFlyer
    even
_L_z04_MoveFlyer_Exit:
    rts

; Returns:
; A: original facing or the opposite
; [0F]: 0 if blocked
;
    even
BoundFlyer:
    lea     ($0098,A4),A0
    move.b  (A0,D2.W),D0
    move.b  D0,($000F,A4)
    jsr     BoundDirectionHorizontally
    ; Check vertical boundaries, if object is not a boulder.
    ;
