    ;
    moveq   #16,D0
    move.b  D0,($28,A4,D2.W)
    even
TurnTowardsPlayer8:
    ; Build a direction in [00] towards the player.
    ;
    ; First, calculate a horizontal component:
    ;
    ; If   observed player X = object X, [00] := 0 (none)
    ; elif observed player X > object X, [00] := 1 (right)
    ; else                               [00] := 2 (left)
    ;
    moveq   #0,D3
    move.b  D3,($0000,A4)
    addq.b  #1,D3
    move.b  ($0061,A4),D0
    move.b  ($70,A4,D2.W),D1
    cmp.b   D1,D0
    beq  _L_z04_TurnTowardsPlayer8_CalcVertical
    bcs  _anon_z04_175
    addq.b  #1,D3
_anon_z04_175:
    move.b  D3,($0000,A4)
    even
_L_z04_TurnTowardsPlayer8_CalcVertical:
    ; Second, calculate a vertical component.
    ; Combine it with the horizontal component:
    ;
    ; Y := 4 (down)
    ; if observed player Y <> object Y then
    ;   if observed player Y < object Y then
    ;     Y := Y << 1   -- makes it 8 (up)
    ;   [00] := [00] | Y
    ;
    moveq   #1,D3
    move.b  ($0062,A4),D0
    lea     ($0084,A4),A0
    move.b  (A0,D2.W),D1
    cmp.b   D1,D0
    beq  _L_z04_TurnTowardsPlayer8_SkipVertical
    bcs  _anon_z04_176
    addq.b  #1,D3
_anon_z04_176:
    move.b  D3,D0
    lsl.b  #1,D0   ; ASL A
    lsl.b  #1,D0   ; ASL A
    move.b  ($0000,A4),D1
    or.b  D1,D0
    move.b  D0,($0000,A4)
    even
_L_z04_TurnTowardsPlayer8_SkipVertical:
    ; Get the index of the object's direction.
    ;
    jsr     GetObjDir8Index
    ; Check 3 directions turning left:
    ; 1. right from object direction
    ; 2. object direction
    ; 3. left from object direction
    ;
    ; If the target direction matches any of these, then
    ; leave the object's direction alone.
    ;
    moveq   #3,D0
    move.b  D0,($0001,A4)
    addq.b  #1,D3
    even
_L_z04_TurnTowardsPlayer8_LoopLeft:
    move.b  D3,D0
    andi.b #$07,D0
    moveq   #0,D3
    move.b  D0,D3
    lea     (Directions8).l,A0
    move.b  (A0,D3.W),D0
    move.b  ($0000,A4),D1
    cmp.b   D1,D0
    bne.s  __far_z_04_0151
    jmp  L1336F_Exit
__far_z_04_0151:
    subq.b  #1,D3
    subq.b  #1,($0001,A4)
    bne  _L_z04_TurnTowardsPlayer8_LoopLeft
    ; Check 3 directions turning right:
    ; 1. left of object direction
    ; 2. object direction
    ; 3. right of object direction
    ;
    ; If any direction component of the target direction matches
    ; these, then see if we should turn to this direction.
    ;
    moveq   #3,D0
    move.b  D0,($0001,A4)
    addq.b  #1,D3
    even
LoopRight:
    move.b  D3,D0
    andi.b #$07,D0
    moveq   #0,D3
    move.b  D0,D3
    lea     (Directions8).l,A0
    move.b  (A0,D3.W),D0
    move.b  ($0000,A4),D1
    and.b   D0,D1   ; BIT: set Z/N/V from D1 AND A
    beq.s  __far_z_04_0152
    jmp  TestDir
__far_z_04_0152:
    even
NextLoopRight:
    addq.b  #1,D3
    subq.b  #1,($0001,A4)
    beq.s  __far_z_04_0153
    jmp  LoopRight
__far_z_04_0153:
    ; We didn't find a direction to switch to.
    ; So turn left once; to one turn right of object direction.
    ;
    subq.b  #1,D3
    even
SetDir8ForIndex:
    ; Apply the new direction.
    ;
    lea     (Directions8).l,A0
    move.b  (A0,D3.W),D0
    lea     ($0098,A4),A0
    move.b  D0,(A0,D2.W)
    even
L1336F_Exit:
    rts

    even
TestDir:
    ; If (test direction OR target direction) < 7, then allow this turn.
    ; Else go try the next test direction.
    ;
    ; For 3/5 of the arrangements of angles between Link and
    ; objects; this test yields a turn towards Link. The rest of
    ; the time, the object will keep going in its original direction
    ; or turn away from Link.
    ;
    move.b  ($0000,A4),D1
    or.b  D1,D0
    cmpi.b  #$07,D0
    bcs.s  __far_z_04_0154
    jmp  NextLoopRight
__far_z_04_0154:
    bcs.s  __far_z_04_0155
    jmp  SetDir8ForIndex
__far_z_04_0155:
