    even
PatraSines:
    dc.b    $00, $18, $30, $47, $5A, $6A, $76, $7D
    dc.b    $80, $7D, $76, $6A, $5A, $47, $30, $18

; Params:
; A: high bits of cosine to use in calculating Y increment
; Y: high bits of sine to use in calculating X increment
; X: object index
;
; Returns:
; A: new Y coordinate of object
;
; [06] holds the number of high bits of cosine to use
    even
RotateObjectLocation:
    move.b  D0,($0006,A4)
    move.b  D3,($0005,A4)
    ; First, rotate the X coordinate.
    ;
    ; Look up the sine for the current angle, and store it in [00].
    ;
    lea     ($0394,A4),A0
    move.b  (A0,D2.W),D0
    andi.b #$0F,D0
    moveq   #0,D3
    move.b  D0,D3
    lea     (PatraSines).l,A0
    move.b  (A0,D3.W),D0
    move.b  D0,($0000,A4)
    ; Mutliply q-speed by [00].
    ;
    ; Q-speed has the default value $20 set when entering the room.
    ;
    lea     ($03BC,A4),A0
    move.b  (A0,D2.W),D0
    moveq   #0,D3
    move.b  ($0005,A4),D3
    jsr     ShiftMultiply
    ; The absolute X increment for the current angle is now in [02:03].
    ;
    ; If angle >= $10, then the monster is in the top half of circle going left.
    ;
    lea     ($0394,A4),A0
    move.b  (A0,D2.W),D0
    andi.b #$18,D0
    cmpi.b  #$10,D0
    bcs  _L_z04_RotateObjectLocation_AddToX
    ; Subtract the product's fraction from the X coordinate fraction.
    ;
    lea     ($0412,A4),A0
    move.b  (A0,D2.W),D0
    ori     #$11,CCR  ; SEC: set C+X
    move.b  ($0002,A4),D1
    eori    #$10,CCR  ; flip X: 6502 SBC polarity
    subx.b  D1,D0   ; SBC $02
    eori    #$10,CCR  ; restore X = 6502 C
    lea     ($0412,A4),A0
    move.b  D0,(A0,D2.W)
    ; And subtract the product's whole part from the X coordinate with carry.
    ;
    move.b  ($70,A4,D2.W),D0
    move.b  ($0003,A4),D1
    eori    #$10,CCR  ; flip X: 6502 SBC polarity
    subx.b  D1,D0   ; SBC $03
    eori    #$10,CCR  ; restore X = 6502 C
    jmp     _L_z04_RotateObjectLocation_SetXRotateY

    even
_L_z04_RotateObjectLocation_AddToX:
    ; Else angle < $10. So, the monster is in the bottom half of circle going right.
    ; Add the product's fraction to the X coordinate fraction.
    ;
    lea     ($0412,A4),A0
    move.b  (A0,D2.W),D0
    andi    #$EE,CCR  ; CLC: clear C+X
    move.b  ($0002,A4),D1
    addx.b  D1,D0   ; ADC $02
    lea     ($0412,A4),A0
    move.b  D0,(A0,D2.W)
    ; And add the product's whole part to the X coordinate with carry.
    ;
    move.b  ($70,A4,D2.W),D0
    move.b  ($0003,A4),D1
    addx.b  D1,D0   ; ADC $03
    even
_L_z04_RotateObjectLocation_SetXRotateY:
    move.b  D0,($70,A4,D2.W)
    ; Now rotate the Y coordinate.
    ;
    ; Look up the cosine for the current angle, and store it in [00].
    ; The cosine corresponds to the sine offset by a quarter circle (8).
    ;
    lea     ($0394,A4),A0
    move.b  (A0,D2.W),D0
    andi    #$EE,CCR  ; CLC: clear C+X
    move.b  #$08,D1
    addx.b  D1,D0   ; ADC #$08 (X flag = 6502 C)
    andi.b #$0F,D0
    moveq   #0,D3
    move.b  D0,D3
    lea     (PatraSines).l,A0
    move.b  (A0,D3.W),D0
    move.b  D0,($0000,A4)
    ; Multiply q-speed by [00].
    ;
    lea     ($03BC,A4),A0
    move.b  (A0,D2.W),D0
    moveq   #0,D3
    move.b  ($0006,A4),D3
    jsr     ShiftMultiply
    ; The absolute Y increment for the current angle is now in [02:03].
    ;
    ; If (angle - 8) >= $10, then the monster is in the right half of circle going up.
    ;
    lea     ($0394,A4),A0
    move.b  (A0,D2.W),D0
    ori     #$11,CCR  ; SEC: set C+X
    move.b  #$08,D1
    eori    #$10,CCR  ; flip X: 6502 SBC polarity
    subx.b  D1,D0   ; SBC #$08
    eori    #$10,CCR  ; restore X = 6502 C
    andi.b #$18,D0
    cmpi.b  #$10,D0
    bcs  _L_z04_RotateObjectLocation_AddToY
    ; Subtract the product's fraction from the Y coordinate fraction.
    ;
    lea     ($041F,A4),A0
    move.b  (A0,D2.W),D0
    ori     #$11,CCR  ; SEC: set C+X
    move.b  ($0002,A4),D1
    eori    #$10,CCR  ; flip X: 6502 SBC polarity
    subx.b  D1,D0   ; SBC $02
    eori    #$10,CCR  ; restore X = 6502 C
    lea     ($041F,A4),A0
    move.b  D0,(A0,D2.W)
    ; And subtract the product's whole part from the Y coordinate.
    ;
    lea     ($0084,A4),A0
    move.b  (A0,D2.W),D0
    move.b  ($0003,A4),D1
    eori    #$10,CCR  ; flip X: 6502 SBC polarity
    subx.b  D1,D0   ; SBC $03
    eori    #$10,CCR  ; restore X = 6502 C
    eori    #$01,CCR  ; normalize C to 6502 polarity before RTS
    rts

    even
_L_z04_RotateObjectLocation_AddToY:
    ; Else (angle - 8) < $10. So, the monster is in the left half of circle going down.
    ; Add the product's fraction to the Y coordinate fraction.
    ;
    lea     ($041F,A4),A0
    move.b  (A0,D2.W),D0
    andi    #$EE,CCR  ; CLC: clear C+X
    move.b  ($0002,A4),D1
    addx.b  D1,D0   ; ADC $02
    lea     ($041F,A4),A0
    move.b  D0,(A0,D2.W)
    ; And add the product's whole part to the Y coordinate with carry.
    ;
    lea     ($0084,A4),A0
    move.b  (A0,D2.W),D0
    move.b  ($0003,A4),D1
    addx.b  D1,D0   ; ADC $03
    rts

; Params:
; A: multiplicand
; Y: number of high bits of [00] to use
; [00]: multiplier (high Y bits are used)
;
; Returns:
; [02:03]: product
;
    even
ShiftMultiply:
    move.b  D0,($0001,A4)
    moveq   #0,D0
    move.b  D0,($0002,A4)
    move.b  D0,($0003,A4)
    even
_L_z04_ShiftMultiply_Loop:
    move.b  ($0002,A4),D1
    lsl.b  #1,D1   ; ASL $02
    move.b  D1,($0002,A4)
    move.b  ($0003,A4),D1
    roxl.b  #1,D1   ; ROL $03
    move.b  D1,($0003,A4)
    move.b  ($0000,A4),D1
    lsl.b  #1,D1   ; ASL $00
    move.b  D1,($0000,A4)
    bcc  _L_z04_ShiftMultiply_Next
    move.b  ($0002,A4),D0
    andi    #$EE,CCR  ; CLC: clear C+X
    move.b  ($0001,A4),D1
    addx.b  D1,D0   ; ADC $01
    move.b  D0,($0002,A4)
    bcc  _L_z04_ShiftMultiply_Next
; Unknown block
    dc.b    $E6, $03

    even
_L_z04_ShiftMultiply_Next:
    subq.b  #1,D3
    bne  _L_z04_ShiftMultiply_Loop
    rts

; Params:
; A: low amount byte
; X: object index
; [0B]: high amount byte
;
; Subtract the low amount byte from low angle byte.
;
    even
DecreaseObjectAngle:
    move.b  D0,($000A,A4)
    lea     ($0380,A4),A0
    move.b  (A0,D2.W),D0
    ori     #$11,CCR  ; SEC: set C+X
    move.b  ($000A,A4),D1
    eori    #$10,CCR  ; flip X: 6502 SBC polarity
    subx.b  D1,D0   ; SBC $0A
    eori    #$10,CCR  ; restore X = 6502 C
    lea     ($0380,A4),A0
    move.b  D0,(A0,D2.W)
    ; Subtract the high amount byte from high angle byte with borrow.
    ;
    lea     ($0394,A4),A0
    move.b  (A0,D2.W),D0
    move.b  ($000B,A4),D1
    eori    #$10,CCR  ; flip X: 6502 SBC polarity
    subx.b  D1,D0   ; SBC $0B
    eori    #$10,CCR  ; restore X = 6502 C
    ; Cap the high byte at $1F.
    ;
    andi.b #$1F,D0
    lea     ($0394,A4),A0
    move.b  D0,(A0,D2.W)
    eori    #$01,CCR  ; normalize C to 6502 polarity before RTS
    rts


